INSERT INTO `yl_chat_message` VALUES (52, 4, '39c8c439-e079-495d-a664-d77ae89e1709', 2, '好的！根据【平台真实资料库存】，为您推荐以下计算机专业考研数学资料：\n\n---\n\n### 📚 平台可购数学资料\n\n1. **《考研数学基础通关讲义》** - 价格：**49元**  \n   [查看详情](path=/materials&id=101) - 适合基础阶段系统学习，含例题详解。\n\n2. **《数学历年真题精解（近10年）》** - 价格：**68元**  \n   [查看详情](path=/materials&id=102) - 含2014-2024年真题及逐题解析，适合刷题实战。\n\n3. **《高等数学强化冲刺800题》** - 价格：**55元**  \n   [查看详情](path=/materials&id=103) - 针对考数学一的计算机专业，题型覆盖全面。\n\n4. **《线性代数与概率论速成手册》** - 价格：**35元**  \n   [查看详情](path=/materials&id=104) - 小巧便携，公式+典型题速查。\n\n---\n\n### 💡 购买建议\n- 若您**刚开始复习**，建议先入手《基础通关讲义》+《速成手册》。\n- 若您**已进入强化阶段**，可直接选《真题精解》+《800题》。\n\n如需进一步了解某本书的目录或适用版本（数一/二/三），请告诉我！', '2026-05-01 17:52:48', '2026-05-01 17:52:48', 0);
