INSERT INTO `yl_chat_message` VALUES (82, 4, '39c8c439-e079-495d-a664-d77ae89e1709', 2, '好的，根据您的需求（计算机专业、数学资料），我为您查询了平台【研路无忧】资料商城的真实库存。目前平台中与数学/计算机相关的资料如下：\n\n---\n\n### 📚 平台真实资料推荐\n\n1. [数据结构1800题](path=/materials/detail/4) - 价格：50.00元 - 分类：专业课\n2. [计算机网络考研复习笔记](path=/materials/detail/2) - 价格：30.00元 - 分类：专业课\n\n---\n\n### 💡 说明\n- 平台目前**没有专门的“数学”分类资料**，但以上两件资料属于**计算机专业课**，与您的专业高度相关。\n- 如果您需要**考研数学（数一/数二/数三）** 的专项资料，平台暂无库存，建议您前往其他渠道购买（如张宇、汤家凤、李永乐等主流老师的辅导书）。\n\n如果您有其他需求，欢迎继续提问！', '2026-05-02 03:22:44', '2026-05-02 03:22:44', 0);
