INSERT INTO `yl_guide` VALUES (64, '河北科技大学2026年硕士研究生考试复试加试科目目录', '<h1>河北科技大学2026年硕士研究生考试复试加试科目目录</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：河北科技大学研究生院 2025-10-23　 相关院校：<a href=\"/graduate/grad/schoolID/526.shtml\" title=\"河北科技大学研究生院\" target=\"_blank\"><b>河北科技大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/526.shtml\" target=\"_blank\" title=\"河北科技大学考研资料\"><font color=\"#ff0000\">河北科技大学2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>根据教育部《2026年硕士研究生招生工作管理规定》的要求，以同等学力身份报考并参加复试的考生，在复试中须加试至少两门与报考专业相关的本科主干课程。</p>\n <p>我校所有同等学力考生初试合格后，复试时需另加试两门本学科主干课程，加试方式为笔试，满分100分，考试时长2小时。加试科目和初试科目不同，具体加试科目见下表。</p>\n <p></p>\n <table border=\"1\" width=\"98%\">\n  <tbody>\n   <tr>\n    <td>\n     <div>\n      学院代码\n     </div></td>\n    <td>\n     <div>\n      学院名称\n     </div></td>\n    <td>\n     <div>\n      专业\n     </div>\n     <div>\n      代码\n     </div></td>\n    <td>\n     <div>\n      专业名称\n     </div></td>\n    <td>\n     <div>\n      科目1\n     </div>\n     <div>\n      代码\n     </div></td>\n    <td>\n     <div>\n      科目1名称\n     </div></td>\n    <td>\n     <div>\n      科目2\n     </div>\n     <div>\n      代码\n     </div></td>\n    <td>\n     <div>\n      科目2名称\n     </div></td>\n   </tr>\n   <tr>\n    <td>\n     <div>\n      001\n     </div></td>\n    <td>\n     <div>\n      材料科学与工程学院\n     </div></td>\n    <td colspan=\"2\">\n     <div>\n      该学院所有学科专业同等学力考生复试加试科目相同\n     </div></td>\n    <td>\n     <div>\n      J00101\n     </div></td>\n    <td>\n     <div>\n      材料性能学\n     </div></td>\n    <td>\n     <div>\n      J00102\n     </div></td>\n    <td>\n     <div>\n      金属工艺学\n     </div></td>\n   </tr>\n   <tr>\n    <td rowspan=\"5\">\n     <div>\n      002\n     </div></td>\n    <td rowspan=\"5\">\n     <div>\n      电气工程学院\n     </div></td>\n    <td>\n     <div>\n      080800\n     </div></td>\n    <td>\n     <div>\n      电气工程\n     </div></td>\n    <td rowspan=\"4\">\n     <div>\n      J00201\n     </div></td>\n    <td rowspan=\"4\">\n     <div>\n      电气控制与PLC\n     </div></td>\n    <td rowspan=\"2\">\n     <div>\n      J00202\n     </div></td>\n    <td rowspan=\"2\">\n     <div>\n      电力工程\n     </div></td>\n   </tr>\n   <tr>\n    <td>\n     <div>\n      085801\n     </div></td>\n    <td>\n     <div>\n      电气工程\n     </div></td>\n   </tr>\n   <tr>\n    <td>\n     <div>\n      081100\n     </div></td>\n    <td>\n     <div>\n      控制科学与工程\n     </div></td>\n    <td rowspan=\"2\">\n     <div>\n      J00203\n     </div></td>\n    <td rowspan=\"2\">\n     <div>\n      检测技术及仪表\n     </div></td>\n   </tr>\n   <tr>\n    <td>\n     <div>\n      085400\n     </div></td>\n    <td>\n     <div>\n      电子信息\n     </div></td>\n   </tr>\n   <tr>\n    <td>\n     <div>\n      140500\n     </div></td>\n    <td>\n     <div>\n      智能科学与技术\n     </div></td>\n    <td>\n     <div>\n      J00204\n     </div></td>\n    <td>\n     <div>\n      模式识别与机器学习\n     </div></td>\n    <td>\n     <div>\n      J00205\n     </div></td>\n    <td>\n     <div>\n      数据结构与算法\n     </div></td>\n   </tr>\n   <tr>