INSERT INTO `yl_guide` VALUES (71, '哈尔滨理工大学2026年硕士研究生招生考试复试大纲', '<h1>哈尔滨理工大学2026年硕士研究生招生考试复试大纲</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/97.shtml\" target=\"_blank\" title=\"更多2026考研大纲相关内容列表\">2026考研大纲</a> 来源：哈尔滨理工大学 2026-03-14　 相关院校：<a href=\"/graduate/grad/schoolID/844.shtml\" title=\"哈尔滨理工大学研究生院\" target=\"_blank\"><b>哈尔滨理工大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/844.shtml\" target=\"_blank\" title=\"哈尔滨理工大学考研资料\"><font color=\"#ff0000\">哈尔滨理工大学2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>1.复试大纲请下载附件查看。</p>\n <p>2.管理类联考的考生，复试中需加试思想政治理论。</p>\n <p>3.复试具体安排以复试前公布的《哈尔滨理工大学各学院2026年硕士研究生招生考试复试录取工作细则》为准。</p>\n <p>4.哈尔滨理工大学研究生招生（含调剂）所有公告均只通过哈尔滨理工大学研究生处官网等官方渠道对外公布，请考生提高警惕，谨防上当受骗！</p>\n <p>研招办咨询电话：0451-86390155</p>\n <p><a target=\"_blank\" rel=\"nofollow\" href=\"https://graduate.hrbust.edu.cn/_upload/article/files/70/fb/9287f5f54d36b1970ac86df87295/77496b75-ae3c-43d2-b084-90508b9e27c0.zip\"><font color=\"#008080\">附件：哈尔滨理工大学2026年硕士研究生招生考试复试科目大纲.zip</font></a></p>\n</div>', 'kaoshidagang', NULL, 0, 1, '2026-03-22 18:26:02', '2026-04-08 21:20:00', 0, '哈尔滨理工大学', '不限', 0, 71);
