INSERT INTO `yl_guide` VALUES (73, '佳木斯大学2026年硕士研究生招生考试（复试）大纲', '<h1>佳木斯大学2026年硕士研究生招生考试（复试）大纲</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/97.shtml\" target=\"_blank\" title=\"更多2026考研大纲相关内容列表\">2026考研大纲</a> 来源：佳木斯大学 2026-03-14　 相关院校：<a href=\"/graduate/grad/schoolID/834.shtml\" title=\"佳木斯大学研究生院\" target=\"_blank\"><b>佳木斯大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/834.shtml\" target=\"_blank\" title=\"佳木斯大学考研资料\"><font color=\"#ff0000\">佳木斯大学2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <div id=\"vsb_content\">\n  <div>\n   <div>\n    <p><strong>一、各学院复试大纲（参考书目）请下载附件查看。 </strong></p><strong> </strong>\n    <p><strong> 二、报考会计专硕的考生，复试时须考核政治理论知识，该部分可参考国家初试思想政治理论考试大纲。 </strong></p><strong> </strong>\n    <p><strong> 三、同等学力考生在复试时须加试【获得国家承认的高职（专科）毕业学历后满2年及以上人员（毕业后到录取当年入学前，下同）或国家承认学历的本科结业生，按本科毕业同等学力身份报考】，加试科目为两门本科阶段主干课程，具体要求以研究生部网站发布的招生学院复试方案所列加试科目及加试参考书为准。</strong></p>\n    <p><font color=\"#008080\">附件【</font><a target=\"_blank\" rel=\"nofollow\" href=\"https://yjs.jmsu.edu.cn/system/_content/download.jsp?urltype=news.DownloadAttachUrl&amp;owner=1843095195&amp;wbfileid=93FBD1145BC5DA541A19441E83C83381\"><font color=\"#008080\">佳木斯大学2026年硕士研究生招生（复试）参考书目.pdf</font></a><font color=\"#008080\">】已下载2573次</font></p>\n   </div>\n  </div>\n </div>\n</div>', 'kaoshidagang', NULL, 0, 1, '2026-03-22 18:26:03', '2026-04-08 21:20:00', 0, '佳木斯大学', '不限', 0, 73);
INSERT INTO `yl_guide` VALUES (74, '中南林业科技大学2026年硕士研究生入学考试复试科目考试大纲', '<h1>中南林业科技大学2026年硕士研究生入学考试复试科目考试大纲</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/97.shtml\" target=\"_blank\" title=\"更多2026考研大纲相关内容列表\">2026考研大纲</a> 来源：中南林业科技大学 2026-03-10　 相关院校：<a href=\"/graduate/grad/schoolID/651.shtml\" title=\"中南林业科技大学研究生院\" target=\"_blank\"><b>中南林业科技大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/651.shtml\" target=\"_blank\" title=\"中南林业科技大学考研资料\"><font color=\"#ff0000\">中南林业科技大学2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <div id=\"vsb_content\">\n  <div>\n   <p>各位考生：</p>\n   <p>我校2026年硕士研究生入学考试复试科目考试大纲将会持续更新，近期会全部公布。具体见附件。</p>\n   <p>中南林业科技大学研究生招生办公室</p>\n   <p>2026年3月6日 <font color=\"#008080\"> </font></p><font color=\"#008080\"> </font>\n  </div><font color=\"#008080\"> </font>\n </div><font color=\"#008080\"> </font>\n <div>\n  <font color=\"#008080\"> </font>\n  <p><font color=\"#008080\"> 附件【</font><a target=\"_blank\" rel=\"nofollow\" href=\"https://yjsy.csuft.edu.cn/system/_content/download.jsp?urltype=news.DownloadAttachUrl&amp;owner=2146793819&amp;wbfileid=57E2F6E561369B064FC8DECCD0268DC8\"><font color=\"#008080\">001林学院-复试科目考试大纲.zip</font></a><font color=\"#008080\">】已下载771次 </font></p><font color=\"#008080\"> </font>\n  <p><font color=\"#008080\"> 附件【</font><a target=\"_blank\" rel=\"nofollow\" href=\"https://yjsy.csuft.edu.cn/system/_content/download.jsp?urltype=news.DownloadAttachUrl&amp;owner=2146793819&amp;wbfileid=0078F1ADAC99BE865CD38FCCFC26E111\"><font color=\"#008080\">002材料与能源学院-复试科目考试大纲.zip</font></a><font color=\"#008080\">】已下载160次 </font></p><font color=\"#008080\"> </font>\n  <p><font color=\"#008080\"> 附件【</font><a target=\"_blank\" rel=\"nofollow\" href=\"https://yjsy.csuft.edu.cn/system/_content/download.jsp?urltype=news.DownloadAttachUrl&amp;owner=2146793819&amp;wbfileid=46B727D0F7E13F1B0F31483B8DA8B688\"><font color=\"#008080\">003生态环境学院-复试科目考试大纲.zip</font></a><font color=\"#008080\">】已下载160次 </font></p><font color=\"#008080\"> </font>\n  <p><font color=\"#008080\"> 附件【</font><a target=\"_blank\" rel=\"nofollow\" href=\"https://yjsy.csuft.edu.cn/system/_content/download.jsp?urltype=news.DownloadAttachUrl&amp;owner=2146793819&amp;wbfileid=887BA4DF1D250CE61EF262A657A4DFF4\"><font color=\"#008080\">004生命科学与技术学院-复试科目考试大纲.zip</font></a><font color=\"#008080\">】已下载328次 </font></p><font color=\"#008080\"> </font>\n  <p><font color=\"#008080\"> 附件【</font><a target=\"_blank\" rel=\"nofollow\" href=\"https://yjsy.csuft.edu.cn/system/_content/download.jsp?urltype=news.DownloadAttachUrl&amp;owner=2146793819&amp;wbfileid=F0CB2190EF4BC99B50B5DC7BB23ECB67\"><font color=\"#008080\">006食品科学与工程学院-复试科目考试大纲.zip</font></a><font color=\"#008080\">】已下载103次 </font></p><font color=\"#008080\"> </font>\n  <p><font color=\"#008080\"> 附件【</font><a