INSERT INTO `yl_guide` VALUES (75, '@2027研考生，这两大工程类专业报考条件有变，速看！', '<h1>@2027研考生，这两大工程类专业报考条件有变，速看！</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：研招网资讯 2026-01-12　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>备战2027年研考的同学请注意，教育部公布的《2026年全国硕士研究生招生工作管理规定》中，有一项调整与你息息相关：<strong>自2027年招生起，报考工程管理专业学位中的工业工程与管理（代码：125603）、物流工程与管理（代码：125604），须符合文件中规定的相关报考条件：</strong></p>\n <p>（一）中华人民共和国公民。</p>\n <p>（二）拥护中国共产党的领导，遵纪守法，品德良好。</p>\n <p>（三）身体健康状况符合国家和招生单位规定的体检要求。</p>\n <p>（四）本科毕业后有3年以上工作经验；或获得国家承认的高职（专科）毕业学历或本科结业后，符合招生单位提出的相关学业要求，达到本科毕业同等学力并有5年以上工作经验；或获得硕士、博士研究生学历或学位后有2年以上工作经验。</p>\n <p>这也意味着，未来选择这两个方向的考生，在备考准备阶段需提前核实自身是否满足新的条件要求，避免因信息滞后影响报考。</p>\n <p>小研提醒：备战2027研考的小伙伴，记得盯紧研招网和目标院校的招考动态哦！尽早规划复习节奏，提前核实报考细节，才能一步一个脚印提升竞争力~</p>\n</div>', 'zhaoshengjianzhang', NULL, 0, 1, '2026-03-22 18:28:46', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 75);
INSERT INTO `yl_guide` VALUES (76, '江西省2026年研考初试人数11.03万', '<h1>江西省2026年研考初试人数11.03万</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：江西省教育考试院 2025-12-26　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p><strong>江西省2026年全国硕士研究生招生考试(初试)顺利结束</strong></p>\n <p>12月20日至21日，江西省2026年全国硕士研究生招生考试(初试)顺利举行。全省共有11.03万名考生，设16个考区，68个考点、3691个考场，涉考工作人员1.2万人。在全体考试工作人员的共同努力下，全省各考点秩序井然，考风考纪良好，实现了“平安研考”的工作目标。</p>\n <p>省委、省政府高度重视研究生招生考试工作，提出明确工作要求。考试期间，省、市教育行政部门、考试机构会同保密、网信、工信、公安、卫生健康、市场监管、通信管理、电力等部门在各级考务指挥中心联合值班值守，及时处置突发偶发事件，全方位保障考试平稳有序进行。</p>\n <p>各地各考点认真贯彻落实教育部和省教育厅工作要求，切实加强组织领导，严格落实保密规定，严守试卷安全保密底线;实行“智能安检门+人工安检”双安检，配备无线电监测车，严防高科技作弊，坚决维护考试公平公正;全力优化考生服务，在官网、微信公众号发布温馨提示、考场示意图，提供休息区、饮水点等，营造良好的考试环境。</p>\n <p>根据工作安排，本次考试评卷统分工作预计于2026年2月中旬前完成，2月24日后由招生单位公布考生成绩。</p>\n <p>原文链接http://www.jxeea.cn/jxsjyksy/gzdt38/pc/content/content_2003032669398503424.html</p>\n</div>', 'zhaoshengjianzhang', NULL, 0, 1, '2026-03-22 18:28:47', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 76);
INSERT INTO `yl_guide` VALUES (77, '2026年考研河南农业大学考点迎来了3499名考生', '<h1>2026年考研河南农业大学考点迎来了3499名考生</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：河南农业大学 2025-12-24　 相关院校：<a href=\"/graduate/grad/schoolID/552.shtml\" title=\"河南农业大学研究生院\" target=\"_blank\"><b>河南农业大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/552.shtml\" target=\"_blank\" title=\"河南农业大学考研资料\"><font color=\"#ff0000\">河南农业大学2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p><strong>12月20日至21日，我校圆满平稳顺利完成2026年全国硕士研究生招生考试考点工作。河南农业大学考点迎来了3499名考生，考点共设置了151个正式考场、 2个备用考场，设6个考务组，高质量实现平安研考。</strong></p>\n <p>考试期间，河南省教育厅、河南省教育考试院、郑州市招办到校检查指导考试工作，对我校组考工作给予了充分肯定。副校长张骁带队在考区进行全方位、全程指导工作，在考场、视频监考区检查指导考务，并慰问考务工作人员和研招志愿者。研究生院院长宋安东现场介绍了考试组织工作，党委研究生工作部部长郭治鹏介绍了视频监考情况。</p>\n <p>学校党委、行政高度重视本次研招组考工作，坚决贯彻落实教育部、河南省、郑州市的各项要求规定，成立了以校党委书记岳杰勇、校长周卫为组长的研究生招生考试工作领导小组，全面统筹考试组织与协调。学校多次组织召开考试工作部署会、协调会和培训会，压实主体责任、做好制度落实。考试期间，校领导到考场、保密室、考务组等重要点位进行检查，详细询问了考场秩序、突发事件应急预案和考生服务等相关事宜，对组考工作给予充分认可，并鼓励所有参与组考的工作人员再接再厉，继续以饱满的工作热情和强烈的责任感完成研招初试组考任务。研究生院（研工部）科学部署、周密安排、统筹协调，一体布局、一体化推进、一体化利用资源，党办、宣传、纪检、学工、保卫、校办、人事、教务、后勤、信息等部门各</p>\n</div>', 'zhaoshengjianzhang', NULL, 0, 1, '2026-03-22 18:28:47', '2026-04-08 21:20:00', 0, '2026年考研河南农业大学', '不限', 0, 77);
INSERT INTO `yl_guide` VALUES (78, '浙江：浙里平稳收官！2026年研招初试结束', '<h1>浙江：浙里平稳收官！2026年研招初试结束</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：浙江考试 2025-12-22　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>12月21日下午5点，随着考试结束铃声响起，浙江省2026年全国硕士研究生招生考试(初试)平稳落幕。浙江考研学子顺利完成第一段征程，向梦想迈出了坚实的步伐。</p>\n <p><strong>高位统筹，强化监督执行</strong></p>\n <p>研究生招生考试是国家选拔培养高层次人才的重要途径，事关考生切身利益，备受社会关注。省委、省政府高度重视，高位统筹本次研考工作，要求认真做好各环节组织，强化责任落实和监督指导，确保考试平稳顺利。考前我省多次召开专题会议，细化考务工作部署，开展自命题调研指导，制定安全工作方案，强化动态工作提示，以更严、更实举措做好组考工作。考试期间，省委教育工委副书记、省教育厅党组书记、厅长陈春雷在国家教育考试浙江省指挥中心实时调度，并深入杭州市人民职业学校、杭州市中策职业学校等考点实地巡查。省教育厅党组成员、省纪委监委派驻省教育厅纪检监察组组长王健在省指挥中心巡查全省考试实施情况。省市两级网信、经信、公安、生态环境、卫健、市场监管等国家教育考试联席会议成员单位集中办公值守，与教育部门紧密协作，共同为考试顺利实施保驾护航。</p>\n <p>本次研考，我省严格按照教育部有关要求持续织牢“六位一体”防护网。在考生入场环节实施人脸识别、手机集中管理和二次安检，强化对违规物品的重点检查，安排工作人员引导考生有序存取手机等物品，全力落实保密室实时智能巡检和考场实时智能巡查全覆盖。考前对所有考务人员进行了“线上+线下”全覆盖培训和考核，各地考点开展实景模拟演练，确保顺利施考。各级教育考试机构和高校通过组织生动的诚信教育宣传，强化源头管理，引导考生自觉抵制考试违规违法行为。</p>\n <p>考试过程中，全省所有考场均开启视频监控和无线信号屏蔽设备，考点配备视频监考员实时监控考场情况，无线电信号车监测考点周边可疑信号。省市各级巡考员提前一天进驻各考区，考试期间蹲点巡查，确保组考流程规范有序实施。</p>\n <p><strong>暖心护航，传递冬日温情</strong></p>\n <p>本次考试正值凛冬时节，在严格规范组考的同时，各地坚持以生为本，结合考生需求推出了一系列暖心服务举措。考前，我省各级教育考试机构和考点通过官网、官微、短信等渠道，纷纷发布考试公告和考前提醒，提前告知赴考路线和注意事项。各高校开展了形式多样的加油祝福活动，为学子提供全方位的服务保障。考试当天，为方便考生快速找到自己的考场，各考点制作了考场示意图或指示牌，安排志愿者为考生提供指引。考虑到研考期间天气较冷，不少考点设立暖心服务点、医疗服务站，为考生提供饮食、文具以及休息候考、打印制作、医疗救助等服务，积极营造舒适温馨的考试环境。</p>\n <p><strong>绍兴、金华等地考点安排专人护送行动不便的考生</strong></p>\n <p>同时，浙江省持续为特殊考生提供精准服务。本次研考，全省共为21位残疾考生提供合理便利，从考场路线安排到志愿者贴心护送，以细致关怀铺就考生赴考之路。</p>\n <p>接下来，研考试卷回收和评阅工作即将展开。本次考试成绩将按教育部统一部署发布，考生请及时关注中国研究生招生信息网(yz.chsi.com.cn)发布的相关资讯。</p>\n <p>星光不负赶路人，岁月眷顾奋楫者。预祝各位考生取得理想的成绩，迈向人生新旅程!</p>\n</div>', 'zhaoshengjianzhang', NULL, 0, 1, '2026-03-22 18:28:48', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 78);
INSERT INTO `yl_guide` VALUES (79, '西藏自治区2026年研考顺利开考', '<h1>西藏自治区2026年研考顺利开考</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：西藏自治区教育考试院 2025-12-22　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>12月20日上午，我区2026年全国硕士研究生招生考试(初试)顺利开考。全区共5000余人报名考试，共设8个考区10个考点183个考场。所有考生通过智能安检门和人脸识别身份验证后进入考点考场，均在国家教育考试标准化考点进行考试。所有考点实现手机信号降频屏蔽全覆盖，考场实时智能巡查违规作弊情况，确保考试安全和公平。</p>\n <p>考试期间，自治区领导赴考务指挥中心和部分考点巡视指导，教育厅主要领导、分管领导在考务指挥中心调度全区考试情况，教育、网信、公安、卫健、移动、电信、联通、电力等部门相关负责同志在国家教育考试指挥中心联合值班，第一时间研判处置突发事件，共同护航平安研考。</p>\n <p>所有考点按照“六位一体”要求，全面实行“智能安检门+人工安检”双安检模式，配备无线电信号屏蔽设备，加强考生入场检查，做好考生身份核对、违禁物品检查，严防替考考生、手机等作弊器材进入考点考场，严防考生和涉考人员携带高科技作弊工具进入考场。实现考场实时智能巡查全覆盖，全力筑牢考试安全防线，维护公平公正的考试环境。</p>\n <p>各考点合理设置物品存放处、卫生医疗点、热水供应点等，高海拔考点还配备血氧监测仪、架设医用输氧设备、准备治疗高反的特效药物等，对考场采取集中供暖，为考生提供暖心护考工作，积极回应社会关注、考生关切，确保研考各项工作落到实处。</p>\n</div>', 'zhaoshengjianzhang', NULL, 0, 1, '2026-03-22 18:28:49', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 79);
INSERT INTO `yl_guide` VALUES (80, '广西2026年研考平稳收官', '<h1>广西2026年研考平稳收官</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：广西招生考试院 2025-12-22　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>12月21日下午，为期两天的2026年全国硕士研究生招生考试顺利结束。我区各考点考场秩序良好，未发生试题失泄密及有组织舞弊事件，圆满实现“平安研考”目标。</p>\n <p>自治区领导高度重视研考安全工作，作出指示批示，将考试安全作为维护教育公平的核心底线抓实抓牢。自治区教育厅牵头与宣传、网信、工信、公安、保密等部门建立集中联合办公机制，实施统一调度、快速响应的协同保障模式。自治区招生考试院考前组织线上线下培训，开展全流程应急演练，覆盖全体考务人员;考中启用“智能安检门”、人脸识别、5G信号屏蔽仪等设备，强化无线电侦测与智能巡考，织密高科技作弊防控网;以“钉钉子精神”对试卷流转、考场管理、安检执行等关键环节开展全流程督查，层层压实责任，筑牢研考安全的坚固防线。</p>\n <p>“以考生为本”贯穿组考全程。自治区招生考试院主动搭建多维度考生服务体系：通过网站、微信公众号、短信等渠道，精准推送考点分布、安检要求、诚信考试等备考信息;增设咨询举报专线，建立快速响应机制，及时回应考生关切;统筹协调特殊考生合理便利申请审核工作，为4名残疾考生、1名视障考生提供大字号试卷等合理便利。</p>\n <p>全区各考点统筹优化，积极为考生提供暖心服务，当好考生赴考“护航人”。部分考点提供暖心热水及爱心文具;供应热茶;开放教学楼作为午间休息室;开通校园免费公交，安排专车接送偏远考点考生;设立应急打印点，协调公安干警现场办理临时身份证明;开设考生就餐专窗并提供加餐补助。</p>\n <p>我区2026年研考评卷工作将于2026年1月上旬启动，按照教育部日程安排，初试成绩计划于2月下旬公布。</p>\n <p>广西壮族自治区招生考试院</p>\n <p>2025年12月21日</p>\n</div>', 'zhaoshengjianzhang', NULL, 0, 1, '2026-03-22 18:28:50', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 80);
INSERT INTO `yl_guide` VALUES (81, '福建省2026年硕士研究生招生考试7.38万名报名参加', '<h1>福建省2026年硕士研究生招生考试7.38万名报名参加</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：福建省教育考试院 2025-12-22　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p><strong>福建省2026年全国硕士研究生招生考试(初试)顺利结束</strong></p>\n <p>12月21日17时，福建省 2026年全国硕士研究生招生考试(初试)圆满收官。全省7.38万名考生在14个报考点、70个考点、2510个考场顺利完成考试，7500名考试工作人员履职尽责，多部门协同联动保驾护航，全省各地考风考纪良好，实现“平安研考”工作目标。</p>\n <p>全省各级教育部门、招生考试机构认真贯彻落实教育部和省委省政府部署要求，拧紧考试保密“安全阀”，抓实试卷流转全过程监控和全环节交接，确保试卷绝对安全。构建“六位一体”立体防护网，首次实现所有考场实时智能巡查全覆盖，重点加强对手机等高科技作弊行为的防范，坚决维护考试公平公正。各考区规范考务组织管理，健全考务人员全员培训机制，明确责任分工。各考点严把入口、监考、出口“三关”，确保考务工作严密有序开展。各研究生招生单位加强自命题工作管理，压实主体责任，严格执行保密规定与流程管控，筑牢自命题工作安全和质量“双防线”。各地各高校聚焦考生需求精准发力，多措并举优化服务保障，共同营造暖心舒心应考环境。</p>\n</div>', 'zhaoshengjianzhang', NULL, 1, 1, '2026-03-22 18:28:50', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 81);
INSERT INTO `yl_guide` VALUES (82, '2026考研初试开考：343万人报名 连续三年下降', '<h1>2026考研初试开考：343万人报名 连续三年下降</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：网络 2025-12-21　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>2026年研考初试时间为2025年12月20日至21日，考试时长为6小时的考试科目在12月22日举行。</p>\n <p>其中，12月20日上午8:30-11:30思想政治理论或管理类综合能力;12月20日下午14:00-17:00外国语;12月21日上午8:30-11:30业务课(一)或专业基础综合;12月21日下午14:00开始业务课(二);12月22日上午8:30-14:30业务课(二)。</p>\n <p>据教育部统计，2026年全国硕士研究生报名人数为343万，这一数据引发关注。</p>\n <p>近年来，考研报名人数持续增加，教育部数据显示，2021年和2022年的考研报名人数分别为377万人和457万人，2023年增至474万人，创下历史新高。而2024年考研报名人数为438万人，较上一年减少36万人，2025年则较2024年下降50万人，只有388万，但今年2026考研报名人数下跌至343万，已是连续三年报名人数下降。</p>\n</div>', 'zhaoshengjianzhang', NULL, 2, 1, '2026-03-22 18:28:51', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 82);
INSERT INTO `yl_guide` VALUES (83, '2026年全国硕士研究生招生考试各项工作准备就绪', '<h1>2026年全国硕士研究生招生考试各项工作准备就绪</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：微言教育 2025-12-19　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>2026年全国硕士研究生招生考试将于2025年12月20日至21日举行。教育部深入学习贯彻党的二十届四中全会精神，坚持以考生为中心，积极推动考试环境综合治理向事前预防转型。会同国家教育统一考试工作部际联席会议其他成员单位，召开研考安全工作视频会议、印发专项工作文件，全面动员部署考试安全工作。继续依托并强化跨部门综合治理机制，积极主动将考试安全防线前移，坚决守好考试安全、公平底线。各地强化安全责任落实，周密部署，强化人防、物防、智防相结合，大力推进考场综合安防体系建设，全面排查整治考试组织安全隐患和薄弱环节，完善工作方案和应急预案，优化考生服务，全力实现平安研考、温馨研考。目前，全国研考各项工作准备就绪。</p>\n <p>全国硕士研究生招生考试是法律规定的国家考试。广大考生要知法守法，诚信应考，严格遵守考规考纪，主动接受身份验证核查、安全检查和随身物品检查，不携带智能手机、智能手表、智能眼镜等违禁物品进入考场，不心存侥幸代替他人或者让他人代替自己参加考试，不参与涉考违法犯罪活动。对在研究生招生考试中违反考试管理规定和考场纪律，影响考试公平、公正的考生，一律按《中华人民共和国刑法》《中华人民共和国教育法》《最高人民法院 最高人民检察院关于办理组织考试作弊等刑事案件适用法律若干问题的解释》及《国家教育考试违规处理办法》(教育部令第33号)严肃处理。对在校生，由其所在学校按有关规定给予处分，直至开除学籍;对在职考生，通知考生所在单位，由考生所在单位视情节给予党纪或政纪处分;构成违法的，依法追究法律责任，其中构成犯罪的，依法追究刑事责任。相关单位依法将考生的作弊事实记入《国家教育考试考生诚信档案》，并将考生有关情况通报其所在学校或单位。</p>\n <p>教育部提醒广大考生，提前做好考前准备，全面阅读掌握考试须知，认真核实确认考试时间、地点，仔细检查考试所须携带的证件和文具，合理规划赴考行程安排;关注天气变化，注意防寒保暖，做好健康防护，调适好心理状态，沉着冷静从容应考。</p>\n <p>附各省(区、市)教育招生考试机构网址及微信公众号详见：<a ahwt97n31z2najevf3exaq=\"\" s=\"\" mp.weixin.qq.com=\"\" href=\"https://mp.weixin.qq.com/s/aHWt97N31Z2NAJeVf3eXAQ\"><font color=\"#008080\">https://mp.weixin.qq.com/s/aHWt97N31Z2NAJeVf3eXAQ</font></a></p>\n</div>', 'zhaoshengjianzhang', NULL, 7, 1, '2026-03-22 18:28:52', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 83);
INSERT INTO `yl_guide` VALUES (84, '准备就绪！教育部提醒广大研考考生诚信考试', '<h1>准备就绪！教育部提醒广大研考考生诚信考试</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：微言教育 2024-12-20　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49071.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试调剂1对1辅导</font></a></li>\n  <li><a rel=\"nofollow\" href=\"/tiaoji/schooldetail/id/49069.shtml\" target=\"_blank\"><font color=\"#ff0000\">2026考研复试系统特训班 ￥299元</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://l.koolearn.com/LvpDDuz\" target=\"_blank\"><font color=\"#ff0000\">2027考研英语全程班 早鸟1班</font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index1146.html?jt_site_id=45395&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">2027考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li><!--<li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#9642;笔记&#9642;讲义&#9642;题库」</font></a></li>-->\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>2025年全国硕士研究生招生考试将于2024年12月21日至22日举行。教育部深入贯彻落实习近平总书记等中央领导同志重要指示精神，树牢底线思维、极限思维，会同中央宣传部、中央网信办、中央保密办、工业和信息化部、公安部等国家教育统一考试工作部际联席会议成员单位，召开研考安全工作视频会议、印发专项工作文件，进行全面动员部署，联合开展综合治理考试环境专项行动，严守考试安全、公平底线；严肃考风考纪，强化人防、物防、技防相结合，大力推动考场综合安防体系建设；加强协调调度，指导各地全面排查整治考试组织安全隐患和薄弱环节、完善应急预案、优化考生服务，全力实现平安研考。各省（区、市）党委政府高度重视研考组织工作，加强组织领导，周密部署检查；教育部门积极会同各有关部门齐抓共管、协调联动，强化安全责任落实。目前，全国研考各项工作准备就绪。</p>\n <p>全国硕士研究生招生考试是法律规定国家考试，凡在考试中作弊的考生，其作弊事实将依法记入《国家教育考试考生诚信档案》，并通报其所在学校或单位。广大考生应知法守法，严格遵守考试考场规则，切实履行诚信考试义务，以诚取信，以信取胜，莫拿个人诚信当儿戏。遵守考试纪律，不携带手机等违禁物品进入考场，不心存侥幸替他人或者让他人代替自己参加考试，不参与涉考违法犯罪活动；服从监考人员管理，主动接受身份核验和考试违禁物品检查。</p>\n <p><strong>教育部提醒广大考生&#x2014;&#x2014;</strong></p>\n <p>及时关注天气变化，注意防寒保暖，做好个人健康防护；</p>\n <p>提前认真阅读考试须知，认真核实确认考试时间、地点，仔细检查考试所须携带的证件和文具，合理规划赴考行程安排；</p>\n <p>保持积极心态和良好身体状态，沉着冷静参加考试。</p>\n</div>', 'zhaoshengjianzhang', NULL, 1, 1, '2026-03-22 18:28:52', '2026-04-08 21:20:00', 0, '未知院校', '不限', 0, 84);
