INSERT INTO `yl_guide` VALUES (97, '东北林业大学2026年硕士研究生招生考试复试及录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>东北林业大学2026年硕士研究生招生考试复试及录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月19日</span> <span>来源：东北林业大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据《教育部关于印发&lt;2026年全国硕士研究生招生工作管理规定&gt;的通知》(教学〔2025〕2号)《关于做好2026年全国硕士研究生复试录取工作的通知》（教学司〔2026〕3号）等文件要求，结合我校实际情况，特制定本办法。</p>\n     <p><strong>一、工作原则</strong></p>\n     <p><strong></strong></p>\n     <p>坚持服务战略、按需招生、全面衡量、择优录取和宁缺毋滥的原则，对考生进行德智体美劳全面衡量;在保证人才培养质量的前提下，既尊重考生的求学意愿，又兼顾国家需求和学科发展等方面的需要。</p>\n     <p>复试工作要做到全面考察，有所侧重，在德智体美劳等各方面全面衡量的基础上，突出对专业知识、科研能力、创新能力和综合素质等方面的考核。复试过程要政策透明、程序规范、操作公开、监督机制健全，要提高服务意识，维护考生的合法权益。</p>\n     <p><strong>二、工作组织</strong></p>\n     <p><strong></strong></p>\n     <p>学校招生委员会负责制定和审核有关政策，指导全校的硕士研究生招生考试复试及录取工作，具体由研究生院负责组织，各学院负责实施。学院招生委员会负责制定本单位2026年硕士研究生招生考试复试及录取工作实施细则，指导学科复试小组进行相应考核工作。学科成立复试小组，具体实施复试考核工作。</p>\n     <p>学校研究生招生工作监察工作组对学院硕士研究生招生考试复试及录取工作进行督察。学校成立硕士研究生招生工作巡查小组，对学院硕士研究生招生考试复试及录取工作进行巡查。学院研究生招生工作监察工作组对本单位硕士研究生招生考试复试及录取工作进行全过程监察。</p>\n     <p><strong>三、复试工作</strong></p>\n     <p><strong></strong></p>\n     <p>（一）复试分数线划定</p>\n     <p>1.复试采取差额形式。同一学院各招生专业须在国家线的基础上，结合招生计划和生源情况划定复试分数线，复试差额比例不低于120%，合格生源比例不足的，按实际合格生源数组织复试，确定复试名单。</p>\n     <p>2.各学院划定学术学位招生专业复试分数线时，按照一级学科统一划定复试分数线；对于一级学科分列招生计划的分别划定复试分数线。</p>\n     <p>3.各学院划定专业学位招生专业复试分数线时，分列招生计划的分别划定复试分数线；同一类别（领域）既有全日制和非全日制招生的执行相同政策和标准，须统一划定相同的复试分数线。</p>\n     <p>4.少数民族高层次骨干人才计划（含南疆高校教师专项）考生进入复试的单科要求为30分（满分=100分）、45分（满分&gt;100分），总分执行相应学科专业对报考“少数民族高层次骨干人才计划”和享受少数民族照顾政策考生总分要求的国家线。</p>\n     <p>5.退役大学生士兵计划考生进入复试的单科要求执行相应学科专业A类考生国家线单科要求，总分要求在相应学科专业A类考生国家线总分要求基础上降5分。</p>\n     <p>6.单独考试考生进入复试的单科及总分要求均执行相应学科专业A类考生国家线。</p>\n     <p>7.报名时工作单位和户籍在国务院公布的民族区域自治地方，且定向就业单位为原单位的少数民族在职人员考生，可按规定享受少数民族照顾政策。进入复试的单科要求为30分（满分=100分）、45分（满分&gt;100分），总分执行相应学科专业对报考“少数民族高层次骨干人才计划”和享受少数民族照顾政策考生总分要求的国家线。</p>\n     <p>8.对服役期间获得三等战功、二等功以上奖励或者二级以上表彰，符合全国硕士研究生招生考试报考条件的退役人员，可申请免初试攻读我校硕士研究生。我校对申请免初试的考生组织复试，复试合格者即可予以拟录取。</p>\n     <p>9.学校不接受破格复试。</p>\n     <p>（二）复试资格审查</p>\n     <p>复试前各学院须对考生进行线上复试资格审查，资格审查不合格者不予参加复试。审查条件以我校2026年硕士研究生招生简章的规定为准。除审查考生初试准考证和有效身份证件外，非应届本科生须提交学历证书（《教育部学历证书电子注册备案表》或《中国高等教育学历认证报告》）；应届本科生须提交学生证、《教育部学籍在线验证报告》，其毕业证书将在入学时提交审查;同等学力考生按我校招生简章要求提供相关材料。</p>\n     <p>考生可登录中国高等教育学生信息网(www.chsi.com.cn)进行学历或学籍认证。如考生提供虚假材料，任何时候一经发现，将取消其录取资格。</p>\n     <p>（三）复试形式和内容</p>\n     <p>1.复试形式</p>\n     <p>一志愿复试采取现场面试形式，调剂复试采用网络远程视频面试形式。一般每位考生面试时间不少于20分钟，考生明确表示已作答完毕的可提前结束考核。</p>\n     <p>2.复试内容</p>\n     <p>复试内容包括专业能力考核（50分）和综合素质考核（50分）两部分。学术学位重点考核考生的学术素养、对学科知识掌握与运用情况、科研创新能力，专业学位重点考核考生的专业基础、实践能力和职业素养。</p>\n     <p>专业能力考核：包括专业外语听说能力测试（20分）和专业课测试（30分）。工商管理（1251）、会计（1253）和工程管理（1256）等3个专业学位复试中组织思想政治理论考试，占专业课测试成绩的三分之一，成绩计入复试总成绩。</p>\n     <p>综合素质考核：考核内容应涉及考生的创新精神和创新能力考核；考生理论知识和应用技能掌握程度、利用所学理论发现、分析和解决问题的能力考核；考生对报考专业发展动态了解以及在本专业发展潜力考核；考生的科研和社会工作能力、实践能力考核；考生的事业心、责任感、协作性和心理健康情况考核；人文素质、举止礼仪和表达能力考核等。</p>\n     <p>加试科目：同等学力考生另须加试至少两门不同于初试科目的本专业本科阶段主干课程，每门科目100分，加试科目成绩低于60分者不予录取，加试成绩不计入复试总成绩。</p>\n     <p>（四）复试总成绩计算方法</p>\n     <p>考生复试总成绩（100分）＝专业能力考核成绩（50分）＋综合素质考核成绩（50分），复试总成绩低于60分视为复试成绩不合格。</p>\n     <p>（五）照顾或加分政策</p>\n     <p>报名时工作单位和户籍在国务院公布的民族区域自治地方，且定向就业单位为原单位的少数民族在职人员考生，可按规定享受少数民族照顾政策。符合下列条件之一后3年内报名参加全国硕士研究生招生考试（不含单独考试）的考生，可申请享受初试总成绩加10分，同等条件下优先录取。符合多项加分项目的考生，分值不得累加。</p>\n     <p>1.参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”项目之一，服务期满且考核合格。</p>\n     <p>2.退役大学生士兵〔即高校学生应征入伍退出现役者，其中，高校学生指全日制普通本专科（含高职）、研究生、第二学士学位的应（往）届毕业生、在校生和入学新生，以及成人高校招收的普通本专科（含高职）应（往）届毕业生、在校生和入学新生，下同〕达到全国硕士研究生招生考试报考条件。</p>\n     <p>符合享受初试加分、少数民族照顾政策、免初试或报考专项计划有关条件的考生，须在网上报名时按要求填报申请信息。有关部门、报考点对相关考生资格进行初审，招生单位在复试前进行复审，确定考生的相应资格。其中，申请享受少数民族照顾政策的资格由报考点进行初审，其余资格由有关部门按职责分工进行初审。未按规定申报或审核（含复审）未通过的，不享受相应的加分、照顾、免初试政策，或不得参加有关专项计划初、复试。</p>\n     <p>（六）思想政治素质和品德考核</p>\n     <p>思想政治素质和品德考核主要考核考生本人的现实表现，包括考生的政治态度、思想表现、道德品质、遵纪守法、诚实守信等方面。思想政治素质和品德考核不作量化计入总成绩，但对于思想品德考核不合格者不予录取。</p>\n     <p>（七）复试全程要求录音录像。录音录像资料由各学院保存至少5年时间。</p>\n     <p><strong>四、调剂工作</strong></p>\n     <p><strong></strong></p>\n     <p>（一）考生调剂基本条件</p>\n     <p>1.符合调入专业的报考条件。</p>\n     <p>2.初试成绩须符合第一志愿报考专业在A类地区的全国初试成绩基本要求。退役大学生士兵计划、少数民族高层次骨干人才计划（含南疆高校教师专项）、享受少数民族照顾政策考生须符合我校一志愿相应复试线要求。</p>\n     <p>3.原则上调剂考生第一志愿专业与调入专业相同相近。</p>\n     <p>4.满足教育部规定的其他调剂要求。</p>\n     <p>5.满足学院招生专业（方向）规定的其他调剂要求。</p>\n     <p>（二）接收调剂程序</p>\n     <p>1.学院将本单位2026年硕士研究生招生考试复试及录取工作实施细则报研究生招生办公室审核合格后对外公布。</p>\n     <p>2.教育部调剂系统开通后，考生通过调剂系统进行报名。</p>\n     <p>3.每轮报名结束后，各学院根据对外公布的调剂条件和规则，对申请我校同一专业的调剂考生，按考生初试成绩总分排序，择优遴选进入复试的考生名单。拟复试考生名单经学院招生委员会签字确认后，报研究生招生办公室审核备案。</p>\n     <p>4.学校研究生招生办公室根据各学院公布的调剂条件和规则，对学院报送的拟复试名单审核合格后，方可发送复试通知及组织复试。</p>\n     <p><strong>五、录取工作</strong></p>\n     <p><strong></strong></p>\n     <p>（一）录取规则</p>\n     <p>1.录取工作贯彻对考生进行德智体美劳全面衡量的精神，坚持“择优录取、宁缺毋滥”的原则，在学校招生委员会统一领导下，按照教育部有关规定，根据学校招生计划、复试录取办法以及考生初试和复试成绩、思想政治和品德考核情况、身心健康状况等择优确定拟录取考生名单。在确定拟录取名单前，全面开展录取检查，对报考资格、录取条件、录取程序等不符合规定者不予录取。</p>\n     <p>2.录取考生时按照考生总成绩从高到低依次进行；若考生总成绩相同时，按初试总分从高到低排序；若初试总分再相同时，按综合素质考核成绩从高到低排序。调剂考生可根据调剂复试批次，分批次排名，分批次录取。</p>\n     <p><strong>考生总成绩计算公式为：（初试总分为500分）</strong></p>\n     <p>考生总成绩＝（初试总成绩÷5）×60%＋复试总成绩×40%</p>\n     <p><strong>考生总成绩计算公式为：（初试总分为300分）</strong></p>\n     <p>考生总成绩＝（初试总成绩÷3）×60%＋复试总成绩×40%</p>\n     <p>3.出现如下情况之一者不予录取。报考资格审查不合格者；思想政治素质和品德考核不合格者；未按规定时间参加复试者；复试成绩不合格者；同等学力加试科目的任一门成绩低于60分者；未通过或未完成学历（学籍）审核者；体检不合格者。</p>\n     <p>（二）各学院将拟录取名单，经本单位招生委员会审核无误后，报研究生招生办公室汇总，待学校招生委员会和省级招生管理部门审定后正式录取。</p>\n     <p>（三）录取类别分为非定向就业和定向就业两种类型。一经录取后，不得变更录取信息中的就业方式。</p>\n     <p>（四）体检要求。体检安排在考生入学报到期间，具体时间另行通知。体检要求根据《残疾人教育条例》和《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）等文件规定，参照《教育部、卫生部、中国残疾人联合会关于印发〈普通高等学校招生体检工作指导意见〉的通知》（教学〔2003〕3号）。</p>\n     <p><strong>六、信息公布和公示制度</strong></p>\n     <p><strong></strong></p>\n     <p>（一）学校公布复试及录取工作实施细则、招生人数、拟复试考生名单、调剂通知及拟接收调剂生的数量。</p>\n     <p>（二）拟复试名单（包括考生姓名、考生编号、初试各科成绩等）、拟录取名单（包括考生姓名、考生编号、初试成绩、复试成绩、总成绩等信息）须在网上进行公示，对参加专项计划、享受初试加分或照顾政策的考生相关情况，在公布考生名单时进行说明。</p>\n     <p>（三）拟录取名单公示7日。拟录取考生名单由学校统一公示。公示期间名单如有变动，须对变动部分做出说明，并对变动内容另行公示7日。未经公示的考生，一律不得录取，不予注册学籍。</p>\n     <p><strong>七、监督保障制度</strong></p>\n     <p><strong></strong></p>\n     <p>（一）集体决策制度。在专家组对考生进行全面考核的基础上，学院招生委员会集体讨论，确定拟录取名单，并对结果负责。</p>\n     <p>（二）巡查和监察制度。学校成立硕士研究生招生工作巡查小组，对学院硕士研究生招生考试复试及录取工作进行巡查。学校研究生招生工作监察工作组对学院硕士研究生招生考试复试及录取工作进行督察。学院研究生招生工作监察工作组对本单位硕士研究生招生考试复试及录取工作进行全过程监察。</p>\n     <p>（三）申诉反馈机制。学校保障考生申诉渠道的畅通，考生可向学院提出异议或申诉，学院应及时调查处理考生提出的异议或申诉。考生对学院作出答复不满意的，可向研究生院申请复查。申诉途径：https://yz.nefu.edu.cn/sstj.htm。</p>\n     <p>（四）实行回避制度。招生工作人员本人或直系亲属或非直系亲属或其他利益相关者报名参加本校研究生考试招生的，应主动提出回避，并不得参加当年的招生考试工作。</p>\n     <p>（五）严肃工作纪律。对违法违规行为，一律按《普通高等学校招生违规行为处理暂行办法》（教育部令第36号）严肃处理，并追究直接责任人员的责任，造成严重后果和恶劣影响的，要追责问责。</p>\n     <p>本办法由东北林业大学研究生院负责解释。本办法如有同国家、黑龙江省有关规定不符之处及本文未尽事宜，按国家、黑龙江省有关规定执行。</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zy