INSERT INTO `yl_guide` VALUES (98, '沈阳药科大学2026年硕士研究生复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>沈阳药科大学2026年硕士研究生复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月19日</span> <span>来源：沈阳药科大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>为确保安全、公平、科学地做好我校2026年硕士研究生招生复试录取各项工作，根据教育部《2026年全国硕士研究生招生工作管理规定》（教学〔2025〕2号）、《关于做好2026年全国硕士研究生招生复试录取工作的通知》（教学司〔2026〕2号）、《关于做好辽宁省2026年全国硕士研究生招生复试录取工作的通知》（辽招考委字〔2026〕8号）等文件精神，制定本复试录取工作办法。</p>\n     <p style=\"text-align: center;\"><strong>第一章 总 则</strong></p>\n     <p><strong>第一条</strong> 招生复试录取工作以习近平新时代中国特色社会主义思想为指导，坚持以人民为中心，践行全心全意为人民服务的根本宗旨，切实为人民选拔出创新能力强、专业素养好和综合素质优良的人才。</p>\n     <p><strong>第二条</strong> 招生复试录取工作坚持公平、公正、公开的原则，做到政策透明、规则科学、程序公正、结果公开、监督机制健全，维护考生合法权益。</p>\n     <p><strong>第三条</strong> 我校2026年硕士研究生复试考核方式包含现场考核和网络远程考核。具体复试工作在校研究生招生委员会的统一领导下由学院组织实施，各学院根据本学院实际情况，在确保同一批次同一学科的考核方式、考试流程、招生复试专家组、选拔标准一致的前提下，制定学院复试实施细则及工作安排。</p>\n     <p><strong>第四条</strong> 我校2026年硕士研究生计划分配原则按照《沈阳药科大学研究生招生指标分配管理办法》（沈药大研生字〔2020〕11号）执行，以上级下达实际计划为准。</p>\n     <p style=\"text-align: center;\"><strong>第二章 组织管理</strong></p>\n     <p><strong>第五条</strong> 学校研究生招生委员会负责全校研究生招生复试录取工作的组织和领导，工作职责包括：</p>\n     <p>1.执行教育部和辽宁省教育厅研究生招生工作的方针、政策和规定；</p>\n     <p>2.负责招生计划的分配、制定学校研究生招生复试录取办法、调剂方案；</p>\n     <p>3.指导、监督研究生招生复试工作的具体实施，包括命题、考试、评卷及录取工作的全部环节，加强对学校研究生考试安全保密工作的管理，确保学校招生工作顺利进行；</p>\n     <p>4.负责审核各学院硕士复试实施细则，公布复试分数线、复试名单及调剂名单；</p>\n     <p>5.审核全日制研究生拟录取人员名单，维护研究生招生录取的公平与公正；</p>\n     <p>6.协调、研究和处理研究生招生复试工作有关命题、考试和录取等过程中的重大问题,拥有对此问题的行政裁决权。</p>\n     <p><strong>第六条</strong> 各学院成立研究生招生委员会，负责本学院研究生复试和录取工作的组织、协调与管理，工作职责包括:</p>\n     <p>1.根据教育部、辽宁省及学校的有关规定，制定学院复试实施细则，并报研究生院审定、备案。学院复试实施细则要符合本学院招生学科特点，明确衡量标准、复试程序以及调剂方案；</p>\n     <p>2.组织成立本学院招生复试专家组，指导并培训专家组进行相应的复试考核工作；</p>\n     <p>3.确定本学院所有学科考核科目、评分标准、程序，并组织实施；</p>\n     <p>4.审核各招生复试专家组的复试记录、复试结果和考生的其他情况；</p>\n     <p>5.负责进行资格审查、通知考生参加复试，负责确定调剂复试名单报研究生院审定、备案，负责确定拟录取名单报研究生院审定，负责对参加调剂而未予复试考生的必要解释、考生疑义和遗留问题的处理。</p>\n     <p><strong>第七条 </strong>各学院研究生招生委员会负责组织成立若干复试专家组，复试专家组具体实施对每位考生的复试考核。校内复试专家原则上应现场集中、协同育人基地复试专家可通过现场或线上参加复试考核，并进行现场评分。每个复试专家组应由不少于5名（含协同育人基地专家）政治过硬、品德优良、业务熟练、责任心强的副教授（或相当职称）及以上教师组成，设立组长1名（由分科负责人或分科委员担任），秘书1名（可由组员兼任）。工作职责包括：</p>\n     <p>1.在考核前召开复试专家组会议，明确工作纪律、工作程序、评判规则和评判标准，规范工作行为，明确复试人员在复试工作中的责权；</p>\n     <p>2.在考核时需现场独立评分，评分记录和考生作答情况要上交学院并由研究生院集中统一保管，任何人不得改动；</p>\n     <p>3.复试全程录音录像，将录音录像材料上交学院并由研究生院集中统一保管。</p>\n     <p style=\"text-align: center;\"><strong>第三章 复试名单确定</strong></p>\n     <p><strong>第八条</strong> 复试分数线</p>\n     <p>1.非专项普通考生</p>\n     <p>各学院招生学科（研究方向）的复试分数线按国家教育部划定的一区各学科门类分数线执行。</p>\n     <p>2.专项考生</p>\n     <p>报考“退役大学生士兵计划”考生，进入复试的初试成绩基本要求为总分不低于220分，政治理论、外国语不低于30分，专业课单科不低于50分。</p>\n     <p>其他专项计划考生的分数线与非专项普通考生一致，不单独划线。</p>\n     <p>3.享受少数民族照顾政策考生</p>\n     <p>享受少数民族照顾政策的考生，复试分数线按国家教育部划定的享受少数民族照顾政策考生总分要求和单科成绩要求执行。</p>\n     <p><strong>第九条</strong> 复试比例及复试名单</p>\n     <p>1.我校硕士研究生复试实行差额复试，一志愿合格生源充足的专业复试比例一般不低于130%；一志愿合格生源比例不足的，按实际合格生源数组织复试。</p>\n     <p>2.在单科和总分成绩符合报考专业（领域、方向）所在学科门类复试分数线的基础上，按总分由高至低确定复试名单，计算复试人数时遵循有小数点进位原则。</p>\n     <p style=\"text-align: center;\"><strong>第四章 资格审核</strong></p>\n     <p><strong>第十条</strong> 研究生院负责同技术平台提供方，积极运用“人脸识别”“人证识别”等技术，通过综合对比“报考库”“学籍学历库”“人口信息库”“诚信档案库”等措施，对参加考核的考生身份进行审核。</p>\n     <p><strong>第十一条</strong> 各学院负责对考生复试资格进行审核，审查内容主要包括以下材料的相应电子版：</p>\n     <p>1.初试准考证。</p>\n     <p>2.身份证原件。</p>\n     <p>3.学历（学籍材料）</p>\n     <p>（1）应届本科毕业生的学生证原件、《教育部学籍在线验证报告》；</p>\n     <p>（2）非应届本科毕业生的本科毕业证书和学位证书的原件、《教育部学历证书电子注册备案表》或教育部学历认证中心出具的《中国高等教育学历认证报告》，在境外获得学历证书考生的教育部留学服务中心出具的《国外学历学位认证书》。</p>\n     <p>4.《2026年硕士招生考试考生诚信复试承诺书》。</p>\n     <p>5.《沈阳药科大学硕士研究生政治资格审查表》。</p>\n     <p>6.其他类别考生相关证明材料</p>\n     <p>（1）同等学力报考人员：英语水平证明材料（复印件）和报考相关专业本科核心课程成绩单（原件）；</p>\n     <p>（2）“退役大学生士兵”专项计划报考人员：入伍批准书（注意：不是入伍通知书）、退出现役证；</p>\n     <p>（3）日语考生：国家大学英语四级或六级成绩单（复印件）；</p>\n     <p>（4）享受加分政策和少数民族照顾政策考生：学校通知要求的相关证明材料。</p>\n     <p><strong>第十二条</strong> 资格审核材料一律通过“沈阳药科大学研究生招生系统”（https://yjs.syphu.edu.cn/）上传并审核。</p>\n     <p style=\"text-align: center;\"><strong>第五章 复试管理</strong></p>\n     <p><strong>第十三条</strong> 复试内容</p>\n     <p>1.复试内容包括专业考核和综合素质考核，复试成绩满分为300分，其中专业考核满分200分，综合素质考核满分100分。</p>\n     <p>2.专业考核内容详见我校研究生教育网公布的沈阳药科大学2026年硕士研究生招生简章与招生专业目录中的复试专业课；综合素质考核主要包括外语听说能力、科研基本技能、综合素质与能力、思想品德考核等。</p>\n     <p>3.同等学力考生须加试《无机化学》和《药用植物学》课程，加试的考试方式为笔试，时间为每科60分钟，满分各100分。</p>\n     <p>4.各专业具体考核内容、考核办法详见各学院复试实施细则。</p>\n     <p><strong>第十四条</strong> 复试时间及地点</p>\n     <p>1.复试时间</p>\n     <p>一志愿考生：2026年3月27日-29日。</p>\n     <p>调剂考生：2026年4月8日待全国硕士生招生复试调剂服务系统正式开通后各招生学院开展调剂复试工作。</p>\n     <p>2.复试地点</p>\n     <p>根据学院实际情况为沈阳校区或南校区（本溪），具体以学院公布的复试实施细则为准。</p>\n     <p><strong>第十五条</strong> 复试试题及答案在启用前均系国家机密材料，所有参加复试及录取工作的人员都应认真、严格地执行教育部有关硕士生招生录取工作的各项规定，不得有任何泄露试题和故意提高或压低考分的行为。复试形式中“线下笔试”的试题管理由研究生院统一负责，“线下面试”和“网络远程面试”的试题管理由招生学院统一负责。</p>\n     <p><strong>第十六条</strong> 复试过程中实行随机确定考生复试次序、随机确定招生复试专家组组成人员、随机抽取复试试题的工作方式。</p>\n     <p><strong>第十七条</strong> 享受加分及照顾政策。</p>\n     <p>1.符合下列条件之一后3年内报名参加全国硕士研究生招生考试的考生，可申请享受初试总成绩加10分，同等条件下优先录取。</p>\n     <p>（1）参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”项目之一，服务期满且考核合格；</p>\n     <p>（2）退役大学生士兵〔即高校学生应征入伍退出现役者，其中，高校学生指全日制普通本专科（含高职）、研究生、第二学士学位的应（往）届毕业生、在校生和入学新生，以及成人高校招收的普通本专科（含高职）应（往）届毕业生、在校生和入学新生，下同〕达到全国硕士研究生招生考试报考条件；</p>\n     <p>申请享受初试加分的考生，须在网上报名时按要求填报相关信息，有关部门按职责分工进行审核。未按规定申报或审核未通过的，不享受加分政策。加分项目不累计。</p>\n     <p>2.少数民族照顾政策。报考地处二区招生单位且毕业后在国务院公布的民族区域自治地方定向就业的少数民族普通高校应届本科毕业生；或者工作单位和户籍在国务院公布的民族区域自治地方，且定向就业单位为原单位的少数民族在职人员考生，可按规定享受少数民族照顾政策。申请享受少数民族照顾政策的考生，须在网上报名时按要求填报相关信息。报考点对相关考生资格进行初审，招生单位在复试（含调剂）前进行复审。未按规定申报或审核未通过的，不享受照顾政策。</p>\n     <p>3.报考专项计划的考生，不再享受初试加分和少数民族照顾政策。</p>\n     <p>4.符合加分或少数民族照顾政策的考生，须按学校相关通知的时间要求向研究生院提出申请并提供相关证明材料。我校将根据教育部下发的相关名单或教育部文件相关要求严格审核考生资格，逾期不提供证明材料的考生视为自动放弃。</p>\n     <p><strong>第十八条</strong> 各批次复试前，我校将提前在研究生院网站向社会公布参加复试考生名单（包括考生姓名、考生编号、初试各科成绩等信息）。对参加专项计划、享受初试加分或照顾政策的考生相关情况，在公布考生名单时进行说明。我校不做破格复试。</p>\n     <p style=\"text-align: center;\"><strong>第六章 调剂管理</strong></p>\n     <p><strong>第十九条 </strong>调剂基本条件</p>\n     <p>1.调剂考生需符合调入专业的报考条件，且具有大学本科学历。</p>\n     <p>2.调剂考生初试外国语为英语一、二或日语，且初试成绩符合第一志愿报考专业的国家一区分数线的全日制合格考生。“退役大学生士兵计划”考生初试成绩，须符合我校“退役大学生士兵计划”复试的初试成绩要求。</p>\n     <p>3.原则上，调剂考生第一志愿专业与调入专业相同相近，或初试科目与调入专业初试科目相同相近。</p>\n     <p>4.符合招生学院的其它调剂要求。</p>\n     <p>5.调剂复试执行差额复试，招生学院根据各招生专业（方向）的学科特点和招生计划自行确定调剂复试差额比例，一般不高于300%。</p>\n     <p>6.具体调剂专业接收考生第一志愿专业范围要求须经校学位评定委员会审核通过后发布，详见《沈阳药科大学2026年硕士研究生调剂方案》。</p>\n     <p><strong>第二十条 </strong>调剂要求</p>\n     <p>1.所有调剂考生必须通过教育部“全国硕士生招生复试调剂服务系统”进行，否则该调剂考生在国家的录取检查中不予认可。调剂工作由研究生院归口管理并统一办理相关手续。</p>\n     <p>2.调剂系统开放时间、调剂志愿锁定时间由我校统一设定，每次开放调剂系统持续时间不低于12个小时，考生调剂志愿锁定时间一般为18小时，学校不单独给考生解锁调剂志愿。</p>\n     <p>3.调剂系统开放前，将在学校研究生院官网发布调剂时间、调剂专业、调剂名额等。</p>\n     <p>4.严禁任何学院或个人任意圈定调剂复试考生范围，不得以考生第一志愿报考单位、毕业院校、提交调剂志愿的时间先后顺序等非学业水平标准，或考生所在单位、行业、地域、学校层次类别等非学业水平标准作为遴选条件，也不得设置其他歧视性条件。</p>\n     <p>5.每位调剂考生只能选报我校一个专业或方向，多报或不选研究方向视为无效报名。调剂系统关闭后，符合我校调剂要求的考生，按初试成绩择优遴选进入复试。</p>\n     <p>6.调剂考生复试结束后，学校通过中国研究生招生信息网发放拟录取通知，考生需在规定时间内进行网上确认拟录取操作，否则将取消拟录取资格。</p>\n     <p>7.第一批调剂复试后有缺额的专业将继续调剂，请考生及时关注全国硕士生招生复试调剂服务系统的相关专业缺额情况和我校研究生院网站发布的相关通知。</p>\n     <p style=\"text-align: center;\"><strong>第七章 录取管理</strong></p>\n     <p><strong>第二十一条</strong> 总成绩为初试成绩与复试成绩之和。总成绩计算公式如下：</p>\n     <p>总 成 绩=初试成绩+复试成绩</p>\n     <p>复试成绩=专业考核成绩+综合素质考核成绩</p>\n     <p><strong>第二十二条</strong> 录取办法</p>\n     <p>1.复试结束后按照同一学院同一专业（研究方向）总成绩由高分到低分排序，录取至该专业（研究方向）招生限额，并以此为顺序确定录取名单。各专业（研究方向）一志愿考生与调剂考生分别排序，先录取第一志愿考生，后录取调剂考生。调剂考生按复试批次，分批次排名，分批次录取。</p>\n     <p>2.考生按总成绩排序优先录取。如因总成绩相同且超过本专业招生计划，在总成绩相同情形下，逐次按初试成绩总分、初试外国语成绩、业务课一成绩、业务课二成绩由高到低排序，录取至该专业招生限额。上述考生如成绩仍相同，由学院研究生招生委员会讨论，形成关于上述考生排名的书面意见，报请学校研究生招生委员会审议。</p>\n     <p><strong>第二十三条</strong> 出现如下情况之一者不予录取</p>\n     <p>1.复试成绩低于180分。</p>\n     <p>2.综合素质考核成绩低于60分。</p>\n     <p>3.同等学力加试科目的任一门成绩低于60分。</p>\n     <p>4.复试期间发现考生不符合报考规定条件、材料不真实、复试过程不诚信、弄虚作假、徇私舞弊等。</p>\n     <p><strong>第二十四条</strong> 参加复试人员要严格按照学校复试标准和办法评分，评分要客观、公正，真实反映学生的实际水平。将考生的面试情况和成绩详细记录在《复试登记表》中，并交研究生院保管，以备查核。</p>\n     <p><strong>第二十五条</strong> 拟录取考生的体检工作，在新生入学后按照学校要求统一进行，具体安排详见入学指南，体检标准按照《普通高等学校招生体检工作指导意见》执行。</p>\n     <p><strong>第二十六条</strong> 考生入学后三个月内，学校将按照《普通高等学校学生管理规定》有关要求，对考生录取手续、录取资格、身份证、学生证、学历学位证书、学历学籍验证结果、考生档案、函调材料以及体检结果等进行复查，复查不合格的，取消学籍。</p>\n     <p style=\"text-align: center;\"><strong>第八章 监督和复议</strong></p>\n     <p><strong>第二十七条</strong> 复试及录取工作实行回避制度，凡有直系亲属参加复试的人员，主动回避不得参加与复试及录取有关的工作。对有违反规定行为的单位和当事人，将视情节轻重给予批评教育或纪律处分，直至追究法律责任。</p>\n     <p><strong>第二十八条</strong> 校研究生招生委员会及学校、学院纪委对复试过程和复试结果进行指导与审查，对在复试录取工作中违规违纪违法行为，校纪委将依规依纪依法严肃处理并追责问责。。研究生院将组织复试督导小组对各学院的复试过程进行监督和检查。</p>\n     <p><strong>第二十九条</strong> 复试录取工作自觉接受学校、学院纪检、监察部门的监督、检查。保证申诉渠道畅通。对复试过程中投诉和申诉问题经调查属实的，由学校研究生招生委员会责成各学院研究生招生委员会进行复议，考生可以通过E-Mail：syphuyz@126.com、电话024-43520089/98联系我校研究生招生工作人员。</p>\n     <p style=\"text-align: center;\"><strong>第九章 其它</strong></p>\n     <p><strong>第三十条</strong> 硕士研究生在复试期间如发生突发事件，按照《沈阳药科大学研究生招生考试突发事件应急处置预案》的有关规定进行处理。</p>\n     <p><strong>第三十一条</strong> 我校硕士研究生复试工作方案以及相关通知发布的官方网站为沈阳药科大学研究生教育网（网址：http://grs.syphu.edu.cn/），2026年招生政策宣传及考生咨询QQ群号为469917099。各学院复试实施细则及招生咨询方式在沈阳药科大学研究生教育网和各学院网站公布。</p>\n     <p><strong>第三十二条</strong> 本办法经沈阳药科大学研究生招生委员会审议通过后发布，最终解释权归沈阳药科大学研究生招生委员会。办法如有同国家、辽宁省有关规定不符，按国家、辽宁省有关规定执行。</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n  