INSERT INTO `yl_guide` VALUES (99, '厦门大学2026年硕士研究生复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>厦门大学2026年硕士研究生复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月19日</span> <span>来源：厦门大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>为做好我校2026年硕士研究生招生复试录取工作，根据《2026年全国硕士研究生招生工作管理规定》（教学〔2025〕2号）等有关文件要求，结合我校实际，制定本办法。</p>\n     <p><strong>一、复试</strong></p>\n     <p><strong></strong></p>\n     <p><strong>（一）复试成绩要求和实施细则</strong></p>\n     <p>各学院、直属系、研究院（以下统称院系）在单科和总分都不低于学校相应学科复试基本分数线的原则下，根据学科特点、专业需要、招生计划及上线考生情况进一步研究确定本院系各学科专业的复试成绩要求、复试名单和复试录取工作实施细则，并提前在院系网站公布。</p>\n     <p><strong>（二）复试资格审查</strong></p>\n     <p>考生复试前须向院系提交以下材料接受审查，提交方式和时间以院系通知为准，未进行资格审查或资格审查未通过的考生一律不予录取。</p>\n     <p>1．由考生本人亲笔签名的《诚信复试承诺书》。</p>\n     <p>2．填写完整并密封完好的《厦门大学硕士研究生思想政治素质和品德情况审查表》（该表可在厦门大学招生网https://zs.xmu.edu.cn “下载区”下载）。</p>\n     <p>3．往届生提交毕业证书、学位证书原件和复印件、《教育部学历证书电子注册备案表》（或学历认证报告）；应届本科毕业生等提交学生证原件和复印件、《教育部学籍在线验证报告》；在境外获得学历、学位的考生，提交由教育部留学服务中心出具的《国（境）外学历学位认证书》（以应届生身份报考的考生须于入学前取得）。</p>\n     <p>4．大学期间成绩单（加盖教务部门或档案单位公章）。</p>\n     <p>5．身份证原件和复印件。</p>\n     <p>6．准考证。</p>\n     <p>7．考生自述（主要包括考生本人的思想政治素质和品德表现、外语水平、业务和科研能力、研究计划等方面内容）。</p>\n     <p>8.同等学力考生（专科毕业或本科结业）须提供英语水平证明原件和复印件、6门及以上本科专业课程成绩证明，报考工商管理[125100]、旅游管理[125400] 、工程管理[125601]、项目管理[125602]专业的考生可免提交。</p>\n     <p>9.服役期间获得三等战功、二等功以上奖励或者二级以上表彰的退役人员还须提供相关奖励和表彰证明，以及退出现役证明。</p>\n     <p>10.报考“退役大学生士兵”专项硕士研究生招生计划的考生须提供《入伍批准书》和《退出现役证》，院系留存其复印件（或电子扫描件）。</p>\n     <p>11.享受加分、照顾政策的考生按院系要求提供相应证明材料。</p>\n     <p><strong>（三）复试内容和形式</strong></p>\n     <p>复试主要考查考生的创新能力、专业素养和综合素质等。主要方式为笔试、面试、实践（实验）能力考核等。复试成绩满分为100分，复试成绩占总成绩的权重一般在30－50%的范围内。</p>\n     <p>以同等学力参加复试的考生，在复试中须加试至少两门与报考专业相关的本科主干课程。加试方式为笔试，加试科目不得与初试科目相同。</p>\n     <p>具体复试相关信息见院系通知。</p>\n     <p><strong>二、调剂</strong></p>\n     <p><strong></strong></p>\n     <p>院系根据教育部调剂相关政策规定，结合学科专业要求确定调剂细则并提前公布。所有调剂考生（含报考“退役大学生士兵计划”与普通计划之间调剂的考生等）调剂申请均须通过教育部“全国硕士生招生复试调剂服务系统”进行。</p>\n     <p><strong>三、拟录取</strong></p>\n     <p><strong></strong></p>\n     <p>1.院系根据各学科专业的招生计划、复试录取实施细则以及考生初试成绩、复试成绩、思想政治和品德情况、健康状况等择优确定拟录取名单。总成绩=初试成绩÷5（如初试满分为300分，则除以3）×权重+复试成绩（百分制）×权重。如果考生的总成绩完全相同，则比较初试总成绩，成绩高者被录取；如果初试总成绩再相同，则比较满分大于100分的单科成绩之和，成绩之和高者被录取。</p>\n     <p>2.按顺序确定候补录取名单。院系可根据考生总成绩的高低确定候补录取名单。考生应自愿和慎重地持有候补录取资格，考生如因选择等候候补录取名额而丧失调剂机会，后果由本人负责。在候补录取中，如排序靠前的候补考生已调剂至其它学校，我校将跳过该生顺次递补录取。</p>\n     <p>3.不予录取情况。复试成绩不合格（60分以下）者、思想品德考核不合格者、体检不合格者或同等学力任一门加试科目不合格（60分以下）者不予录取。院系可在此基础上，根据学科专业特点对复试中的单项考核成绩设立合格标准。应届本科毕业生及自学考试和网络教育届时可毕业本科生等考生，入学前未取得国家承认的本科毕业证书者或教育部留学服务中心出具的《国（境）外学历学位认证书》，录取资格无效。</p>\n     <p>4.拟录取名单经福建省教育考试院和教育部审批后最终确定。</p>\n     <p>5.定向就业的考生应当在被录取前与我校、用人单位签订定向就业合同。一经录取后，不得变更录取信息中的就业方式。考生因报考硕士研究生与所在单位产生的问题由考生自行处理，若因此造成考生不能复试或无法录取，我校不承担责任。</p>\n     <p><strong>四、体检</strong></p>\n     <p><strong></strong></p>\n     <p>院系根据《中华人民共和国残疾人教育条例》和《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）等文件规定，参照《教育部 卫生部 中国残疾人联合会关于印发〈普通高等学校招生体检工作指导意见〉的通知》（教学〔2003〕3号）要求，结合招生专业实际情况，提出本单位体检要求。考生应前往具有二级甲等资质及以上的医院进行体检，体检报告于公示拟录取名单后10个工作日内提交（以寄出时间为准），体检报告日期3个月内有效。</p>\n     <p><strong>五、监督和违规处理</strong></p>\n     <p><strong></strong></p>\n     <p><strong>（一）</strong>我校纪检监察机构负责监督研究生招生工作，电话：0592-2186219。</p>\n     <p><strong>（二）</strong>对复试过程中有违规行为的考生，一经查实，将按照《国家教育考试违规处理办法》等文件规定严肃处理。</p>\n     <p><strong>六、其他</strong></p>\n     <p><strong>（一）</strong>所有被录取的考生均须参加复试考核。对服役期间获得三等战功、二等功以上奖励或者二级以上表彰，符合全国硕士研究生招生考试报考条件的退役人员，须参加复试。如有必要，经所在地省级教育招生考试机构同意，我校可以对考生再次复试。</p>\n     <p><strong>（二）</strong>新生入学后，我校在3个月内按照国家招生规定对其进行思想政治素质和品德、专业素质、健康状况等全面复查，复查不合格者，由我校根据实际情况予以处理，直至取消学籍。</p>\n     <p><strong>（三）</strong>未尽事宜以教育部《2026年全国硕士研究生招生工作管理规定》等文件和学校相关规定为准。</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研