INSERT INTO `yl_guide` VALUES (100, '中国社会科学院大学2026年硕士研究生招生考试复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>中国社会科学院大学2026年硕士研究生招生考试复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月19日</span> <span>来源：中国社会科学院大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>为全面做好我校2026年硕士研究生招生考试复试录取工作，根据教育部《2026年全国硕士研究生招生工作管理规定》和《关于做好2026年全国硕士研究生录取工作的通知》等文件精神及北京市招生考试委员会相关文件要求，结合学校实际，制订《中国社会科学院大学2026年硕士研究生招生考试复试录取工作办法》（以下简称“工作办法”）。</p>\n     <p><strong>一、复试组织管理</strong></p>\n     <p><strong></strong></p>\n     <p>硕士研究生复试录取工作实行学校、学院两级管理。</p>\n     <p>1.校招生委员会负责组织领导、统筹协调、监督管理全校硕士研究生复试录取工作，由招生与就业处具体指导、协调、监督各学院实施。</p>\n     <p>2.各学院研究生招生委员会负责本学院硕士研究生复试录取工作的领导，成立不少于三人的复试录取工作小组负责具体落实，确保工作政策执行准确、组织有序、管理到位。</p>\n     <p>3.各学院复试录取工作小组遴选组建若干复试小组，小组一般由不少于5名副高级（含）以上职称并承担过或正在承担硕士生教学工作的教师组成，设立组长一名。</p>\n     <p><strong>二、进入复试基本分数要求</strong></p>\n     <p><strong></strong></p>\n     <p>各学院参加复试的考生，其初试分数不得低于《2026年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》中A类考生成绩要求。我校硕士研究生不允许破格复试录取。各学院可根据本学院生源情况、培养要求上调分数线，除成绩要求之外，可根据专业特点和培养需要提出其他学术要求，但不得出台歧视性规定。</p>\n     <p>参加我校“退役大学生士兵计划”复试的考生，其初试分数不得低于《2026年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》中B类考生成绩要求。</p>\n     <p>根据《2026年全国硕士研究生招生工作管理规定》，对服役期间获得三等战功、二等功以上奖励或者二级以上表彰，符合全国硕士研究生招生考试报考条件的退役人员，可申请免初试攻读硕士研究生。（以下简称这类考生为“立功表彰免初试生”）。已按要求报名且审核通过的考生可进入复试。</p>\n     <p><strong>三、复试安排</strong></p>\n     <p><strong></strong></p>\n     <p>复试是硕士研究生录取的必要环节，复试不合格者不予录取。</p>\n     <p>1.复试方式</p>\n     <p>我校考生复试一般采用现场复试的方式进行。调剂复试按学院通知的方式进行。</p>\n     <p>2.复试时间和地点</p>\n     <p>（1）一志愿考生复试。于3月19日—31日期间进行，各专业具体复试时间和地点详见各学院网站后续通知，请考生及时关注。</p>\n     <p>（2）调剂考生复试在4月8日以后举行，4月24日前全部完成。具体时间详见各学院网站后续通知。</p>\n     <p>（3）因个人原因未能如期参加复试的考生，不予补复试。</p>\n     <p>3.复试资格审查</p>\n     <p>复试前各学院将对复试考生资格进行认真审查。各学院对考生的准考证、有效居民身份证、学历学位证书（应届本科毕业生交验学生证或“在读证明”）、学历学籍核验结果等进行审查核验，对不符合规定或弄虚作假者，一经查实，视为资格审查不通过，取消复试资格。未在规定时间内按要求提交材料者，视为自动放弃复试资格。</p>\n     <p>对考生的学历（学籍）信息有疑问的，各学院可以要求考生在复试前提供权威机构出具的认证证明，考生应予配合，未通过或未完成学历（学籍）审核的考生不得列入拟录取名单。</p>\n     <p>拟录取考生待入学报到时，学院对其相关材料原件及报考资格进行再次审查，对不符合规定或弄虚作假者，一经查实，取消入学资格。</p>\n     <p>4.复试比例</p>\n     <p>按照教育部有关规定，我校硕士生招生实行差额复试，按照不低于120%的差额比例（合格生源比例不足的，按实际合格生源数组织复试），确定各专业复试名单。各学院可根据生源情况、招生计划、学科专业特点和复试考核工作需要等确定本学院各专业复试比例。</p>\n     <p>5.复试考核内容</p>\n     <p>复试包括专业综合笔试、外语听力与口语测试、专业能力和综合素质面试、思想政治素质和品德考核。</p>\n     <p>同等学力考生除参加复试外，还须在复试期间加试两门与报考专业相关的本科主干课程。加试科目不得与初试科目相同，加试方式为笔试，试卷满分为100分，60分以上为合格。加试成绩不计入复试总成绩，但加试成绩不合格者不予录取。加试具体实施方式由学院自行安排。</p>\n     <p>会计硕士、工商管理硕士、公共管理硕士的思想政治理论考试在复试中进行，由学院自行确定组织方式并实施。</p>\n     <p>6.复试材料提交</p>\n     <p>取得复试资格的考生，按照学院规定的方式和时间提交如下材料：</p>\n     <p>（1）准考证；</p>\n     <p>（2）有效身份证件原件；</p>\n     <p>（3）学历、学位证书原件（往届生），未通过学籍学历验证的考生还需提供学信网出具的学籍学历认证报告；学生证原件（包括个人信息页和注册页，须加盖有效注册章）或在读证明（应届生）；</p>\n     <p>（4）个人陈述（包括个人基本信息、政治表现、外语水平、与报考专业相关的学术科研能力和经历、研究生期间学习研究规划，1500字左右）；</p>\n     <p>（5）可以反映考生科研能力和潜质、综合素质和能力的其他材料，包括但不限于本科毕业学校正式成绩单、毕业论文（大纲、摘要或进展报告）、科研成果、参加学术科研活动等方面的情况和证明。具体附加材料要求由各学院结合学科专业特点和复试考核工作需要自行确定。</p>\n     <p>以上（1）（2）（3）项为必须项，（4）（5）项由考生根据学院要求及个人实际情况提交。</p>\n     <p>符合教育部规定可享受加分政策的考生，需向招生学院提出书面申请并提交相关证明材料。</p>\n     <p>报考“退役大学生士兵计划”的考生还应提交本人的《入伍批准书》和《退出现役证》原件。</p>\n     <p>考生须保证提交材料的真实性，如因特殊原因影响无法提交应向学院说明情况。</p>\n     <p>7.思想政治素质和道德品质考核及体检</p>\n     <p>学院在复试时组织思想政治工作人员、导师与考生面谈，直接了解思想政治情况。拟录取名单确定后，拟录取考生应按照学院要求提交由所在单位、存档单位党组织（党委、分党委、党总支）、人事、政工部门出具的思想政治素质和道德品质鉴定材料，并加盖印章。</p>\n     <p>拟录取考生应进行体检，按照招生学院要求在二级甲等以上等级医院或专业体检机构完成体检，将体检结果提交报考学院，由学院送医务室审核，体检不合格者不予录取。</p>\n     <p>8.成绩的评定及计算</p>\n     <p>初试成绩和复试成绩在总成绩中的占比分别为60%和40%，总成绩计算公式一般为：（1）初试满分500分的专业：总成绩=初试成绩/5*60%+复试成绩（折算成百分制）*40%；（2）初试满分300分的专业：总成绩=初试成绩/3*60%+复试成绩（折算成百分制）*40%。</p>\n     <p>复试成绩或复试各方式单项考核成绩不合格者，不予录取。同等学力加试的成绩不计入复试成绩，但不合格者（合格线为60分）不予录取。思想政治素质和道德品质考核不作量化计入总成绩，但考核结果不合格者不予录取。</p>\n     <p>对符合政策要求的“立功表彰免初试生”，复试合格即可予以拟录取。</p>\n     <p>报考“退役大学生士兵计划”的考生，按照国家和学校相关规定，依据初试、复试合格考生的标准分数，在该专项招生计划限额内从高到低排序后择优录取。考生标准分数=（考生考试总成绩-考生报考学院专业的所有复试考生平均考试总成绩）/该学院专业所有复试考生考试总成绩标准差。</p>\n     <p><strong>四、调剂</strong></p>\n     <p><strong></strong></p>\n     <p>所有调剂考生均通过教育部“全国硕士生招生调剂服务系统”接收。各学院接收的调剂考生，包括校外调剂考生，校内各学院之间的调剂考生，也包括报考“退役大学生士兵计划”与普通计划之间调剂的考生，以及同一学院内不同学科专业的调剂考生（含全日制与非全日制之间的调剂）。</p>\n     <p>1.考生参与调剂的基本条件</p>\n     <p>（1）符合招生简章中规定的调入专业的报考条件；初试成绩（含加分）符合第一志愿报考专业在调入地区的全国初试成绩基本要求；</p>\n     <p>（2）调剂考生第一志愿专业与调入专业相同相近，或初试科目与调入专业初试科目相同相近；</p>\n     <p>（3）第一志愿报考工商管理、公共管理、会计、旅游管理、图书情报、工程管理、审计等7个专业学位的考生，在满足调入专业报考条件的基础上，可申请相互调剂，但不得调入其他专业；报考其他专业的考生也不得调入该7个专业学位。</p>\n     <p>（4）第一志愿报考法律硕士（非法学）的考生不得调入其他专业，其他专业的考生也不得调入该专业学位。</p>\n     <p>（5）第一志愿报考“退役大学生士兵计划”的考生，申请调剂到普通计划，其初试成绩须达到调入地区相关专业所在学科门类（专业学位类别）的国家初试成绩基本要求。符合条件的，可按规定享受退役大学生士兵初试加分政策。</p>\n     <p>报考普通计划的考生，符合“退役大学生士兵计划”报考条件的，可申请调剂到该专项计划，其初试成绩须符合相关招生单位确定的接受“退役大学生士兵计划”考生调剂的初试成绩要求。调入“退役大学生士兵计划”招录的考生，不再享受退役大学生士兵初试加分政策。</p>\n     <p>（6）报考学术学位考生可以调剂到相关专业学位专业，报考专业学位考生不得调剂到学术学位专业。</p>\n     <p>（7）符合教育部关于调剂工作的其他条件要求。</p>\n     <p>2.调剂工作程序及要求</p>\n     <p>学校将根据各学院复试录取情况，通过“调剂服务系统”和学校招生网站发布招生计划余额信息，我校接受所有调剂考生（含报考“退役大学生士兵计划”与普通计划之间调剂的考生等）调剂申请均须通过教育部“调剂服务系统”进行，不接受其他渠道的调剂申请。具体程序和要求参见我校2026年硕士研究生调剂招生工作办法。</p>\n     <p><strong>五、信息公布的时间和方式</strong></p>\n     <p><strong></strong></p>\n     <p>公布时间：招生政策、招生计划、复试工作实施细则、复试名单由各学院于复试前公布；复试结果（排名）、推荐待录取名单于各学院复试结束后公布；学校拟录取名单于5月公布（公示不少于7日）。</p>\n     <p>公布渠道：我校复试录取相关信息均在各学院网站和大学招生网进行公布，拟录取考生名单将统一在大学招生网公示。</p>\n     <p>我校及相关招生学院以网站、电话、电子邮件、短信等方式公开或发送给考生的相关信息、文件和消息，均视为送达，因考生个人疏忽等原因造成的一切后果由考生本人承担。</p>\n     <p><strong>六、复试的监督和复议</strong></p>\n     <p><strong></strong></p>\n     <p>复试工作在各学院复试录取工作小组的指导与监督下进行，考生对学院硕士生招生环节有异议的，可向学院书面形式具名提起申诉，学院应当受理并予以答复。申诉人对答复有异议的，可向招生与就业处提起申诉。</p>\n     <p><strong>七、其他说明</strong></p>\n     <p><strong></strong></p>\n     <p>1.凡弄虚作假、违反考试相关规定和纪律、存在学术不端行为的考生，我校将取消录取资格，并按照有关规定严肃处理。考生须承诺学历、学位证书、个人及其它报考信息的真实性，存在学术道德、专业伦理、诚实守信等方面问题者，一经查实，取消考试、录取或学习资格。</p>\n     <p>2.我校将在新生入学后3个月内，按照《普通高等学校学生管理规定》有关要求对所有考生进行全面复查。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p>3.定向就业的硕士研究生均须在被录取前与学校、用人单位分别签订定向就业协议。</p>\n     <p>考生因报考硕士研究生与所在单位产生的问题由考生自行处理。若因此造成考生不能复试或无法录取，我校不承担责任。</p>\n     <p>4.被录取的全日制学习方式的非定向就业考生的人事档案必须转入我校，户口可按个人意愿确定是否转入。调档函随录取通知书一并发放。</p>\n     <p>5.经考生确认的报考信息在录取阶段一律不作修改，对报考资格不符合规定者不予录取。未通过或未完成学历（学籍）审核的考生不得列入拟录取名单进行公示或上报。</p>\n     <p><strong>八、监督电话及考生咨询电话</strong></p>\n     <p><strong></strong></p>\n     <p>1.咨询电话：010-81360224（大学研招办）</p>\n     <p>2.监督电话：010-81360318（大学纪委办公室）</p>\n     <p>我校各学院具体负责考生复试、调剂、录取工作，负责接待考生咨询。各学院联系电话见中国社会科学院大学招生网－联系我们－附件。</p>\n     <p><strong>九、其他</strong></p>\n     <p><strong></strong></p>\n     <p>如果上级部门出台新政策，我校将作相应调整并及时公布。</p>\n     <p>本办法的最终解释权归中国社会科学院大学招生与就业处所有。</p>\n     <p style=\"text-align: right;\">中国社会科学院大学招生与就业处</p>\n     <p style=\"text-align: right;\">2026年3月17日</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chsi.com.cn/sswbgg/\" ta