INSERT INTO `yl_guide` VALUES (101, '2026年电子科技大学硕士研究生复试录取工作安排通知', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>2026年电子科技大学硕士研究生复试录取工作安排通知</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月19日</span> <span>来源：电子科技大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据教育部和四川省教育考试院有关文件精神，结合学校实际情况，现将我校2026年硕士研究生复试录取工作安排通知如下：</p>\n     <p><strong>一、总体要求</strong></p>\n     <p>以习近平新时代中国特色社会主义思想为指导，深入学习贯彻党的二十大和二十届历次全会精神，全面落实党的教育方针，在确保安全性、科学性、公平性的基础上，坚持服务战略、按需招生、全面衡量、择优录取和宁缺毋滥的招生原则，严格规范执行招生政策，加强组织领导，强化督导和检查，扎实做好信息公开，维护考生合法权益，确保2026年硕士研究生复试录取平稳有序进行。</p>\n     <p><strong>二、工作组织</strong></p>\n     <p>学校研究生招生委员会负责对全校复试录取工作的领导和统筹管理。研究生院在学校研究生招生委员会领导下，负责对全校复试录取工作进行管理、协调和督导。</p>\n     <p>学院研究生招生委员会负责按照学校有关规定，结合学院实际情况，制定复试工作具体实施方案，设立复试工作小组和一定数量的复试面试小组具体落实复试录取工作各项规定，执行各类招生计划。</p>\n     <p>学院研究生复试工作小组负责本学院复试工作具体组织实施，指导复试小组进行相应考核工作，协调落实复试工作。</p>\n     <p>复试面试小组负责在学院研究生招生委员会和复试工作小组指导下，按照相关规定具体实施复试面试考核。复试面试小组一般由5名（含）以上具有副高及以上职称、师风师德表现良好、能正确执行招生政策、责任心强的教师组成。</p>\n     <p><strong>三、复试方式及内容</strong></p>\n     <p>1.复试方式：原则上采用现场复试方式，调剂到非全日制且有复试科目笔试成绩的考生可以采用网络远程复试。</p>\n     <p>2.复试占比：复试成绩和初试成绩一般各占总成绩50%。</p>\n     <p>3.复试内容：</p>\n     <p>（1）笔试</p>\n     <p>笔试科目为第一志愿报考专业对应的复试科目（调剂考生为调剂专业对应的复试科目），不得与初试科目重复，详见招生简章，笔试时间120分钟，总分四舍五入取整数。学院另有要求的按学院要求执行。</p>\n     <p>（2）外语测试</p>\n     <p>外语测试一般采用面试方式进行，其中口语50%、听力50%，总分四舍五入取整数。时间一般不少于5分钟。</p>\n     <p>（3）综合考核（考查专业素质和能力、综合素质和能力、实践（试验）能力考核、思想政治素质和品德等）。</p>\n     <p>分值：总分200分，总分四舍五入取整数。</p>\n     <p>综合考核中综合面试时间一般不少于15分钟。</p>\n     <p>（4）以同等学力参加复试的考生，需加试至少两门与报考专业相关的本科主干课程，加试科目不得与初试科目相同。加试成绩不计入复试总成绩，所有加试科目的成绩须达到满分的60%，否则加试成绩不合格，不予录取。</p>\n     <p>4.依照教育部有关规定，学院认为有必要时，报研究生院备案审核，经四川省教育考试院同意后，可对相关考生再次组织复试。</p>\n     <p><strong>四、时间安排</strong></p>\n     <p>我校复试录取工作于3月下旬启动，原则上在4月底前完成，具体时间请以学院发布的复试工作安排相关通知为准。</p>\n     <p><strong>五、复试信息确认</strong></p>\n     <p>1.考生登录“电子科技大学研究生招生管理信息系统”（https://yzbm.uestc.edu.cn/logout，具体时间以学院复试安排通知为准）进行复试信息确认（填报联合培养项目意向、确认联系方式等）。考生登录系统后可查看相关操作指南。</p>\n     <p>2.网上交费。考生通过“电子科技大学研究生招生管理信息系统”缴纳复试费120元（川发改价格规〔2022〕484号）。</p>\n     <p><strong>六、资格审核</strong></p>\n     <p>1.考生根据学院要求，通过“电子科技大学研究生招生管理信息系统”平台上传或现场提交本人以下材料：</p>\n     <p>（1）基础材料</p>\n     <p>①《2026年电子科技大学硕士研究生诚信复试承诺书》（考生本人签字）</p>\n     <p>②《全国硕士研究生招生考试准考证》（通过“中国研究生招生信息网”下载）。</p>\n     <p>（2）学历学籍证明材料</p>\n     <p>考生应根据个人的身份属性选择材料进行提交。</p>\n     <p>①应届本科毕业生（含成人教育、网络教育届时可毕业考生）提供：学生证或《教育部学籍在线验证报告》。</p>\n     <p>②自学考试届时可毕业本科生提供：自考准考证、注册地自考办打印加盖公章的考生考籍表。</p>\n     <p>③往届毕业生提供：毕业证或《教育部学历证书电子注册备案表》。</p>\n     <p>④在境外获得学历或学位证书的考生需提供：教育部留学服务中心出具的《国外学历学位认证书》。</p>\n     <p>（3）补充材料</p>\n     <p>考生需提交的其他补充材料以各学院通知为准。（如：个人简历、大学学习成绩单、毕业论文（设计）（摘要）、研究成果、专家推荐信等。如提交补充材料，须本人在材料正面右下角签字确认后提交。）</p>\n     <p>（4）其他材料</p>\n     <p>曾经更改过姓名或身份证号的考生还需提供：户口本或公安机关开具的证明。</p>\n     <p>2.各学院将对考生提交的上述材料进行严格审核，同时运用“人脸识别”、“人证识别”等技术，综合比对“报考库”、“学籍学历库”、“人口信息库”、“考生考试诚信档案库”，加强对考生身份的鉴别。凡弄虚作假者一律不予复试，资格审查不合格者不予复试。对提供虚假信息或材料，一经核实将取消其复试资格、录取资格、入学资格、学籍直至取消学历学位，责任由考生自负。</p>\n     <p>3.应届本科毕业生、自学考试和网络教育等届时可毕业本科生须在录取当年入学前（以学校当年开学报到时间为准）取得国家承认的本科毕业证或教育部留学服务中心出具的《国（境）外学历学位认证书》，否则录取资格无效。</p>\n     <p><strong>七、调剂</strong></p>\n     <p>1．考生调剂基本条件：</p>\n     <p>（1）符合调入专业的报考条件。</p>\n     <p>（2）初试成绩（含加分，下同）符合第一志愿报考专业在调入地区的全国初试成绩基本要求以及我校对应专业初试成绩基本要求。</p>\n     <p>（3）调入专业与第一志愿报考专业相同或相近。</p>\n     <p>（4）初试科目与调入专业初试科目相同或相近，其中初试全国统一命题科目应与调入专业全国统一命题科目相同。统考数学（一）专业可申请调剂统考数学（二）、统考数学（三）等专业，统考数学（二）专业可申请调剂统考数学（三）专业，反之不能申请调剂。</p>\n     <p>（5）符合教育部调剂基本条件。</p>\n     <p>（6）符合调入学院提出的其他相关要求。</p>\n     <p>2.考生调剂申请流程：</p>\n     <p>考生申请调剂首先需在“全国硕士生招生复试调剂服务系统”进行填报，招生学院审核考生填报的调剂信息，给符合调剂条件的考生发送复试通知，考生接受复试通知后登录学校研究生招生管理信息系统进行复试信息确认、缴费等操作（具体以学院发布的调剂通知为准）。考生调剂录取后需通过“全国硕士生招生复试调剂服务系统”最终确认录取到我校。</p>\n     <p>3.我校2026年硕士研究生一志愿上线生源总体充足，生源饱和的专业不接收调剂。少数生源不饱和的专业可接收调剂，接收调剂生源的学院按照有关要求制定调剂工作办法，调剂信息第一时间发布在学校研招网和全国研招网（yz.chsi.com.cn）“全国硕士研究生招生复试调剂服务系统”，不接受电话、邮件、来人来函等其他方式申请。</p>\n     <p>强军计划、少数民族高层次骨干人才计划、退役大学生士兵计划不接收调剂。</p>\n     <p>4.复试合格且已经拟录取的考生原则上不能再调剂。考生复试成绩原则上校内学院可以互认，学院另有要求的按学院要求执行。</p>\n     <p>5.调剂要求以教育部最终公布文件为准，如调剂不符合教育部文件要求，则复试成绩无效。</p>\n     <p><strong>八、录取与公示</strong></p>\n     <p>1.复试成绩为各项考核成绩之和。复试成绩合格要求：非国家专项计划考生的复试总成绩及单项成绩均达到满分的60%；国家专项计划考生的复试总成绩达到满分60%。复试成绩不合格者，不予录取。</p>\n     <p>2.总成绩计算公式：</p>\n     <p>（1）初试总成绩为500分的学科（专业）：</p>\n     <p>总成绩=初试成绩÷5×50%+复试成绩÷5×50%，总成绩四舍五入保留两位小数。</p>\n     <p>（2）初试总成绩为300分的学科（专业）：</p>\n     <p>总成绩=初试成绩÷3×50%+复试成绩÷3×50%，总成绩四舍五入保留两位小数。</p>\n     <p>（3）对于调剂考生的总成绩构成，各学院可在此基础上优化调整，但复试成绩占比不超过60%。具体占比报研究生院审核通过后，在调剂通知中提前公布。</p>\n     <p>3.录取优先顺序为：第一志愿考生优先级大于调剂考生。同一优先级按总成绩从高到低依次择优录取。若总成绩相同，依次比较初试总成绩、业务课二成绩、业务课一成绩、外国语成绩，从高到低择优录取。</p>\n     <p>4.部队立功申请免初试攻读硕士研究生的考生，已在中国研究生招生信息网管理平台推免服务系统完成报名，申请免初试攻读硕士研究生，经资格审核通过后，准予参加复试。复试总成绩及单项成绩均须达到满分的60%，复试成绩不合格不予录取。</p>\n     <p>5.在复试、录取阶段，各学院将提前在学院网站向社会公布复试相关安排，学院或学科、专业招生人数，参加复试考生名单（包括考生姓名、考生编号、初试各科成绩等信息）和拟录取考生名单（包括考生姓名、考生编号、初试成绩、复试成绩、总成绩等信息）。</p>\n     <p>6.体检统一在拟录取后进行，具体见学校及学院后续相关通知。体检不合格者不予录取。</p>\n     <p>7.拟录取公示后，考生须将《电子科技大学研究生招生考生现实表现情况表》由考生档案或学习工作所在单位的人事、政工部门或居住地街道办签署意见加盖印章，并在规定时间内提交至拟录取学院。对于思想政治素质和品德考核考察不合格的考生，不予录取或入学。</p>\n     <p>8.档案与派遣：录取为非定向的考生必须在入学前（以学校当年开学报到时间为准）将个人档案调入学院；录取为定向的考生必须在录取前与学校、用人单位签订定向协议（合同）书（强军计划除外）。按照教育部有关规定，我校非全日制硕士研究生原则上录取为定向。</p>\n     <p>9.拟录取考生经公示、教育部录检合格后才确定为正式录取，并以录取通知书为准。</p>\n     <p>10.入学后3个月内，学校按规定对所有考生进行全面复查。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p><strong>九、监督信息</strong></p>\n     <p>1.研招办</p>\n     <p>电话：028-61830153，邮箱：yzb@uestc.edu.cn。</p>\n     <p>2.学校纪检、监察部门</p>\n     <p>电话：028-61830237， 邮箱：jjs@uestc.edu.cn。</p>\n     <p><strong>十、其他</strong></p>\n     <p>1.按照教育部相关规定，符合下列条件之一后3年内报名参加全国硕士研究生招生考试的考生，可申请享受初试总成绩加10分，同等条件下优先录取。</p>\n     <p>（一）参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”项目之一，服务期满且考核合格。</p>\n     <p>（二）退役大学生士兵〔即高校学生应征入伍退出现役者，其中，高校学生指全日制普通本专科（含高职）、研究生、第二学士学位的应（往）届毕业生、在校生和入学新生，以及成人高校招收的普通本专科（含高职）应（往）届毕业生、在校生和入学新生〕达到全国硕士研究生招生考试报考条件。</p>\n     <p>申请享受初试加分的考生，须在网上报名时按要求填报相关信息。有关部门按职责分工进行审核。未按规定申报或审核未通过的，不享受加分政策。加分项目不累计。报考专项计划的考生，不再享受初试加分。</p>\n     <p>请符合条件的考生于3月23日前将本人签名的《2026年全国硕士研究生招生享受初试加分政策申请表》、身份证复印件、参与项目协议（合同）复印件及考核材料复印件，通过“电子科技大学研究生招生管理信息系统”（https://yzbm.uestc.edu.cn/logout）“初试成绩加分或照顾政策申请”模块提交申请材料审核，否则视为自动放弃。</p>\n     <p>2.“享受少数民族照顾政策”的考生请于3月23日前将本人签名的《电子科技大学硕士研究生招生考试申请“享受少数民族照顾政策”考生登记表》、身份证复印件、户口本复印件（首页和个人页）、单位同意报考定向就业研究生的证明等通过“电子科技大学研究生招生管理信息系统”（https://yzbm.uestc.edu.cn/logout）“初试成绩加分或照顾政策申请”模块提交申请材料审核，否则视为自动放弃。</p>\n     <p>申请享受少数民族照顾政策的考生，须在网上报名时按要求填报相关信息。未按规定申报或审核未通过的，不享受照顾政策。报考专项计划的考生，不再享受少数民族照顾政策。</p>\n     <p>3.部队立功申请免初试攻读硕士研究生的考生，请于3月23日前将本人签名的《立功表彰退役军人免初试攻读硕士研究生考生登记表》、身份证复印件、立功相关证明材料复印件及学历学位证明材料复印件通过邮件发送到uestcyanzhaoban@uestc.edu.cn进行审核（已经提交的考生不用再次提交），资格审核通过后，准予参加复试。</p>\n     <p>4.在读研究生报考我校的，须在复试前将所在培养单位同意报考的书面意见提交到复试学院。</p>\n     <p>5.对弄虚作假或不符合报考、复试、录取资格者，不论何时，一经查实，即按有关规定取消报考、复试、录取、学习资格直至取消学籍和学历学位，责任由考生自负。</p>\n     <p>6.本通知内容如有变动，请以最新通知为准。请考生密切关注电子科技大学研招网及各学院网站上发布的最新信息。其他未尽事宜请参见相关文件通知或由电子科技大学研究生院负责解释。</p>\n     <p>7.联系方式</p>\n     <p>（1）研招办联系方式</p>\n     <p>联系电话：028-61830152、028-61830153</p>\n     <p>电子邮箱：yzb@uestc.edu.cn</p>\n     <p>通讯地址：四川省成都市高新西区西源大道2006号电子科技大学清水河校区主楼B2-419研招办</p>\n     <p>邮编：611731</p>\n     <p>（2）学院联系方式</p>\n     <p>详见：https://yz.uestc.edu.cn/lxwm.htm</p>\n     <p style=\"text-align: right;\">电子科技大学研究生院</p>\n     <p style=\"text-align: right;\">2026年3月17日</p>\n     <p>附件</p>\n     <p>附件1：2026年电子科技大学硕士研究生诚信复试承诺书</p>\n     <p>附件2：2026年全国硕士研究生招生享受初试加分政策申请表</p>\n     <p>附件3：立功表彰退役军人免初试攻读硕士研究生考生登记表</p>\n     <p>附件4：电子科技大学硕士研究生招生考试申请“享受少数民族照顾政策”考生登记表</p>\n     <div>\n      <div>\n       ----\n      </div>\n      <div>\n       &nbsp;&nbsp;\n      </div>\n      <div>\n       &nbsp;&nbsp;\n      </div>\n      <div>\n       &nbsp;&nbsp;\n      </div>\n      <div>\n       &nbsp;&nbsp;\n      </div>\n     </div>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n   