cn/tm/\" target=\"_blank\">推荐系统</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/\" target=\"_blank\">申请指南</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/#bmlc\" target=\"_blank\">推免流程</a> <a href=\"https://yz.chsi.com.cn/tm/zyml/\" target=\"_blank\">专业目录</a> <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">填报志愿</a> <a href=\"https://yz.chsi.com.cn/tm/lqmd/index\" target=\"_blank\">信息公开</a>\n      </div>\n     </div>\n    </div>\n   </div>\n  </div>\n </div>\n</div><!-- 4: 底部区域 -->\n<svg style=\"display: block; width: 0; height: 0\">\n <defs>\n  <symbol id=\"weibo\" viewBox=\"0 0 16 16\">\n   <g stroke=\"none\" stroke-width=\"1\" fill=\"none\" fill-rule=\"evenodd\">\n    <g transform=\"translate(-139.000000, -4036.000000)\" fill=\"currentColor\" fill-rule=\"nonzero\">\n     <g transform=\"translate(139.000000, 4036.000000)\">\n      <rect opacity=\"0\" x=\"0\" y=\"0\" width=\"16\" height=\"16\"></rect>\n      <path d=\"M10.565,3.6325 C10.565,3.6325 12.335,3.445 13.0875,4.5425 C13.84,5.64 13.515,7.02 13.515,7.02 C13.4949253,7.12321653 13.5233752,7.22993417 13.5921672,7.30945968 C13.6609592,7.38898519 13.7624686,7.43250415 13.8675,7.4275 L14.0425,7.4275 C14.2747485,7.42111375 14.4682944,7.24766281 14.5,7.0175 C14.5,7.0175 14.9075,4.8525 13.65,3.6475 C12.67,2.705 11.3275,2.6025 10.79,2.6025 L10.5525,2.6025 C10.3240422,2.60790517 10.1412883,2.79398193 10.1399581,3.0225 L10.1399581,3.2275 C10.1383884,3.33892927 10.183335,3.44597927 10.264011,3.52285878 C10.3446871,3.59973829 10.4537777,3.63947671 10.565,3.6325 L10.565,3.6325 Z M7.08,11.845 C8.315,11.595 9.15,10.565 8.9475,9.5225 C8.7725,8.625 7.8875,8.0225 6.8575,8.0225 C6.6895953,8.02269714 6.52211889,8.03944478 6.3575,8.0725 C5.1225,8.3225 4.2875,9.3525 4.49,10.395 C4.6925,11.4375 5.8475,12.085 7.08,11.845 Z M7.115,9.1625 C7.27228055,9.15431868 7.41868486,9.24275691 7.48462743,9.38578027 C7.55057,9.52880363 7.52275233,9.69756891 7.41439607,9.8118625 C7.3060398,9.9261561 7.13899693,9.96292865 6.99266239,9.90470229