INSERT INTO `yl_guide` VALUES (102, '江苏理工学院2026年硕士研究生招生复试录取办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>江苏理工学院2026年硕士研究生招生复试录取办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月18日</span> <span>来源：江苏理工学院 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>研究生招生考试是国家选拔高层次专门人才的重要途径，复试是研究生招生考试的重要组成部分。根据教育部《关于印发&lt;2026年全国硕士研究生招生工作管理规定&gt;的通知》（教学[2025]2号）、《关于做好2026年全国硕士研究生招生复试录取工作的通知》（教学司〔2026〕3号）、教育部和省教育厅2026年硕士研究生招生录取工作会议精神等相关要求，为加强和规范复试录取工作，结合我校2026年硕士研究生招生工作实际情况，特制定本办法。</p>\n     <p><strong>一、指导思想</strong></p>\n     <p><strong></strong></p>\n     <p>始终坚持“服务战略、按需招生、全面衡量、择优录取和宁缺毋滥”的原则，严格执行政策，严把质量关口，严守工作纪律，强化监督管理，优化考生服务，切实做好我校2026年硕士研究生复试录取各项工作，确保公平、公正、科学。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p><strong></strong></p>\n     <p><strong>（一）学校研究生招生委员会</strong></p>\n     <p>学校研究生招生委员会全面领导我校硕士研究生招生复试录取工作。复试录取工作由研究生院统筹协调，招生专业所在学院组织实施。</p>\n     <p><strong>（二）学院研究生招生工作小组</strong></p>\n     <p>各学院成立由院领导、纪检委员及学科负责人组成的学院研究生招生工作小组，全面负责本学院的复试录取工作。组长由本学院党政主要负责人担任，并实行组长负责制。切实加强对复试工作的领导，充分认识复试工作的重要性，建立有效的监督和约束机制，明确职责，责任到人。招生学院根据本办法以及招生专业特点，制定本专业“复试录取工作实施细则”，报研究生院审核后，向社会公布并组织实施复试工作。</p>\n     <p><strong>（三）学院招生复试小组</strong></p>\n     <p>学院研究生招生工作小组负责组建若干复试小组，复试小组成员应由本专业具有较高政治素质、办事公正、经验丰富、业务水平高、当年无直系亲属报考的在职教师随机组成，成员不少于5人，其中研究生导师不少于3人、外语听说能力较强的老师不少于1人，并指定组长1名，另配秘书1-2名。鼓励聘请符合遴选标准的外单位（高校、科研院所、企业等）专家参与面试。复试小组人员名单须提前报学校研究生院备案。</p>\n     <p><strong>（四）</strong><strong>两级研究生复试监督组</strong></p>\n     <p>成立学校、学院两级研究生复试录取督导组，校纪检监察部门负责对全校复试工作进行监督检查，各招生学院成立招生复试监督检查小组,负责对本学院复试录取工作全程监督，以及对各类申诉的调查复议等，组长由学院党委书记担任。招生复试监督检查小组人员名单须提前报学校研究生院备案。</p>\n     <p><strong>三、招生计划</strong></p>\n     <p><strong></strong></p>\n     <p>（一）学校研究生招生委员会根据省教育厅下达我校的硕士研究生招生计划，结合各专业上线生源情况、培养质量及上一年度规模等情况，综合确定各专业招生计划。</p>\n     <p>（二）学校将对各学院的招生计划实行动态管理。根据各学院实际复试(含调剂)人数与录取进展情况，对学院招生计划进行适当调整。</p>\n     <p><strong>四、复试（一志愿报考）</strong></p>\n     <p><strong></strong></p>\n     <p><strong>（一）复试形式</strong></p>\n     <p>2026年江苏理工学院硕士研究生招生复试方式将采用现场复试方式或网络远程复试方式；具体见各招生学院“复试录取工作实施细则”。采取网络复试形式的，以学信网招生远程面试系统为主系统。</p>\n     <p>按照有关规定，复试费为80元/人。考生于复试前通过支付宝扫码缴费（缴费时请备注：复试+专业+考生姓名+考生编号后四位），未按时缴费者，不得参加复试。缴费后因各种原因未参加复试者，已支付的复试费不予退还。</p>\n     <p><strong>（二）复试时间</strong></p>\n     <p>一志愿复试时间原则上为3月下旬开始，4月7日前完成。具体以学院通知为准。</p>\n     <p><strong>（三）复试比例</strong></p>\n     <p>结合生源情况确定参加复试的考生人数（差额比例一般不低于120%，如合格生源不足招生规模120%的专业，则按实际上线人数进行复试）。</p>\n     <p><strong>（四）复试信息发布</strong></p>\n     <p>提前在我校研究生院网站招生工作栏目和各招生学院官网向社会公布复试录取工作办法及实施细则、复试分数线、各专业招生人数、复试考生名单等相关信息。</p>\n     <p><strong>（五）复试资格条件</strong></p>\n     <p><strong>一志愿报考我校且初试成绩达到</strong><strong>2026</strong><strong>年国家一区复试基本分数线要求的考生。</strong></p>\n     <p><strong></strong><strong>（六）复试资格审查</strong></p>\n     <p>招生学院派专人负责对考生复试资格进行审查。考生须按照报考学院要求通过指定方式上传以下材料，未经资格审查或资格审查不合格的考生，一律不得参加复试。对弄虚作假的考生，一经核查确定，一律按照有关规定取消录取资格或学籍。</p>\n     <p>1.考生的准考证和有效居民身份证；</p>\n     <p>2.国家承认学历的应届本科毕业生（含普通高校、成人高校、普通高校举办的成人高等学历教育应届本科毕业）的学生证；</p>\n     <p>3．往届生的学历学位证书和教育部学历证书电子注册备案表（或学历认证报告）；</p>\n     <p>4.在境外获得学历、学位的考生，须提交教育部留学服务中心出具的《国（境）外学历学位认证书》（以应届生身份报考的考生须于入学前取得）；</p>\n     <p>5.入学前可取得国家承认本科毕业证书的自学考试和网络教育本科生，须提交颁发毕业证书的省级高等教育自学考试办公室或高校出具的相关证明；</p>\n     <p>6.政治思想情况表，该表须由考生人事所在单位基层党组织或人事组织部门填写（应届毕业生由所在院系党组织填写，无学习工作单位的考生由居住地所在街道办事处或居委会的党组织填写）；</p>\n     <p>7.《诚信复试承诺书》；</p>\n     <p>8.复试费用缴纳记录证明；</p>\n     <p>9.其他相关表现证明材料等。</p>\n     <p><strong>（七）复试内容</strong></p>\n     <p>1.思想政治素质和品德考核</p>\n     <p>思想政治素质和品德考核工作在复试中进行，思想政治素质和品德考核不计入总成绩，但考核结果不合格者不予录取。</p>\n     <p>2.复试内容</p>\n     <p>学术学位重点考核考生的学术素养、对学科知识掌握与运用情况、科研创新能力，专业学位重点考核考生的专业基础、实践能力和职业素养。会计、旅游管理专业学位复试中组织思想政治理论考试，成绩计入复试总成绩，具体以各招生学院公布的复试实施细则为准。各项内容的考察，其内容和形式由各学院根据本专业特点制定。并在《复试情况记录表》上做好详细记录，复试结束后，各学院应及时将复试情况表报研究生院备案。每位考生面试时间原则上不少于20分钟，考生明确表示已作答完毕的可提前结束考核。</p>\n     <p>3.加试</p>\n     <p>以同等学力参加复试的考生，在复试中须加试两门与报考专业相关的本科主干课程。加试方式为笔试，加试科目不得与初试科目相同，加试科目的成绩不计入复试总成绩，<strong>加试不合格者不予录取。</strong></p>\n     <p><strong>（八）复试成绩</strong></p>\n     <p>复试总成绩满分为100分，具体内容包括：本科阶段学习情况（10%）、外语听说能力（10%）、综合能力成绩（80%）（招生章程中复试专业科目内容及会计、旅游管理专业思想政治理论考试并入综合能力环节进行考察）。</p>\n     <p><strong>复试总成绩低于60分即为不合格，不予录取。</strong></p>\n     <p><strong>（九）复试组织管理要求</strong></p>\n     <p>1.复试全程记录</p>\n     <p>按照研究生招生考试相关管理规定，对复试全程录音录像（包括复试小组专家、考生现场情况），保存时间为5年。任何人员和机构（学校授权除外）不得对复试过程录音录像、拍照、截屏或网络直播，不得传播试题等复试内容，否则将依据相关规定追究相关人员责任。</p>\n     <p>严禁考核人员携带手机等通讯工具进入复试现场、中途离场或开展其他与复试无关的工作。</p>\n     <p>2.建立“两识别”“四比对”“三随机”工作机制</p>\n     <p>两识别：复试过程中严把入口关，积极运用“人脸识别”“人证识别”技术，通过查验加强对考生身份的审查核验。</p>\n     <p>四比对：通过综合比对考生“报考库”“学籍学历库”“人口信息库”“诚信档案库”中数据信息，严防复试“替考”。</p>\n     <p>三随机：复试过程中加强规范化管理，通过落实“随机选定考生复试次序”“随机确定复试工作组成人员”“随机抽取复试试题”的三随机工作机制，确保复试录取工作的公平公正。</p>\n     <p><strong>（十）</strong><strong>破格复试</strong></p>\n     <p>我校不接收破格复试。</p>\n     <p><strong>五、调剂</strong></p>\n     <p><strong></strong></p>\n     <p><strong>（一）调剂考核</strong><strong>内容</strong></p>\n     <p>2026年学校各专业调剂考核均参照一志愿复试执行。</p>\n     <p><strong>（二）调剂基本条件</strong></p>\n     <p>1.调剂考生初试成绩须符合第一志愿报考专业在调入地区的国家分数线，并符合调入专业的报考条件。</p>\n     <p>2.调剂考生第一志愿专业与调入专业相同相近，或初试科目与调入专业初试科目相同相近。</p>\n     <p>3.报考工商管理、公共管理、会计、旅游管理、图书情报、工程管理、审计等7个专业学位的考生，在满足调入专业报考条件、且初试成绩同时符合调出专业和调入专业在调入地区的国家分数线的基础上，可申请相互调剂，但不得调入其他专业；报考其他专业的考生不得调入该7个专业学位。</p>\n     <p><strong>（三）调剂流程</strong></p>\n     <p>1.调剂考生均须通过教育部指定的“全国硕士生招生复试调剂服务系统”进行报名，未通过该系统调剂录取的考生一律无效。</p>\n     <p>2.调剂到本专业的考生复试成绩与本专业一志愿复试合格考生分别排序。</p>\n     <p>3.收到我校“待录取”通知的调剂考生，请及时登录研招网确认“待录取”，<strong>确认录取后不得更改。</strong></p>\n     <p><strong>（四）调剂具体要求</strong></p>\n     <p>1.一志愿合格生源不足的专业启动调剂程序。每次调剂系统开放报名持续时间不得少于12小时。</p>\n     <p>2.各学院对调剂考生进行复试资格审核，资格审核根据调剂办法中调剂要求进行，资格审查不合格者不予调剂。回复调剂考生复试资格审核结果不得超过考生报名后36小时。</p>\n     <p>3.调剂复试内容和要求与一志愿考生复试保持一致。</p>\n     <p><strong>六、体检</strong></p>\n     <p><strong></strong></p>\n     <p>我校2026年硕士研究生招生考试体检在考生拟录取后组织进行，与新生入学体检合并。已录取考生将在开学时参加我校组织的入学体检，体检要求按照《普通高等学校招生体检工作指导意见》（教学〔2003〕3号）、《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）等文件执行。</p>\n     <p><strong>七、录取</strong></p>\n     <p><strong></strong></p>\n     <p><strong>（一）入学总成绩计算</strong></p>\n     <p>研究生入学总成绩实行百分制，并按照初试总成绩占60%、复试总成绩占40%计算。具体计算方法如下：</p>\n     <p>会计、旅游管理专业：</p>\n     <p>入学总成绩=（初试总成绩/3）×60%+复试总成绩×40%</p>\n     <p>其他专业：</p>\n     <p>入学总成绩=（初试总成绩/5）×60%+复试总成绩×40%</p>\n     <p>入学总成绩精确至小数点后2位小数。</p>\n     <p><strong>（二）录取程序</strong></p>\n     <p>1.各学院研究生招生工作小组根据考生初试与复试成绩的综合情况，结合其思想政治表现、业务素质以及身心健康状况，择优提出各专业待录取和候补待录取名单，并将名单及复试成绩汇总表报研究生院。</p>\n     <p>2.学校研究生招生委员会审核各专业的待录取和候补待录取名单，确定拟录取名单，如待录取名单中有学生放弃录取资格则从候补待录取名单中顺位录取。拟录取名单公示7日，公示结束后，通过“全国硕士研究生招生信息公开平台”上报江苏省教育考试院审核，并向教育部备案。</p>\n     <p>3.拟录取名单须经教育部审批。经教育部同意，并完备所需各项手续者，将由校研究生院发放录取通知书。手续不完备者一律不发录取通知书。</p>\n     <p>4.学历（学籍）信息有疑问的考生，须按要求在规定时间内提供权威机构出具的认证证明，对未通过或未完成学历（学籍）审核的考生不予录取。对报考资格不符合规定者不予录取。</p>\n     <p>5.应届本科毕业生及自学考试和网络教育届时可毕业本科生考生，在录取当年入学前须取得国家承认的国（境）内高校本科毕业证书或教育部留学服务中心出具的《国（境）外学历学位认证书》。录取当年入学前未取得相关证书的，其录取资格无效。</p>\n     <p>6.一经录取后，不得变更录取信息中的就业方式。拟录取为全日制定向研究生不调档案。定向就业的考生应当在被录取前与我校、用人单位签订定向就业合同。</p>\n     <p><strong>八、复查</strong></p>\n     <p><strong></strong></p>\n     <p>入学后3个月内，我校将按照《普通高等学校学生管理规定》有关要求，对所有研究生新生进行全面复查。一旦出现复查不合格，将取消入学资格；情节严重的，将移交有关部门调查处理。</p>\n     <p><strong>九、监督和复议</strong></p>\n     <p><strong></strong></p>\n     <p>（一）实行责任制度和责任追究制度。各复试小组要坚持集体把关、组长负责制的原则。学院研究生招生工作小组对本专业复试过程的公平、公正和复试结果全面负责。学校研究生招生委员会对全校复试过程的公平、公正和复试结果全面负责。所有参与复试的人员都要认真负责，切实维护复试工作的公平公正，对徇私舞弊的人员要追究责任。</p>\n     <p>（二）实行回避制度。参与考试招生相关工作的人员，如本人报名参加本次研究生招生考试的，应主动向研究生院申请全程回避；如有直系亲属或利益相关者报名的，应主动申请在影响保密、公平的必要环节和特定工作时期回避；有非直系亲属等报名的应主动报备，由招生学院和研究生院研究决定是否需要回避及如何回避。我校中层及以上领导干部，其本人或直系亲属、其他利益相关者报名参加本校研究生考试招生的，应主动向学校研究生招生委员会报备并全程回避；如有非直系亲属等报名本校的，应主动报备，由学校研究生招生委员会研究决定是否需要回避及如何回避。本校工作人员原则上不得报考本单位单独考试。对未按规定报备或回避的相关工作人员，应依规依纪严肃处理。</p>\n     <p>（三）实行全程监督制度和巡视制度。学校研究生招生委员会对复试录取工作进行全面、有效监督。如发现复试工作中有违纪舞弊行为，一经查实，对所涉及的工作人员按国家有关条例处理，取消相关考生的录取资格。</p>\n     <p>（四）实行信息公开制度。生源调剂信息、复试考生名单、复试工作方案等信息都将在研究生院网站上及时公布。学校招生计划、学校复试管理办法以及拟录取名单将按相关要求上传至“全国硕士研究生招生信息公开平台”。</p>\n     <p>（五）实行复议制度。为及时处理复试中出现的争议，在公示有关信息的同时，公布相应的咨询及申诉电话、邮箱等，保证考生咨询、申诉、监督渠道的畅通。学校研究生招生委员会对复试结果负责，并负责对考生提出的有关疑问做出必要的解释。对投诉和申诉问题经调查属实的，由学校研究生招生委员会责成学院研究生招生工作小组进行复议。咨询电话：0519-86953093，邮箱：yjsc@jsut.edu.cn；投诉电话：0519-86953052，邮箱：jwxf@jstu.edu.cn。</p>\n     <p><strong>十、其他</strong></p>\n     <p><strong></strong></p>\n     <p>（一）考生因报考硕士研究生与所在单位产生的问题由考生自行处理。若因此造成考生不能复试或无法录取，我校不承担任何责任。</p>\n     <p>（二）复试期间发现考生不符合报考规定条件、政治思想道德不符合录取要求的，一律视为不合格，不予录取。</p>\n     <p>（三）在复试录取工作中，若有违反相关法律法规和招生管理规定的，一律按教育部相关法令严肃处理。</p>\n     <p>（四）考生本人须签写《诚信复试承诺书》，承诺所提交全部材料真实和复试过程诚实守信。在我校复试工作结束前不得对外透露或传播复试试题内容等有关情况。</p>\n     <p>（五）在复试过程中存在违规行为的考生，一经查实，即按照《国家教育考试违规处理办法》、《普通高等学校招生违规行为处理暂行办法》等规定严肃处理，取消录取资格，记入《考生考试诚信档案》。</p>\n     <p>（六）请考生及时关注我校及各招生学院以网站、电话、电子邮件、短信等方式公开或发送给考生的相关信息等。考生若联系方式有变更，须及时告知各招生学院。因考生个人疏忽等原因造成的一切后果由考生本人承担。</p>\n     <p>（七）复试命题严格按照我校招生考试相关规定执行，复试试题及答案在启用前均系国家机密材料，命题人员须按照保密要求执行。</p>\n     <p>（八）如有必要，学院可对考生再次复试。考生在同一专业或方向只能参加一次复试。</p>\n     <p>本办法经学校研究生招生委员会审议通过，由研究生院负责解释。未尽事宜、政策变化之处，以上级主管部门和相关规定为准。</p>\n     <p style=\"text-align: right;\">江苏理工学院</p>\n     <p style=\"text-align: right;\">2026年3月18日</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-titl