INSERT INTO `yl_guide` VALUES (103, '贵州大学2026年硕士研究生复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>贵州大学2026年硕士研究生复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月18日</span> <span>来源：贵州大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据《2026年全国硕士研究生招生工作管理规定》《关于做好2026年全国硕士研究生复试录取工作的通知》以及教育部、贵州省关于2026年硕士研究生复试工作的重要部署和要求，为保证硕士研究生复试工作的平稳顺利，结合我校工作实际，制定本办法。</p>\n     <p><strong>一、工作原则</strong></p>\n     <p>全面落实党的教育方针，落实立德树人根本任务，坚持综合评价、择优录取，严格执行政策，严把质量关口，严守工作纪律，规范录取行为，强化监督管理，优化考生服务，确保2026年硕士研究生复试录取工作公平、公正、科学、安全。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p>学校研究生招生委员会全面负责硕士研究生复试录取工作。研究生院负责对全校硕士研究生复试录取工作统一管理。</p>\n     <p>各学院（中心、实验室）研究生招生委员会负责本单位硕士研究生复试和录取相关工作，制定本单位硕士研究生复试录取工作具体方案并组织实施，对相关人员进行政策、纪律、规则及程序等方面的教育和培训，组织对考生的复试考核，提出拟录取考生名单，公开有关信息，受理考生申诉并及时妥善处理，制定应急处置预案，确保复试录取工作安全、平稳、有序。</p>\n     <p><strong>三、复试分数线</strong></p>\n     <p>（一）各学院（中心、实验室）综合考虑生源情况、招生计划、学科专业特点和相应的差额复试比划定复试分数线，确定进入复试的考生名单。符合初试成绩基本要求且生源充足的专业，复试差额比例一般不低于120%。符合初试成绩基本要求但生源数量少于招生计划120%的学科专业，应安排全部合格生源参加复试。</p>\n     <p>（二）“少数民族高层次骨干人才计划”、“退役大学生士兵”专项计划复试分数线由学校招生委员会确定，详见下表：</p>\n     <p style=\"text-align: center;\"></p>\n     <p>（三）对服役期间获得三等战功、二等功以上奖励或者二级以上表彰，符合全国硕士研究生招生考试报考条件的退役人员，可申请免初试攻读我校硕士研究生。我校对申请免初试的考生组织复试，复试合格者予以拟录取。</p>\n     <p>（四）我校不接受破格复试。</p>\n     <p><strong>四、复试时间</strong></p>\n     <p>一志愿考生：<strong>三月底前完成复试</strong><strong>，</strong>具体时间、程序及相关要求详见各学院（中心、实验室）网站。考生不按时参加复试的，视为自动放弃复试资格。</p>\n     <p>调剂考生：<strong>四月中下旬完成复试</strong>，具体时间、程序及相关要求详见各学院（中心、实验室）网站。</p>\n     <p><strong>五、复试</strong><strong>方式</strong></p>\n     <p>一志愿考生、调剂考生均采用现场（线下）复试方式。一志愿考生和调剂考生分批次进行复试。</p>\n     <p><strong>六</strong><strong>、</strong><strong>复试工作实施</strong></p>\n     <p><strong>（一）资格审查</strong></p>\n     <p>所有进入复试的考生必须在学院（中心、实验室）规定的时间内按要求提交以下材料进行资格审查：</p>\n     <p>1.初试准考证。</p>\n     <p>2.居民身份证复印件（正反面印在一页A4纸上）。</p>\n     <p>3.考生本人签名的《诚信复试承诺书》。</p>\n     <p>复试前考生须签订《诚信复试承诺书》并自觉遵守，在复试结束前不得对外透露或传播复试试题内容等有关情况，诚信应试。</p>\n     <p>4.学籍学历证明。应届生提供学生证或具有验证码的《教育部学籍在线验证报告》；往届生提供毕业证书或具有验证码的《教育部学历证书电子备案表》或《教育部学历认证报告》（在境外、国外取得学位的，须提供教育部留学服务中心出具的《国（境）外学历学位认证书》）。</p>\n     <p>5.“退役大学生士兵”专项计划考生还须提供本人《入伍批准书》和《退出现役证》原件的扫描件或照片。</p>\n     <p>6.“少数民族高层次骨干人才计划”须提供《少数民族高层次骨干人才计划考生登记表》原件的扫描件或照片。</p>\n     <p>7.各学院（中心、实验室）要求考生提供的其他材料。</p>\n     <p>未进行资格审查、资格审查不通过，及弄虚作假者，取消复试资格。</p>\n     <p><strong>（二）复试费</strong></p>\n     <p>复试考生须在复试前缴纳复试费，收费标准：100元/人。缴费后因各种原因未参加复试者，已支付的复试费不予退回。</p>\n     <p><strong>（三）复试考</strong><strong>查</strong><strong>要求</strong></p>\n     <p>1.复试可综合运用笔试、面试、实验、实践操作等方式选拔。</p>\n     <p>2.坚持综合评价和以德为先，加强对考生的全面考查和综合评价。<strong>学术学位重点考核</strong>考生的学术素养、对学科知识掌握与运用情况、科研创新能力，<strong>专业学位重点考核</strong>考生的专业基础、实践能力和职业素养。</p>\n     <p>3.思想政治素质和品德考核是复试的重要内容和录取的重要依据，各培养单位要遵循实事求是的原则，注重对学生政治态度、思想表现、道德品质、科学精神、诚实守信、遵纪守法等方面的考查，思想品德考核不合格者不予录取。</p>\n     <p>4.专业素质和能力以考生在学期间素质和能力综合评价等级（考生既往学业、一贯表现、科研能力）和面试成绩来考查。主要考查考生对本学科（专业）理论知识和应用技能掌握程度，利用所学理论发现、分析和解决问题的能力，对本学科发展动态的了解以及在本专业领域发展的潜力、外语听说能力、创新精神和创新能力。</p>\n     <p>5.综合素质和能力主要考查学生在本学科（专业）以外的学习、科研、社会实践（学生工作、社团活动、志愿服务等）或实际工作表现等方面的情况；事业心、责任感、纪律性（遵纪守法）、协作性和心理健康情况；人文素养；举止、表达和礼仪等。</p>\n     <p>6.管理类联考考生的思想政治理论考试考试由各学院（中心、实验室）在复试中进行，成绩计入复试总成绩。</p>\n     <p>7.对符合复试基本要求的同等学力考生（包括毕业满两年的高职高专生、普通高校本科结业生）须加试与报考专业相关的两门本科主干课程，且不与初试科目相同。加试方式为笔试。加试成绩低于60分（不含60分）视为成绩不合格，不予录取。同等学力考生加试成绩不计入复试总成绩。</p>\n     <p>8.严格考风考纪，严肃查处违规违纪行为，对在复试过程中有学术不端、弄虚作假等违规行为的考生，一经查实，即按照《国家教育考试违规处理办法》《普通高等学校招生违规行为处理暂行办法》等规定严肃处理，取消复试、录取资格，记入《考生考试诚信档案》。入学后3个月内，将按照《普通高等学校学生管理规定》有关要求，对所有考生进行全面复查。复查不合格的，取消入学资格或学籍；情节严重的，移交有关部门调查处理。</p>\n     <p><strong>（</strong><strong>四</strong><strong>）复试成绩</strong></p>\n     <p>复试成绩满分为100分（保留小数点后两位），复试成绩不合格者不予录取（60分及以上为合格，下同）。其中，外国语成绩、专业素质和能力、综合素质和能力在复试成绩中的权重由学院根据专业特点和要求酌定。</p>\n     <p>思想政治素质和道德品质考核不作量化计入总成绩，但考核结果不合格者不予录取。</p>\n     <p><strong>（</strong><strong>五</strong><strong>）总成绩</strong></p>\n     <p>考生总成绩由初试成绩和复试成绩根据一定比例计算而成。具体算法：</p>\n     <p>1.初试满分500分：总成绩=（初试成绩÷5）×X+复试成绩×Y</p>\n     <p>2.初试满分300分：总成绩=（初试成绩÷3）×X+复试成绩×Y</p>\n     <p>X为初试成绩权重，Y为复试成绩权重。全日制研究生复试成绩占总成绩50%权重；非全日制研究生复试成绩占总成绩30%-50%权重。</p>\n     <p><strong>七</strong><strong>、体检</strong></p>\n     <p>学校医院在复试期间为考生提供体检服务，收费标准和流程以校医院届时公布的相关通知为准。体检要求以《2026年全国硕士研究生招生工作管理规定》中第七十二条为准，未达到体检要求的，取消拟录取资格。</p>\n     <p><strong>八</strong><strong>、调剂</strong></p>\n     <p>我校调剂工作拟于4月上旬开展，请持续关注贵州大学研究生院网站。</p>\n     <p><strong> &nbsp; &nbsp;九</strong><strong>、录取</strong></p>\n     <p>（一）录取原则</p>\n     <p>1.未进行资格审查或资格审查未通过的考生不予录取。</p>\n     <p>2.没有参加复试或者复试成绩不合格的考生不予录取。</p>\n     <p>3.政审（思想政治素质和品德考核）不合格的考生不予录取。</p>\n     <p>4.同等学力加试科目不合格的考生不予录取。</p>\n     <p>5.未经公示的考生不予录取。</p>\n     <p>6.符合学校基本分数线的“退役大学生士兵专项计划”“少数民族高层次骨干人才计划”考生，在专项计划内单独排名进行录取。</p>\n     <p><strong>十、信息公开公示</strong></p>\n     <p>各学院（中心、实验室）将在其官方网站上公布<strong>复试录取实施细则、复试名单</strong>（包括考生姓名、考生编号、初试各科成绩等，专项计划考生和国家政策加分应在备注中注明）以及<strong>复试成绩</strong>等。</p>\n     <p>学校将在研究生院网站上公布复试录取工作办法、调剂工作办法等信息。</p>\n     <p>拟录取名单将在学校网站上公示，公示期不少于7日。考生如有异议，请于公示期内实名向学校提出申诉。</p>\n     <p><strong>十</strong><strong>一</strong><strong>、政审</strong></p>\n     <p>拟录取名单确定后，学院应向考生所在单位函调人事档案（或档案审查意见）和本人现实表现等材料，全面考查其思想政治和品德情况。函调的考生现实表现材料，需由考生本人档案或工作所在单位的人事、政工部门加盖印章。审查合格者给予发放录取通知书；未调档审查或审查不合格者不予发放录取通知书。</p>\n     <p><strong>十</strong><strong>二</strong><strong>、违规处理</strong></p>\n     <p>考生应诚信复试，签订《诚信复试承诺书》。提前认真阅读教育部《2026年全国硕士研究生招生工作管理规定》以及学校和学院（中心）发布的相关信息。<strong>复试内容属于国家机密级，考生不得以任何形式录制、复制或传播复试相关内容，不得在相关科目考试结束前泄露试题信息。</strong>对有违规行为的考生，一经查实，按照《国家教育考试违规处理办法》、《中华人民共和国刑法》、《普通高等学校招生违规行为处理暂行办法》等规定予以处理，取消录取资格，记入《考生考试诚信档案》。</p>\n     <p>入学后3个月内，学校将按照《普通高等学校学生管理规定》有关要求，对所有考生进行全面复查。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p><strong>十</strong><strong>三</strong><strong>、其他</strong></p>\n     <p>1.复试期间，考生应密切关注我校研究生院和各学院（中心、实验室）官网发布的通知公告，保持移动电话、邮件等通讯方式畅通并注意查看各学院（中心、实验室）发送的通知信息。</p>\n     <p>2.学校未委托任何单位、个人和机构代理招生。提醒各位考生要提高对一些社会办学机构或非法网站的警惕及识别判断能力，不给不法分子可乘之机，切实保护自身权益。</p>\n     <p>3.本办法由研究生院负责解释。未尽事宜以教育部《2026年全国硕士研究生招生工作管理规定》等文件和学校相关规定为准。</p>\n     <p><strong>十四、联系方式</strong></p>\n     <p>贵州大学代码：10657</p>\n     <p>联系部门：贵州大学研究生招生办公室</p>\n     <p>地址：贵州省贵阳市花溪区贵州大学西校区德正楼研究生院230</p>\n     <p>电话：0851-88292217</p>\n     <p>电话咨询时间为周一至周五（节假日除外）上午9:00—11:30，下午14:30—17:30</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chsi.com.cn/sswbgg/\" target=\"_blank\">网报公告</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\" target=\"_blank\">博士目录</a> <a href=\"https://yz.chsi.com.cn/help/\" target=\"_blank\">帮助中心</a>\n      </div>\n      <div class=\"aside-con-title\">\n       统考\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108-4.html\" target=\"_blank\">报名条件</a> <a href=\"https://yz.chsi