INSERT INTO `yl_guide` VALUES (106, '中国传媒大学2026年硕士研究生招生复试录取办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>中国传媒大学2026年硕士研究生招生复试录取办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月17日</span> <span>来源：中国传媒大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据《关于做好2026年全国硕士研究生复试录取工作的通知》（教学司［2026］3号）要求，为做好我校2026年全国硕士研究生招生复试录取工作，特制定此办法。</p>\n     <p><strong>一、总体原则</strong></p>\n     <p>1.严格落实教育部和北京市文件要求，坚持立德树人，落实分类选拔要求，以提高选拔质量为核心，着力选拔德智体美劳兼备的高层次人才。</p>\n     <p>2.严格复试组织管理，做到政策透明、流程规范、监督机制健全，维护考生合法利益，确保公平公正。</p>\n     <p>3.严格复试考核标准，坚持科学有效，做到全面衡量、综合评价、择优录取，确保招生质量。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p>学校研究生招生委员会统筹领导我校硕士研究生招生考试复试录取工作。招生处在学校研究生招生委员会领导下，制定相关规定和办法，确定基本原则及复试录取方案等，并组织全校硕士研究生复试录取工作。</p>\n     <p>各学院（研究院、实验室）研究生招生工作领导小组负责制定本单位的复试实施细则，对相关人员进行政策、业务、纪律、规则及程序等方面的培训，组织实施本单位的硕士研究生复试工作。</p>\n     <p>各学院（研究院、实验室）根据实际需要按学科、专业或研究方向成立若干复试小组，开展复试具体工作。复试面试小组一般不少于5人，原则上由本学科具有副教授职称（含）以上或相当专业技术职务的专家担任。每个复试小组设秘书1名，负责复试情况记录等工作。</p>\n     <p><strong>三、考生进入复试考核的基本要求</strong></p>\n     <p>根据教育部有关规定，我校复试考核采取差额方式，差额比例一般不低于120%。报考我校且符合《中国传媒大学2026年硕士研究生招生考试考生进入复试考核基本要求》的考生（含各类专项计划），复试资格审查合格后，均可参加复试考核。</p>\n     <p>符合调剂接收条件的考生，经复试资格审查合格后，择优确定进入复试考核的名单。</p>\n     <p><strong>四、复试考核方式及复试内容</strong></p>\n     <p><strong>（一）复试考核方式</strong></p>\n     <p>我校2026年全国硕士研究生招生考试复试考核采用现场考试方式进行，考试地点为中国传媒大学。</p>\n     <p><strong>（二）复试考核内容</strong></p>\n     <p>1.专业能力与综合素质考核</p>\n     <p>专业能力考核：以现场笔试、机试、现场创作或面试等方式，重点考核考生的专业基础理论、专业知识、专业能力，以及分析问题、解决问题的能力，具体考核方式参照《中国传媒大学2026年硕士研究生招生各学院（研究院、实验室）复试方案》。</p>\n     <p>综合素质考核：结合考生提交的报考材料，根据考生的教育背景、本科成绩、科研或实践经历、个人陈述等，对考生的专业素养、创新潜质、事业心、责任感、团队协作等进行考查；通过交流问答方式，对考生的思想品德、心理素质、人文素养、沟通表达能力等进行考查。</p>\n     <p>2.外语听说能力考核</p>\n     <p>以随机抽题或交流问答方式，考查考生的外语听力、口语能力。</p>\n     <p>考核语种原则上为英语（含“骨干”等专项计划）。</p>\n     <p>注：每个考生专业能力与综合素质考核、外语听说能力考核的总时长不少于20分钟。</p>\n     <p>3.思想政治素质和道德品质考核</p>\n     <p>通过《国家教育考试考生诚信档案》记录、考生提交的思想政治品德考核表等材料，以及在面试考核过程中与考生的交流，考查考生的现实表现，内容包括政治态度、理想信念、道德品质、遵纪守法、诚实守信等方面。</p>\n     <p>思想政治素质和道德品质考核不计入复试总成绩，但考核结果不合格者不予录取。</p>\n     <p>4.加试内容</p>\n     <p>（1）所有同等学力考生（含工商管理硕士MBA、公共管理硕士MPA）须加试两门与报考专业相关的本科主干课程，每个科目满分为100分，60分为及格线。加试成绩不计入复试总成绩，但不及格者不予录取。</p>\n     <p>（2）报考工商管理硕士MBA、公共管理硕士MPA、会计硕士MPAcc的考生须加试政治理论科目。政治理论加试科目满分为100分，成绩计入复试总成绩。</p>\n     <p>5.复试考核成绩计算方法</p>\n     <p>（1）除MBA、MPA、MPAcc之外的专业：</p>\n     <p>复试考核成绩=专业能力与综合素质×90%+外语听说能力×10%</p>\n     <p>（2）MBA、MPA、MPAcc专业：</p>\n     <p>复试考核成绩=专业能力与综合素质×80%+政治理论×10%+外语听说能力×10%</p>\n     <p>备注：各学院（研究院、实验室）根据专业选拔需求制定专业能力部分的考核方式和成绩占比，具体参照《中国传媒大学2026年硕士研究生招生各学院（研究院、实验室）复试方案》。</p>\n     <p>（3）复试考核成绩低于60分的，视为复试不合格，不予录取。</p>\n     <p>（4）复试成绩中规定了单项考核成绩标准的，单项成绩不合格的，视为复试不合格，不予录取。</p>\n     <p><strong>五、复试考核程序及时间安排</strong></p>\n     <p><strong>（一）缴费和打印复试通知书</strong></p>\n     <p>进入我校复试考核环节的考生，须于3月16日至3月19日在我校研究生招生管理系统中缴纳复试费100元并打印复试通知书。系统网址为：https://yzbm.cuc.edu.cn/10033/user/login/login。</p>\n     <p>复试时须持本人有效身份证件及复试通知书入校。</p>\n     <p><strong>（二）复试考核资格审查</strong></p>\n     <p>考生在复试报到时须携带复试通知书、有效身份证件、学历学位证书（往届生）、学历学籍核验结果（前置学历为境外获得）、学生证（应届生）等报名材料原件及复印件。</p>\n     <p>各学院（研究院、实验室）对考生的相关材料进行复试资格审查，确定复试考核资格。对不符合规定或弄虚作假者，一经查实，视为资格审查不通过，取消复试考核资格。</p>\n     <p>拟录取考生待入学报到时，各学院（研究院、实验室）将对其有效身份证件、学历学位证书、学历学籍核验结果等报名材料原件及报考资格进行再次审查。对不符合规定或弄虚作假者，一经查实，取消录取资格。</p>\n     <p><strong>（三）现场复试</strong></p>\n     <p>复试考核时间拟定为3月20日至3月23日，具体时间安排及其他相关要求见中传研招网发布的通知。</p>\n     <p>我校部分专业接收调剂生源，符合调剂要求的考生必须通过中国研究生招生信息网调剂系统填报调剂志愿，通过审核后方可择优进入复试。调剂志愿考生报名时间及复试考核安排见中传研招网后续发布的通知。</p>\n     <p><strong>六、录取原则</strong></p>\n     <p>我校坚持公平、公正、公开和科学选拔的原则，对考生进行德、智、体、美、劳全面衡量，按需招生，择优录取，宁缺毋滥，确保招生质量。</p>\n     <p><strong>（一）总成绩计算方法</strong></p>\n     <p>考生总成绩由初试成绩和复试考核成绩按一定比例计算而得。</p>\n     <p>除MBA、MPA、MPAcc之外的专业：</p>\n     <p>总成绩=（初试总成绩/5）×50% +复试考核成绩×50%</p>\n     <p>MBA、MPA、MPAcc专业：</p>\n     <p>总成绩=（初试总成绩/3）×50% +复试考核成绩×50%</p>\n     <p><strong>（二）录取原则</strong></p>\n     <p>1.各学院（研究院、实验室）根据专业目录下达的专业（方向）指导性招生计划，按总成绩从高到低，分别给出“建议录取”或“建议不予录取”的意见，确定拟录取名单。</p>\n     <p>2.“少数民族高层次骨干人才计划”考生,按照国家下达专项计划指标单独录取。录取时,根据分省计划，按总成绩由高到低依次确定拟录取名单。</p>\n     <p>3.“退役大学生士兵专项硕士研究生招生计划”考生，按照国家下达专项计划指标单独录取。录取时,按总成绩由高到低并参考报考专业依次确定拟录取名单。</p>\n     <p><strong>（三）说明</strong></p>\n     <p>1.参加复试考核的考生必须完成所有考试环节，如有一个环节缺考，则不予录取。</p>\n     <p>2.思想政治素质和道德品质考核不合格的，不予录取。</p>\n     <p>3.复试考核成绩低于60分的，视为复试不合格，不予录取。</p>\n     <p>4.复试成绩中规定了单项考核成绩标准的，单项成绩不合格的，视为复试不合格，不予录取。</p>\n     <p>5.同等学力考生任何一门加试科目成绩低于60分的，视为复试不合格，不予录取。</p>\n     <p>6.加分政策。</p>\n     <p>（1）参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”等项目服务期满、考核合格的考生，3年内参加全国硕士研究生招生考试的，初试总分加10分，同等条件下优先录取。</p>\n     <p>（2）高校学生应征入伍服现役退役，达到报考条件后，3年内参加全国硕士研究生招生考试的考生，初试总分加10分，同等条件下优先录取。</p>\n     <p>（3）参加“选聘高校毕业生到村任职”项目服务期满、考核称职以上的考生，3年内参加全国硕士研究生招生考试的，初试总分加10分，同等条件下优先录取，其中报考人文社科类专业研究生的，初试总分加15分。</p>\n     <p>（4）享受加分政策的考生以教育部研招网后台的加分名单为准。</p>\n     <p>7.“少数民族高层次骨干人才计划”考生须在复试考核前提交经省教育行政部门审核通过的《少数民族高层次骨干人才计划考生登记表》（在职考生还须经所在单位审批同意）。拟录取的该类考生还须签订“国家定向培养计划少数民族高层次骨干人才攻读硕士学位研究生定向协议书”，否则不予录取。</p>\n     <p>8.定向就业的考生，须在规定时间内签订定向就业协议书，并交至我校，否则不予录取。</p>\n     <p><strong>七、信息公开公示</strong></p>\n     <p>我校复试录取办法、进入复试考核的考生名单、拟录取名单等信息均在中传研招网公布，网址为：http://yz.cuc.edu.cn。国家公示平台网址为：中国研究生招生信息网http://yz.chsi.com.cn/。</p>\n     <p><strong>八、监督渠道</strong></p>\n     <p>我校招生处咨询电话为：010-65779227（正常工作日的9:00-11:30,14:00-16:30），邮箱为：cucyzb@cuc.edu.cn，自动传真为：010-65768805。</p>\n     <p>我校纪检监察部门研究生招生专用监督电话为：010-65779383。</p>\n     <p><strong>九、其他</strong></p>\n     <p>1.体检在入学时统一进行，体检合格者，方可进行中国传媒大学学籍注册。</p>\n     <p>2.一旦发现有不符合报考条件、考试违纪、作弊等，或者发现通过弄虚作假取得初试、复试及录取资格的，一律不予录取。已经录取的取消录取资格，已入学的取消学籍。</p>\n     <p>3.学校不允许研究生同时攻读两个以上（含）不同层次或相同层次的学位。有此情形的考生，应在复试前主动告知我校招生处。</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chsi.com.cn/sswbgg/\" target=\"_blank\">网报公告</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\" target=\"_blank\">博士目录</a> <a href=\"https://yz.chsi.com.cn/help/\" target=\"_blank\">帮助中心</a>\n      </div>\n      <div class=\"aside-con-title\">\n       统考\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108-4.html\" target=\"_blank\">报名条件</a> <a href=\"https://yz.chsi.com.cn/yzwb/\" target=\"_blank\">网上报名</a> <a href=\"https://yz.chsi.com.cn/yzwb/#xcqr\" target=\"_blank\">网上确认</a> <a href=\"https://yz.chsi.com.cn/yzwb/#zkzxz\" target=\"_blank\">下载准考证</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">分数线</a> <a href=\"https://yz.chsi.com.cn/yztj/\" target=\"_blank\">调剂</a>\n      </div>\n      <div class=\"aside-con-title\">\n       推免\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">推荐系统</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/\" target=\"_blank\">申请指南</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/#bmlc\" target=\"_blank\">推免流程</a> <a href=\"https://yz.chsi.com.cn/tm/zyml/\" target=\"_blank\">专业目录</a> <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">填报志愿</a> <a href=\"https://yz.chsi.com.cn/tm/lqmd/index\" target=\"_blank\">信息公开</a>\n      </div>\n     </div>\n    </div>\n   </div>\n  </div>\n </div>\n</div><!-- 4: 底部区域 -->\n<svg style=\"display: block; width: 0; height: 0\">\n <defs>\n  <symbol id=\"weibo\" viewBox=\"0 0 16 16\">\n   <g stroke=\"none\" stroke-width=\"1\" fill=\"none\" fill-rule=\"evenodd\">\n    <g transform=\"translate(-139.000000, -4036.000000)\" fill=\"currentColor\" fill-rule=\"nonzero\">\n     <g transform=\"translate(139.000000, 4036.000000)\">\n      <rect opacity=\"0\" x=\"0\" y=\"0\" width=\"16\" height=\"16\"></rect>\n      <path d=\"M10.565,3.6325 C10.565,3.6325 12.335,3.445 13.0875,4.5425 C13.84,5.64 13.515,7.02 13.515,7.02 C13.4949253,7.12321653 13.5233752,7.22993417 13.5921672,7.30945968 C13.6609592,7.38898519 13.7624686,7.43250415 13.8675,7.4275 L14.0425,7.4275 C14.2747485,7.42111375 14.4682944,7.24766281 14.5,7.0175 C14.5,7.0175 14.9075,4.8525 13.65,3.6475 C12.67,2.705 11.3275,2.6025 10.79,2.6025 L10.5525,2.6025 C10.3240422,2.60790517 10.1412883,2.79398193 10.1399581,3.0225 L10.1399581,3.2275 C10.1383884,3.33892927 10.183335,3.44597927 10.264011,3.52285878 C10.3446871,3.59973829 10.4537777,3.63947671 10.565,3.6325 L10.565,3.6325 Z M7.08,11.845 C8.315,11.595 9.15,10.565 8.9475,9.5225 C8.7725,8.625 7.8875,8.0225 6.8575,8.0225 C6.6895953,8.02269714 6.52211889,8.03944478 6.3575,8.0725 C5.1225,8.3225 4.2875,9.3525 4.49,10.395 C4.6925,11.4375 5.8475,12.085 7.08,11.845 Z M7.115,9.1625 C7.27228055,9.15431868 7.41868486,9.24275691 7.48462743,9.38578027 C7.55057,9.52880363 7.52275233,9.69756891 7.41439607,9.8118625 C7.3060398,9.9261561 7.13899693,9.96292865 6.99266239,9.90470229 C6.84632786,9.84647593 6.75021264,9.70499305 6.75,9.5475 C6.7