INSERT INTO `yl_guide` VALUES (107, '湖北大学2026年硕士研究生招生复试录取办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>湖北大学2026年硕士研究生招生复试录取办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月17日</span> <span>来源：湖北大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据《2026年全国硕士研究生招生工作管理规定》《关于做好2026年全国硕士研究生复试录取工作的通知》和《关于做好2026年湖北省硕士研究生复试录取工作的通知》等文件精神，结合学校招生工作实际，制定本办法。</p>\n     <p><strong>一、指导思想</strong></p>\n     <p>全面落实党的教育方针，落实立德树人根本任务，坚持综合评价、择优录取，加强创新潜质考核，提升人才选拔质量。落实主体责任、深化信息公开、加强监督管理、提升服务水平，严格复试考核标准和复试组织管理，确保科学选拔、公平公正。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p>学校研究生招生委员会领导和统筹管理全校研究生复试录取工作，负责招生计划分配、复试录取办法制定、复试过程监管和拟录取名单审定，决策处置重大问题等。驻校纪检监察组、校纪委牵头成立复试监督组，负责复试监督检查工作。研究生院统一管理本校研究生招生考试工作。各招生单位招生委员会具体领导、组织本单位的招生复试工作，负责制定本单位硕士研究生复试工作具体方案并组织实施，对相关人员进行政策、纪律、规则及程序等方面的教育和培训，组织对考生的复试考核，提出拟录取考生名单，受理考生申诉并及时妥善处理，按要求公开有关信息。</p>\n     <p><strong>三、</strong><strong>复试安排</strong></p>\n     <p>（一）复试时间。第一志愿考生复试3月下旬启动，月底完成；调剂复试4月8日启动，4月28日前完成。复试考生名单、具体时间、程序及相关要求由招生单位在本单位网站发布。考生不按时参加复试的，视为自动放弃复试资格。</p>\n     <p>（二）复试形式。第一志愿考生复试采取现场复试方式进行，考生到校参加复试，专家组现场集中对考生进行考核。调剂考生复试由各招生单位结合实际情况，采取现场复试或远程复试的方式进行；同一招生单位同一专业原则上采取一致的复试方式。各考核项目的具体考试形式和考试时长等信息见招生单位网站的复试录取实施细则。</p>\n     <p>（三）复试分数线。</p>\n     <p>1.普通计划。各招生单位根据《2026年全国硕士研究生招生考试考生进入复试的初试成绩基本要求（A类线）》，按照进入复试的考生人数一般不少于学科专业已公布招生计划的120%，自主划定进入复试的初试成绩要求及其他学术要求，不得出台歧视性或其他有违公平的规定。同一招生单位同一专业，非全日制与全日制考生进入复试的初试成绩要求相同。合格生源比例不足的，按实际合格生源数组织复试。</p>\n     <p>2.专项计划。少数民族骨干计划，执行国家总分线要求；退役大学生士兵计划，标准分不低于104.70分，标准分=考生初试总分/报考专业国家A类线总分×100，标准分保留2位小数。</p>\n     <p>3.享受少数民族照顾政策考生。总分执行国家总分线要求，单科要求均为30分（满分100分）、45分（满分&gt;100分）。</p>\n     <p>(四)复试费用。考生参加复试需缴纳复试费（100元/人次），现场复试考生现场扫码缴费，远程复试的考生资格审查合格后在复试平台缴纳复试费。</p>\n     <p>(五)复试体检。复试阶段体检与入学报到体检合并进行，学生9月来校后在校医院进行体检。不参加体检或体检不合格者按教育部相关文件进行处理。</p>\n     <p><strong>四、</strong><strong>工作</strong><strong>要求</strong></p>\n     <p>（一）复试方案。各招生单位根据学校方案，结合工作实际，制定本单位的复试方案，建立机构、明确任务、细化要求、落实责任，明确复试小组成员和工作人员的遴选办法、纪律要求、行为规范等。复试录取实施细则包括各专业的招生计划数，复试分数线，复试时间、地点、方式、内容，成绩使用办法，工作程序，咨询申诉渠道等，细则经研究生院审定后发布。</p>\n     <p>（二）工作人员。各招生单位应遴选经验丰富、业务水平高、公道正派的人员参与复试工作，遵守回避原则并签订《工作责任书》。向参与复试的所有人员宣讲政策、纪律和复试工作规范，明确工作纪律和工作程序、评判规则和评判标准。成立不少于5人的复试小组，小组成员现场独立评分。</p>\n     <p>（三）资格审查。加强复试资格审查，严格采取人证识别及报考库、学籍学历库、人口信息库、诚信档案库数据比对等措施，加强对复试考生的身份审核及报考专项计划、申请享受初试加分、免初试的资格审核。对考生的学历（学籍）信息有疑问的，应要求考生在规定时间内提供权威机构出具的证明材料。申请享受初试加分、少数民族照顾政策、免初试及报考专项计划的考生，于3月18日前联系招生单位并提交相关证明材料，招生单位初审后报学校复审。不符合规定者，不予复试。</p>\n     <p>（四）复试考核。各招生单位以提高选拔质量为核心，完善和细化复试考核评价机制，根据培养目标要求、学科专业特点和办学特色等自主合理设计复试内容，确保复试考核科学有效、公平公正。坚持德智体美劳全面衡量，把思想品德考核作为复试的重要内容和录取的重要依据，加强对考生的全面考查和综合评价，既要注重考生的学业知识，又要注重考生的专业能力素质和科研创新潜质；既要注重考生的考试成绩，又要注重考生的一贯学业表现。学校不执行破格复试录取政策，具体复试内容和复试程序由各招生单位通知。</p>\n     <p>（五）组织实施</p>\n     <p>1.建立健全随机选定考生次序、确定复试小组成员、抽取复试试题工作机制。各招生单位以适当形式提前组织模拟演练，确保复试过程安全、顺畅。复试全程录音录像并妥善保存备份，确保资料清晰完备。</p>\n     <p>2.考生签订《诚信复试承诺书》，并自觉遵守复试规则，不得对外透露或传播复试试题内容等有关情况。</p>\n     <p>3.严肃考风考纪。各招生单位严格按照相关规定，严肃查处违规违纪行为。加强复试导师和工作人员的遴选、培训和管理，强化保密意识、责任意识和政治意识。要建立健全回避制度，复试相关工作人员有直系亲属或利益相关人员参加复试的，应主动申请回避，有非直系亲属等参加复试的要主动报备。对复试过程中有违规行为的考生，一经查实，即按照《国家教育考试违规处理办法》《普通高等学校招生违规行为处理暂行办法》等规定严肃处理，取消录取资格。入学后3个月内，各招生单位按照《普通高等学校学生管理规定》要求，对所有考生进行全面复查。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p>（六）成绩核算</p>\n     <p>复试一般包括专业知识、外国语听力及口语、综合素质3项；工商管理、公共管理、旅游管理、会计、图书情报5个专业学位复试阶段组织政治理论考试；同等学力考生须另外加试2门与报考专业相关的本科主干课程，加试科目不能与初试科目相同。</p>\n     <p>复试各科成绩均按百分制评分，满分均为100分，60分及以上为合格。政治理论成绩计入复试总成绩，加试成绩不计入总成绩。入学考试的总评成绩=（初试成绩/初试满分）×60%×100+复试综合成绩（复试分项成绩1×权重+复试分项成绩2×权重+复试分项成绩3×权重…）×40%，各项成绩均保留2位小数。</p>\n     <p>（七）调剂工作</p>\n     <p>1.调剂程序。各招生单位先复试第一志愿考生，根据复试结果和招生计划，确定调剂缺额信息和调剂要求并及时发布；按调剂要求遴选确定进入复试的调剂考生名单并按规定公布；调剂考生复试程序与第一志愿考生基本相同。</p>\n     <p>2.调剂要求。各招生单位规范制定调剂考生进入复试的遴选规则，对申请同一专业、初试科目完全相同的调剂考生，按考生初试成绩择优确定进入复试的考生名单。</p>\n     <p>（1）申请调入我校的考生应符合以下要求：符合调入专业的报考条件，且初试成绩需达到第一志愿报考专业国家A类线及我校调入学科专业复试分数线；原则上，调剂考生第一志愿专业与调入专业相同或相近，或初试科目与调入专业初试科目相同或相近；符合招生单位提出的其他相关要求。</p>\n     <p>（2）原则上，第一志愿报考学术学位和专业学位的考生可相互调剂；调剂全日制专业的考生其第一志愿必须为全日制专业；调剂非全日制的考生必须为在职定向就业人员。具体要求以招生单位复试录取实施细则为准。</p>\n     <p>3.调剂手续。调剂考生均应在“全国硕士生招生调剂服务系统”办理调剂手续。接收调剂考生报考的招生专业、拟招生人数，通过研招网调剂系统或招生单位网站发布。</p>\n     <p>4.自愿调剂。考生申请调入非全日制专业的，招生单位要充分尊重考生意愿，根据《关于做好非全日制研究生管理工作的意见》的规定，详细解释相关管理规定。</p>\n     <p>5.统一审核。拟录取通知须经研究生招生办公室审核后发送给调剂待录取考生。</p>\n     <p>（八）信息公开</p>\n     <p>1.平台公开。各招生单位要高度重视招生信息公开工作，在招生单位门户网站设置专栏，按规定及时、完整、规范公开复试录取信息，接受监督和检查。</p>\n     <p>2.内容公开。做到政策公开、方案公开、程序公开、成绩公开、结果公开。具体包括：复试录取办法，各招生单位实施细则和学科专业招生人数、复试考生名单、拟录取考生名单等。</p>\n     <p>3.其他要求。拟录取名单由研究生招生办公室统一公示，公示时间不少于7日；名单如有变动，须对变动部分作出说明，并对变动内容另行公示7日；未经公示的考生不予录取。</p>\n     <p><strong>五、结果报送</strong></p>\n     <p>招生单位研究生招生委员会讨论确定拟录取名单，经组长审签并加盖招生单位公章后报学校研究生招生办公室，学校研究生招生委员会审定后报上级主管部门。</p>\n     <p>（一）严格按照招生计划和复试录取实施细则进行录取。考生思想政治素质和品德考核合格、复试成绩及格的前提下，按照招生计划和总评成绩择优录取。国家专项计划（少数民族骨干计划、退役大学生士兵计划）考生单独排序录取。</p>\n     <p>（二）认真核对拟录取名单的各项信息，确保准确无误。有以下情况之一者不予录取或取消录取：</p>\n     <p>1.资格审核不合格；</p>\n     <p>2.思想政治素质和道德品质考核不合格；</p>\n     <p>3.复试单科成绩不及格；</p>\n     <p>4.经查实复试过程中有不诚信行为；</p>\n     <p>5.定向就业考生未与在职单位签订定向就业协议。</p>\n     <p>（三）拟录取名单确定后，向考生所在单位函调人事档案和本人现实表现等材料，全面审查政治思想情况。函调的考生现实表现材料，需由考生本人档案所在单位的人事、政工部门加盖印章。</p>\n     <p>（四）非定向就业考生按要求转档案到学校研究生院。定向就业考生须于录取前签订定向就业协议。</p>\n     <p><strong>六、服务保障</strong></p>\n     <p>（一）加强应急处置。成立研究生招生考试（复试）巡视及突发事件应急管理领导小组，负责突发事件应急处置工作。校长任领导小组组长，分管研究生工作副校长任副组长，党校办、研究生院、大数据中心、党委宣传部、安全保卫部、校医院等相关部门为成员单位，全面梳理复试环节，主动排查风险点，完善应急处置预案。</p>\n     <p>（二）畅通咨询渠道。加强政策宣传与咨询指导，及时、准确发布和解读招生政策规定、复试、调剂及录取工作方案的相关内容和要求。及时解答考生咨询，确保信息沟通畅通。</p>\n     <p>（三）强化支持保障。做好相关技术保障预案，提前检查复试场所相关设备，确保正常使用。强化人性化关怀和个性化安排，积极采取有效措施，做好贫困地区考生、残疾考生等特殊群体的关爱帮扶。</p>\n     <p><strong>七、监督管理</strong></p>\n     <p>（一）加强组织领导，压实工作责任。学校主要负责人是研究生复试工作的第一责任人，分管领导是直接责任人。各招生单位是本招生单位研究生复试工作的责任主体，主要负责人是第一责任人，分管领导是直接责任人。主要负责人要亲自把关、亲自协调、亲自督查，直接负责人要全程参与、全程组织、全程管理。充分发挥学术组织和导师群体在人才选拔中的主体作用，切实履行好复试工作的主体责任。</p>\n     <p>（二）落实检查监督，严格追责问责。招生单位招生委员会对本单位复试录取工作负责，一岗多控、多岗监督，落实责任追究，严肃处理复试录取工作中存在的违纪违法行为。建立巡察监督制度，通过回避机制、轮换机制等措施管控风险，加强复试过程规范管理。</p>\n     <p>（三）信息公开公示，畅通申诉渠道。提前公布复试录取办法、实施细则及监督渠道，受理考生申诉并调查回复。考生对复试录取结果有异议，可向招生单位研究生招生委员会提出申诉。招生单位研究生招生委员会3个工作日内组织核查，答复申诉人。考生对招生单位答复仍有异议，可向学校研究生招生办公室申诉。学校研究生招生办公室组织复查，如申诉情况属实，由学校研究生招生委员会组织复议并给予答复。</p>\n     <p>咨询和申诉联系部门：学校研究生招生办公室</p>\n     <p>027-88663060（工作时间），yjsc@hubu.edu.cn</p>\n     <p>举报联系部门：驻校纪检监察组、校纪委</p>\n     <p>027-88663907（工作时间）</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box a