INSERT INTO `yl_guide` VALUES (108, '北京工商大学2026年硕士研究生招生复试录取工作方案', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>北京工商大学2026年硕士研究生招生复试录取工作方案</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月17日</span> <span>来源：北京工商大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据《教育部关于印发〈2026年全国硕士研究生招生工作管理规定〉的通知》（教学〔2025〕2号）、《关于做好2026年全国硕士研究生招生复试录取工作的通知》（教学司〔2026〕3号）等文件和北京市工作要求，结合学校实际，特制定本方案。</p>\n     <p><strong>一、复试组织管理</strong></p>\n     <p><strong></strong></p>\n     <p>学校是研究生考试招生工作的责任主体，研究生考试招生工作已纳入学校党委全面从严治党责任清单，主要负责人是本校研究生考试招生工作第一责任人，分管负责人是直接责任人。学校研究生招生委员会全面负责我校硕士研究生复试、调剂和录取工作，坚持服务国家战略、按需招生、全面衡量、择优录取、宁缺毋滥的原则，严格执行政策，严把质量关口，严守工作纪律，强化监督管理，优化考生服务，确保公平、公正、科学。招生就业处负责全校研究生考试招生工作制度建设、组织协调、指导监督、信息化建设及政策咨询、信访受理等，负责统筹管理招生宣传、考试组织、调剂、录取等工作，统一审核学院考试招生各环节实施细则，统一公开招生信息（含招生章程、考生进入复试的初试成绩要求、调剂信息等），统一监督检查各学院考试招生执行情况，统一审核复试（含调剂复试）及拟录取名单，统一办理录取相关手续。</p>\n     <p>学院是本院研究生考试招生工作的责任主体，直接负责人是本院研究生考试招生工作第一责任人，分管负责人是直接责任人。各招生学院成立由院长牵头，分管副院长、纪检委员参与的学院研究生招生委员会，委员人数原则上不少于5人且为奇数，统筹推进本院研究生考试招生工作，严格执行“集体议事、集体决策、会议决定”的规程，审议决策学院硕士研究生复试录取实施细则（简称“学院复试录取细则”）等考试招生重大事项。学院按学科（专业）成立若干复试小组，在学院研究生招生委员会的指导下，根据学院复试录取细则要求，具体实施硕士研究生招生复试录取工作。交叉学部参照学院执行。</p>\n     <p><strong>二、复试工作办法</strong></p>\n     <p><strong></strong></p>\n     <p>（一）复试方式</p>\n     <p>根据教育部相关文件精神并结合学校实际，2026年硕士研究生一志愿上线考生与调剂考生复试工作分开进行。各学院根据学科特点和专业要求，在确保公平和可操作的前提下自主确定各专业的复试方式，可采用现场复试或网络远程复试。采用现场复试的专业，校外考生可在规定的复试时间内，凭准考证、身份证原件入校参加复试。</p>\n     <p>（二）复试时间</p>\n     <p>一志愿考生复试工作原则上于2026年4月2日前完成。具体复试安排见学院复试录取细则。</p>\n     <p>（三）复试分数线和各学院复试录取细则</p>\n     <p>《北京工商大学2026年硕士研究生一志愿考生复试基本分数线》和各学院复试录取细则将于近期在北京工商大学研究生招生信息网公开发布。</p>\n     <p>（四）复试比例及名单</p>\n     <p>根据教育部、北京市相关政策要求，我校复试采取差额形式，各学科（专业）差额比例一般不低于120%，合格生源比例不足的，按实际合格生源数量组织复试。一志愿考生复试名单将在北京工商大学研究生招生信息网公布。</p>\n     <p>（五）复试考核方式及复试成绩计算办法</p>\n     <p>复试的主要形式有笔试、面试、实践（实验）能力考核等，其中面试是必要环节。面试（可含实践能力考核）主要考查考生的专业素质、综合素质及外语口语及听力等，满分为100分。复试成绩计算办法见各学院复试录取细则。</p>\n     <p>（六）思想政治素质和道德品质考核</p>\n     <p>思想政治素质和品德考核是复试的重要内容和录取的重要依据，必须严格遵循实事求是的原则，注重对学生政治态度、思想表现、道德品质、遵纪守法、诚实守信等方面的考查。</p>\n     <p>学院可在复试中加强考生思想政治素质和品德考核，也可组织思想政治工作部门工作人员与考生面谈，直接了解考生思想政治情况，还可采取“函调”或“派人外调”等方式对考生的思想政治素质和品德进行考核。函调的考生现实表现材料，须由考生本人档案所在单位或工作所在单位的人事、政工部门加盖印章。</p>\n     <p>（七）关于同等学力考生的复试</p>\n     <p>以同等学力参加复试的考生，在复试中须加试至少两门与报考专业相关的本科主干课程。加试方式为笔试，加试科目不得与初试科目相同，加试不合格者不予录取。</p>\n     <p><strong>三、录取工作办法</strong></p>\n     <p><strong></strong></p>\n     <p>（一）录取成绩计算办法</p>\n     <p>学校严格遵循择优录取、宁缺毋滥、“公平、公正、科学”的录取原则。具体录取成绩计算办法和录取办法由各招生学院在复试录取细则中规定。</p>\n     <p>考生总成绩为统考初试成绩和复试成绩按权重相加，一志愿考生初试成绩占总成绩的权重为70%，复试成绩占30%。</p>\n     <p>（二）录取办法</p>\n     <p>1.考生的录取以总成绩为依据，考生的总成绩相同时，录取规则由招生学院确定。</p>\n     <p>2.复试成绩不合格者（成绩低于60分为不合格，专项计划低于45分为不合格，下同）不予录取；复试单项考核成绩不合格者不予录取；思想政治素质和道德品质考核不合格者不予录取；同等学力考生加试课程的成绩不合格者不予录取。</p>\n     <p>3.定向就业的硕士研究生须在被录取前与学校、用人单位签订《北京工商大学招收定向就业录取类别研究生培养协议》，拟录取名单公布5个工作日内须将协议提交至录取学院，未按时提交定向协议者不予录取。一经录取后，不得变更录取信息中的就业方式。</p>\n     <p>4.考生因报考硕士研究生与所在单位产生的问题由考生自行处理。若因此造成考生不能复试或无法录取，学校不承担责任。</p>\n     <p>5.经考生确认的报考信息在录取阶段一律不作修改，对报考资格不符合规定者不予录取。</p>\n     <p>6.应届本科毕业生及自学考试和网络教育届时可毕业本科生考生，如在录取当年入学报到时未取得国家承认的本科毕业证书或教育部留学服务中心出具的《国（境）外学历学位认证书》，其录取资格无效。</p>\n     <p>7.考生体检工作在考生入学后统一组织。学校根据《中华人民共和国残疾人教育条例》和《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）等文件规定，参照《教育部 卫生部 中国残疾人联合会关于印发〈普通高等学校招生体检工作指导意见〉的通知》（教学〔2003〕3号）要求执行。体检不合格者，将取消录取资格。</p>\n     <p>8.学校不开展破格复试录取工作。</p>\n     <p>9.若拟录取考生自愿放弃录取资格或因招生计划动态调整等原因增加招生指标，则按总成绩由高到低依次递补录取，递补录取考生如已接受其他招生单位录取且无法按期解锁的不予录取。</p>\n     <p>10.入学后3个月内，学校按照《普通高等学校学生管理规定》有关要求，对所有考生进行全面复查。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p><strong>四、复试资格审查和复试费缴纳办法</strong></p>\n     <p><strong></strong></p>\n     <p>（一）资格审核携带的材料</p>\n     <p>1.本人手写签名的《北京工商大学2026年研究生招生考试诚信复试承诺书》；</p>\n     <p>2.由考生本人档案所在单位或工作所在单位的人事、政工部门加盖印章的《北京工商大学2026年硕士研究生政审函调表》；</p>\n     <p>3.初试准考证、有效身份证及复印件、毕业证书原件和复印件（往届生）、学生证原件和复印件或在读证明（应届生）；</p>\n     <p>4.未通过网上学历学籍校验的考生需提供学历（学籍）认证报告，或教育部留学服务中心出具的《国（境）外学历学位认证书》；</p>\n     <p>5.同等学力考生（报考工商管理硕士、旅游管理硕士的考生除外）须提供大学英语四级成绩单证明（425分及以上）原件及复印件或公共英语三级证书原件及复印件；或在正式刊物上已发表与所报考学科专业研究领域相关的学术论文原件；</p>\n     <p>6.定向或委托培养的应届本科毕业生报考硕士研究生，还须提供原定向、委培单位准予继续脱产攻读硕士研究生的证明原件。</p>\n     <p>（二）缴纳复试费</p>\n     <p>所有参加复试的考生在资格审查前需缴纳复试费100元。</p>\n     <p>（三）资格审查</p>\n     <p>1.资格审查在复试前进行。所有进入复试的考生均须进行资格审查，资格审查不合格者不予复试。</p>\n     <p>2.考生资格审查由学院组织进行，时间与地点见学院复试录取细则。</p>\n     <p>3.考生通过资格审查之后，须由学院在初试准考证上盖章，以此作为参加复试笔试和面试的凭证。</p>\n     <p>考生须对本人提交的材料和信息负责，对于提交材料与实际情况不符或弄虚作假者，一经发现学校将取消其复试录取、入学资格或取消学籍。情节严重的，根据相关法律法规移交有关部门处理。</p>\n     <p><strong>五、复试工作监督电话</strong></p>\n     <p><strong></strong></p>\n     <p>学校研招办： 010-68987086, btbuyjs@163.com</p>\n     <p>学校纪委监督检查室： 010-81353212</p>\n     <p>若考生本人对复试结果有异议，可在接到复试结果通知后的3日内向学校研招办提出复议申请。</p>\n     <p><strong>六、信息公布</strong></p>\n     <p><strong></strong></p>\n     <p>我校各项复试录取信息由学校研究生招生信息网（yzb.btbu.edu.cn）和相关学院网站公布，考生可登录网站查询。</p>\n     <p><strong>七、其他</strong></p>\n     <p><strong></strong></p>\n     <p>非全日制研究生上课时间安排在周末，不享受国家及学校奖助学金，学校不安排住宿，不转档案，毕业后按签订的《北京工商大学招收定向就业录取类别研究生培养协议》就业。</p>\n     <p style=\"text-align: right;\">北京工商大学</p>\n     <p style=\"text-align: right;\">研究生招生办公室</p>\n     <p style=\"text-align: right;\">2026年3月16日</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n