INSERT INTO `yl_guide` VALUES (109, '华南理工大学2026年硕士研究生招生复试录取办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>华南理工大学2026年硕士研究生招生复试录取办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2026年03月17日</span> <span>来源：华南理工大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据《2026年全国硕士研究生招生工作管理规定》《关于做好2026年全国硕士研究生招生复试录取工作的通知》等文件精神，学校结合实际，制定本办法。</p>\n     <p><strong>一、工作原则</strong></p>\n     <p>1.坚持综合评价，提升招生质量。坚持服务战略、按需招生、全面衡量、择优录取和宁缺毋滥的原则，德智体美劳全面衡量，以德为先，把考生思想品德考核作为复试的重要内容和录取的重要依据。加强对考生的全面考查和综合评价，促进高层次拔尖创新人才脱颖而出。</p>\n     <p>2.坚持严格管理，确保公平公正。严格按照教育部有关文件精神，政策透明，信息公开，程序公平，结果公正，监督机制健全。</p>\n     <p>3.坚持以人为本，优化考生服务。增强服务意识，强化人性化安排和个性化关怀，确保咨询渠道畅通，维护考生的合法权益。</p>\n     <p>4.加强组织领导，确保安全平稳。严格执行“集体议事、集体决策、会议决定”的规程，审议决策考试招生工作重大事项等。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p>研究生院在学校研究生招生委员会的领导下，统筹负责全校研究生复试录取工作。院（系）研究生招生工作领导小组负责领导和协调本单位复试录取的各项工作。院（系）研究生复试工作小组严格根据本单位复试方案，落实各项具体工作。院（系）研究生招生工作监督小组负责对复试录取工作的各个环节进行监督，受理考生申诉。</p>\n     <p><strong>三、确定复试名单</strong></p>\n     <p>院（系）在学校公布的2026年硕士研究生复试基本分数线基础上综合考虑招生计划、生源情况、学科（专业）特点等，确定本院（系）各专业考生进入复试的初试总分以及其他学术要求。</p>\n     <p>院（系）根据各专业（方向）可用招生计划以及合格生源情况，确定差额复试比例。合格生源充足的专业（方向）差额复试比例一般不低于120%。合格生源不足120%的专业（方向），所有合格生源可参加复试。</p>\n     <p>参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”项目之一，服务期满且考核合格，以及退役大学生士兵报考普通计划，且符合教育部《2026年全国硕士研究生招生工作管理规定》第二十二条规定条件的考生，执行初试加分政策。考生初试总分加分后达到院（系）线列入复试名单，计算总成绩时，初试成绩按加分后分数计算。</p>\n     <p>对服役期间获得三等战功、二等功以上奖励或者二级以上表彰，符合全国硕士研究生招生考试报考条件的退役人员，在教育部规定的全国统考报名时间内登录“全国推荐免试攻读研究生（免初试、转段）信息公开暨管理服务系统”（网址：https://yz.chsi.com.cn/tm）完成报名，经相关部门审核通过后，可进入学院复试名单。</p>\n     <p>符合享受初试加分、少数民族照顾政策、免初试或报考专项计划有关条件的考生，须在网上报名时按要求填报申请信息。有关部门、报考点对相关考生资格进行初审，学校将在复试前进行复审，确定考生的相应资格。其中，申请享受少数民族照顾政策的资格由报考点进行初审，其余资格由有关部门按职责分工进行初审。未按规定申报或审核（含复审）未通过的，不享受相应的加分、照顾、免初试政策，或不得参加有关专项计划初、复试。</p>\n     <p><strong>四、资格审查</strong></p>\n     <p>所有参加复试的考生均需进行资格审查，考生须携带复试通知书在院（系）规定时间到报考院（系）指定的地点办理资格审查手续。</p>\n     <p>1.应届生持学生证、身份证、大学成绩单的原件。</p>\n     <p>2.往届考生持毕业证、学位证、身份证、大学成绩单的原件（或加盖档案单位红章的成绩单复印件）。</p>\n     <p>3.“退役大学生士兵”专项计划考生还需携带“入伍批准书”和“退出现役证”原件。</p>\n     <p>4.考生报考时，学籍（学历）信息未通过学信网校验的考生：境内应届生还需提供《教育部学籍在线验证报告》、本科所在学校学籍管理部门出具的学籍证明以及相关证明材料；境内往届生还需提供《教育部学历证书电子注册备案表》或《中国高等教育学历认证报告》《教育部学籍在线验证报告》，如有更名或身份证号变更的还需出具公安机关的证明材料；获境外学历学位考生需提交教育部留学服务中心出具的《国（境）外学历学位认证书》。</p>\n     <p>考生还需按照规定将上述文件扫描件在复试系统提交，上传文件资料必须真实准确。新生入学后还将进行入学资格复查，复查不合格的，取消入学资格直至取消学籍。</p>\n     <p><strong>五、复试</strong></p>\n     <p>复试原则上采取现场考核方式进行。复试内容一般包括专业课考核、外语听说能力测试、综合素质与专业知识面试或院（系）要求的其他考核内容。具体复试方式和考核内容见各院（系）发布的复试录取实施方案。</p>\n     <p>同等学力考生须在复试时加试所报考专业的两门本科主干课程，加试方式为笔试，时间为每科2小时，满分为100分。加试科目不得与初试科目相同，具体以学院对外公布的加试科目为准，具体由院（系）单独组织。</p>\n     <p>报考125100工商管理、125200公共管理、125300会计、125601工程管理、125603工业工程与管理、125604物流工程与管理专业的考生还需进行思想政治理论考核，由院（系）自定考核方式，成绩计入复试成绩。</p>\n     <p>考生参加复试须签订《诚信复试承诺书》，按照要求对本人既往表现进行如实陈述；对复试试题内容、过程等有关情况保密，本人复试结束后亦不得对外透露和传播。</p>\n     <p><strong>六、调剂</strong></p>\n     <p>考生报考学校、报考院（系）、报考专业、报考学习方式任意一项在录取时发生变更，均属于调剂。完成第一志愿合格考生复试录取后，招生计划未完成的专业（方向）方可进行调剂。</p>\n     <p>1．调剂规则和办法</p>\n     <p>（1）调剂考生须符合调剂接收专业（即调入专业）的报考条件，原则上，调剂考生第一志愿报考专业与调入专业相同或相近，或初试科目与调入专业初试科目相同相近。调剂工作必须坚持公平、公正、公开的原则，给予生源充足专业参加复试但被淘汰考生以同等的调剂复试机会。调剂考生初试成绩须达到第一志愿报考专业所在学科（学位类别）的国家线和我校基本复试分数线，同时还须满足调入专业的院（系）线。</p>\n     <p>统考科目中，英语（一）可调英语（二）、数学（一）可调数学（二）和数学（三）、数学（二）可调数学（三），反之则不可。</p>\n     <p>（2）生源调剂信息须在学校研究生招生信息网和教育部“全国硕士研究生招生调剂服务系统”（以下简称“调剂服务系统”）发布。考生通过“调剂服务系统”报名，考生报名后，接收调剂生的院（系）将及时审核考生报考信息并通知相关考生复试。</p>\n     <p>2．特殊专业调剂要求</p>\n     <p>报考工商管理、公共管理、会计、工程管理等4个专业学位的考生，只能从报考工商管理、公共管理、会计、旅游管理、图书情报、工程管理、审计等7个专业学位的考生中调剂，且必须符合调剂接收专业的报考条件；法律硕士（非法学）专业只能从报考法律硕士（非法学）专业的考生中调剂；参加“单独考试”的考生不得调剂复试；报考“少数民族高层次骨干人才计划”的考生不得调剂到普通计划复试录取，未报考该专项计划考生也不得调剂到该专项计划复试录取。报考其他专业（含医学学术学位）的考生不可调剂到临床医学类专业学位。</p>\n     <p><strong>七、录取</strong></p>\n     <p>1.成绩计算</p>\n     <p>（1）复试成绩计算方法</p>\n     <p>专业课成绩占复试成绩的权重一般在30%—70%之间，由各院（系）自定。考生的复试成绩按下式计算：</p>\n     <p>复试成绩＝专业课考核成绩×专业课考核成绩权重＋综合素质与专业知识面试成绩×（1-专业课考核成绩权重-其他考核成绩权重-10%）＋外语听说能力成绩×10%+其他考核成绩×其他考核成绩权重。（四舍五入，保留2位小数）</p>\n     <p>外语类专业、管理类专业学位及单独考试专业成绩计算办法由院（系）自行确定并在复试录取细则中明确。</p>\n     <p>复试成绩不合格（四舍五入取整数低于60分）者不予录取。思想政治素质和道德品质考核不合格者不予录取。同等学力考生加试科目成绩不计入复试成绩，但若有一门科目成绩不合格（四舍五入取整数低于60分）者不予录取。</p>\n     <p>（2）总成绩计算方法</p>\n     <p>复试成绩占录取总成绩的权重一般在40%—50%之间，由各院（系）自定。考生的总成绩按下式计算：</p>\n     <p>总成绩＝初试成绩×（1-复试权重）＋复试成绩×复试权重×5（初试满分300分的专业×3）。（四舍五入，保留2位小数）</p>\n     <p>来源不同且初试科目不同的调剂复试考生，院（系）可另行确定总成绩计算办法并在调剂复试细则中明确。</p>\n     <p>复试结束后，考生在院（系）规定的时间通过学校研究生招生系统查询本人复试成绩、总成绩，查询时间见各院（系）网站通知。</p>\n     <p>2.录取原则</p>\n     <p>（1）总成绩是确定拟录取的重要依据。院（系）按专业（方向）考生总成绩从高到低的顺序排序（总成绩相同时，按复试成绩、复试成绩中的综合素质与专业知识面试成绩、专业考核成绩依次排序确定），依据招生计划数顺次拟录取，直至完成招生计划，不得少录、跳录。如有考生放弃或计划调增，顺次递补拟录取。生源不足情况下，各院（系）可视生源情况对招生计划予以微调。</p>\n     <p>（2）拟录取考生名单确定后在院（系）网站公示，公示时间不少于3个工作日。</p>\n     <p>（3）凡拟录取为定向就业的考生，须按要求签订协议书，参加单独考试的考生，只能被录取为回原单位定向就业。学院将严格审核定向就业合同。未签订协议书的，不发放录取通知书。考生因报考研究生与所在单位产生的问题由考生自行处理。若因此造成考生不能复试或无法录取，学校不承担责任。</p>\n     <p>（4）拟录取考生若放弃报考专业的录取，申请调剂其他专业，须按照调剂复试要求进行，不得直接录取到调剂专业。</p>\n     <p>3.确定导师</p>\n     <p>院（系）组织拟录取考生与导师进行双向选择。全日制硕士研究生录取时均应确定导师。</p>\n     <p>4.考生身体状况检查</p>\n     <p>拟录取全日制非定向就业类别考生须参加学校统一组织的体检。体检标准根据《残疾人教育条例》和《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）等文件规定，参照《教育部、卫生部、中国残疾人联合会关于印发〈普通高等学校招生体检工作指导意见〉的通知》（教学〔2003〕3号）要求，结合招生专业实际情况执行。不参加体检或体检不合格者不予录取。新生入学后将进行体检复查，若有弄虚作假者取消入学资格。</p>\n     <p><strong>八、监督和复议</strong></p>\n     <p>1．实行监督制度和巡查制度</p>\n     <p>全校研究生招生工作接受学校纪委的全面监督；研究生院组织人员对院（系）研究生招生复试录取工作进行督导；院（系）研究生招生工作监督小组对本院（系）及学校指定院（系）贯彻落实教育部和学校研究生招生政策、规章、纪律的情况进行监督。</p>\n     <p>2．实行复试信息公开制度</p>\n     <p>院（系）复试基本分数线、复试名单、拟录取考生名单等信息应及时进行公布，接受社会监督。</p>\n     <p>3．严肃考风考纪</p>\n     <p>对在复试过程中有违规行为的考生，一经查实，按照《国家教育考试违规处理办法》、《普通高等学校招生违规行为处理暂行办法》等规定严肃处理，取消录取资格，记入《考生考试诚信档案》。新生入学后3个月内，院（系）要按照教育部《普通高等学校学生管理规定》《2026年全国硕士研究生招生工作管理规定》有关要求，对所有新生进行全面复查。复查不合格的，取消学籍，情节严重的，移交有关部门调查处理。</p>\n     <p><strong>九、其他</strong></p>\n     <p>各院（系）复试录取实施方案将于近期陆续公布，考生应密切留意我校研究生招生信息网发布的信息。复试工作将在3月19日开始分批次组织，具体时间由各院（系）确定。</p>\n     <p>复试名单确定后，考生登录学校研究生招生系统下载复试通知书，并按要求上传资格审查、既往表现等材料。学校不再寄发纸质复试通知书。考生在参加复试期间应充分考虑天气变化和交通状况，妥善安排好个人行程，注意出行安全。</p>\n     <p>本办法由研究生院负责解释。未尽事宜以教育部《2026年全国硕士研究生招生工作管理规定》等文件和学校相关规定为准。</p>\n     <p>联系电话:020-87113401</p>\n     <p>网址：https://yz.scut.edu.cn/</p>\n     <p>电子邮箱:adyzb@scut.edu.cn</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n   