INSERT INTO `yl_guide` VALUES (111, '浙江工业大学2025年硕士研究生复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>浙江工业大学2025年硕士研究生复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2025年03月28日</span> <span>来源：浙江工业大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据教育部《2025年全国硕士研究生招生工作管理规定》等招生相关文件精神和我校2025年硕士研究生招生简章及实际情况，制定本工作办法。</p>\n     <p><strong>一、组织领导</strong></p>\n     <p>1.学校成立由学校主要负责人任组长的研究生招生工作领导小组，全面负责2025年硕士研究生招生复试和录取工作。学校领导小组下设研究生复试突发应急管理领导小组、研究生招生工作督查组等，确保复试录取工作安全、公平、科学。</p>\n     <p>2.学院成立由学院主要负责人任组长的学院研究生招生工作领导小组，全面负责本学院的硕士研究生复试、调剂、录取工作和招生廉政建设工作。在学院研究生招生工作领导小组中指定一人，负责复试、调剂、录取过程中的纪律检查工作。</p>\n     <p>3.学院根据学科（专业）组成若干个复试小组，一般不少于5人，由办事公正且没有近亲属参加当年复试或存在其他利害关系可能影响复试公平公正的相关专业教师担任，实行组长责任制。</p>\n     <p>4.学院做好复试工作人员的遴选、培训工作，选派经验丰富、业务水平高、公道正派的人员参与复试工作。</p>\n     <p>5.对所有参与招生工作人员进行政策、业务、纪律等方面的培训，使其明确工作纪律和工作程序、评判规则和评判标准。</p>\n     <p><strong>二、复试工作</strong></p>\n     <p><strong>（一）复试工作基本原则</strong></p>\n     <p>1.学校各学科（专业）复试分数线根据国家教育部确定的2025年全国硕士研究生招生考试考生进入复试的初试成绩A类考生基本要求执行（包括学术学位和专业学位硕士研究生）。生源富余的学科专业可在此基本要求上，再划定复试分数线，并报研究生院备案。</p>\n     <p>2.复试采取差额形式，差额比例一般不低于120%。对合格生源不足120%的专业按实际合格考生名单组织复试。</p>\n     <p>3.对同一学院同一专业的全日制和非全日制研究生划定公布相同的分数线。</p>\n     <p>4.“退役大学生士兵专项硕士研究生招生计划”考生进入复试的初试成绩要求为参考《2025年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》的各门类要求，单科下降5分，总分下降20分。各学院在学校复试分数线基本要求之上，可根据学科专业特点及生源和招生计划等情况，自主确定考生进入复试的初试成绩要求及其他学术要求。考生须达到学院确定的学科专业复试基本要求，才能进入复试。</p>\n     <p><strong>（二）复试方式</strong></p>\n     <p>2025年度我校硕士研究生复试原则上采用现场线下方式。具体请考生关注各学院官方网站公布的复试方案，按照要求提前做好相应准备。</p>\n     <p><strong>（三）考生资格审查</strong></p>\n     <p>1.做好心理素质普测。各学院要对所有复试考生进行心理素质测试，根据本单位招生计划、复试录取办法以及考生初试和复试成绩、思想政治表现、身心健康状况等择优确定拟录取名单。</p>\n     <p>2.各学院应认真做好复试准备工作，公布拟复试考生的名单，并及时通知考生参加复试。复试前，各学院须对考生的居民身份证、学历学位证书、学历学籍核验结果、学生证、准考证、《教育部学历证书电子注册备案表》或《教育部学历认证报告》或《教育部学籍在线验证报告》等报名材料原件及考生资格进行严格审查，定向就业考生须提供劳动合同或者定向就业单位出具的其他相关就业证明（在被录取前须与学校、用人单位分别签订定向就业合同），退役大学生士兵计划考生须提供本人《入伍批准书》和《退出现役证》，享受照顾（含加分）政策的考生须提供相关证明材料，对不符合规定条件者，不予复试。</p>\n     <p>对考生的学历（学籍）信息核验有问题的，应要求考生在复试前完成学历（学籍）核验，提供权威机构出具的认证证明。考生凭下载打印的《准考证》及居民身份证参加复试。</p>\n     <p>考生最终需要上传提交的资格审查材料以及提交方法请以各学院官方网站通知为准。</p>\n     <p>3.少数民族考生身份以报考时查验的身份证为准，复试时不得更改。少数民族地区以国务院有关部门公布的《全国民族区域自治地方简表》为准。</p>\n     <p>4.规范执行加分政策。符合下列条件之一后3年内报名参加全国硕士研究生招生考试的考生，可申请享受初试总成绩加10分，同等条件下优先录取。(1)参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”项目之一，服务期满且考核合格。(2)退役大学生士兵〔即高校学生应征入伍退出现役者，其中，高校学生指全日制普通本专科(含高职)、研究生、第二学士学位的应(往)届毕业生、在校生和入学新生，以及成人高校招收的普通本专科(含高职)应(往)届毕业生、在校生和入学新生，下同〕达到全国硕士研究生招生考试报考条件。</p>\n     <p>申请享受初试加分的考生，须在网上报名时按要求填报相关信息。有关部门按职责分工进行审核。未按规定申报或审核未通过的，不享受加分政策。加分项目不累计。除上述加分项目外，各学院不得擅自扩大加分范围、另设标准，对加分项目考生提供的相关证明材料进行认真核实，并报研究生院审核。</p>\n     <p>报考专项计划的考生，不再享受初试加分和少数民族照顾政策。</p>\n     <p>5.对服役期间获得三等战功、二等功以上奖励或者二级以上表彰，符合全国硕士研究生招生考试报考条件的退役人员，可申请免初试攻读硕士研究生。</p>\n     <p>符合免初试资格的考生，应在教育部规定的全国统考报名时间内登录“全国推荐免试攻读研究生(免初试、转段)信息公开暨管理服务系统”(网址：https://yz.chsi.com.cn/tm)报名，逾期不得补报。</p>\n     <p>各学院应对申请免初试的考生组织复试，复试合格者即可予以拟录取。</p>\n     <p>6.各学院加强诚信评判和作弊考生查处。强化对考生诚信的要求，要充分利用《国家教育考试考生诚信档案》记录，对考生在报考时填写的考试作弊受处罚情况进行认真核查，将考生诚信状况作为思想品德考核的重要内容和录取的重要依据，切实将诚信考核作为专项环节纳入复试工作。凡有违反国家教育考试规定、情节严重受到停考处罚，在处罚结束后继续报名参加研究生招生考试的，由学院决定是否予以录取。</p>\n     <p>复试期间，考生应自觉遵守校院考场规则及考生所签署的《诚信复试承诺书》等内容，在复试工作结束前不得对外透露或传播复试试题内容等有关情况。对在研究生考试招生中违反考试管理规定和考场纪律，影响考试公平、公正的考生、考试工作人员及其他相关人员，一律按《中华人民共和国教育法》和《国家教育考试违规处理办法》（教育部令第33号）等严肃处理。</p>\n     <p><strong>（四）复试基本内容和主要形式</strong></p>\n     <p>1.复试的主要方式包括笔试、实践（实验）能力考核、面试等。具体复试安排以各学院后续通知为准，请考生关注报考学院官方网站。复试成绩为复试各类考核成绩之和，总分为100分。</p>\n     <p>2.复试主要内容由学院根据学科（专业）特点及办学特色决定，一般应包括专业素质和能力、综合素质和能力等基本方面，各方面内容所占复试成绩的百分比由学院在复试方案中制定。专业素质能力主要全面考核考生对本学科（专业）理论知识和应用技能掌握程度；考察学生利用所学理论发现、分析和解决问题的能力，对本学科发展动态的了解以及在本专业领域发展的潜力；外语听说能力；创新精神和创新能力。综合素质和能力主要考察学生思想政治素质和品德，包括考生的政治态度、道德品质、遵纪守法、诚实守信等方面，同时还要注意考察学生的事业心、责任感、协作性和心理健康情况等方面的情况。</p>\n     <p>会计硕士、工商管理硕士、公共管理硕士、工程管理硕士的思想政治理论考试在复试中进行，成绩计入复试总成绩。</p>\n     <p>3.面试内容和形式由各学院制定，面试要求每生时间一般不少于20分钟；同一学科（专业）各复试小组的面试方式、时间、试题难度和成绩评定标准原则应统一。</p>\n     <p>4.以同等学力参加复试的考生，在复试中须加试至少两门与报考专业相关的本科主干课程。加试科目不得与初试科目相同。加试方式为笔试。同等学力考生加试课程的成绩不计入复试成绩，但不合格者不予录取。</p>\n     <p>5.复试权重及综合总成绩计算。2025年硕士研究生综合总成绩等于初试总成绩（折算成百分制）和复试成绩（百分制）的加权平均。复试成绩比重须在30%-50%之间，学院须在复试方案中明确。</p>\n     <p>6.推荐免试生的复试工作在全国统一报名前已完成，不再重复进行，但须做好推免生进一步确认工作。</p>\n     <p><strong>三、调剂工作</strong></p>\n     <p><strong>（一）调剂基本原则</strong></p>\n     <p>1.符合调入专业的报考条件。</p>\n     <p>2.初试成绩（含加分，下同）符合第一志愿报考专业A区全国初试成绩基本要求。</p>\n     <p>3.调入专业与第一志愿报考专业相同或相近，原则上应在同一学科门类范围内。</p>\n     <p>4.初试科目与调入专业初试科目相同或相近，其中初试全国统一命题科目原则上应与调入专业全国统一命题科目相同。</p>\n     <p>5.第一志愿报考照顾专业的考生若调剂出同类照顾专业，其初试成绩必须达到调入地区该照顾专业所在学科门类的全国初试成绩基本要求。</p>\n     <p>报考非照顾专业的考生若调入照顾专业，其初试成绩必须符合调入地区对应的非照顾专业所在学科门类的全国初试成绩基本要求。</p>\n     <p>工学照顾专业之间，体育学与体育硕士之间调剂，按本类照顾专业全国初试成绩基本要求执行。</p>\n     <p>6.第一志愿报考工商管理、公共管理、工程管理、会计、旅游管理、图书情报、审计等7个专业学位的考生，在满足调入专业报考条件、且初试成绩同时符合调出专业和调入专业在调入地区的全国初试成绩基本要求的基础上，可申请相互调剂，但不得调入其他专业；报考其他专业的考生不得调入该7个专业学位。</p>\n     <p>7.第一志愿报考法律（非法学）专业学位的考生不得调剂到其他学科专业，其他学科专业的考生也不得调入调剂到该专业。</p>\n     <p>8.报考“退役大学生士兵计划”的考生，可申请调剂到普通计划录取，其初试成绩须达到调入地区相关专业所在学科门类的全国初试成绩基本要求。符合条件的，可按规定享受退役大学生士兵初试加分政策。</p>\n     <p>报考普通计划的考生，若符合“退役大学生士兵计划”报考条件，可申请调剂到该专项计划，其初试成绩须符合我校确定的接受“退役大学生士兵计划”考生调剂的初试成绩要求。调入“退役大学生士兵计划”招录的考生，不再享受退役大学生士兵初试加分政策。对于“退役大学生士兵计划”和普通计划之间的调剂，各学院须严格按照调剂程序和要求组织，不得直接改变考生志愿、调整计划类型进行复试录取。</p>\n     <p>报考普通计划的考生，若报名时申请退役大学生士兵初试加分并填报了相关信息，经有关部门审核通过后，调剂阶段可按规定申请调剂“退役大学生士兵计划”；若报名时未申请退役大学生士兵初试加分的，不可参加“退役大学生士兵计划”调剂。</p>\n     <p>9.有专门规定的情况从其规定（详见《2025年全国硕士研究生招生工作管理规定》第六十一条）。</p>\n     <p>10.符合所申请调剂学院规定的其他具体调剂要求。</p>\n     <p><strong>（二）调剂具体要求</strong></p>\n     <p>1.接收所有调剂考生（既包括接收外单位调剂考生，也包括接收本单位内部调剂考生，以及报考“退役大学生士兵计划”和普通计划之间调剂的考生）均须通过教育部指定的“全国硕士生招生复试调剂服务系统”进行。</p>\n     <p>2.学院每次开放调剂系统持续时间不得低于12个小时。对申请同一招生单位同一专业、初试科目完全相同的调剂考生，学院应当按考生初试成绩择优遴选进入复试的考生名单。严禁学院或个人任意圈定调剂复试考生范围，严禁以考生提交调剂志愿的时间先后顺序作为调剂遴选条件，严禁以考生所在单位、行业、地域、学校层次类别等非学术水平标准限定调剂生源范围，严禁设置歧视性调剂条件。</p>\n     <p>3.考生调剂志愿锁定时间最长不超过36小时。锁定时间到达后，如学院未明确受理意见，锁定解除，考生可继续填报其他志愿。</p>\n     <p>4.学院拟发复试通知、待录取通知的调剂考生名单，须报研究生院审批备案。</p>\n     <p><strong>（三）调剂工作程序</strong></p>\n     <p>1.学院在本学院网站公布调剂方案，并报研究生院备案。</p>\n     <p>2.各学院应根据实际复试录取情况，通过 “全国硕士研究生招生复试调剂服务系统”（网址：https://yz.chsi.com.cn/yztj/）及时、准确发布计划余额信息及接收考生调剂申请的初试成绩等基本要求。</p>\n     <p>3.调剂考生（包括一志愿报考我校的调剂考生）登录“全国硕士研究生招生复试调剂服务系统”网站填报调剂志愿。</p>\n     <p>4.学院通过“全国硕士研究生招生复试调剂服务系统”网站筛选本学院调剂考生情况，确定复试名单并报研究生院审批后，通知考生复试。</p>\n     <p>5.学院将复试合格同意拟录取的名单及时报研究生院，经研究生院审核后，学院再通过“全国硕士研究生招生复试调剂服务系统”给调剂考生待录取信息。</p>\n     <p>6.调剂考生在规定时间内确认同意待录取。</p>\n     <p><strong>四、录取工作</strong></p>\n     <p>1.录取工作要坚持“按需招生、全面衡量、择优录取、宁缺毋滥”的原则，严格遵守相关规定，确保录取工作公平公正。</p>\n     <p>2.各学院要严格按照学校下达的招生名额（含各专项计划）及相关要求开展招生录取工作。录取人数不得超过本学院招生名额。录取为保留入学资格考生纳入学院当年的招生计划。</p>\n     <p>3.复试成绩不合格（低于60分）或思想政治素质和品德考核不合格者或身心健康状况不符合相关规定要求者，采取一票否决制，不予录取。同等学力考生加试科目成绩不合格者（低于60分）不予录取。</p>\n     <p>4.在学校研究生招生工作领导小组的统一领导下，按照教育部有关招生政策规定及属地省级高等学校招生委员会的管理和实施办法，根据招生计划、复试录取办法以及考生初试和复试成绩、思想政治和品德情况、身心健康状况等择优确定拟录取名单。拟录取名单由学校研究生招生办公室统一公示，公示时间不少于7日。</p>\n     <p>被我校拟录取且通过上级主管部门录取检查的考生，学校予以录取。</p>\n     <p>5.定向就业的硕士研究生应当在被录取前与学校、用人单位分别签订定向就业合同。</p>\n     <p>6.应届本科毕业生考生入学时未取得国家承认的本科毕业证书者，录取资格无效。</p>\n     <p>7.入学后3个月内，我校将按照《普通高等学校学生管理规定》有关要求，对所有录取的考生进行政治、业务、健康状况等全面复查。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p>8.拟录取的考生须在我校医院或其他二级甲等（含）以上医院进行体检，体检表须在学院复试成绩公示后两周内邮寄至相关学院。体检标准参照教育部、原卫生部、中国残联印发的《普通高等学校招生体检工作指导意见》（教学〔2003〕3号）要求，按照《教育部办公厅卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）以及招生学院相关规定要求执行。体检不合格者或未在学校规定时间内提交体检表者，取消录取资格。</p>\n     <p><strong>五、信息公开</strong></p>\n     <p><strong>1.招生计划公开。</strong>各学院应根据学校下达的招生名额编制分专业计划，并在本学院网站公布。</p>\n     <p><strong>2.复试录取办法公开。</strong>各学院要在本学院网站提前向社会公开本学院复试录取办法及具体实施细则，复试录取办法及具体实施细则要求复试前在学院网站公布，并报研究生院备案，未按要求提前公布的复试录取规定一律无效。</p>\n     <p><strong>3.复试考生名单公开。</strong>各学院要在本学院网站公布进入复试考生的姓名、考生编号、初试各科成绩等信息，对退役大学生士兵等专项计划、享受初试加分或照顾政策考生的相关情况应进行说明。</p>\n     <p><strong>4.录取信息公示与公开。</strong>各学院要在本学院网站公布各专业复试结果，结果应包括考生姓名、考生编号、初试成绩、复试成绩、总成绩等信息，并应对专项计划、享受初试加分或照顾政策的拟录取考生进行说明。拟录取名单由学校统一公示，公示时间不少于7日，公示期间名单不得修改；名单如有变动，须对变动部分做出说明，并对变动内容另行公示7日。公示结束后，学校通过“研招信息公开平台”将拟录取名单报省级教育招生考试管理机构进行政策审核，并按要求向教育部备案。最终录取名单及新生学籍注册均以“研招信息公开平台”备案信息为准。未经学校公示及“研招信息公开平台”备案的考生不得录取。</p>\n     <p><strong>5.调剂方案公开。</strong>各学院在本学院网站公布调剂方案，并报研究生院备案。各学院应根据实际复试录取情况，通过“全国硕士生招生调剂服务系统”及时、准确发布计划余额信息及调剂要求。</p>\n     <p><strong>6.咨询及申诉渠道公开。</strong>各学院要在本学院网站公布咨询及申诉渠道（含部门、电子信箱、电话号码和通讯地址等），并保证相关渠道畅通，对考生反映的问题及时核查处理，切实保障考生合法权益。</p>\n     <p>7、学院对于其他按规定应予公开的招生录取信息也要及时主动予以公开。</p>\n     <p><strong>六、学校咨询及申诉渠道</strong></p>\n     <p>考生对招生环节有异议的，可向招生学院以书面形式具名提起申诉，学院应当受理并予以答复。对答复有异议的，可向学校研究生招生办公室提起申诉。</p>\n     <p>浙江工业大学研究生招生办公室：东教科南207室</p>\n     <p>电话：0571-88320119</p>\n     <p>传真：0571-88320119</p>\n     <p>E-mail:yzb@zjut.edu.cn</p>\n     <p>学校纪检监察部门申诉举报电话：0571-88320102</p>\n     <p>通讯地址：浙江杭州拱墅区潮王路18号</p>\n     <p>邮编：310014</p>\n     <p>各学院咨询及申诉渠道请查看相应学院网站。</p>\n     <p><strong>七、本办法如与上级部门最新政策要求不一致的，按上级部门相关要求执行。</strong></p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a hr