INSERT INTO `yl_guide` VALUES (112, '河南大学2025年硕士研究生复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>河南大学2025年硕士研究生复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2025年03月26日</span> <span>来源：河南大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据《2025年全国硕士研究生招生工作管理规定》（教学〔2024〕4号）《关于做好2025年全国硕士研究生复试录取工作的通知》(教学司〔2025〕4号)等文件和2025年全国硕士研究生招生复试录取工作部署会、2025年河南省硕士研究生招生录取工作视频会等会议精神，为加强和规范复试录取工作，结合学校2025年硕士研究生招生工作实际情况，特制定本方案。</p>\n     <p><strong>一、指导思想</strong></p>\n     <p>以习近平新时代中国特色社会主义思想为指导，深入贯彻党的二十大精神，落实全国研究生教育会议精神，坚持“按需招生、全面衡量、择优录取、宁缺毋滥”的原则，坚持综合评价、落实立德树人根本任务，把立德树人成效作为检验研究生考试招生和培养工作的根本标准；坚持严格管理、确保公平公正，坚持以人为本、优化考生服务，坚持加强领导、确保安全平稳；优化人才选拔机制，创新复试考核方式，努力提升人才选拔质量；强化主体责任，深化信息公开，加强监督管理，提升服务水平；在确保安全性、公平性、科学性的基础上，统筹兼顾、严格管理，稳妥做好我校2025年全国硕士研究生招生考试复试录取工作。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p>学校2025年硕士研究生复试录取工作在学校研究生招生工作领导小组的统一领导和指导下，由各学院（实验室、中心）研究生招生工作领导小组负责具体实施。</p>\n     <p>各学院（实验室、中心）研究生招生工作领导小组负责领导、组织本单位的招生复试录取工作，负责按照教育部、河南省和学校有关招生政策、规定、办法等和报考上线生源情况，确定本单位各学科专业的招生计划，负责制定本单位的《研究生招生复试录取工作实施细则》，并组织实施复试录取工作。</p>\n     <p>各单位研究生招生工作领导小组组织成立本单位“考生资格核查小组”、“学科专业复试小组”和“监督小组”，具体负责组织实施本单位的复试和录取工作。</p>\n     <p><strong>三、复试方式</strong></p>\n     <p>我校研究生复试原则上采取现场复试方式进行。复试考生在复试时间段内凭初试准考证和身份证进出校园。</p>\n     <p><strong>四、复试比例、复试分数线、复试名单和实施细则</strong></p>\n     <p>（一）复试比例</p>\n     <p>2025年我校所有招生学科（专业）复试比例一般均为1:1.2，合格生源比例不足的，按实际合格生源数组织复试。</p>\n     <p>（二）复试分数线</p>\n     <p>我校2025年硕士研究生复试分数线陆续会在河南大学研究生院网站和各学院（实验室、中心）网站公布。</p>\n     <p><strong>我校不接受</strong><strong>任何形式的</strong><strong>破格复试</strong><strong>申请</strong><strong>。</strong></p>\n     <p>（三）复试名单</p>\n     <p>复试名单由各学院（实验室、中心）于复试前在各单位网站公布。</p>\n     <p>（四）复试录取工作实施细则</p>\n     <p>各学院（实验室、中心）的复试录取工作实施细则由各单位于复试前在本单位网站公布。考生应及时关注我校各学院（实验室、中心）官方网站，认真查看各学院（实验室、中心）复试录取工作实施细则，并按照相关要求提前准备复试需要提交的相关材料。</p>\n     <p><strong>五、复试时间</strong></p>\n     <p>我校2025年硕士研究生复试录取工作原则上在2025年4月20日前完成，其中一志愿考生复试原则上在4月6日前完成。具体时间见各学院（实验室、中心）的复试录取工作实施细则。</p>\n     <p><strong>六、复试通知</strong></p>\n     <p>复试通知同时采用以下方式进行：</p>\n     <p>（一）网络通知：各学院（实验室、中心）在本单位网站公布参加复试的考生名单。</p>\n     <p>（二）电话通知：各学院（实验室、中心）在复试前，将电话通知考生参加复试，请考生保持联系方式畅通。</p>\n     <p><strong>七、资格复查</strong></p>\n     <p>考生须提前按照《河南大学2025年硕士研究生复试录取工作考生须知》准备相关材料，以备资格审查。</p>\n     <p>各学院（实验室、中心）考生资格核查小组在复试前将对考生的居民身份证、学籍学历证明等报名材料及考生资格进行严格审查，对不符合规定者，不予复试。对报名信息存疑的考生，考生资格审查时需提交相应证明材料，以供审核。尤其是考生学历（学籍）信息不匹配的，应提供权威机构出具的认证证明；属于成人教育本科在读的，需要打印专题网页证明是成人教育本科四年级学生；若考生在2024年10月研究生招生报名结束以后又取得新的更高的学历，仍按原来报名时的学历认定。</p>\n     <p>考生复试前，阅读并签订“诚信考试承诺书”。</p>\n     <p><strong>八、复试内容</strong></p>\n     <p>复试内容主要包括外语测试、专业知识测试、综合能力面试。对实践（实验）能力有特殊考核需求的学科（专业），根据实际情况设置实践（实验）能力考核环节（详见各学院的《复试录取工作实施细则》）。</p>\n     <p>（一）外语测试</p>\n     <p>外语测试采取口语或听力测试方式进行，外语测试成绩单独打分，满分为100分，计入复试总成绩，在复试成绩中所占权重为10%，成绩低于60分者，不予录取。</p>\n     <p>（二）专业知识测试</p>\n     <p>各专业按照《2025河南大学硕士研究生招生简章》中公布的“复试”内容组织专业知识测试。考察内容为2025年专业目录中公布的“复试科目”内容，满分为100分，计入复试总成绩，其在复试成绩中所占权重详见各学院的《复试录取工作实施细则》，成绩低于60分者，不予录取。</p>\n     <p>（三）综合能力面试</p>\n     <p>综合能力面试采取面试的方式进行，主要对考生的知识结构和综合能力、思想品德以及心理素质等方面进行测试。满分为100分，计入复试总成绩，其在复试成绩中所占权重详见各学院的《复试录取工作实施细则》，成绩低于60分者，不予录取。</p>\n     <p>（四）单独设置“思想政治理论考试”科目的专业</p>\n     <p>会计硕士、图书情报硕士、工商管理硕士、审计硕士、公共管理硕士、旅游管理硕士、工程管理硕士等专业学位，需单独设置“思想政治理论考试”科目。该科目满分为100分，计入复试总成绩，其在复试成绩中所占权重详见各学院的《复试录取工作实施细则》，成绩低于60分者，不予录取。</p>\n     <p>（五）同等学力加试</p>\n     <p>以同等学力参加复试的考生在复试中均须加试至少两门不同于初试科目的本科主干课程。加试方式为笔试。加试科目参照《2025年河南大学硕士研究生招生简章》中已公布的“同等学力加试科目”内容。试卷满分为100分。同等学力加试成绩只作为录取参考，不计入复试成绩总分。加试科目单科成绩低于60分者，不予录取。</p>\n     <p><strong>九、成绩构成、成绩排名</strong></p>\n     <p>（一）成绩构成</p>\n     <p>总成绩包括初试成绩和复试成绩，初试成绩和复试成绩按权重相加，得出总成绩。初试成绩、复试成绩所占权重由各学院（实验室、中心）自定。总成绩四舍五入保留两位小数。总成绩计算可参照以下形式：</p>\n     <p><strong>复试成绩（管理类专硕）</strong>=外语测试×10%+专业知识测试成绩×专业知识测试成绩权重+综合能力面试×综合能力面试权重+思想政治理论考试×思想政治理论考试权重</p>\n     <p><strong>复试成绩（管理类专硕以外专业）</strong>=外语测试×10%+专业知识测试成绩×专业知识测试成绩权重+综合能力面试×综合能力面试权重</p>\n     <p><strong>总成绩（管理类专硕）</strong>=（初试成绩÷3）×初试成绩权重+复试成绩×复试成绩权重</p>\n     <p><strong>总成绩（管理类专硕以外专业）</strong>=（初试成绩÷5）×初试成绩权重+复试成绩×复试成绩权重</p>\n     <p>（二）成绩排名</p>\n     <p>各学院（实验室、中心）要进一步完善成绩数据审核管理，健全成绩数据审核机制，确保成绩复核无误。经各学院（实验室、中心）招生工作领导小组审核后，考生按录取规则以总成绩降序排列；<strong>如总成绩相同，按初试成绩从高分到低分排列；如总成绩、初试成绩、复试成绩均相同，按初试国家统考科目成绩之和从高分到低分排列</strong>。一般在复试结束后24小时内公示考生总成绩。</p>\n     <p>学校认为有必要时，可对相关考生再次复试。</p>\n     <p><strong>十、调剂</strong></p>\n     <p>调剂相关政策按照《河南大学2025年硕士研究生接收调剂工作办法》（待调剂系统开通前另行公布）执行。</p>\n     <p><strong>十一、拟录取</strong></p>\n     <p>（一）各学院（实验室、中心）研究生招生工作领导小组根据本单位招生计划、复试录取办法以及考生初试成绩、复试成绩、总成绩、思想政治表现、身心健康状况等择优提出拟录取考生名单，报送学校研究生招生领导小组办公室审核。</p>\n     <p>（二）对于接收调剂考生的专业，根据招生计划和提前公布的录取原则，分别对第一志愿考生和调剂考生进行复试排序，首先从复试合格的一志愿考生中根据总成绩由高到低依次录取，确定拟录取名单；待国家调剂系统开放，调剂生复试结束，再从复试合格的调剂考生中根据总成绩由高到低依次录取，确定拟录取名单。</p>\n     <p>（三）对于同时招收全日制研究生和非全日制研究生的专业，分别按照考生报考的学习方式，根据招生计划（全日制计划或非全日制计划）和总成绩由高到低依次录取。若非全日制考生拟录取生源不足，剩余非全日制招生计划开通“研招网全国调剂服务系统”，面向所有考生调剂。</p>\n     <p>（四）若考生因特殊原因自愿放弃（书面申请）拟录取资格，在上报学校之前其招生计划可由培养单位按录取原则递补录取。</p>\n     <p>（五）各培养单位向拟录取考生所在单位函调人事档案和本人现实表现等材料，全面审查其思想政治表现情况，必要时派人进行外调。函调和外调有关材料需由考生所在单位组织（或人事）部门加盖印章。思想品德考核不合格者不予录取。</p>\n     <p>（六）根据《国家教育考试考生诚信档案》记录，对考生在报考时填写的考试作弊受处罚情况进行认真核查，将考生诚信状况作为思想品德考核的重要内容和录取的重要依据。对在复试过程中有违规行为的考生，一经发现，经查实后按照《国家教育考试违规处理办法》《普通高等学校招生违规行为处理暂行办法》等规定严肃处理，取消录取资格，记入考生考试诚信档案。入学三个月内，学校将按照有关要求，对所有考生进行全面复查，复查不合格的，撤销拟录取资格；情节严重的，移交有关部门调查处理。</p>\n     <p><strong>十二、信息公开</strong></p>\n     <p>各学院（实验室、中心）要对硕士研究生复试录取相关信息全程公开、公示，主要包括以下内容：</p>\n     <p>（一）复试录取工作办法。学校在研究生院网站公布《河南大学2025年硕士研究生复试录取工作办法》，各学院（实验室、中心）在本单位网站公布《复试录取工作实施细则》。</p>\n     <p>（二）调剂工作办法。学校在研究生院网站公布《河南大学2025年硕士研究生接收调剂工作办法》，接收调剂的单位在本单位网站公布《接收调剂工作实施细则》。</p>\n     <p>（三）进入复试名单公示。复试前各单位要在本单位网站公布（可根据复试时间分批公布）进入复试考生的考生编号、姓名、初试各科成绩、总成绩等信息。</p>\n     <p>（四）复试成绩公示。确保成绩复核无误，经各学院（实验室、中心）招生工作领导小组审核后，一般应于24小时内公示所有参加复试考生的复试结果，复试结果按录取规则以总成绩降序排列。公示时间不少于7日。</p>\n     <p>（五）拟录取名单公示。待学校将拟录取名单报至研招网并审核通过后，统一在研究生院网站公示拟录取名单（包括考生编号、姓名、初试成绩、复试成绩、总成绩等信息），公示时间不少于7日。</p>\n     <p>以上各项考生名单公示时，如遇有加分考生、大学生退役士兵专项计划、立功表彰考生等特殊类型考生，应在公布成绩时在备注栏注明加分类型、加分值、专项计划类型等信息。</p>\n     <p><strong>十三、监督</strong></p>\n     <p>研究生复试实行监督制度和巡考制度，建立公众、学校、纪检监察部门、督导组、培养单位、导师代表等多方参与的全覆盖立体化监督巡考体系。各学院（实验室、中心）成立“监督小组”，全程监督检查本单位研究生复试录取全过程、各环节等相关工作；学校成立“研究生复试督导巡考小组”，对各学院（实验室、中心）复试工作进行督导巡考；学校研究生复试录取工作全程接受学校纪检监察部门和社会监督。</p>\n     <p>监督电话：16627575626（纪委）</p>\n     <p>0371-22867269（研究生院）</p>\n     <p><strong>十四、咨询及复议</strong></p>\n     <p>1.咨询。各学院（实验室、中心）应公布联系部门、电子信箱、电话号码和通讯地址等信息，指定熟悉政策的工作人员专门值守接听考生咨询电话，及时为考生答疑解惑，确保咨询渠道畅通。</p>\n     <p>2.复议。研究生复试实行复议制度，各学院（实验室、中心）应公布联系部门、电子信箱、电话号码、通讯地址等信息，指定熟悉政策的工作人员受理考生的投诉和申诉，确保投诉和申诉渠道畅通。考生对复试结果有异议，可在复试结束后10天内提出投诉和申诉，由学校研究生招生工作领导小组组织调查和复议。</p>\n     <p>咨询电话：0371-22867269（研究生院）</p>\n     <p>邮箱：zsgl@vip.henu.edu.cn</p>\n     <p><strong>十五、其他事项</strong></p>\n     <p>（一）录取类别。非定向就业硕士研究生人事档案须在规定时间内转至学校。定向就业硕士研究生（含全日制和非全日制）须与招生单位、用人单位签订定向培养协议。原则上非全日制硕士研究生招收在职定向就业人员，就业方式均为定向就业。</p>\n     <p>（二）学习方式。全日制研究生在基本修业年限或者学校规定年限内，须全脱产在校学习。非全日制研究生在基本修业年限或者学校规定的修业年限内，采取多种方式和灵活时间安排进行非脱产学习。</p>\n     <p>（三）拟录取手续办理。拟录取考生必须在我校规定的时间（相关安排另行通知）完成拟录取手续的办理（调档、政审和签订定向协议等手续）。所有拟录取名单须报送教育部审核通过，方为正式录取名单。</p>\n     <p>（四）体检。考生于拟录取后提供近期（三个月内）的体检报告即可，体检报告的由各学院（实验室、中心）的“考生资格核查小组”负责审核；体检不合格者不予录取。</p>\n     <p>本办法未尽事宜以教育部、河南省相关招生政策为准，由河南大学研究生招生工作领导小组负责解释；本办法如与国家有关招录政策相冲突时，按照国家规定执行。</p>\n     <p>本办法由河南大学研究生招生工作领导小组负责解释。</p>\n     <p style=\"text-align: right;\">河南大学研究生招生工作领导小组</p>\n     <p style=\"text-align: right;\">2025年3月25日</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chsi.com.cn/sswbgg/\" target=\"_blank\">网报公告</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\" target=\"_blank\">博士目录</a> <a href=\"https://yz.chsi.com.cn/help/\" target=\"_blank\">帮助中心</a>\n      </div>\n      <div class=\"aside-con-title\">\n       统考\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108-4.html\" target=\"_blank\">报名条件</a> <a href=\"https://yz.chsi.com.cn/yzwb/\" target=\"_blank\">网上报名</a> <a href=\"https://yz.chsi.com.cn/yzwb/#xcqr\" target=\"_blank\">网上确认</a> <a href=\"https://yz.chsi.com.cn/yzwb/#zkzxz\" target=\"_blank\">下载准考证</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">分数线</a> <a href=\"https://yz.chsi.com.cn/yztj/\" target=\"_blank\">调剂</a>\n      </div>\n      <div class=\"aside-con-title\">\n       推免\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">推荐系统</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/\" target=\"_blank\">申请指南</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/#bmlc\" target=\"_blank\">推免流程</a> <a href=\"https://yz.chsi.com.cn/tm/zyml/\" target=\"_blank\">专业目录</a> <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">填报志愿</a> <a href=\"https://yz.chsi.com.cn/tm/lqmd/index\" target=\"_