INSERT INTO `yl_guide` VALUES (113, '西南科技大学2025年硕士研究生复试录取工作方案', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>西南科技大学2025年硕士研究生复试录取工作方案</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2025年03月22日</span> <span>来源：西南科技大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>为做好西南科技大学2025年硕士研究生招生复试及录取相关工作，根据《2025年全国硕士研究生招生工作管理规定》（教学〔2024〕4号）及教育部、四川省关于2025年硕士研究生招生复试的相关要求，结合学校实际，制定本工作方案。</p>\n     <p>一、组织领导</p>\n     <p>（一）学校研究生招生工作领导小组负责学校硕士研究生招生复试及录取工作的领导和统筹管理，严格执行“集体议事、集体决策、会议决定”的规程，审议决策重大事项等。研究生院负责制定学校硕士研究生招生复试及录取工作的总体实施方案，指导并检查各招生学院（以下简称“学院”）相关工作，汇总上报各类录取材料。学校保密办公室负责指导与监督学校硕士研究生复试及录取保密工作。学校分管校领导、纪委、研究生院和保密办公室等部门组成的监督检查工作组，全程监督、巡视、检查学院2025年硕士研究生复试和录取工作情况。</p>\n     <p>（二）学院研究生招生工作领导小组负责本学院硕士研究生复试工作，领导小组由学院党政主要负责人、分管研究生教育的院领导、学院纪委负责人、招生学科/专业学位类别（以下统称“专业”）负责人等组成，组长由院长担任。学院应高度重视、精心准备，结合本学院专业特点，认真梳理复试环节，对各环节进行认真研判，确定学院的复试工作相关要求，强化责任，规范流程，严守纪律。</p>\n     <p>（三）学院研究生招生工作领导小组负责组织成立若干复试小组，具体实施对每位考生的复试考核。每个复试小组应分专业或研究方向由不少于5名经验丰富、业务水平高、公道正派的具有副高及以上职称的教师组成，并设立组长1名。</p>\n     <p>（四）学院应强化分岗分级培训，对所有参加复试的人员进行招生政策、业务和纪律等方面的培训，使其明确工作纪律、工作程序、评判规则和评判标准，做到任务清楚、责任明确；要充分发挥和规范导师的作用，明确导师在复试工作中的权利、责任和纪律要求，规范其工作行为，同时建立和完善复试导师信息库；对不称职的复试导师或工作人员要及时调换。</p>\n     <p>二、工作原则</p>\n     <p>学校2025年硕士研究生招生复试及录取工作坚持综合评价、择优录取，严格规范执行国家招生政策；在确保安全性、公平性和科学性的基础上，以“按需招生、全面衡量、择优录取、宁缺毋滥”的原则进行公开、公平、公正和科学的选拔；学院要探索和完善拔尖创新人才的选拔机制，进一步改进和完善复试考核评价机制，提高复试的科学性和有效性；不断加强监督管理，切实做到信息公开、以人为本、尊重考生、服务考生，确保科学公正、规范透明。</p>\n     <p>三、复试</p>\n     <p>（一）考生进入复试的基本条件</p>\n     <p>1.考生进入复试的初试成绩按教育部《2025年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》执行。学院还可结合专业的生源情况以及差额复试的要求，在不低于教育部划定的初试成绩基本要求的前提下，自主确定本学院考生进入复试的初试成绩基本要求，报学校研究生招生工作领导小组备案，由研究生院统一对外公布。此外，学院还可根据培养需要提出进入复试的其他学术要求，但不得出台歧视性规定。</p>\n     <p>2.学校依据教育部有关政策自主确定“退役大学生士兵专项硕士研究生招生计划”（以下简称“大学生士兵计划”）考生进入复试的初试成绩基本要求，提前对外公布并严格执行。</p>\n     <p>（二）复试比例</p>\n     <p>学院应根据学校下达的招生计划数差额确定复试考生名单，差额比例一般不低于120%（合格生源比例不足的，按实际合格生源数组织复试）。所有考生（含“立功表彰退役军人免试生”，不包括已录取公示的推免生）均须参加复试考核，并按照《四川省发展和改革委员会 四川省财政厅关于重新发布全省教育系统考试考务行政事业性收费的通知》（川发改价格规〔2022〕484号）的规定交纳复试费120元/生，同等学力考生另加收加试科目考试费80元/生。</p>\n     <p>（三）考生复试资格审核</p>\n     <p>1.复试资格</p>\n     <p>学院在复试前应对考生报名材料及资格进行严格审查，不符合教育部规定者不予复试；凡未进行资格审查或资格审查未通过的考生一律不允许参加复试。</p>\n     <p>（1）考生复试前应将以下材料提交给学院检查，学院应安排专人严格审查：</p>\n     <p>①有效身份证；</p>\n     <p>②应届本科生（含网络教育应届本科生）的《教育部学籍在线验证报告》和本科成绩单；</p>\n     <p>③往届生（含本科结业生、高职高专毕业生）的《教育部学历证书电子注册备案表》（学信网上查不到学历的考生提供教育部《中国高等教育学历认证报告》，持有国外学历的考生或中外合作办学只获得国外学历的考生提供教育部留学服务中心出具的国外学历学位认证书）和本/专科成绩单；</p>\n     <p>④自考本科应届生的自考考籍表（注册地自考办打印并加盖公章）、成绩单和专科阶段的《教育部学籍在线验证报告》（如考生已取得国家承认的本科学历则提供本科阶段的《教育部学历证书电子注册备案表》）；</p>\n     <p>⑤“大学生士兵计划”考生本人的《入伍批准书》和《退出现役证》；</p>\n     <p>⑥思想政治素质和品德考核材料；</p>\n     <p>⑦学院要求提供的其他材料。</p>\n     <p>（2）在资格审查过程中，学院要积极运用“人脸识别”“人证识别”等技术，并通过综合比对“报考库”“学籍学历库”“人口信息库”“考生考试诚信档案库”等措施，加强对考生身份的审查核验，严防复试“替考”。审查过程中收取的考生材料应由学院工作人员签名后归档留存备查。</p>\n     <p>（3）报考工商管理（MBA）、公共管理（MPA）、法律硕士等有特殊报考要求专业的考生须按照《2025年全国硕士研究生招生工作管理规定》的相关要求严格审查报考条件。</p>\n     <p>（4）少数民族考生身份以报考时查验的身份证为准，复试时不得更改。</p>\n     <p>2.加分资格</p>\n     <p>对于满足《2025年全国硕士研究生招生工作管理规定》中规定的加分条件，在网上报名时按要求填报了相关信息，并通过国家有关部门审核的考生，学院需在复试前对考生的资格进行复审。考生应在复试前向学院提交相关书面佐证材料。审核通过的，可享受初试总成绩加10分，同等条件下优先录取的政策。除教育部统一规定的范围和标准外，任何单位和个人不得擅自扩大范围、另设标准。</p>\n     <p>（四）复试形式与内容</p>\n     <p>1.复试细则</p>\n     <p>按照教育部提出的“分类复试，分别进行，各有侧重”的原则，学院要结合本学院情况、各专业的招生计划数和一志愿/调剂生源情况，根据专业特色和专业要求，制订有利于优秀人才选拔的复试工作细则，提前公布并严格执行，确保复试工作程序严谨，操作规范。复试工作细则中要明确复试程序、方式，明确复试成绩计算方法，说明接收考生调剂的时间、基本要求、工作程序，公布联系咨询电话以及其它需要考生注意的事项。实际工作中，要优化复试内容，改进评价方法，建立多元化评价体系，全面且多环节、多角度地对考生的智力因素与非智力因素、专业基础与学术水平、平时成绩与考试成绩、现有成就与发展潜力等多方面进行考察评价；要注重考察考生在专业领域的创新精神、能力和潜质。学院的复试细则在报送学校研究生院审核通过后方可在“全国硕士生招生复试调剂服务系统”和本学院网站上公布。</p>\n     <p>2.复试方式</p>\n     <p>（1）学院根据学科特点和专业要求，在确保公平和可操作的前提下自主确定复试方式，可采用现场复试、网络远程复试等，同一学院同一专业应采用同一种复试方式。复试过程须全程录音录像。</p>\n     <p>（2）选择网络远程复试的学院自行确定网络远程复试平台（同步确定备用平台），网络远程复试平台应具备人脸识别、作弊抓拍、防截屏缩屏、视频同步录制等功能。同一学院同一专业的复试平台应当保持一致，并提前对考生公布。学院选用的复试平台应多次试用以确保其系统的稳定性，考生端应使用双机位（主机位用于面试答辩，面对考生正面，次机位用于考生复试整体环境的监控）。</p>\n     <p>（3）复试可采取笔试、面试、实践（实验）能力考核等模式。笔试主要为专业课测试。实践（实验）能力考核主要测试实验和操作技能，或解决实际问题的能力。面试试题应以综合性、开放性的能力型试题为主，各专业应准备充足的面试试题，考生在面试时应随机抽取试题即行作答。面试前，各专业要随机确定各复试小组组成人员，随机确定考生所在复试小组和复试次序。面试期间，复试小组应对考生的作答情况进行现场书面记录。复试小组成员应现场独立评分，一经确定不得改动。</p>\n     <p>（4）同一专业的复试时长、难度和成绩评定标准应当统一。按国家文件要求，复试的面试时长原则上不少于20分钟，具体时长由招生学院自行确定。</p>\n     <p>（5）复试试题及其评分标准在启用前均系国家机密材料，学院应按照学校硕士研究生招生考试自命题工作的相关要求采取切实有效措施，做好安全保密工作。学院应安排专人专柜保存复试相关资料，复试试题及复试记录的保存期不少于3年，复试期间的录音录像资料的保存期不少于1年。</p>\n     <p>3.复试内容</p>\n     <p>复试科目应与学校2025年硕士研究生招生章程中专业目录的规定一致，基本内容应主要包含以下方面：</p>\n     <p>（1）专业素质和能力测试。主要考查内容包括：创新精神和能力；对本专业的发展潜力以及发展动态的了解；考生运用本专业知识发现、分析和解决实际问题的能力。</p>\n     <p>（2）综合素质及能力测试。主要考查内容包括：思想政治素质和品德考核；本专业以外的学习、科研、社会实践或实际工作表现等方面的情况；事业心、责任感、遵纪守法、协作性和心理健康情况；科研创新潜质等。</p>\n     <p>（3）外语测试。含外语听力测试、外语口语测试和专业外语测试等方面。由于全国统考初试外语中没有听力测试，各学院在复试中应特别加强对外语听力的考核。</p>\n     <p>（4）专业学位硕士研究生的复试还要突出对专业知识的应用和专业能力倾向的考查，加强对考生实践经验和科研动手能力等方面的考查。</p>\n     <p>（5）学院还可根据各自专业特点和培养需要提出复试其他学术要求，应提前对外公布。</p>\n     <p>4.考生在复试前应签订《复试考生诚信承诺书》，确保提交材料真实和复试过程诚信。</p>\n     <p>5.以同等学力参加复试的考生，应在复试中加试不少于两门与报考专业相关的本科主干课程，加试方式应为笔试，每门课程满分为100分，考试时长不少于120分钟。加试科目应与招生章程中公布的科目一致且不得与初试科目相同。加试课程不计入总成绩。加试结束后，考生的名单及成绩应报学校研究生院备案。同等学力考生的身份以初试网上报名时的信息为准。</p>\n     <p>6.学院应安排专人对考生进行思想政治素质和品德考核。考核的内容包括考生的政治态度、思想表现、工作学习态度、职业道德、遵纪守法等方面。考核结论分为“合格”与“不合格”。</p>\n     <p>7.工商管理（MBA）、公共管理（MPA）的政治理论考试在复试中进行，由相关学院组织实施，形式由学院根据具体情况自行确定，但应提前对考生公布，成绩计入复试总成绩。</p>\n     <p>（五）破格复试</p>\n     <p>学院在合格生源充足的情况下，一般不再破格复试；如确需破格复试，应在学院细则中明确。学院开展破格复试，必须符合《2025年全国硕士研究生招生工作管理规定》第五十一条之规定，且考生初试公共科目成绩较一区复试分数线单科差距在5分以内。破格复试人数不得超过学院全日制招生计划的3%。破格复试考生的申请，应经学院研究生招生工作领导小组集体研究同意后提请学校研究生招生工作领导小组审查，考生是否具有破格复试资格由学校报四川省教育考试院审核确定。</p>\n     <p>（六）时间安排</p>\n     <p>1.学院应在4月1日前完成第一志愿考生的复试，在4月20日前开展调剂工作并完成调剂考生的复试。</p>\n     <p>2.学院可结合自身情况，分批次开展研究生复试工作，时间安排应及时报学校研究生院，并在本学院网站公布。学院认为有必要时，可对相关考生再次复试。复试结束后学院应在24小时内公示复试成绩及结果，并将复试成绩及拟录取意见报送学校研究生院。</p>\n     <p>（七）体检</p>\n     <p>复试结束后，考生应在拟录取阶段向学院提交二级甲等及以上等级医院出具的体检报告，报告需加盖体检医院公章。考生体检项目和标准应按照《普通高等学校招生体检工作意见》（教学〔2003〕3号）和《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）的规定执行。</p>\n     <p>四、调剂</p>\n     <p>（一）基本要求</p>\n     <p>学院完成第一志愿复试后，根据招生计划和生源缺额情况确定可接收调剂考生的专业，并开展调剂工作。向学校提交调剂申请的考生应满足下列基本条件：</p>\n     <p>1.符合学校2025年硕士研究生招生章程中规定的调入专业的报考条件。</p>\n     <p>2.初试成绩（含加分）符合第一志愿报考专业所在学科门类的一区复试分数线。</p>\n     <p>3.调入专业与第一志愿报考专业相同或相近，应在同一学科门类范围内。</p>\n     <p>4.考生初试科目应与调入专业初试科目相同或相近，其中初试全国统一命题科目应与调入专业全国统一命题科目相同。</p>\n     <p>5.第一志愿报考照顾专业的考生若调出照顾专业，其初试成绩必须达到该照顾专业所在学科门类的一区初试成绩基本要求；第一志愿报考非照顾专业的考生若调入照顾专业，其初试成绩必须符合对应的非照顾专业所在学科门类的一区初试成绩基本要求。</p>\n     <p>6.第一志愿报考工商管理、公共管理、旅游管理、工程管理、会计、图书情报、审计专业学位的考生在满足工商管理（MBA）、公共管理（MPA）报考条件且初试成绩同时符合调出专业和调入专业一区初试成绩基本要求的前提下可调入学校工商管理（MBA）、公共管理（MPA），但不得调入其它专业；其它专业的考生不得调入工商管理（MBA）、公共管理（MPA）。</p>\n     <p>7.第一志愿报考法律（非法学）专业学位的考生不得调入学校其它专业，其它专业的考生也不得调入法律（非法学）。</p>\n     <p>（二）调剂程序</p>\n     <p>1.学院应在中国研究生招生信息网的“全国硕士生招生复试调剂服务系统”中公布接收调剂考生的专业、缺额信息及第一志愿专业范围。调剂系统开放（含多批次开放）的起止时间应提前对外公布，每次系统开放的持续时间不得低于12个小时。</p>\n     <p>2.考生应在国家规定的时间内登录“全国硕士生招生复试调剂服务系统”填报调剂志愿，学院应在相应批次调剂系统关闭后的12小时内发送是否同意考生参加复试的通知，考生应于复试通知发出后12小时内通过调剂系统回复是否同意参加复试。复试后，如调剂考生被学院确定为拟录取，其应在学院发送 “待录取通知”后的12小时内在调剂系统中确定是否接受。</p>\n     <p>3.学院不得将考生第一志愿报考单位、毕业院校、提交调剂志愿的时间先后顺序等非学业水平标准作为调剂考生的遴选依据。对申请同一招生单位同一专业、初试科目完全相同的调剂考生，学院应当按考生初试成绩择优遴选进入复试的考生名单并发送复试通知。</p>\n     <p>4.调剂考生与第一志愿考生持同一标准进行复试。</p>\n     <p>五、录取</p>\n     <p>（一）成绩核算方式</p>\n     <p>1.复试成绩</p>\n     <p>满分为100分，学院可根据专业特点确定各部分的成绩比例，原则上专业素质和能力测试成绩不少于30分，综合素质及能力测试成绩不少于30分，外语（含专业外语、听力和口语）成绩不少于30分。</p>\n     <p>2.考生入学考试总成绩</p>\n     <p>满分为100分，计算方式为“初试总成绩÷5（注：满分300分的科目此处为3）×权重1 +复试成绩（满分100分）×权重2”。</p>\n     <p>权重1、权重2应在学院复试细则中提前向考生公布。其中，权重1不得低于50%，权重2不得超过50%，具体权重由各学院自定（采用网络远程复试方式的专业，权重1应为70%，权重2应为30%）。</p>\n     <p>（二）录取规则</p>\n     <p>1.各专业根据复试批次按考生入学考试总成绩由高分到低分的顺序依次录取（“大学生士兵计划”、“立功表彰退役军人免试生”考生单独排序）。</p>\n     <p>2.当同一总成绩出现并列时，复试成绩高者优先；若同一复试成绩分数出现并列时，初试外语科目成绩高者优先。</p>\n     <p>3.学院研究生招生工作领导小组应对本学院拟录取名单进行审核，并报送至学校研究生招生工作领导小组。研究生拟录取名单经学校研究生招生工作领导小组审定后在研究生院网站（http://gs.swust.edu.cn/）上公示7日，公示无异议的由研究生院统一办理录检手续。经教育部录检合格的为正式录取的考生。</p>\n     <p>（三）有下列情况之一者，一律不得予以录取：</p>\n     <p>1.复试成绩未达到60分者；</p>\n     <p>2.同等学力考生加试科目任何一门成绩未达到60分者；</p>\n     <p>3.思想政治素质和品德考核不合格者；</p>\n     <p>4.体检不合格或未进行体检者；</p>\n     <p>5.报考资格不符合规定者（包括经考生确认的报考信息填写错误引起的）；</p>\n     <p>6.调剂考生未按要求在教育部调剂系统确认待录取者；</p>\n     <p>7.未通过学历（学籍）审核且未能在规定的日期前按要求提供认证材料者；</p>\n     <p>8.不能提供有效材料或提供虚假材料（包括经考生确认的报考信息），无论何时一经查实者；</p>\n     <p>9.其它不符合教育部、四川省招生规定者。</p>\n     <p>对在复试过程中有违规行为的考生，一经查实，即按照《国家教育考试违规处理办法》（教育部令第33号）、《普通高等学校招生违规行为处理暂行办法》（教育部令第36号）等规定严肃处理，取消录取资格，记入考生考试诚信档案。</p>\n     <p>六、入学复查</p>\n     <p>录取的新生入学后3个月内，学院应根据《普通高等学校学生管理规定》（教育部令第41号）和《西南科技大学研究生学籍管理规定》（西南科大发〔2021〕32号）的要求，对所有新生进行全面复查，复查不合格的，不予注册学籍或取消学籍；情节严重的，将移交有关部门调查处理。入学复查包含下列方面：</p>\n     <p>（一）报考资格复查</p>\n     <p>录取的新生报到时，学院通过审查新生提交的材料，再次核实学生是否满足研究生的报考及录取条件；个人相关信息要与复试信息库、复试录像资料和录取信息库进行核对。</p>\n     <p>（二）学业水平复查</p>\n     <p>录取的新生入校后，学院应组织学业水平复查，复查可采取笔试、面试、综合考核等方式进行。复查内容应根据学校2025年硕士研究生招生章程中招生目录规定的初/复试科目考察范围确定。</p>\n     <p>（三）健康状况复查</p>\n     <p>录取的所有新生都应在入学后根据学校统一安排到西南科技大学医院参加体检；各招生学院组织开展身心健康复查。</p>\n     <p>七、其他</p>\n     <p>（一）学校纪委全程监督学校硕士研究生招生复试及录取工作，监督电话：0816-6089051（纪委办公室）。学院纪委负责监督本学院的相关工作。监督检查人员应在不干扰正常复试工作的前提下，采取适当的措施现场督查复试工作。</p>\n     <p>（二）学校、学院参与复试录取工作的人员均应认真负责、严格保密，切实维护复试录取工作的公平公正。本年度有近亲属或利害关系人参加复试的教师和工作人员应主动回避，不得参加复试相关工作。对在复试录取工作中有违反国家有关法律法规和招生管理规定行为的单位及个人，一律按《普通高等学校招生违规行为处理暂行办法》（教育部令第36号）严肃处理，追究直接责任人员的责任，造成严重后果和恶劣影响的，还将按相关规定对有关责任人实行问责。</p>\n     <p>（三）学院要在本学院网站上开辟专栏，及时公布、公示复试工作细则、破格复试条件、调剂的原则和办法，各专业的招生计划，所有参加复试的考生名单（包括考生编号、初试成绩、复试成绩、考生入学考试总成绩）等重要信息。</p>\n     <p>（四）学院要保证投诉、申诉和监督管道的畅通。受理投诉和申诉应规定时限。对投诉和申诉问题经调查属实的，由学院研究生招生工作领导小组责成复试小组进行复议。</p>\n     <p>（五）本工作方案未尽事宜以教育部及四川省的规定为准。方案自发布之日起执行，由研究生院负责解释。</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chsi.com.cn/sswbgg/\" target=\"_blank\">网报公告</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\" target=\"_blank\">博士目录</a> <a href=\"https://yz.chsi.com.cn/help/\" target=\"_blank\">帮助中心</a>\n      </div>\n      <div class=\"aside-con-title\">\n       统考\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108-4.html\" target=\"_blank\">报名条件</a> <a href=\"https://yz.chsi.com.cn/yzwb/\" target=\"_blank\">网上报名</a> <a href=\"https://yz.chsi.com.cn/yzwb/#xcqr\" target=\"_blank\">网上确认</a> <a href=\"https://yz.chsi.com.cn/yzwb/#zkzxz\" target=\"_blank\">下载准考证</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">分数线</a> <a href=\"https://yz.chsi.com.cn/yztj/\" target=\"_blank\">调剂</a>\n      </div>\n      <div class=\"aside-con-title\">\n       推免\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">推荐系统</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/\" target=\"_blank\">申请指南</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/#bmlc\" target=\"_blank\">推免流程</a> <a hre