INSERT INTO `yl_guide` VALUES (114, '东华大学2025年硕士研究生招生复试与录取办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>东华大学2025年硕士研究生招生复试与录取办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2025年03月18日</span> <span>来源：东华大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>硕士研究生考试招生是国家选拔高层次创新型人才的重要途径，复试录取是硕士研究生考试招生的重要组成部分，是保证生源质量的基础环节。2025年研究生招生工作要以习近平新时代中国特色社会主义思想为指导，全面贯彻党的二十大和二十届二中、三中全会精神，深入学习贯彻全国教育大会精神，全面落实党的教育方针，坚持综合评价、择优录取，严格执行政策，严守工作纪律，规范录取行为，强化监督管理，优化考生服务，切实做好复试录取各项工作，确保公平、公正、科学。根据《教育部关于印发&lt;2025年全国硕士研究生招生工作管理规定&gt;的通知》（教学〔2024〕4号）《关于做好2025年全国硕士研究生复试录取工作的通知》（教学司〔2025〕4号）《上海市教育考试院关于印发&lt;2025年上海市硕士研究生复试录取工作指导意见&gt;的通知》（沪教考院社考〔2025〕4号）等要求，结合学校实际，特制订本办法。</p>\n     <p><strong>一、工作原则</strong></p>\n     <p>（一）坚持立德树人。始终坚持把立德树人成效作为检验研究生考试招生和培养工作的根本标准，牢固树立“考试招生育人”的理念，着力选拔培养社会主义事业合格建设者和可靠接班人。坚持德智体美劳全面衡量，以德为先，把考生思想品德考核作为复试的重要内容和录取的重要依据。遵循实事求是的原则，注重对学生政治态度、思想表现、道德品质、科学精神、诚实守信、遵纪守法等方面的考查，思想品德考核不合格者不予录取。</p>\n     <p>（二）坚持科学选拔。以提高选拔质量为核心，进一步改进和完善复试考核评价机制，加强对考生的全面考查和综合评价，提高复试的科学性和有效性，促进高层次拔尖创新人才脱颖而出。完善学术学位与专业学位分类选拔机制，合理设计复试内容。</p>\n     <p>（三）坚持公平公正。做到政策透明、流程规范、监督机制健全，维护考生的合法权益。</p>\n     <p>（四）坚持全面考查，突出重点。在对考生德智体美劳等各方面全面考查基础上，突出对创新能力、专业素养、综合素质等的考查，促进拔尖创新人才脱颖而出。</p>\n     <p>（五）坚持以人为本，增强服务意识，提高管理水平。</p>\n     <p><strong>二、组织领导</strong></p>\n     <p>（一）落实招生主体责任</p>\n     <p>学校研究生招生工作领导小组统一领导和统筹管理全校复试与录取工作。研究生招生工作领导小组要加强组织协调，统筹和推进研究生考试招生工作，严格执行“集体议事、集体决策、会议决定”的规程，审议决策考试招生重大事项等。研究生招生管理部门统一管理本单位研究生考试招生工作，统一审核复试、调剂、录取有关操作细则，统一发布调剂信息、统一监督巡查、统一审核调剂复试及录取名单、统一办理相关手续。</p>\n     <p>学校成立研究生招生监督复核工作小组。研究生招生监督复核工作小组成员由学校研究生招生工作领导小组、监察处和研究生招生办公室工作人员组成，对学院复试工作进行全面、有效监督，必要时通过抽查等方式复核学院的拟录取情况，确保招生复试录取公平公正、规范有序。</p>\n     <p>学校成立研究生招生突发事件应急管理领导小组。成员包括学校研究生招生工作领导小组、党委办公室、宣传部、研究生院、学生处保卫处负责人，处理复试突发事件确保相关工作安全稳定。</p>\n     <p>各学院成立院研究生招生工作小组，切实落实学院研究生复试录取工作主体责任。学院主要负责同志是第一责任人，要亲自把关、亲自协调、亲自督查；分管院长是直接责任人，要全程参与、全程组织、全程管理。招生工作小组一般由5-7人组成，由学院主要负责同志担任组长，负责制定学院复试方案和复试实施细则并组织实施。复试方案包括复试专家和工作人员遴选办法、命题管理办法和复试考试办法等。学院研究生招生工作小组名单和复试方案报研究生院备案，学院复试细则学校审核通过后对外发布。</p>\n     <p>（二）严肃工作纪律、加强队伍建设</p>\n     <p>各学院要加强复试录取政策和保密规定的培训，要做好复试录取环节的安全保密工作。学校任何部门和工作人员不得举办或参与举办考研辅导活动，相关命题人员不得参与任何与考研内容有关的咨询、考研复习资料编写、出版等活动。不得向社会培训机构提供举办考研辅导活动的场所和设施，严禁社会培训机构进入校园以张贴简章、广告等各种方式进行考研辅导培训的招生宣传和组织活动。</p>\n     <p><strong>三、复试</strong></p>\n     <p>复试是硕士研究生招生考试的重要组成部分，是保证选拔质量的重要环节。要加强对考生的专业素养、科研创新能力和综合素质等方面的考查。</p>\n     <p>学术学位硕士研究生与专业学位硕士研究生属同一层次的不同类型，根据教育部“分类复试、分别进行、各有侧重”的要求，各学院分别确定两类硕士研究生参加复试的考生名单，分别进行复试。</p>\n     <p>（一）精准划定专业分数线</p>\n     <p>全校复试差额比例原则上不低于1.2:1。合格生源比例不足的，按实际合格生源数组织复试。各学院根据学校下达的招生计划、学科特点及生源情况适当调整差额比例，在国家分数线基础上，精准确定各专业考生进入复试的初试成绩基本要求和复试名单。</p>\n     <p>（二）结合实际情况制定复试方式</p>\n     <p>各学院根据学校复试与录取工作的相关要求，结合学科特点和专业要求，自主确定复试方式，制定切实可行的学院复试实施细则，细化工作流程。可采取现场复试和网络远程复试，原则上同一招生学院的同一专业应采取相同复试方式。确需采用混合方式复试的专业，招生学院应统筹安排，确保不同复试方式的考试流程、导师组组成人员、选拔标准等的一致性和公平性。</p>\n     <p>（三）严格加强复试工作人员管理</p>\n     <p>学院要制定复试专家及工作人员遴选办法，选派责任心强、经验丰富、业务水平高、品行端正的人员参与复试工作。学院对所有人员进行政策、业务、纪律等方面的培训，提升政策意识、保密意识和责任意识，严格履行复试有关规章制度和相应职责，坚决杜绝工作人员自行其是、擅自调整或破坏规则。严禁复试专家和工作人员携带手机等通讯工具进入复试考场、中途离场或开展其他与复试无关的工作。要对复试全程进行录音录像，以备复查。</p>\n     <p>复试工作严格执行回避制度和保密制度，即：如有直系亲属、三代以内旁系亲属、近姻亲关系、其他亲属关系参加当次复试或存在其他利害关系可能影响当次复试公平公正的，复试专家和工作人员应当回避接触学院当次考试的命题、阅卷、复试、现场评分和录取等工作。如有以上范围人员参加其他学院的复试，要主动报备。凡参与命题、阅卷、复试、现场评分和录取工作的所有复试专家和工作人员，必须签署《东华大学2025年全国硕士研究生招生考试（复试）回避及安全保密承诺书》。</p>\n     <p>各学院确定复试专家选聘标准和要求，建设学院专家库，根据复试需要统筹使用专家库，随机抽取复试专家，报学院研究生招生工作小组审批。复试专家小组一般成员不少于5人，由责任心强、教学经验丰富、业务水平高、公道正派的副高级专技职务以上人员担任，组长原则上由学术带头人担任，复试专家小组的秘书应由专职教师担任。专业学位硕士研究生的复试专家小组可有一定比例的企业导师参与。招生人数较多的学科或学科面较宽的学科（领域），可组织若干复试专家小组，同一学科（专业）各复试小组的复试方式、时间、试题难度和成绩评定标准原则上应统一。复试专家小组成员负责具体组织实施对考生的面试工作，须现场集中，独立实名评分。要发挥和规范复试专家在复试选拔中的作用，加强复试专家遴选和培训，强化保密意识、责任意识和政治意识，并提高复试专家运用新技术、新手段科学规范选拔人才的能力。</p>\n     <p>（四）规范组织复试命题和考试</p>\n     <p>1.各学院应根据教育部、上海市教育考试院及学校相关文件制定学院复试命题管理办法和考试办法。复试试题包括笔试、面试试题，复试试题及其答案在启用前均系国家机密材料。</p>\n     <p>2.各学院研究生招生工作小组要加强对命题工作的指导。复试试题管理工作要按照初试自命题有关工作要求执行，原则上应命制多套试题，确保科学、规范、安全。严防三年内重复用题，杜绝泄题漏题，严禁出现复试“压分”现象，确保公平公正。</p>\n     <p>3.命题人员应为政治素质好、责任心强、教学经验丰富、学术水平较高并且近期承担教学工作的人员。命题人员原则上应具有副教授及以上职称或相当职称并具有硕士研究生招生考试命题经验。</p>\n     <p>4.试题（卷）由学院根据不同复试方式、学科专业特点和办学特色自主合理设计，要确保科学有效、公平公正。采取远程复试的，应尽可能采用综合性、开放性试题。</p>\n     <p>5.试题（卷）由学院相关负责同志随机抽取，并报学院研究生招生工作小组审批。</p>\n     <p>6.考试应由学院研究生招生工作小组统一组织实施。相关负责同志牵头组建考务人员队伍。统一进行考务培训，使相关工作人员熟悉有关规章制度和纪律，明确具体任务和职责。</p>\n     <p>7.考试原则上应在标准化考场内进行，如因特殊原因在非标准化考场内进行，必须在考场内架设录音录像设备，并全程录音、录像。</p>\n     <p>（五）科学设计复试内容</p>\n     <p>1.考核内容</p>\n     <p>各学院在复试时，以程序规范、科学选拔、提高质量为核心，进一步改进和完善复试考核评价机制。完善学术学位与专业学位分类选拔机制，学术学位重点考核考生的学术素养、对学科知识掌握与运用情况、科研创新能力，专业学位重点考核考生的专业基础、实践能力和职业素养。根据学科特点和专业要求，由学院合理设计复试内容，复试阶段可综合运用笔试、面试、实验、实践操作等方式，主要考核考生专业素质和潜力、综合素质和能力。</p>\n     <p>（1）专业素质和潜力</p>\n     <p>通过大学阶段学习成绩、毕业论文、科研成果等材料，全面考查考生的专业能力，同时加强对专业外语能力的考核。</p>\n     <p>（2）综合素质和能力</p>\n     <p>思想政治素质和道德品质等的考查。</p>\n     <p>本学科（领域）以外的学习、科研、社会实践（学生工作、社团活动、志愿服务等）或实际工作表现等方面的情况。</p>\n     <p>事业心、责任感、纪律性（遵纪守法）、协作精神、创新意识、道德水准、情商、性格、人格特征、人文素养、行为举止、语言表达、礼仪等综合素质。</p>\n     <p>2.复试时间</p>\n     <p>预计安排在三月中下旬至四月上旬，每位考生的复试时间一般不少于20分钟，考生明确表示已作答完毕的可提前结束考核。</p>\n     <p>3.复试成绩、总成绩</p>\n     <p>复试成绩满分为220分，总成绩＝初试成绩＋复试成绩。</p>\n     <p>以同等学力参加复试的考生，在复试中须加试至少两门与报考专业相关的本科主干课程。加试方式为笔试，加试科目不得与初试科目相同，加试不合格者不予录取。</p>\n     <p>学院在工商管理、公共管理、会计、工程管理专业学位复试中组织思想政治理论考试，成绩计入复试成绩。学院在复试中组织外国语听力及口语测试，成绩计入复试成绩。</p>\n     <p>（六）严格复试组织管理</p>\n     <p>1.复试资格审查</p>\n     <p>各学院要严把复试入口关，指定专人负责考生的资格审查。考前，要采取“两识别”（人脸识别、人证识别）、“四比对”（报考库、学籍学历库、人口信息库、诚信档案库数据比对）等措施（网报时学历或学籍验证未通过者，须提供学历或学籍验证报告），加强对复试考生的身份审核及报考专项计划、申请享受初试加分、申请免初试的资格审核，严防“替考”。</p>\n     <p>2.加强复试监管</p>\n     <p>各学院需与考生逐一签订《诚信复试承诺书》，确保提交材料真实和复试过程诚信。对在复试过程中有违规行为的考生，一经查实，即按照《国家教育考试违规处理办法》《普通高等学校招生违规行为处理暂行办法》等规定严肃处理，取消录取资格，记入《考生考试诚信档案》。入学后3个月内，可按照《普通高等学校学生管理规定》有关要求，对所有考生进行全面复查。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p>各学院建立健全“随机选定考生次序”“随机确定考核组人员”“随机抽取复试试题”的“三随机”工作机制。加强复试过程监管，确保公平公正。学院对复试过程要全程录音录像，以备复查。采用现场复试的，要确保安全、有序。采取远程复试的，要采用必要的技术手段和管理措施提高防范水平，提前研究防范通过AI技术作弊的有效措施。复试过程要加强台账记录，并及时整理、分类、汇总。</p>\n     <p>3.依照教育部文件规定，如有必要，可对相关考生再次复试。对需进一步考查的考生经学校研究生招生工作领导小组审核后，由学校组织专家组进行再次复试。</p>\n     <p>（七）及时公布复试结果</p>\n     <p>复试结束后，学院在规定时间内告知考生复试结果。</p>\n     <p><strong>四、调剂</strong></p>\n     <p>学院在非全日制第一志愿合格生源不足时，可组织开展调剂工作。开展调剂的学院应当按照教育部有关政策、上海市相关文件规定以及本校学科建设和发展需要，坚持“公平、公正、公开”的原则，科学、规范制定调剂工作办法。严禁任何教职员工和学生未经学校授权擅自发布调剂信息。调剂考生初试成绩须符合第一志愿报考专业在调入地区的全国初试成绩基本要求，并符合调入专业的报考条件。原则上，调剂考生第一志愿专业与调入专业相同相近，或初试科目与调入专业初试科目相同相近。</p>\n     <p>各学院要坚持以质量为核心，认真制定学院的调剂细则。调剂工作由学校统一管理，统一审核学院调剂细则、统一发布调剂信息、统一监督巡查、统一审核调剂复试及录取名单、统一办理相关手续。</p>\n     <p>各学院在规定的时间内尽可能缩短考生调剂等待时间，务必在规定时间内及时向考生反馈是否接受其调剂复试申请。学院根据申请调剂考生的初试成绩择优确定进入复试的考生名单。</p>\n     <p>调剂复试工作必须通过教育部指定的“全国硕士生招生复试调剂服务系统”进行（https://yz.chsi.com.cn或https://yz.chsi.cn），严禁通过其他渠道接受考生调剂申请，或以“预调剂”“采集考生调剂意向”等为名变相开展调剂工作。严禁以考生所在单位、行业、领域、学校层次类别等非学业水平标准限定调剂生源范围，严禁设置歧视性调剂条件。未通过该调剂系统调剂录取的考生一律无效。</p>\n     <p><strong>五、录取</strong></p>\n     <p>各学院按照学校下达的招生计划开展录取工作，录取人数不得超过下达的招生计划。分别确定全日制学术学位硕士研究生、全日制专业学位硕士研究生、非全日制专业学位硕士研究生拟录取名单。</p>\n     <p>各专业（领域或方向）按照总成绩排序，第一志愿和第二志愿分列，从高分到低分依次录取，总成绩相同的按初试成绩从高分到低分录取。复试成绩不合格者、面试成绩不合格者不予录取。</p>\n     <p>符合下列条件之一后3年内报名参加全国硕士研究生招生考试的考生，可申请享受初试总成绩加10分，同等条件下优先录取：</p>\n     <p>1.参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”项目之一，服务期满且考核合格。</p>\n     <p>2.退役大学生士兵达到全国硕士研究生招生考试报考条件。</p>\n     <p>申请享受初试加分的考生，须在网上报名时按要求填报相关信息。有关部门按职责分工进行审核。未按规定申报或审核未通过的，不享受加分政策。加分项目不累计。</p>\n     <p>参加我校前一年暑期学校、夏令营或优才计划并符合条件的本科应届生，享受学院相应的优惠政策。</p>\n     <p>思想政治素质和品德考核是保证入学新生质量的重要工作环节，主要考核考生本人的现实表现，内容包括考生的政治态度、思想表现、道德品质、科学精神、遵纪守法、诚实守信等方面。学院可在复试时通过面谈，直接了解考生思想政治情况，也可采取“函调”或“派人外调”的方式对考生的思想政治素质和品德考核。将考生诚信状况作为思想品德考核的重要内容和录取的重要依据。思想品德考核不合格者不予录取。</p>\n     <p>各学院研究生招生工作小组集体讨论，确定拟录取名单，并对结果负责。</p>\n     <p>拟录取为定向就业的研究生，应当签署协议书。</p>\n     <p>全日制考生的招生体检与新生入学体检合并，在新生报到后的三个月新生复查期间进行体检。如体检不合格则依据相关规定取消入学资格或作其他学籍处理。体检标准参照《教育部、卫生部、中国残疾人联合会关于印发&lt;普通高等学校招生体检工作指导意见&gt;的通知》（教学〔2003〕3号）和《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）文件要求，考生需依据文件标准自行评估身体状况，如有不合格情况应如实申报，凡因未诚信申报、新生入学复查体检不合格影响入学的，后果由考生本人承担。</p>\n     <p>严格按照相关规定，严肃查处违规违纪行为。对在报考、复试、录取过程中有违规行为的考生，一经查实，严肃处理，取消录取资格，记入《考生考试诚信档案》。</p>\n     <p><strong>六、监督与复议</strong></p>\n     <p>实行责任制度和责任追究制度。校研究生招生工作领导小组对复试过程的公平、公正和复试结果全面负责。学院研究生招生工作小组全权负责本学院的复试过程，处理复试录取过程中随时可能出现的问题，并及时通报有关情况。复试期间，应增强复试录取工作透明度，坚决抵制不正之风。</p>\n     <p>实行监督制度和巡视制度。学校及学院健全监督检查制度，加强对复试录取工作方案、组织过程、招生计划变动、调剂政策执行、信息公开情况等重要事项的监督检查。研究生招生监督复核工作小组对复试录取工作进行全面监督，加强对学院的培训、指导和对复试全流程进行监督，采用现场参与、线上旁听、调阅复试情况等方式加强复试检查。成绩复核严格把关，绝不允许出错和违规更改。</p>\n     <p>实行复议制度。保证投诉、申诉和监督渠道的畅通，对投诉和申诉问题经调查属实的，由校研究生招生工作领导小组责成学院研究生招生工作小组组织专家进行复议。</p>\n     <p><strong>七、信息公开</strong></p>\n     <p>学校和学院应按照教育部和上海市有关政策要求和“谁公开、谁把关”“谁公开、谁解释”的原则，做好研究生招生信息公开工作。</p>\n     <p>招生计划公开。按照招生简章公布的招生计划，并结合教育部下达学校的招生计划开展招生工作。</p>\n     <p>复试录取办法公开。及时公布学校进入复试的初试成绩基本要求、复试与录取办法和各学院复试实施细则、复试安排、复试招生人数等信息。</p>\n     <p>录取信息公示与公开。拟录取名单由学校统一公示，公示期为7个工作日。</p>\n     <p><strong>八、考生服务</strong></p>\n     <p>加强政策宣传解读。结合学校复试工作安排，综合运用各类媒体特别是新媒体，做好相关政策的宣传解读；及时、准确解读我校复试工作方案的内容和相关要求，特别是复试时间、方式、流程等安排，让社会和考生充分知晓，确保复试组织工作顺畅有序。</p>\n     <p>加强考生咨询服务。畅通考生联系咨询通道，安排专人受理考生咨询，及时为考生答疑解惑。加强对考生参加远程复试工作的指导，向考生详细介绍有关面试平台使用办法、复试流程和相关要求等。发布需考生确认拟录取或复试通知时，需充分考虑考生学习、工作、休息时间等因素做出合理安排，给考生预留充足的确认时间。对于没有按时确认的考生，应通过电话、短信、邮件等方式逐一联系确认，不得简单以“逾期不接受视为自行放弃”对待。</p>\n     <p>做好兜底支持保障。强化人性化关怀和个性化安排，积极采取有效措施，加强对贫困地区考生、残疾考生等特殊群体的关爱帮扶。</p>\n     <p><strong>九、应急处置与舆情应对</strong></p>\n     <p>学校和学院健全突发事件应急管理机制，学校成立研究生招生突发事件应急管理领导小组，全面梳理复试环节，主动排查，精准识别其中的每一个风险点，制订风险隐患台账，完善复试期间发生各类突发事件的应急处置预案，并认真组织模拟演练。采取远程复试的，学院要对复试平台的适用性、安全性、可靠性和稳定性等功能进行充分评估、测试和完善，并做好备用网络及复试平台紧急使用准备；以适当形式提前组织考生、复试考核人员和工作人员进行模拟演练，熟练掌握工作流程和平台使用，确保复试过程安全、顺畅、稳定。健全舆情监测机制，强化舆情监测处置。对涉及研究生复试录取的苗头性舆情信息，要第一时间进行调查核实、解释说明、澄清声明，及时回应社会关切，及早消除负面影响，避免形成舆情事件。一旦发生重大舆情事件，要迅速启动多部门会商机制，快速妥善处置，并第一时间报告上级部门。</p>\n     <p>如教育部或上海市有新文件精神，按新文件精神执行。</p>\n     <p>本方案由研究生院负责解释。</p>\n     <p>招生办公室电话：021-62373355</p>\n     <p>招生办公室邮箱：gs@dhu.edu.cn</p>\n     <p>监督和举报电话：021-67792259</p>\n     <p>监督举报邮箱：jwjc@dhu.edu.cn</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chsi.com.cn/sswbgg/\" target=\"_blank\">网报公告</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\" target=\"_blank\">博士目录</a> <a href=\"https://yz.chsi.com.cn/help/\" target=\"_blank\">帮助中心</a>\n      </div>\n      <div class=\"aside-con-title\">\n       统考\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108-4.html\" target=\"_blank\">报名条件</a> <a href=\"https://yz.chsi.com.cn/yzwb/\" target=\"_blank\">网上报名</a> <a href=\"https://yz.chsi.com.cn/yzwb/#xcqr\" target=\"_blank\">网上确认</a> <a href=\"https://yz.chsi.com.cn/yzwb/#zkzxz\" target=\"_blank\">下载准考证</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">分数线</a> <a href=\"https://yz.chsi.com.cn/yztj/\" target=\"_blank\">调剂</a>\n      </div>\n      <div class=\"aside-con-title\">\n       推免\n      </div>\n      <