INSERT INTO `yl_guide` VALUES (121, '安徽中医药大学：2024年硕士研究生复试录取办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>安徽中医药大学：2024年硕士研究生复试录取办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2024年03月29日</span> <span>来源：安徽中医药大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>为深入贯彻党的二十大精神，全面落实党的教育方针，根据教育部、安徽省有关文件精神和要求，统筹做好2024年硕士研究生复试录取工作，确保招生工作安全平稳、公平公正，结合我校实际，制定本办法。</p>\n     <p><strong>一、组织领导</strong></p>\n     <p>学校成立由校领导牵头，招生、纪检监察、宣传、网络信息、后勤保障等相关职能部门和二级培养单位负责同志为成员的研究生招生工作领导小组和突发事件应急管理领导小组， 领导全校硕士研究生招生录取工作，负责相关研究生招生工作的审议决策和统筹协调及各类突发事件的应急处置和调度。下设办公室，办公室设在研究生院，负责招生日常工作。学校成立复试工作督查工作组，对复试录取工作进行全过程监督。</p>\n     <p>各培养单位成立相应的招生复试工作领导小组。切实落实研究生复试工作主体责任，加强对复试录取工作的领导，贯彻执行招生政策和规定，认真研究制定本培养单位复试工作办法实施细则，并负责组织实施。</p>\n     <p><strong>二、工作原则</strong></p>\n     <p>全面贯彻《2024年全国硕士研究生招生工作管理规定》及相关招生政策，坚持德智体美劳全面衡量，择优录取，严格执行复试程序和要求；坚持立德树人，着力加强对考生的思想政治素质和品德考核；坚持能力、素质与知识考核并重，突出对考生专业素质、创新能力的考查；坚持以提高选拔质量为核心，促进高层次拔尖创新人才脱颖而出。</p>\n     <p>按照以人为本原则，加强统筹协调，维护师生安全，增强服务意识，确保应考尽考，维护考生合法权益。认真落实招生信息公开相关要求，做好信息公开公示工作，确保招生公开、公平、公正。</p>\n     <p><strong>三、复试工作安排</strong></p>\n     <p>（一）复试方式：详见各培养单位复试工作办法实施细则，请考生密切关注我校研究生院网站的相关通知。</p>\n     <p>（二）复试资格：</p>\n     <p>一志愿生源充足的专业原则上按照1:1.2的比例划定分数线，进行差额复试，具体分数线另行公布。其他专业执行国家划定的A类线。</p>\n     <p>报考“退役大学生士兵”专项计划的考生，单科成绩须达到国家划定的A类线，总分按照国家划定A类线降10分划线。</p>\n     <p>符合加分政策的考生，加分后达到报考专业的复试线可进入复试。加分政策按照《2024年全国硕士研究生招生工作管理规定》执行。</p>\n     <p>（三）复试时间</p>\n     <p>第一批（一志愿考生复试）：预计4月2日开始，具体日程由各培养单位根据实际情况安排，请考生密切关注我校研究生院网站的相关通知。</p>\n     <p>调剂复试：预计4月上旬开始，有缺额专业开始接收调剂。调剂专业信息在研究生院网站及中国研究生招生信息网分别发布。调剂考生的复试时间，另行通知。</p>\n     <p>（四）复试资格审核</p>\n     <p>各培养单位负责考生的资格审核，复试前加强对考生身份的审查核验，对不符合规定者，不予复试。</p>\n     <p>1.复试考生报到、复试资格审查等由各培养单位自行组织实施，具体在培养单位招生工作领导小组指导下进行。</p>\n     <p>2.严格考生报考资格审查。考生复试时须携带材料到各培养单位接受审查（现场查验原件，复印件存档），资格审查材料不齐全或审查不合格的考生不予复试。</p>\n     <p>考生须提供材料参考如下：（具体以报考学院复试办法要求为准，请考生密切关注我校研究生院网站发布的各培养单位复试工作方案实施细则）</p>\n     <p>1.复试费缴费凭证（具体要求另行公布）</p>\n     <p>2.身份证明材料</p>\n     <p>（1）有效期内的身份证原件及复印件。</p>\n     <p>（2）准考证（中国研究生招生信息网可下载）。</p>\n     <p>3.学历学位证明材料</p>\n     <p>（1）往届生须提交有效期内的教育部学历证书电子注册备案表、学历学位证书原件及复印件、加盖公章的本科阶段成绩单。</p>\n     <p>（2）应届生须提交有效期内的教育部学籍在线验证报告和每学期均已注册的学生证、加盖公章的本科阶段成绩单</p>\n     <p>（3）尚未毕业，但承诺在录取当年9月1日前可取得国家承认本科毕业证书的自学考试和网络教育本科生，须提交颁发毕业证书的省级高等教育自学考试办公室或网络教育高校出具的相关证明。</p>\n     <p>4.考生诚信复试承诺书</p>\n     <p>考生本人签名的《诚信复试承诺书》（从研究生院网站“下载中心”-“招生工作”栏目下载）。</p>\n     <p>5.其他相关材料</p>\n     <p>（1）政审表（从研究生院网站“下载中心”-“招生工作”栏目下载）。</p>\n     <p>（2）退役大学生士兵入伍批准书和退出现役证。</p>\n     <p>（3）报考中医专硕的成人本科考生须提交中医执业医师资格证原件及复印件；报考全科医学的定向考生，提交单位同意报考的意见书。</p>\n     <p>（4）培养单位要求的其他材料（以各培养单位最后的通知要求为准）。</p>\n     <p>（五）复试内容及组织管理</p>\n     <p>复试的内容：专业课、英语听力及口语水平测试、专业能力面试及思想品德考核。</p>\n     <p>复试由各硕士学位授权点所在培养单位负责组织，成绩满分100分，达到60分为合格。</p>\n     <p>复试小组工作基本规范：复试工作执行“随机确定考生复试次序”、“随机确定导师组组成人员”、“随机抽取复试试题”的“三随机”工作机制。考生人数较多的可随机分组，或按报考方向分组复试，由培养单位确定。复试全程录音录像。</p>\n     <p>每生面试时间不少于20分钟。</p>\n     <p>（六）成绩计算及排序</p>\n     <p>1.复试成绩计算办法由各培养单位确定。</p>\n     <p>2.总成绩计算</p>\n     <p>总成绩＝初试总成绩／5×60%＋复试成绩<span style=\"text-wrap: wrap;\">×</span>40%</p>\n     <p>3.排序：按照总成绩高低，分专业对一志愿考生和调剂考生分别排序，依次录取。总成绩一致时，按复试成绩高低排序，数值一般保留小数点后两位，必要时按照小数点后三位、四位排序。</p>\n     <p>（七）调剂</p>\n     <p>考生在规定时间内通过中国研究生招生信息网“调剂服务系统”申请，具体调剂复试办法另行公布。</p>\n     <p><strong>四、体检事宜</strong></p>\n     <p>考生体检标准参照教育部、卫生部、中国残疾人联合会制订的《普通高等学校招生体检标准工作指导意见》（教学[2003]3号）及《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）执行。</p>\n     <p>拟录取名单公示后，考生按照我校公布的体检项目到当地三级以上医院体检，在规定时间内向所在培养单位提交体检报告。</p>\n     <p><strong>五、录取</strong></p>\n     <p>研究生院根据复试结果及招生计划确定拟录取名单，报学校招生领导小组审核后上传研招网。在研究生院网站公示10天后，将拟录取名单通过“全国硕士研究生招生信息公开平台”上报审核备案。</p>\n     <p>复试成绩不合格者不予录取。未通过或未完成学历（学籍）审核的考生不列入拟录取名单公示或者上报。已接受其他招生单位“待录取”的考生，视为放弃我校录取资格。对弄虚作假及考试违规、作弊的考生，无论何时核查确定，一律按照《国家教育考试违规处理办法》和《普通高等学校学生管理规定》等严肃处理，取消录取资格。经考生确认的报考信息在录取阶段一律不作修改，对报考资格不符合规定者不予录取。</p>\n     <p><strong>六、联合培养研究生复试事宜</strong></p>\n     <p>各联合培养单位派复试小组到我校组织复试工作。</p>\n     <p>上海药物所和皖西学院联合培养研究生复试工作，由药学院负责帮助完成。</p>\n     <p>合肥综合性国家科学中心大健康研究院研究生复试工作，由新安医学与中医药现代化研究所负责帮助完成。</p>\n     <p>中外双导师联合培养专项计划硕士研究生，从2024年录取硕士研究生中选拔，学生向培养单位提出申请，选择此专项招生计划的导师，由培养单位组织评审后确定人选。其中校内导师当年带教研究生人数限额可予以适当放宽，具体以2024级硕士研究生与导师双选工作文件为准。</p>\n     <p>安徽高等研究院校企联合科研与人才培养专项计划硕士研究生，从2024年录取硕士研究生中选拔，学生向培养单位提出申请，选择此专项招生计划的导师，由培养单位组织评审后确定人选。</p>\n     <p><strong>七、入校须知</strong></p>\n     <p>1.考生须凭本人身份证和准考证入校（本校考生可以直接刷校园卡出入）。与复试无关的人员及车辆一律不准进入学校。</p>\n     <p>2.考生如有携带行李等与考试无关的随身用品，均不可以带入考场内。建议不要携带过多行李进入校园。</p>\n     <p><strong>八、复试费用</strong></p>\n     <p>根据安徽省物价主管部门核定标准，所有参加我校复试的考生需缴纳复试费人民币60元，具体缴费方法另行通知，请考生密切关注我校研究生院网站的相关通知。考生复试期间所有食宿费用自理。</p>\n     <p><strong>九、其他</strong></p>\n     <p>研究生院对分专业招生计划、复试名单、初试成绩、复试成绩、拟录取名单等按要求统一进行公示。</p>\n     <p>各培养单位的复试工作办法实施细则由培养单位的复试工作领导小组负责解释。本复试办法由学校研招办负责解释，未尽事宜由学校研究生招生工作领导小组研究决定。</p>\n     <p><strong>十、咨询、监督联系方式</strong></p>\n     <p>研究生院招生办</p>\n     <p>电话：0551-68129404，邮箱：yzb@ahtcm.edu.cn</p>\n     <p>学校纪委</p>\n     <p>电话：0551-68129047，邮箱：azyjw@ahtcm.edu.cn</p>\n     <p>地址：安徽省合肥市新站区龙子湖路350号</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <