INSERT INTO `yl_guide` VALUES (122, '安徽理工大学：2024年硕士研究生招生复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>安徽理工大学：2024年硕士研究生招生复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2024年03月27日</span> <span>来源：安徽理工大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>根据教育部、教育厅相关文件精神，为做好我校2024年硕士研究生复试录取工作，结合学校实际，制订本办法。</p>\n     <p><strong>一、组织领导</strong></p>\n     <p>（一）成立由学校主要负责同志为组长，分管负责同志为副组长，宣传部、纪委办、学生处、研究生院、保卫处、总务部等职能部门负责同志为成员的研究生招生复试录取工作领导小组和突发事件应急管理领导小组（以下简称领导小组），负责执行教育部、教育厅关于招生工作的政策、规定和办法，根据上级主管部门要求，审定学校分专业招生计划及复试录取工作办法并组织实施，负责复试录取期间的组考、舆情等各类突发事件的应急处置和调度。领导小组办公室设在研究生院，负责组织协调复试录取相关工作。成立复试录取工作督查组，对研究生复试、录取工作进行全程监督检查。</p>\n     <p>（二）各招生学院（含联合培养单位，下同）成立研究生招生工作小组，负责对本学院硕士研究生招生工作实施领导和监督，制定本学院复试录取工作实施细则（以下简称“实施细则”）并组织实施，指导复试小组进行相应考核工作。按学科（专业）成立复试小组，负责具体实施面试和综合能力等考核。</p>\n     <p><strong>二、复试分数线和复试差额</strong></p>\n     <p>（一）各学院按照教育部公布的《2024年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》（以下简称“国家线”），结合本单位生源和招生计划等情况，自主确定本单位进入复试的初试成绩基本要求，并在学院网站公布。</p>\n     <p>（二）学校下达学院分专业招生计划，并加强对学院分专业招生计划的管理，已公布的招生计划不得随意调整。若某专业调剂生源不足，经校领导小组研究同意，可根据实际调整，调整后的分专业计划需重新公布。</p>\n     <p>（三）实行差额复试，差额比例原则上不低于120%，学院根据各学科专业特点及生源情况确定差额复试比例，报学校研究生招生办公室备案后公布并执行。学校领导小组研究确定各专业一志愿考生复试名单，并在学校研招网公布；学院、学校逐级审核调剂考生报考资格，集体研究择优确定调剂复试考生名单并在学校研招网、学院网站公布。</p>\n     <p>（四）“退役大学生士兵专项计划”在《2024年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》基础上，各考试科目满分合计为500分的考生，按学科门类总分不低于一区国家分数线20分、单科不低于一区国家分数线5分确定复试分数线；各考试科目满分合计为300分的考生，按学科门类总分不低于一区国家分数线12分、单科不低于一区国家分数线3分确定复试分数线，复试名单将在学校研招网公布。</p>\n     <p><strong>三、复试方式和复试时间</strong></p>\n     <p>（一）复试方式：原则上采用线下现场复试。</p>\n     <p>（二）复试时间：一志愿复试：2024年3月30日-4月3日；调剂复试：2024年4月10日-4月15日。</p>\n     <p>具体复试方式及复试时间由各学院制定报研究生院备案，并在学院网站发布复试实施细则。</p>\n     <p><strong>四、复试组织</strong></p>\n     <p><strong>（一）前期准备</strong></p>\n     <p>1.制定复试录取实施细则。学院负责按照学校要求，研究制定包括组织领导、复试导师遴选培训、复试原则和办法、过程监管机制、命题及保密纪律、咨询及申诉渠道等内容的实施细则，初步拟定于3月28日前以正式文件提交研招办，经学校审定后方可对外公布。</p>\n     <p>2.加强复试导师遴选培训。学院要发挥和规范导师在复试选拔中的作用，加强导师遴选和培训，强化保密意识、责任意识和法治意识，并提高导师科学规范选拔人才的能力。</p>\n     <p><strong>（二）</strong><strong>考生报到</strong></p>\n     <p>接到我校复试通知的考生，需在中国研究生招生信息网进行复试确认。考生按时到校（报考学院）报到，提交有关材料，参加学校统一组织的复试。</p>\n     <p>第一志愿达线考生由招生学院通知；调剂考生需在中国研招网“调剂系统”及时回复由学校研招办发送的复试通知。进入复试名单经学校研究生招生工作领导小组审核通过后，在学校研究生招生网对外公布。</p>\n     <p><strong>（</strong><strong>三</strong><strong>）资格审查</strong></p>\n     <p>考生在复试期间须携带以下材料到报考学院进行资格审查。各学院指定专人负责，严格把关，对考生的材料原件及报考资格进行认真审查。</p>\n     <p>1.身份证原件及复印件；</p>\n     <p>2.2024年全国硕士研究生考试初试准考证；</p>\n     <p>3.《安徽理工大学2024年硕士研究生招生政审表》填写完整盖章、《安徽理工大学2024年硕士研究生诚信复试承诺书》阅读并签字；</p>\n     <p>4.学生证原件及复印件（应届生提供）；</p>\n     <p>5.学历、学位证书原件及复印件（往届生提供）；</p>\n     <p>6.学籍学历在线认证报告（研招网下载PDF电子版）；</p>\n     <p>7.大学期间成绩单（须有学校教务部门盖章）；</p>\n     <p>8.复试时尚未取得本科毕业证书的自考和网络教育考生，须出具颁发毕业证书的省级高等教育自学考试办公室或网络教育高校出具的相关证明；</p>\n     <p>9.近期免冠照片2张；</p>\n     <p>10.考生本人认为有必要的其它材料（如科研成果及获奖证明材料等）；</p>\n     <p>11.《入伍批准书》和《退出现役证》原件及复印件（退役大学生士兵计划考生提供）；</p>\n     <p>12.加分证明材料原件及复印件（符合教育部加分政策考生提供）；</p>\n     <p>13.我校非全日制硕士研究生只招收在职定向就业人员，复试时需提供相关工作证明。</p>\n     <p>未进行或未通过资格审查的考生一律不予复试，对弄虚作假者，取消其录取资格。录取入学后3个月内，按要求对所有考生进行资格复查，复查不合格则取消学籍。</p>\n     <p><strong>（</strong><strong>四</strong><strong>）调剂复试</strong></p>\n     <p>调剂复试工作要严格按照全国硕士研究生招生管理规定确定的考生调剂基本条件和要求，以及学校确定公布的调剂工作办法开展。各招生专业的调剂缺额信息，将根据复试录取实际持续更新发布；所有调剂考生必须通过教育部“全国硕士研究生招生考试调剂服务系统”进行调剂，否则不能录取。</p>\n     <p>学校根据调剂考生的学业情况，综合考虑初试成绩及科目、报考专业、本科专业、培养潜质等因素，确定调剂考生复试名单。对申请同一招生单位同一专业、初试科目完全相同的调剂考生，应当按考生初试成绩择优遴选进入复试的考生名单。调剂专业如有特殊要求，学院须提前在对外发布的复试录取工作实施细则中明确，并在研招网调剂系统备注说明。</p>\n     <p>各学院要坚持以质量为核心，依据教育部和省内相关要求，按照“专业相同相近、初试科目相同相近”的基本原则，结合专业实际情况，制订并提前公布本单位调剂办法。严禁以考生第一志愿报考单位、毕业院校、提交调剂志愿的时间先后顺序等非学业水平标准作为遴选依据，严禁以考生所在单位、行业、地域、学校层次类别等非学业水平标准限定调剂生源范围，严禁设置具有歧视性质的调剂条件。调剂工作办法须报学校研究生招生工作领导小组审定，其中涉及考生第一志愿专业范围等学术要求的，须先经学院学位评定委员会或学术委员会审校同意，确保科学性。</p>\n     <p><strong>（</strong><strong>五</strong><strong>）复试内容</strong></p>\n     <p>各招生学院要进一步改进和完善复试考核评价机制，提高复试的科学性和有效性，促进高层次拔尖创新人才脱颖而出。要完善学术学位与专业学位分类选拔机制，合理设计复试内容，学术学位重点考核考生对学科知识的掌握与运用情况以及其学术创新潜力，专业学位重点考核考生的综合实践素质、运用专业知识分析解决实际问题能力以及职业发展潜力。根据选拔需要，复试阶段可综合运用笔试、面试、实验、实践操作等方式。复试内容由招生学院根据不同学科专业特点自主确定，并在复试录取工作实施细则中明确。可通过考生大学学习成绩单、毕业论文、科研成果、专家推荐信等补充材料，加强对考生既往学业、一贯表现、科研能力、综合素质和思想品德等情况的全面考查。提前组织专家命制好充足的试题，并采取有效措施防止试题外泄，应尽可能采用综合性、开放性的能力型试题，提倡学院建立复试试题库。报考人数较多的人文社科类专业可以考虑采用无领导小组讨论等方式进行复试。考生笔试答卷、面试录音录像及各种复试材料，由各学院妥善保存备查，保存期不少于6个月。</p>\n     <p><strong>1.专业笔试</strong></p>\n     <p>笔试分为复试科目和加试科目。复试科目1门，满分100分，成绩计入复试总成绩；同等学力加试科目2门，满分均为100分。加试内容不得与初试及专业课复试科目相同。加试成绩不计入复试总成绩，任一科目低于60分不予录取。</p>\n     <p><strong>2.外语测试</strong></p>\n     <p>外语水平测试由各招生学院自行组织，要求测试考生的听力、阅读、翻译、语言表达等方面的能力，条件不具备的学院可以申请外国语学院教师予以协助。外语水平测试总成绩100分，计入复试总成绩。</p>\n     <p><strong>3.综合面试</strong></p>\n     <p>综合面试按学校统一规范要求，由招生学院负责组织。按照“三随机”原则，复试开始前，学院要以抽签方式随机确定考生复试次序及分组，面试时考生随机抽取试题，面试时间不少于20分钟；学院随机确定面试导师分组人员，每个小组成员不少于5人（均应具有副高以上专业技术职称），小组成员须现场独立评分，面试情况要有书面记录，评分记录和考生作答情况等要交招生单位集中统一保管，任何人不得改动。综合面试满分100分，计入复试总成绩。面试全程须录音录像。</p>\n     <p><strong>4.其他内容</strong></p>\n     <p>各招生学院根据学科专业特点，可增加其他复试方式。学院认为有必要时，可对相关考生再次复试。工程管理类别硕士需加试的思想政治理论等科目包含在该部分考核内容中。推荐免试生和往年申请保留入学资格考生，已参加过复试的，不再参加本次复试。</p>\n     <p><strong>（</strong><strong>六</strong><strong>）体检、心理测试</strong></p>\n     <p>体检工作由学校在考生录取进校后统一组织进行（具体要求入学报到时另行通知），不参加体检或体检不合格者，按教育部《2024年全国硕士研究生招生工作管理规定》明确的有关规定处理。心理测试的具体形式和时间另行通知。</p>\n     <p><strong>（</strong><strong>七</strong><strong>）复试成绩和考生总成绩</strong></p>\n     <p>1.复试成绩满分100分。包括复试专业笔试成绩（或以其他方式考核成绩代替）、外语测试成绩、综合面试成绩，按3：3：4的权重计算。</p>\n     <p>2.考生总成绩满分100分。按以下公式计算：总成绩＝（初试总成绩/5）×0.7+复试总成绩<span style=\"text-wrap: wrap;\">×</span>0.3；工程管理、公共管理类别各专业总成绩＝（初试总成绩/3）<span style=\"text-wrap: wrap;\">×</span>0.7+复试总成绩<span style=\"text-wrap: wrap;\">×</span>0.3。</p>\n     <p><strong>五、录取</strong></p>\n     <p>招生学院于该复试批次结束后3个工作日内，上报并公布复试结果，各专业从高分到低分择优确定拟录取名单，并同时确定拟录取类别；报送《复试情况表》《复试和拟录取情况汇总表》等材料。</p>\n     <p>学院按照学校下达的招生计划开展录取工作，拟录取人数不得超过下达的招生计划。分别确定全日制学术学位硕士研究生、全日制专业学位硕士研究生、非全日制硕士研究生拟录取名单。</p>\n     <p>各专业（领域）按照总成绩排序，第一志愿和调剂考生分列，从高分到低分依次录取，总成绩相同的按初试成绩从高分到低分录取。</p>\n     <p>有下列情形之一的考生不予录取：复试成绩低于60分者；综合面试成绩低于60分者；同等学力加试科目考试成绩低于60分者；思想品德考核不合格者或体检不合格者；资格审查未通过或提供虚假信息者。</p>\n     <p><strong>六、有关要求</strong></p>\n     <p>（一）实行责任制、责任追究制度和回避制度。要切实落实学校、学院的主体责任，主要负责人是第一责任人，分管负责人是直接责任人。学院研究生招生工作小组全权负责本学院的复试过程，解决复试录取过程中随时可能出现的问题，并及时通报有关情况。凡有直系亲属参加复试的人员，不得参加与复试及录取有关的工作。</p>\n     <p>（二）实行监督制度和巡视制度。督查组负责根据复试安排，安排相关人员对复试工作进行全面、有效监督，坚决抵制和防止复试中的徇私舞弊行为，确保公平公正。校巡视组到面试现场巡视，加强监管，以确保复试工作的顺利进行。</p>\n     <p>（三）实行复议制度。保证投诉、申诉和监督渠道的畅通，对投诉和申诉问题经调查属实的，由学校领导小组责成学院研究生招生工作小组或复试小组进行复议。</p>\n     <p>（四）加强政策宣传解读。学院要结合本学院复试工作安排，综合运用各类媒体特别是新媒体，做好相关政策的宣传解读。要及时、准确解读本学院复试工作实施细则的内容和相关要求，特别是复试时间、方式、流程等安排，让社会和考生充分知晓，确保考生复试组织工作顺畅有序。</p>\n     <p><strong>七、信息公开公示</strong></p>\n     <p>深入落实研究生招生录取信息公开，在学校和院系两级网页上开设专栏，经本单位研究生招生工作领导小组审核通过后，对本校或院系的复试、调剂、录取工作办法、招生计划安排及调整、复试考生信息、拟录取信息等应公开的招生录取信息，要严格按照规定准确、规范、充分、及时予以公开。特别是要加大对专项计划、加分或者照顾政策、单独考试等情况的信息公开力度。拟录取名单公示时间不少于10个工作日，公示期间不得修改，名单如有变动，须对变动部分作出说明，并对变动内容另行公示10个工作日。</p>\n     <p><strong>八、咨询及监督联系方式</strong></p>\n     <p>联系电话：0554-6632915（纪委办）;0554-6668749（领导小组办公室）。</p>\n     <p>邮箱：jiwei@aust.edu.cn（纪委办）；yjszb@aust.edu.cn（领导小组办公室）。</p>\n     <p><strong>九、本办法由领导小组办公室负责解释，未尽事宜由领导小组讨论决定。</strong></p>\n     <p>附件（https://yjszs.aust.edu.cn/info/1013/1412.htm）：</p>\n     <p>安徽理工大学2024年硕士研究生招生政审表</p>\n     <p>安徽理工大学2024年硕士研究生诚信复试承诺书</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n    