INSERT INTO `yl_guide` VALUES (123, '云南农业大学：2024年硕士研究生招生复试录取办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>云南农业大学：2024年硕士研究生招生复试录取办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2024年03月27日</span> <span>来源：云南农业大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>硕士研究生考试招生是国家选拔高层次专门人才的重要途径，复试是硕士研究生招生考试的重要组成部分。为切实做好2024年硕士研究生招生复试录取工作，确保公平、公正、科学，根据《2024年全国硕士研究生招生工作管理规定》（教学〔2023〕2号）文件要求，结合学校实际，制定本办法。</p>\n     <p><strong>一、指导思想</strong></p>\n     <p>以立德树人为根本任务，牢固树立“考试招生也是育人”的理念，着力选拔培养社会主义事业合格建设者和可靠接班人。坚持德智体美劳全面衡量，以德为先，把考生思想品德考核作为复试的重要内容和录取的重要依据，加强对考生的全面考查和综合评价。以选拔质量为核心，坚持学术学位与专业学位分类选拔机制。学术学位重点考核考生对学科知识的掌握与运用情况以及其学术创新潜力，专业学位重点考核考生的综合实践素质。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p>（一）按照教育部《2024年全国硕士研究生招生工作管理规定》，学校成立由主要领导牵头、校内有关部门负责人参加的研究生招生工作领导小组，负责按照教育部和云南省招生考试院有关招生规定和办法，充分考虑学校各方面情况和因素，认真研究确定复试办法，并开展招生复试督察工作。</p>\n     <p>（二）各学院组成院级研究生招生工作领导小组，领导小组由学院院长、主管研究生工作的负责人、学院纪检监察委员及相关人员组成，负责制定学院的《复试录取实施细则（方案）》，并在“中国研究生招生信息网”的“招生信息公开”栏和学校研究生处网站发布，指导复试小组开展具体考核工作，同时负责处理招生过程中考生提出的质疑和申诉。</p>\n     <p>（三）根据学科、专业实际情况，成立若干复试小组，复试小组设组长1名，组长一般由1名教授担任，对本组的复试工作负责。每个复试小组一般不少于5人，负责实施对考生的实验（实践）能力测试和面试考核。小组成员须现场独立评分、现场统分，并由复试小组成员及计分员签字确认，评分记录和考生作答情况交研究生招生办公室集中统一保管，任何人不得改动。各学院要按《云南农业大学研究生招生复试工作人员职责与行为规范》（研政发〔2020〕7号），选派经验丰富、业务水平高、公道正派的人员参与复试工作，并对复试教师进行业务和纪律培训，提高教师的学术评价能力和自律意识。</p>\n     <p>复试小组成员由学院研究生招生考试工作领导小组审定后，报学校研究生处备案。</p>\n     <p>（四）由学校纪检监察部门和研究生处组成研究生招生复试工作检查小组，负责对全校各学院研究生调剂、复试和录取工作各个环节的监督检查，严格执行责任制度和责任追究制度，确保复试过程的公平、公正，维护复试录取工作的权威性和严肃性。</p>\n     <p><strong>三、复试分数线</strong></p>\n     <p>学校严格执行教育部《2024年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》（学术学位类和专业学位类），各学院在国家分数线基础上，结合生源情况、招生计划、学科专业要求等方面情况，按照一般不低于招生计划120%、不高于150%的比例，自主确定各招生学科专业（领域）考生进入复试的初试成绩基本要求（专业复试分数线），不得出台歧视性或其他有违公平的规定。“退役大学生士兵计划”等专项计划考生进入复试的初试成绩要求由学校统一划定，计划单列。</p>\n     <p><strong>四、复试安排及相关要求</strong></p>\n     <p>（一）复试时间与方式</p>\n     <p>复试时间：第一志愿考生复试安排在3月下旬，第一志愿考生复试录取工作应于4月8日前完成，具体复试时间由学院自行安排。</p>\n     <p>调剂考生的复试录取工作将于4月8日后，通过“全国硕士研究生招生调剂服务系统”分批组织调剂考生复试、录取及发送待录取通知等相关调剂录取工作。原则上应于4月28日前（含）完成。</p>\n     <p>复试方式：现场复试。</p>\n     <p>（二）资格审查</p>\n     <p>复试前，各学院要对考生有效居民身份证、学历学位证书、学历（学籍）核验结果、学生证等材料原件及考生资格进行严格审查，对不符合规定者，不予复试。对考生的学历（学籍）信息有疑问的，学院应当要求考生在规定时间内完成学历（学籍）材料的完善、验证。</p>\n     <p>少数民族考生身份以报考时查验的身份证为准，复试时不得更改。少数民族地区以国务院有关部门公布的《全国民族区域自治地方简表》为准。</p>\n     <p>符合教育部相关规定，且享受研究生招生加分政策后达到招生学院复试分数线的考生，于复试前联系招生学院并提交相关证明材料，报学校审核通过后，准予参加复试。</p>\n     <p>按照教育部相关规定，在部队荣立二等功以上的退役人员，符合全国硕士研究生招生考试报考条件的，可申请免初试攻读硕士研究生。复试前须向招生学院提交相关证明材料，报学校审核通过后，准予参加复试。复试综合成绩不合格者不予录取。</p>\n     <p>参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“赴外汉语教师志愿者”等项目服务期满、考核合格的考生，3年内参加全国硕士研究生招生考试的，初试总分加10分，同等条件下优先录取。</p>\n     <p>退役大学生士兵达到报考条件后，3年内参加全国硕士研究生招生考试，初试总分加10分，同等条件下优先录取。报考（含调剂）“退役大学生士兵”专项计划的，不享受退役大学生士兵初试加分政策。</p>\n     <p>参加“选聘高校毕业生到村任职”项目服务期满、考核称职以上的考生，3年内参加全国硕士研究生招生考试的，初试总分加10分，同等条件下优先录取，其中报考人文社科类专业研究生的，初试总分加15分。</p>\n     <p>加分项目不累计，同时满足两项以上加分条件的考生按最高项加分。</p>\n     <p>（三）复试内容</p>\n     <p>复试内容应包括专业能力考核和综合素质考核两部分。专业能力考核包括专业课笔试和外语听说能力测试；综合素质考核包括实验（实践）能力测试和综合面试。各学院要根据不同学科专业特点和办学特色自主合理设计，应尽可能采用综合性、开放性试题，坚决杜绝泄题风险。具体复试内容由各学院（硕士点）自主确定并负责组织实施。</p>\n     <p>以同等学力参加复试的考生，在复试中须加试至少两门与报考专业相关的本科主干课程。加试科目不得与初试科目相同。加试方式为笔试。加试科目成绩不计入拟录取总成绩，加试科目不及格者不能录取。报考法律硕士（非法学）、工商管理硕士、公共管理硕士、工程管理硕士或旅游管理硕士的同等学力考生可以不加试。</p>\n     <p>对成人教育应届本科毕业生及复试时尚未取得本科毕业证书的自考和网络教育考生，招生学院可自主确定是否加试，相关办法应在学院招生实施方案中提前公布。</p>\n     <p>会计硕士、图书情报硕士、工商管理硕士、公共管理硕士、旅游管理硕士、工程管理硕士和审计硕士的思想政治理论考试由招生学院在复试中进行，成绩计入复试总成绩。</p>\n     <p>1.专业能力考核</p>\n     <p>专业课和外语听说能力测试由各学院自行组织，专业课考试采用闭卷笔试，满分为100分。外语听说能力测试，内容包含：语言的准确性、话语的长短和连贯性、语言的灵活性和适应性等，满分为100分。</p>\n     <p>2.综合素质考核</p>\n     <p>（1）实验（实践）能力测试。对理工科、农科考生主要测试其实验和动手操作的能力；对文科类考生主要测试其理论联系实际和解决问题的能力。实验（实践）能力测试可采用笔试、操作或面试方式进行。</p>\n     <p>（2）综合面试由考生当场作答。考核内容应涉及考生政治态度、思想表现、道德品质、科学精神、诚实守信、遵纪守法等方面，思想品德考核不合格者不予录取。每位考生的面试时间一般不少于20分钟，面试情况要有记录，面试过程要全程录音录像。综合面试由各专业复试小组负责考核，面试成绩满分为100分，面试成绩由每位复试小组成员独立给出分数，然后取平均值得出考生的面试成绩，面试结束后由学院如实填写《云南农业大学2024年硕士研究生招生考试复试情况表》。</p>\n     <p>（3）复试试题包括笔试、面试和实践能力考核试题。各学院要参照《全国硕士研究生招生考试自命题工作指导规范》、《云南农业大学研究生入学考试自命题工作管理办法》（研政发[2015]30号）,组织各专业（领域）复试科目的试题命制。复试试题及其答案在启用前均系国家机密材料。</p>\n     <p><strong>五、组织实施</strong></p>\n     <p>各学院要采取切实有效措施，加强复试过程规范管理，特别是要强化复试试题管理，充分考虑组考方式、复试人数、学科专业特点等，提前命制好充足试题，严防试题外泄；建立健全“随机确定考生复试次序”“随机确定导师组成员”“随机抽取复试试题”的“三随机”工作机制。</p>\n     <p>充分发挥和规范导师在复试选拔中的作用，加强导师遴选和培训，强化保密意识、责任意识和法治意识，并提高导师运用新技术、新手段、科学规范选拔人才的能力。招生学院要与考生逐一签署《诚信复试承诺书》，确保提交材料真实和复试过程诚信，在招生单位复试工作结束前不得对外透露或传播复试试题内容等有关情况。要采取灵活有效的方式，加强复试过程监管，严防复试弄虚作假、徇私舞弊。依照《2024年全国硕士研究生招生工作管理规定》，招生学院认为有必要时，可对相关考生再次复试。</p>\n     <p>各学院要严格按照相关规定，严厉打击各类考试作弊行为，严肃考风考纪，严肃查处违规违纪行为。对复试过程中有违规行为的考生，一经查实，即按照《国家教育考试违规处理办法》《普通高等学校招生违规行为处理暂行办法》等规定严肃处理，取消录取资格，记入《考生考试诚信档案》。</p>\n     <p><strong>六、调剂工作</strong></p>\n     <p>（一）调剂程序</p>\n     <p>招生学院在第一志愿合格生源不足时，可组织开展调剂工作，调剂相关信息须报研究生处审核后，由研究生处在“全国硕士生招生复试调剂服务系统”和研究生处网站公布。各学院在自主确定并公布的专业分数线基础上，结合调剂考生缺额情况，自主确定考生进入复试的初试成绩要求及其他学术要求。对某些第一志愿生源不足、未能达到专业（领域）招生计划的学科（类别），可以在校内外合格生源中进行调剂录取，调剂的生源必须达到教育部复试的相应要求，调剂考生必须参加拟录取专业组织的复试。</p>\n     <p>各学院要以学科建设和发展需要为基础，坚持“公平、公正、公开”的原则，科学、规范制订调剂工作办法，由研究生处审核后在“全国硕士生招生复试调剂服务系统”和研究生处网站公布。学院调剂工作办法应明确接受考生调剂的时间、基本要求（含考生第一志愿专业范围、初试科目、初试成绩要求等，其中初试成绩含加分）、工作程序、复试办法（含考生进入复试的遴选规则）、咨询渠道等信息，报学校招生工作领导小组审定，其中涉及考生第一志愿专业范围等学术要求的，须先经学校学位评定委员会或学术委员会审核同意，确保科学性。</p>\n     <p>研究生处统一管理学校调剂工作，统一审核学院调剂细则、统一发布调剂信息、统一监督巡查、统一审核调剂复试及录取名单、统一办理相关手续。</p>\n     <p>（二）调剂原则</p>\n     <p>1.调剂考生初试成绩须符合第一志愿报考专业在调入地区的全国初试成绩基本要求，并符合调入专业的报考条件。考生调入专业应与第一志愿报考专业相同或相近，且在同一学科门类范围内（可授不同学科门类学位的专业可跨门类在对应专业所属一级学科范围内进行调剂）。初试科目与调入专业初试科目相同或相近，其中初试全国统一命题科目应与调入专业全国统一命题科目相同（考生初试统考科目涵盖调入专业所有统考科目的，视为相同）。</p>\n     <p>2.学院要规范制订调剂考生进入复试的遴选规则，不得将考生第一志愿报考单位、毕业院校、提交调剂志愿的时间先后顺序等非学业水平标准作为遴选依据。对申请同一招生单位同一专业、初试科目完全相同的调剂考生，招生学院应当按考生初试成绩择优遴选进入复试。</p>\n     <p>3.报考照顾专业（指工学照顾专业、体育学、体育硕士，教育部将根据国家战略需要、社会发展需求、考生报考情况等因素适时调整，下同）的考生若调剂出本类照顾专业，其初试成绩必须达到调入地区该照顾专业所在学科门类的全国初试成绩基本要求。</p>\n     <p>报考非照顾专业的考生若调入照顾专业，其初试成绩必须符合调入地区对应的非照顾专业所在学科门类的全国初试成绩基本要求。</p>\n     <p>工学照顾专业之间，体育学与体育硕士之间调剂，按本类照顾专业全国初试成绩基本要求执行。</p>\n     <p>4.报考工商管理、公共管理、旅游管理、工程管理、会计、图书情报、审计专业学位硕士的考生，在满足调入专业报考条件、且初试成绩同时符合调出专业和调入专业在调入地区的全国初试成绩基本要求的基础上，可申请相互调剂，但不得调入其他专业；报考其他专业的考生不得调入以上专业。</p>\n     <p>5.报考“退役大学生士兵”专项计划的考生，申请调剂到普通计划，其初试成绩须达到调入地区相关专业所在学科门类的全国初试成绩基本要求。符合条件的，可按规定享受退役大学生士兵初试加分政策。</p>\n     <p>报考普通计划的考生，若符合“退役大学生士兵”专项计划报考条件，可申请调剂到该专项计划，其初试成绩须符合相关招生单位确定的接受“退役大学生士兵”专项计划考生调剂的初试成绩要求。对于“退役大学生士兵”专项计划和普通计划之间的调剂，招生单位须严格按照调剂程序和要求组织，不得直接改变考生志愿、调整计划类型进行复试录取。</p>\n     <p>6.报考法律（非法学）专业学位硕士的考生不得调入其他专业，其他专业的考生也不得调入该专业。</p>\n     <p>7.报考“少数民族高层次骨干人才计划”的考生不得调剂到该计划以外录取；未报考的不得调剂入该计划录取。</p>\n     <p>8.参加单独考试（含强军计划、援藏计划）的考生不得调剂。</p>\n     <p>9.各学院通过“全国硕士生招生复试调剂服务系统”自主设定调剂系统持续时间、考生调剂志愿锁定时间等，并在时间安排上为考生提供合理便利。其中，每次开放调剂系统持续时间不得低于12小时，考生调剂志愿锁定时间不得超过36小时。锁定时间到达后，如学院未明确受理意见，系统自动解除锁定，考生可继续填报其他志愿。</p>\n     <p>招生学院发布需考生确认拟录取或复试通知时，需充分考虑考生学习、工作、休息时间等因素作出合理安排，给考生预留充裕的确认时间。对于没有按时确认的考生，招生学院应通过电话、短信、邮件等方式逐一联系确认，不得简单以“逾期不接受视为自行放弃”对待。</p>\n     <p><strong>七、录取</strong></p>\n     <p>（一）所有拟录取考生必须经过复试所有环节。在学校研究生招生工作领导小组的统一领导下，按照教育部和云南省招生考试院有关招生录取的政策规定，根据2024年硕士招生计划、复试办法、考生初试和复试成绩、思想政治表现、身心健康状况等，全面衡量择优确定拟录取名单。复试不合格者不予录取，对复试后未被录取的考生，学院要及时通知考生本人。</p>\n     <p>（二）录取时按照同一学院、同一学科（类别）对考生拟录取总成绩从高到低进行排序，若成绩相同，则按照复试成绩从高到低排序。初试总成绩占拟录取总成绩的权重为60%，复试总成绩权重为40%。复试总成绩为复试各方式考核成绩之和。</p>\n     <p>拟录取总成绩=(初试总成绩&amp;divide;N)&amp;times;60%+(复试总成绩&amp;divide;3)&amp;times;40%</p>\n     <p>（当初试总成绩为500分时，N为5；当初试总成绩为300分时，N为3）。</p>\n     <p>（三）对有特殊才能和突出贡献的考生，如在各项国际或省部级及以上大赛中获奖，或在相关领域发表过较高水平学术论文，录取时予以优先考虑。</p>\n     <p><strong>八、复试纪律和要求</strong></p>\n     <p>（一）复试小组成员和工作人员要选择能正确执行招生政策、不徇私情、责任心强的教师担任。本年度有直系亲属报考或有其他原因可能影响公正的相关人员应回避复试及录取的相关工作。</p>\n     <p>（二）高度重视参与研究生复试、招生人员的管理和培训，自觉接受社会监督，提高自我约束的自觉性；加大研究生招生工作的透明度，抵制不正之风的干扰，营造研究生招生工作的公正、公平环境。对违反研究生招生政策，造成不良影响的招生人员将按有关规定严肃处理。</p>\n     <p>（三）各研究生招生学院务必严格按照学校规定的复试录取程序、要求和时间表进行操作，不得擅自随意变更。</p>\n     <p>（四）研究生招生工作涉及面广、政策性强，各学院务必严格执行国家政策与学校相关规定，不得超越国家和学校招生政策的规定和权限自定招生办法。</p>\n     <p><strong>九、复试监督</strong></p>\n     <p>（一）加大信息公开力度。各招生学院要按规定准确、规范、充分、及时报送复试实施细则、复试名单、录取名单等招生录取信息，并公布学院监督举报电话，按照“谁公开、谁把关”，“谁公开、谁解释”的原则，做好对所公开信息的把关和解释工作。</p>\n     <p>（二）加强校院二级巡视。学校成立由学校研究生招生工作领导小组成员构成的若干巡视小组，学院成立由学院研究生招生工作领导小组成员构成的若干巡视小组，在不干扰正常复试工作的前提下，通过现场、录像巡查、抽查等方式，加强对复试录取工作全流程特别是关键环节、关键岗位和关键人员的监管，严肃考风考纪，及时纠正复试录取不规范行为，严防弄虚作假、徇私舞弊。</p>\n     <p>（三）强化复试监督检查。招生学院纪检委员要做好本学院的复试录取监督工作，同时接受招生过程中违规违纪行为的举报。校纪委做好监督的再监督工作，同时接受招生过程中违规违纪行为的举报。</p>\n     <p>（四）严格落实复试责任制。所有参与复试录取的工作人员都要认真负责，严格保密，切实维护复试录取工作的公平公正，对弄虚作假、徇私舞弊的工作人员要追究责任。</p>\n     <p><strong>十、其他事项</strong></p>\n     <p>本办法由学校研究生招生办公室负责解释，如与教育部或教育主管部门公布的最新政策有出入，以教育部和教育主管部门公布的政策为准。</p>\n     <p><strong>联系方式：</strong></p>\n     <p>地址：云南省昆明市盘龙区黑金路95号云南农业大学东校区耕读楼附楼126研究生招生办公室</p>\n     <p>联系电话：（0871）65228283</p>\n     <p>电子邮箱：10676yjszb@aliyun.com</p>\n     <p>各招生学院联系方式：https://yjs.ynau.edu.cn/info/1012/3665.htm</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a h