INSERT INTO `yl_guide` VALUES (125, '成都大学：2024年硕士研究生招生复试录取工作方案', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>成都大学：2024年硕士研究生招生复试录取工作方案</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2024年03月27日</span> <span>来源：成都大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>为切实做好我校2024年硕士研究生招生复试工作，根据《教育部关于印发〈2024年全国硕士研究生招生工作管理规定〉的通知》（教学〔2023〕2号）、《教育部关于加强硕士研究生招生复试工作的指导意见》（教学〔2006〕4号）、《四川省高等教育招生考试委员会四川省教育厅关于做好我省2024年硕士研究生招生复试和录取工作的通知》（川招考委〔2024〕6号）和《成都大学硕士研究生招生复试录取工作办法》（成大研〔2024〕2号）等文件精神，结合我校实际，特制定本工作方案。</p>\n     <p><strong>一、招生复试原则</strong></p>\n     <p>1.以习近平新时代中国特色社会主义思想为指导，深入贯彻党的二十大精神，全面落实党的教育方针，坚持综合评价、择优录取，加强督导和检查，严格管理，稳妥做好我校2024年硕士研究生招生复试录取工作。</p>\n     <p>2.坚持“德智体美劳全面衡量，以德为先”的原则，注重对学生政治态度、思想表现、道德品质、科学精神、诚实守信、遵纪守法等方面的考查。</p>\n     <p>3.坚持科学选拔、客观评价，树立科学的人才选拔理念，突出对考生创新能力、专业素养和综合素质的考查，促进拔尖创新人才脱颖而出。</p>\n     <p><strong>二、组织管理</strong></p>\n     <p>1.学校成立研究生招生工作领导小组，负责对全校研究生招生复试及拟录取工作的领导和统筹管理。下设研究生招生办公室，在学校研究生招生工作领导小组的领导下，全面负责全校研究生招生考试、复试、拟录取工作的管理、协调和统筹工作。</p>\n     <p>2.学校成立研究生招生工作督查组，由分管研究生招生的校领导任组长，纪委办公室和研究生处为成员单位，负责全程监督、巡视、检查各学院硕士研究生招生复试工作情况。</p>\n     <p>3.各招生学院成立本学院的研究生招生复试领导小组。负责本单位研究生招生复试各项工作的具体实施。精心组织，科学遴选并培训复试工作人员（含复试专家），协调院内复试工作所需要的人员、场地、设备、经费保障等，并对复试工作负责解释。</p>\n     <p>4.各招生学院成立由学院书记任组长、包括纪检相关工作人员的硕士研究生招生复试录取督查组，切实履行复试工作期间的监督、巡视、检查职责。</p>\n     <p>5.各招生学院根据专业特点，结合实际需求成立1个或多个复试小组，具体实施对考生的全面考核。每个复试小组至少由5名人员组成，包括相关学科专业的硕士生导师3名及综合素质考核人员。各学位点要对复试小组人员进行保密和招生政策的学习培训，切实加强复试人员的责任感，确保复试的公平公正性。</p>\n     <p><strong>三、复试的基本要求</strong></p>\n     <p>1.考生进入复试的初试成绩基本分数要求按《成都大学2024年硕士研究生招生复试分数线》标准，上线考生均可参加我校2024年硕士研究生招生复试。</p>\n     <p>2.学校采取差额复试的办法，全校差额比例不低于120%。</p>\n     <p>3.以同等学力参加复试的考生，需满足学校招生章程中同等学力报考条件，复试时还必须加试两门本科主干课程，加试科目不得与初试科目相同。报考法律硕士（非法学）、工商管理硕士的同等学力考生可以不加试。</p>\n     <p>4.建立复议制度，各招生学院要认真对待和妥善处理考生的申诉和投诉，对考生的申诉，研究生招生复试录取督查组进行复核，并及时对考生反馈复核意见，复核的有关资料要存档备查。</p>\n     <p>5.根据《教育部 中国残联关于印发&lt;残疾人参加普通高等学校招生全国统一考试管理规定&gt;的通知》（教学〔2017〕4号）文件精神，学校对残疾考生复试提供便利条件，学校研究生招生工作领导小组审核残疾考生的便利条件申请并及时告知相关考生。</p>\n     <p><strong>四、复试时间及方式</strong></p>\n     <p>1.复试时间。我校复试录取工作于3月下旬启动，在4月20日前完成本年度复试及拟录取工作。</p>\n     <p>2.复试方式。现场复试，复试中坚持“三随机”（随机确定考生次序、随机确定导师组组成人员、随机抽取复试试题）等管理方式，加强复试过程监管，确保公平公正。</p>\n     <p>3.各专业具体复试工作安排以各招生学院的复试工作通知为准，请考生及时关注报考学院的公告信息，保持通讯畅通。</p>\n     <p><strong>五、复试内容</strong></p>\n     <p>1.思想品德考核：考核内容包括考生的政治态度、思想表现、道德品质、科学精神、诚实守信、遵纪守法等方面，思想品德不合格者不予录取。</p>\n     <p>2.专业课测试：总分100分，具体形式由各招生学院根据学科专业特点确定。会计硕士、工商管理硕士的思想政治理论考试在专业课测试中进行，占比不低于专业课测试总分的20%。对同等学力考生须加试至少两门不同于初试科目的本科主干课程，每门加试科目试卷满分为100分。</p>\n     <p>3.综合面试：总分100分。①外语能力测试：重点考查考生外语听说水平，总分40分。②专业综合面试：重点考察学生专业综合素质能力、创新精神等，总分60分。经批准免除外语听力、口语测试的残疾考生以专业综合面试总分100分计入综合面试成绩。面试时间一般不少于20分钟，具体时间可由复试专家组根据复试情况适当调整。</p>\n     <p><strong>六、复试流程</strong></p>\n     <p>1.资格审查。各招生学院负责复试考生的身份查验，考前严格采取“两识别”（人脸识别、人证识别）、“四比对”（报考库、学籍学历库、人口信息库、诚信档案库数据比对）等措施加强考生身份审核。对考生的居民身份证、学历学位证书、学历学籍核验结果、学生证等报名材料原件及考生资格进行严格审查，对不符合教育部规定报名资格者，不予复试。</p>\n     <p>2.缴纳复试费用。按照《四川省发展和改革委员会 四川省财政厅关于重新发布全省教育系统考试考务行政事业性收费的通知》（川发改价格规〔2022〕484号文件）的规定，每名参加我校2024年硕士研究生招生复试的考生须交纳复试费120元/生，同等学力须另收加试科目考试费80元/生。</p>\n     <p>3.各招生学院组织复试。通过资格审查的考生，持本人居民身份证、准考证、复试通知单、缴费凭证，到相应学院的对应复试小组参加复试。各复试小组应对复试内容进行详细记录，认真填写考生复试表；对复试过程进行全程录音录像，资料留存学院（一年以上），同时报研究生处以备查验。</p>\n     <p>4.体检。所有通过复试并取得拟录取资格的考生均须体检。考生应在拟录取名单公示期结束后五日内，在二级甲等以上医院完成体检，并按学校要求进行材料报送。体检标准按《普通高等学校招生体检工作指导意见》（教学〔2003〕3号）和《教育部办公厅、卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）执行。</p>\n     <p><strong>七、调剂工作</strong></p>\n     <p>1.一志愿生源上线人数不足或经复试后合格生源不足的专业可适当接收考生调剂复试，调剂复试在该专业一志愿复试完成后进行。</p>\n     <p>2.所有考生调剂必须通过中国研究生招生信息网“调剂服务系统”进行，未通过该系统调剂录取的考生一律无效。</p>\n     <p>3.我校开放、关闭调剂系统时间请关注学校研究生处网页通知。每次开放调剂系统持续时间不少于12个小时。对申请同一招生单位同一专业、初试科目完全相同的调剂考生，学校按考生初试成绩择优遴选进入复试的考生名单，不以考生提交调剂志愿的时间先后顺序等非学业水平标准作为遴选依据。</p>\n     <p>4.调剂程序：</p>\n     <p>第一步：发布调剂公告。学校根据各专业生源情况确定接收调剂专业，在学校研究生处网站发布调剂公告，明确考生第一志愿专业范围、初试科目、初试成绩要求、开放申请时间等。</p>\n     <p>第二步：考生申请。拟调剂考生通过中国研究生招生信息网“调剂服务系统”提交申请。</p>\n     <p>第三步：通知复试。我校每次开放调剂系统持续时间不低于12个小时。学校根据调剂考生的初试成绩情况，结合考生综合信息，择优遴选进入复试的考生名单，通过硕士研究生调剂服务系统给考生发放复试通知。考生调剂志愿锁定时间30小时以内，锁定时间到达后，申请考生未收到通知，调剂志愿会自动解除，考生可继续填报其他志愿。</p>\n     <p>第四步：调剂复试。考生接到同意复试通知后，应及时在“调剂服务系统”点击“同意复试”。拟调剂考生回复确认我校的复试通知后即可参加学校组织的复试。</p>\n     <p>第五步：拟录取工作。调剂考生通过我校的复试考试后，学校通过“调剂服务系统”向拟录取调剂考生发送“待录取”通知。调剂考生应在学校发出待录取通知后，及时选择“同意待录取”或“拒绝待录取”，考生选择其中任一项后原则上均不能再做更改，录取结果以调剂系统确认为准。如调剂考生在我校发出待录取通知后，考生未在待录取通知规定时间内完成确认待录取状态，在学校电话联系后仍不完成确认待录取，视为考生自动放弃，一切后果考生自行负责。</p>\n     <p><strong>八、拟录取工作</strong></p>\n     <p>1.复试成绩总分为200分。专业课测试、综合面试成绩之和为复试成绩，专业课测试成绩低于60分或综合面试成绩低于60分均视为复试不合格，不予录取。</p>\n     <p>2.同等学力考生加试的两门主干课程不计入总成绩，加试成绩单科60分为合格线，单科不及格者不予录取。</p>\n     <p>3.思想品德考核是保证入学新生质量的重要工作环节，考核不合格者不予录取。</p>\n     <p>4.体检不合格者不予录取。</p>\n     <p>5.考生入学考试总成绩计算（四舍五入，保留小数点后两位）：</p>\n     <p>①初试总分500：总成绩=(初试总分÷5)*50%+(复试总分<span style=\"text-wrap: wrap;\">÷</span>2)*50%；</p>\n     <p>②初试总分300：总成绩=(初试总分<span style=\"text-wrap: wrap;\">÷</span>3)*50%+(复试总分<span style=\"text-wrap: wrap;\">÷</span>2)*50%。</p>\n     <p>6.各专业按第一志愿考生和调剂考生分别排名，以考生总成绩从高分到低分进行拟录取。在入学考试总成绩相同的情况下（小数点后两位），初试总分较高的考生优先录取。若初试成绩相同，则按照初试业务课一、业务课二、外语科目的顺序逐一比较单科成绩，择优录取，若通过前述内容仍不能确定录取人选时，由学院对相关考生再次复试确定最终拟录取人选。</p>\n     <p>7.拟录取名单公示。按照教育部要求，全校拟录取名单在学校研究生处网站进行公示，公示期不少于10个工作日。公示期间公示内容不得修改，如有变动，将对变动部分做出说明，并对变动内容另行公示10个工作日。未经学校公示的考生一律不得录取，不予学籍注册。</p>\n     <p>8.录取。入学后3个月内，我校将按照《普通高等学校学生管理规定》有关要求，对所有考生进行全面复查（含初试、复试、加试）。复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p>原则上我校非全日制硕士研究生仅招收在职且定向就业的考生，只能录取为“定向就业”类别，考生在拟录取前均须签订定向就业合同。考生因报考硕士研究生与所在单位产生的问题由考生自行处理。若因此造成考生不能复试或无法录取，学校不承担责任。</p>\n     <p><strong>九、违规处理</strong></p>\n     <p>1.复试是硕士研究生招生考试的重要组成部分，任何形式泄露复试试题相关信息、违反复试管理规定和考场纪律、影响考试公平和公正行为的考生，一律按《国家教育考试违规处理办法》（教育部令第33号）等规定严肃处理，取消录取资格，记入《考生考试诚信档案》。</p>\n     <p>2.《中华人民共和国刑法修正案（九）》（自2015年11月1日起实施）第二百八十四条规定：①在法律规定的国家考试中，组织作弊的，处3年以下有期徒刑或者拘役，并处或者单处罚金；情节严重的，处3年以上7年以下有期徒刑，并处罚金。②为他人实施前款犯罪提供作弊器材或者其他帮助的，依照前款的规定处罚。③为实施考试作弊行为，向他人非法出售或者提供第一款规定的考试的试题、答案的，依照第一款的规定处罚。④代替他人或者让他人代替自己参加第一款规定的考试的，处拘役或者管制，并处或者单处罚金。</p>\n     <p>3.对在招生工作中有违反国家有关法律法规和招生管理规定行为的招生单位、招生考试机构、主管教育行政部门及其招生工作人员，一律按《普通高等学校招生违规行为处理暂行办法》（教育部令第36号）严肃处理，并追究直接责任人员的责任，造成严重后果和恶劣影响的，还将按规定对有关责任人实行问责。</p>\n     <p>4.招生工作中，严禁学校内部任何部门和工作人员（包括在校生）举办或参与举办考试招生辅导活动，严禁向社会培训机构提供考试招生辅导活动场所和设施，严禁各招生学院委托社会培训机构进行考试招生辅导培训、招生宣传和组织活动，违反规定的要追究有关部门和相关人员责任。</p>\n     <p><strong>十、监督举报渠道</strong></p>\n     <p>学校研究生招生办公室，咨询监督电话：028-84616702。</p>\n     <p>若发现有违纪、违规行为需要举报和反映，请向学校纪委办公室举报或反映，电话：028-84616636。</p>\n     <p><strong>十一、应急预案</strong></p>\n     <p>1.复试过程中因意外事件导致复试中断、短时间内无法恢复的，学校可根据情况组织考生再次复试。</p>\n     <p>2.因灾害、疫情等突发特殊情况导致考生不能到校，报上级部门同意后，学校可采取其它方式组织复试。</p>\n     <p><strong>十二、其它</strong></p>\n     <p>本方案如与教育部或四川省教育考试院公布的最新政策有出入或未尽事宜，以教育部和四川省教育考试院公布的政策为准。本方案由学校研究生招生办公室负责解释。</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chs