INSERT INTO `yl_guide` VALUES (126, '辽宁大学：2024年硕士研究生复试录取工作办法', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/fstj\">复试指导</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>辽宁大学：2024年硕士研究生复试录取工作办法</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2024年03月26日</span> <span>来源：辽宁大学 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p>为切实做好2024年辽宁大学硕士研究生复试录取工作，确保复试录取工作公平公正、平稳有序，根据教育部、省招考委相关文件要求，结合学校工作实际制定本办法。</p>\n     <p><strong>一、工作原则</strong></p>\n     <p>（一）坚持落实立德树人根本任务。</p>\n     <p>（二）坚持公平公正，维护考生的合法权益。</p>\n     <p>（三）坚持复试选拔的科学性，确保生源质量。</p>\n     <p><strong>二、组织实施</strong></p>\n     <p>（一）学校研究生招生工作领导小组，在省招考委、省教育厅和有关部门的指导下，全面领导学校研究生招生工作。</p>\n     <p>研究生院负责具体落实学校研究生招生工作领导小组各项工作部署，负责对学校硕士研究生复试录取工作进行组织管理与监督检查。</p>\n     <p>（二）各培养单位研究生招生工作领导小组，在学校研究生招生工作领导小组的指导下，组织领导本单位研究生招生工作，负责制定本单位复试、调剂工作实施细则，遴选培训本单位参与复试工作人员。</p>\n     <p>（三）各培养单位可按招生专业、类别（领域或研究方向）设立若干复试小组，在学校及本单位研究生招生工作领导小组的指导下，具体负责对考生实施复试考核。</p>\n     <p><strong>三、复试方式</strong></p>\n     <p>根据教育部、省招考委要求，学校2024年硕士研究生招生考试以招生专业为单位，采用网络远程或线下现场的复试方式。同一招生专业一志愿与调剂考生复试方式一致，各专业复试方式详见各培养单位复试工作实施细则。</p>\n     <p>对于采用网络远程复试方式的专业，复试依托“学信网”招生远程面试系统（“腾讯会议”应急备用）进行。考生持《准考证》和身份证按要求以“双机位”模式参加复试考核。考核内容涵盖《辽宁大学2024年硕士研究生招生章程》附件三中已公布的笔试、实践操作和面试等内容；同等学力加试为网络远程笔试，其他考核项目为网络远程面试。</p>\n     <p>对于采用现场复试方式的专业，考生持《准考证》、身份证和《教育部学籍在线验证报告》（或《教育部学历证书电子注册备案表》或《认证报告（书）》等）按要求到辽宁大学崇山校区或蒲河校区进行线下现场复试。考核内容按《辽宁大学2024年硕士研究生招生章程》附件三中公布内容和考核形式进行复试。</p>\n     <p><strong>四、复试安排</strong></p>\n     <p>预计各培养单位在3月末开始组织考生复试，一志愿考生复试工作一般在4月3日前结束；拟定于4月8日开始调剂复试工作，调剂考生复试工作一般在4月15日前结束。各专业具体复试时间、地点等安排详见各培养单位后续公布的复试工作实施细则。</p>\n     <p>复试开始前各培养单位及时向入围复试的考生发出复试通知。考生复试前准备工作及注意事项参见学校相关通知。</p>\n     <p><strong>五、复试资格</strong></p>\n     <p>（一）复试基本分数线</p>\n     <p>各培养单位依照《2024年全国硕士研究生招生工作管理规定》（以下简称《招生管理规定》）和《2024年全国硕士研究生招生考试考生进入复试的初试成绩基本要求》（以下简称国家分数线）划定复试基本分数线。生源较好专业、类别（领域或研究方向）可在国家分数线（总分）的基础上确定本专业复试基本分数线，进行差额复试，差额比例一般不低于120%。</p>\n     <p>（二）调剂复试</p>\n     <p>1.考生申请调剂的基本条件</p>\n     <p>符合调入专业的报考条件。初试成绩符合第一志愿报考专业在调入地区（一区）的国家分数线基本要求。</p>\n     <p>调入专业与第一志愿报考专业相同或相近，一般应在同一学科门类范围内。其中，学术学位专业仅接收第一志愿报考相同或相近学术学位专业考生的调剂申请；专业学位类别（领域）可接收第一志愿报考相同或相近学术学位专业或专业学位类别（领域）考生的调剂申请。</p>\n     <p>初试科目与调入专业初试科目相同或相近，其中初试全国统一命题科目应与调入专业全国统一命题科目相同。全国统一命题外国语科目中的英语（一）、英语（二）及业务课一科目中的数学（一）、数学（二）、数学（三）仅可进行单向调剂。对于外国语科目，不接收招生专业目录中未列出语种考生的调剂。第一志愿报考专业初试科目数量应与调入专业初试科目数量一致。</p>\n     <p>学习方式为非全日制的调入专业只招收定向就业的在职考生，可以接收相同或相近专业学位类别（领域）全日制学习方式考生（不含应届毕业生）调剂申请，但（拟）录取类别必须为定向就业。</p>\n     <p>报考工商管理、公共管理、旅游管理[125400]、会计、图书情报、审计专业学位硕士的考生，在满足调入专业报考条件、且初试成绩同时符合调出专业和调入专业在调入地区（一区）的国家分数线要求的基础上，可申请相互调剂，但不得调入其他专业;其他专业考生也不得调入以上专业。</p>\n     <p>报考法律（非法学）专业学位硕士的考生不得调入其他专业，其他专业的考生也不得调入该专业。</p>\n     <p>报考“退役大学生士兵”专项计划的考生，申请调剂到普通计划，其初试成绩须达到调入地区（一区）相关专业所在学科门类的国家分数线要求。</p>\n     <p>考生还须符合调入专业对其一志愿报考专业等学术条件的具体要求。其中，对于接收跨学科门类范围申请调剂的专业，考生初试成绩需同时符合调出专业和调入专业在调入地区（一区）国家分数线的要求。</p>\n     <p>2.调剂工作基本要求</p>\n     <p>调剂工作通过“全国硕士研究生招生调剂服务系统”进行。调剂工作开始前学校和相关培养单位公布调剂工作办法和实施细则。</p>\n     <p>调剂考生复试内容要求与一志愿考生复试内容要求一致。</p>\n     <p><strong>六、资格审查与心理测试</strong></p>\n     <p>复试考生可于3月26日（预计开通时间）登录辽宁大学硕士研究生招生信息管理系统（http://lnu.yzsystem.com首次登录前考生须完成系统注册，其中考生姓名、身份证号须与“研招网”报考信息一致），按操作提示完成材料提交并配合学校完成审核。</p>\n     <p>参加复试的全部一志愿考生应在3月28日前完成材料提交，调剂考生在复试考核开始前24小时完成材料提交与审核。</p>\n     <p>材料1.居民身份证</p>\n     <p>须包括考生本人居民身份证正、反面信息。</p>\n     <p>材料2.诚信复试承诺书</p>\n     <p>材料3.学历（学籍）材料</p>\n     <p>（1）已获本科毕（结）业证书的考生提交《教育部学历证书电子注册备案表》，无法提供《教育部学历证书电子注册备案表》的考生须提交《中国高等教育学历认证报告》；</p>\n     <p>（2）在域外获得学士学位（学历）的考生，须提交教育部留学服务中心出具的《国（境）外学历学位认证书》；</p>\n     <p>（3）应届本科毕业生提交《教育部学籍在线验证报告》；</p>\n     <p>（4）复试时尚未取得本科毕业证书，报考法律（非法学）和法律（法学）专业的自考考生提供省（市）高等教育自学考试办公室出具的带有本科学习专业名称的成绩证明；</p>\n     <p>（5）专科毕业的同等学力考生提交专科层次的《教育部学历证书电子注册备案表》。</p>\n     <p>有曾用名或居民身份证号码变更的考生，请将相关证明材料与学历（学籍）材料合并上传。</p>\n     <p>材料4.申请享受加分政策的证明材料</p>\n     <p>考生人事档案内的服务合同，相关项目服务期满考核材料等。</p>\n     <p>材料1、2、3为必传材料，材料4仅满足《招生管理规定》第五十二、六十二条之规定，且申请加分的考生需上传。</p>\n     <p>考生符合报考条件的学历、学籍信息须可通过教育部学信网进行查实或有教育部指定的权威机构出具的认证报告，否则不允许参加复试或不予录取；发现考生不符合报考条件者，取消其复试资格；对审查中弄虚作假者一经发现即取消复试、（拟）录取资格或取消学籍。</p>\n     <p>采用现场复试方式的考生，复试前需按要求提交《准考证》、身份证和《教育部学籍在线验证报告》（或《教育部学历证书电子注册备案表》或《认证报告（书）》等）复印件，并配合各培养单位完成身份复核工作。</p>\n     <p>考生在完成资格审查的同时，还需按要求完成心理测试。采用网络远程方式复试的一志愿考生，应在3月28日15时前完成心理测试；采用现场复试的一志愿考生心理测试工作按相关培养单位要求进行。调剂考生在复试考核开始前24小时完成心理测试。</p>\n     <p><strong>七、复试考核项目</strong></p>\n     <p>（一）外国语口语和听力测试</p>\n     <p>外国语口语和听力测试满分为20分，占复试成绩的20%。考生成绩未达12分者为复试不合格，不予录取。</p>\n     <p>（二）专业课及综合素质测试</p>\n     <p>工商管理、公共管理、会计、旅游管理[125400]、图书情报、审计专业考生的专业课及综合素质测试成绩满分70分，占复试成绩的70%。其他专业考生的专业课及综合素质测试成绩满分80分，占复试成绩的80%；考生成绩未达测试满分的60%者为复试不合格，不予录取。</p>\n     <p>专业课及综合素质测试考察考生对学科知识的掌握与运用情况及学术创新潜力；综合实践素质、运用本专业知识分析解决实际问题能力以及职业发展潜力。</p>\n     <p>（三）思想政治素质和品德考核</p>\n     <p>考核考生的思想政治素质和品德，思想政治素质和品德考核不作量化计入总成绩，但考核结果不合格者不予录取。</p>\n     <p>（四）思想政治理论考试</p>\n     <p>根据《招生管理规定》的要求，学校在复试中对工商管理、公共管理、会计、旅游管理[125400]、图书情报、审计等专业考生进行思想政治理论考试，思想政治理论考试满分10分，占复试成绩的10%。考生成绩未达6分者为复试不合格，不予录取。</p>\n     <p>（五）同等学力加试</p>\n     <p>除法律（非法学）、工商管理、公共管理和旅游管理[125400]专业外，对于以同等学力身份（以报名时为准）报考的考生、成人教育应届本科毕业生、复试时尚未取得本科毕业证书的自考和网络教育考生，加试两门与报考专业相关的本科主干课程。两门考试满分均为100分，60分及格，两门考试成绩不作量化计入总成绩，但不及格者不予录取。</p>\n     <p><strong>八、申请享受加分或照顾政策</strong></p>\n     <p>符合《招生管理规定》第六十二条之规定，在网上报名阶段按要求填报相关信息并申请享受加分政策，且通过相关部门审核的考生可申请加分。申请加分的一志愿考生应于3月28日前按资格审查要求完成相关材料的提交工作，调剂考生在复试考核开始前24小时完成材料提交，学校按教育部要求进行复核。</p>\n     <p>工作单位和户籍在国务院公布的民族区域自治地方，且定向就业单位为原单位的少数民族在职人员考生，可按规定享受少数民族照顾政策。申请享受照顾政策的考生，须在网上报名时按要求填报相关信息，如实填写少数民族身份及定向就业少数民族地区，并在复试前提交相关材料供学校审核。</p>\n     <p><strong>九、录取</strong></p>\n     <p>（一）总成绩计算办法</p>\n     <p>复试成绩和初试成绩按权重相加，得出招生考试总成绩。初试成绩占总成绩70%，复试成绩占总成绩30%。具体计算方法如下：</p>\n     <p>初试满分为500分的专业，总成绩计算公式为：</p>\n     <p>总成绩=初试总分÷5×0.7＋复试成绩<span style=\"text-wrap: wrap;\">×</span>0.3</p>\n     <p>初试满分为300分的专业，总成绩计算公式为：</p>\n     <p>总成绩=初试总分÷3<span style=\"text-wrap: wrap;\">×</span>0.7＋复试成绩<span style=\"text-wrap: wrap;\">×</span>0.3</p>\n     <p>（二）拟录取名单</p>\n     <p>一志愿考生和调剂考生应分别排序依次录取，各培养单位严格按照总成绩计算公式确定考生总成绩，并根据招生计划、复试录取办法审核拟定拟录取名单，并报学校研究生招生工作领导小组审定。</p>\n     <p>（三）拟录取结果公示</p>\n     <p>拟录取名单由研究生院进行网上公示，公示期为10个工作日。</p>\n     <p>（四）拟录取类别</p>\n     <p>根据规定，凡通过复试，被我校拟录取的2024级全部非全日制硕士研究生和其他定向就业硕士研究生，应与我校签订定向就业合同，请相关考生于2024年4月15日前，将单位和本人签署完毕的定向就业合同按相关培养单位指定方式进行提交，逾期视为考生自动放弃拟录取资格。定向就业合同请到本办法附件下载。</p>\n     <p>被我校拟录取的2024级非定向就业硕士研究生入学前需将本人人事档案转至我校。</p>\n     <p>（五）体检</p>\n     <p>考生体检工作在新生开学报到后按照学校要求统一进行，体检标准参照教育部、原卫生部、中国残联印发的《普通高等学校招生体检工作指导意见》（教学〔2003〕3号）要求，按照《教育部办公厅卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）和学校有关规定执行。</p>\n     <p>（六）复查</p>\n     <p>根据教育部文件规定，开学报到后3个月内学校按照《普通高等学校学生管理规定》的有关要求，对所有考生进行全面复查。对于复查不合格的，取消学籍；情节严重的，移交有关部门调查处理。</p>\n     <p><strong>十、监督与公开</strong></p>\n     <p>1.学校研究生招生工作领导小组对复试过程和复试结果进行指导与审查，严肃处理违纪违规事件。</p>\n     <p>2.各专业复试基本分数线、复试工作实施细则、复试结果等信息由培养单位负责及时向考生和社会公布。</p>\n     <p>咨询及申诉联系电话：024-62202349</p>\n     <p>本办法由辽宁大学研究生院负责解释，如同国家、辽宁省有关政策规定存在冲突，按国家、辽宁省有关政策规定执行。</p>\n     <p>附件（https://grs.lnu.edu.cn/info/12169/71633.htm）：</p>\n     <p>定向就业合同（更新中）</p>\n     <p>各培养单位复试工作实施细则（更新中）</p>\n     <p style=\"text-align: right;\">辽宁大学研究生院</p>\n     <p style=\"text-align: right;\">2024年3月26日</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://yz.chsi.com.cn/sswbgg/\" target=\"_blank\">网报公告</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\" target=\"_blank\">博士目录</a> <a href=\"https://yz.chsi.com.cn/help/\" target=\"_blank\">帮助中心</a>\n      </div>\n      <div class=\"aside-con-title\">\n       统考\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108-4.html\" target=\"_blank\">报名条件</a> <a href=\"https://yz.chsi.com.cn/yzwb/\" target=\"_blank\">网上报名</a> <a href=\"https://yz.chsi.com.cn/yzwb/#xcqr\" target=\"_blank\">网上确认</a> <a href=\"https://yz.chsi.com.cn/yzwb/#zkzxz\" target=\"_blank\">下载准考证</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">分数线</a> <a href=\"https://yz.chsi.com.cn/yztj/\" target=\"_blank\">调剂</a>\n      </div>\n      <div class=\"aside-con-title\">\n       推免\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">推荐系统</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/\" target=\"_blank\">申请指南</a> <a href=\"https://yz.chsi.com.cn/yzzt/tmzn/#bmlc\" target=\"_blank\">推免流程</a> <a href=\"https://yz.chsi.com.cn/tm/zyml/\" target=\"_blank\">专业目录</a> <a href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">填报志愿</a> <a href=\"https://yz.chsi.com.cn/tm/lqmd/index\" target=\"_blank\">信息公开</a>\n      </div>\n     </div>\n    </div>\n   </div>\n  </div>\n </div>\n</div><!-- 4: 底部区域 -->\n<svg style=\"display: block; width: 0; height: 0\">\n <defs>\n  <symbol id=\"weibo\" viewBox=\"0 0 16 16\">\n   <g stroke=\"none\" stroke-width=\"1\" fill=\"none\" fill-rule=\"evenodd\">\n    <g transform=\"tran