INSERT INTO `yl_guide` VALUES (128, '教育部关于印发《2026年全国硕士研究生招生工作管理规定》的通知', '<div class=\"main-wrapper\">\n <!-- 吊顶区域 -->\n <div class=\"top-nav-wrapper\">\n  <div class=\"top-nav\">\n   <div class=\"top-nav-list\" onmousedown=\"handleLinkClick(event, \'pc-二级导航\')\">\n    <a href=\"https://yz.chsi.com.cn/\" class=\"top-nav-home\" target=\"_blank\"> </a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/\" target=\"_blank\">首页</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/zcdh/\" target=\"_blank\">国家政策</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/kyzx/kydt/\" target=\"_blank\">资讯</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/sswbgg/\" target=\"_blank\">网报公告</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yzwb/\" target=\"_blank\">统考网报</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/wsqr/stu/\" target=\"_blank\">网上确认</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/apply/cjcx/\" target=\"_blank\">成绩查询</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/yztj/\" target=\"_blank\">复试调剂</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/tm/\" target=\"_blank\">推免服务</a> <a class=\"seach-toggel\" href=\"https://yz.chsi.com.cn/zsgs/\" target=\"_blank\">信息公开</a> <span class=\"top-nav-hide seach-toggel\"> <span class=\"top-nav-more\">更多</span>\n     <div class=\"top-nav-pop\">\n      <span class=\"top-nav-pop-arrow\"></span>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/jybzc/\" target=\"_blank\">教育部政策</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">复试分数线</a> <a href=\"https://yz.chsi.com.cn/yzzt/glllk\" target=\"_blank\">管理类专硕</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/yxzc/\" target=\"_blank\">院校政策</a> <a href=\"https://yz.chsi.com.cn/yzzt/zbft\" target=\"_blank\">研招访谈</a> <a href=\"https://yz.chsi.com.cn/kyzx/zt/zsxz.shtml\" target=\"_blank\">专业学位</a>\n      </div>\n      <div class=\"top-nav-pop-clo\">\n       <a href=\"https://yz.chsi.com.cn/kyzx/zsjz/\" target=\"_blank\">招生简章</a> <a href=\"https://yz.chsi.com.cn/bsmlcx/\" target=\"_blank\">博士目录</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a>\n      </div>\n      <div class=\"top-nav-pop-clo\"> <a href=\"https://yz.chsi.com.cn/bsbm/\" target=\"_blank\">博士网报</a>\n      </div>\n     </div></span>\n   </div>\n   <div class=\"top-nav-load\">\n    <div class=\"top-nav-search-input\" id=\"top-nav-input\">\n    </div><span class=\"search-cancel\">取消</span> <span class=\"top-nav-load-search\" id=\"top-nav-search\"></span> <span class=\"info-line\"></span> <a href=\"https://yz.chsi.com.cn/user/\" target=\"_blank\">用户中心</a> <span class=\"info-line\"></span> <a href=\"https://account.chsi.com.cn/account/preregister.action?from=yz-home\" target=\"_blank\">注册</a>\n   </div>\n  </div>\n </div>\n <div id=\"app\" v-cloak :class=\"\'container font-a-\'+fontSize\">\n  <div class=\"nav-box\">\n   <a href=\"https://yz.chsi.com.cn/\" target=\"_blank\">首页</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/zcdh\" target=\"_blank\">政策导航</a> &gt; <a href=\"https://yz.chsi.com.cn/kyzx/jybzc\" target=\"_blank\">教育部政策</a>\n  </div>\n  <div class=\"title-box\">\n   <h2>教育部关于印发《2026年全国硕士研究生招生工作管理规定》的通知</h2>\n  </div>\n  <div class=\"news-msg-box\">\n   <div class=\"news-msg\">\n    <span>2025年09月24日</span> <span>来源：教育部 </span>\n   </div>\n   <div class=\"tool-warp\">\n    <i class=\"ch-icon ch-icon-zjzh\" :class=\"{\'disabled\': fontSize===4}\" @click=\"fontUp\" title=\"字体变大\"></i> <i class=\"ch-icon ch-icon-jxzh\" :class=\"{\'disabled\': fontSize===1}\" @click=\"fontDown\" title=\"字体变小\"></i> <span class=\"cut-line\"></span>\n    <div class=\"wx-share\">\n     <i class=\"ch-icon ch-icon-wechat-fill share\" title=\"微信\"></i>\n     <div class=\"wx-popup\">\n      <span class=\"wx-popup-arrow\"></span> <img src=\"https://www.chsi.com.cn/qrcodeImg.do\" alt=\"二维码\">\n      <div>\n       用微信扫描二维码\n       <br>\n       分享至好友和朋友圈\n      </div>\n     </div>\n    </div><i class=\"ch-icon ch-icon-wb-fill share\" title=\"新浪微博\" @click=\"share(\'sinawb\')\"></i> <i class=\"ch-icon ch-icon-kj share\" title=\"QQ空间\" @click=\"share(\'qqkj\')\"></i>\n   </div>\n  </div>\n  <div class=\"content-box\">\n   <div class=\"content-l\">\n    <div class=\"detail\" id=\"article_dnull\">\n     <p style=\"text-align: right;\">教学〔2025〕2号</p>\n     <p>各省、自治区、直辖市高等学校招生委员会、教育厅（教委）、教育招生考试机构，新疆生产建设兵团教育局，有关部门（单位）教育司（局），各硕士研究生招生单位：</p>\n     <p>为做好2026年全国硕士研究生招生工作，现将《2026年全国硕士研究生招生工作管理规定》印发给你们，请遵照执行。</p>\n     <p style=\"text-align: right;\">教　育　部</p>\n     <p style=\"text-align: right;\">2025年9月15日</p>\n     <p style=\"text-align: center;\"><strong>2026年全国硕士研究生招生工作管理规定</strong></p>\n     <p style=\"text-align: center;\"><strong>第一章 总则</strong></p>\n     <p>第一条 为加强对全国硕士研究生招生工作的管理，保证硕士研究生的入学质量和招生工作的顺利进行，根据《中华人民共和国教育法》《中华人民共和国高等教育法》《中华人民共和国学位法》等法律法规，制定本规定。</p>\n     <p>第二条 高等学校和科学研究机构（以下统称招生单位）招收硕士研究生，旨在培养热爱祖国，拥护中国共产党的领导，拥护社会主义制度，遵纪守法，品德良好，具有服务国家、服务人民的社会责任感，掌握本学科坚实的基础理论和系统的专业知识，具有创新精神、创新能力和从事科学研究、教学、管理等工作能力的高层次学术创新型专门人才，以及具有较强解决实际问题的能力、能够承担专业技术或管理工作、具有良好职业素养的高层次实践创新型人才。</p>\n     <p>第三条 硕士研究生招生应坚持服务战略、按需招生、全面衡量、择优录取和宁缺毋滥的原则，积极推进学术学位与专业学位硕士研究生分类选拔。</p>\n     <p>第四条 招生学科（类别）、专业（领域）[以下统称学科专业]须经国务院学位委员会批准或备案。</p>\n     <p>第五条 教育部会同国家有关部门根据经济社会发展需要制定并下达年度招生计划。</p>\n     <p>招生单位根据下达的招生计划、社会需求和办学条件，依据有关政策规定确定本单位各学科专业的招生人数。</p>\n     <p>第六条 全国硕士研究生招生考试分初试和复试两个阶段。初试由国家统一组织，复试由招生单位自行组织。初试和复试都是硕士研究生招生考试的重要组成部分。教育部统一确定初试、复试时间。</p>\n     <p>初试方式分为全国统一考试、单独考试以及推荐免试。全国统一考试、单独考试的初试科目包括全国统一命题科目和招生单位自命题、联合命题科目。</p>\n     <p>单独考试、推荐免试应聚焦世界科技前沿和国家重大战略需求，紧密结合招生单位学科专业优势，分别重点面向相关行业企业一线优秀在职科研或技术骨干、优秀应届本科毕业生开展选拔，加强拔尖创新人才培养。开展单独考试招生的招生单位和开展推荐免试招生中推荐工作的高校（以下简称推荐高校），均应具备相应资格。</p>\n     <p>第七条 全国硕士研究生招生考试试题（包括副题）、参考答案、评分参考（指南）等应当按照教育工作国家秘密范围的有关规定严格管理。</p>\n     <p>第八条 硕士研究生学习方式分为全日制和非全日制。全日制和非全日制研究生考试招生依据国家统一要求，执行相同的政策和标准。</p>\n     <p>硕士研究生就业方式分为定向就业和非定向就业。</p>\n     <p>第九条 硕士研究生考试招生工作坚持重大事项集体研究、集体决策，严格规范管理，落实考试招生回避、信息公开等要求。</p>\n     <p>第十条 考生应诚信参加考试，自觉遵守考试管理各项规定。</p>\n     <p style=\"text-align: center;\"><strong>第二章 管理机构及其职责</strong></p>\n     <p>第十一条 教育部负责宏观管理全国硕士研究生招生工作。教育部的主要职责是：</p>\n     <p>（一）研究制定并发布考试招生政策、工作规定和办法，部署全国考试招生工作，推进招生信息公开，监督检查全国考试招生工作执行情况。</p>\n     <p>（二）会同国家有关部门制定并下达年度招生计划。下达年度单独考试招生限额和年度推免生名额。</p>\n     <p>（三）确定初试全国统一命题科目，编制其考试大纲并组织命题工作。</p>\n     <p>（四）会同国家教育统一考试工作部际联席会议成员单位，指导做好全国招生考试组织实施工作。</p>\n     <p>（五）组织考试招生工作示范培训。</p>\n     <p>（六）指导督促各省（区、市）高等学校招生委员会（含承担相应职责的机构，以下统称省级招委会）监督管理本地区考试招生工作，调查处理考试招生工作中发生的重大问题。</p>\n     <p>第十二条 省级招委会负责本行政区域内研究生考试招生工作，统一领导协调本行政区域内各级教育行政部门、教育招生考试机构等部门和招生单位开展考试招生相关工作。省级招委会主要负责人对考试招生工作负领导责任，省级教育行政部门主要负责人是第一责任人，省级教育招生考试机构主要负责人是直接责任人，相关部门的分管负责人对本部门职责范围内的工作负责。省级招委会的主要职责是：</p>\n     <p>（一）执行教育部有关研究生考试招生工作的政策、规定和办法，因地制宜制订管理和实施办法，组织实施并监督检查执行情况。</p>\n     <p>（二）明确本行政区域内各级教育行政部门、教育招生考试机构具体职责分工。积极适应研究生考试招生工作新形势新变化，加强机构和队伍建设，完善考试招生工作人员常态化培训工作机制，确保高质量完成本地区研究生考试招生各项工作。</p>\n     <p>（三）全面负责考试安全工作，综合施策，完善防范和打击考试作弊工作体系，统筹做好本地区组考、安全、防疫等工作。</p>\n     <p>（四）组织本行政区域内招生单位制订并发布招生章程（含招生学科专业目录，下同），开展招生咨询、报考资格审核、初试和复试、录取、招生信息公开等工作。做好考生信息的安全保密工作。</p>\n     <p>（五）组织并做好全国统一命题科目试卷印制及保密、保管等工作。指导本行政区域内招生单位做好自命题科目的命题、制卷、寄送及保密、保管等工作，并开展监督检查，确保试题试卷绝对安全。</p>\n     <p>（六）设置报考点和评卷点，组织报名、考试、评卷等工作，加强试题试卷保密、保管，按时、准确、规范上报有关信息数据。统筹建设和使用标准化考点，部署协调本行政区域内各级教育行政部门、教育招生考试机构及招生单位、各级各类学校，安排充足的考位和考试工作人员，服务保障考试组织工作。</p>\n     <p>（七）及时调查处理本地区考试招生工作中发生的问题。重大问题应立即向所在地省级人民政府和教育部报告。</p>\n     <p>（八）指导、管理、监督本行政区域内招生单位的考试、招生工作。优化考试服务，畅通咨询申诉渠道，根据考生申请对招生单位信访答复情况进行复查。落实有关规定，进一步健全考试招生工作人员的待遇保障和激励机制。依法维护考生和考试招生工作人员的合法权益。</p>\n     <p>第十三条 招生单位主管部门的主要职责是：</p>\n     <p>指导有关教育司（局）根据教育部有关研究生考试招生工作的政策、规定、办法及下达的年度招生计划，拟定本部门所属各招生单位的招生计划，监督管理其考试招生工作；配合有关省级教育行政部门、教育招生考试机构调查处理本部门所属招生单位招生工作中发生的问题，并依法依规依纪追究相关单位和人员的责任。</p>\n     <p>第十四条 招生单位是本单位研究生考试招生工作的责任主体，主要负责人是本单位研究生考试招生工作第一责任人，分管负责人是直接责任人。招生单位的主要职责是：</p>\n     <p>（一）招生单位要将研究生考试招生工作纳入本单位党委全面从严治党责任清单，领导班子成员落实“一岗双责”，严格落实党章党规党纪，严格执行招生管理规章制度，持续梳理招生廉政风险点，制订完善切实有效的防控措施，压实本单位各有关部门、院（系、所等）全面从严治党责任。</p>\n     <p>（二）成立本单位研究生招生委员会（以下简称招生单位招委会），由本单位主要负责人牵头，分管负责人及研究生招生管理、纪检监察等有关部门主要负责人参加。严格执行“集体议事、集体决策、会议决定”的规程，审议决策研究生考试招生工作重大事项等。</p>\n     <p>（三）明确本单位各有关部门、院（系、所等）在研究生考试招生工作中的具体职责分工，并加强监督管理。其中，研究生招生管理部门应加强本单位研究生考试招生工作制度建设、组织协调、指导监督、信息化建设及政策咨询、信访受理等，负责统筹管理招生宣传、考试组织、调剂、录取等工作，统一审核院（系、所等）考试招生各环节实施细则，统一公开招生信息（含招生章程、考生进入复试的初试成绩要求、调剂信息等），统一监督检查各院（系、所等）考试招生执行情况，统一审核复试（含调剂复试，下同）及拟录取名单，统一办理录取相关手续。未经研究生招生管理部门同意，院（系、所等）不得擅自开展考试招生各项工作。院（系、所等）主要负责同志是相关自命题科目命题和复试工作的第一责任人。</p>\n     <p>（四）积极适应研究生考试招生工作新形势新变化，加强机构和队伍建设，完善考试招生工作人员常态化培训工作机制，确保高质量完成本单位考试招生各项工作。</p>\n     <p>（五）根据教育部有关研究生考试招生工作的政策、规定和办法，所在地省级招委会管理和实施办法以及上级主管部门有关工作要求，结合本单位的实际情况，制订并公布本单位的招生章程、体检要求及有关工作方案等。</p>\n     <p>（六）组织招生宣传、咨询、考生报考资格审核、思想政治素质与品德考核、体检、录取、招生信息公开等工作。做好考生信息的安全保密工作。</p>\n     <p>（七）组织本单位自命题管理（命题、制卷、寄送、保管等）、复试等工作，全力确保安全保密。</p>\n     <p>（八）按照省级教育招生考试机构要求，设立报考点和评卷点，做好考生报名、组考、评卷（含全国统一命题科目和自命题科目）等工作，并按时、准确、规范上报有关信息数据。</p>\n     <p>（九）依法维护考生和考试招生工作人员的合法权益。优化考试服务，畅通咨询申诉渠道，根据考生申请对本单位有关考试招生行为进行调查、处理并给予答复。落实有关规定，进一步健全考试招生工作人员的待遇保障和激励机制。</p>\n     <p style=\"text-align: center;\"><strong>第三章 报名</strong></p>\n     <p>第十五条 报名参加全国硕士研究生招生考试的人员，须符合下列条件：</p>\n     <p>（一）中华人民共和国公民。</p>\n     <p>（二）拥护中国共产党的领导，遵纪守法，品德良好。</p>\n     <p>（三）身体健康状况符合国家和招生单位规定的体检要求。</p>\n     <p>（四）考生学业水平须符合下列条件之一，本章另有规定的除外：</p>\n     <p>1.国家承认学历的应届本科毕业生（含普通高校、成人高校、普通高校举办的成人高等学历教育等应届本科毕业生）及自学考试和网络教育届时可毕业本科生。</p>\n     <p>2.具有国家承认的本科毕业学历的人员。</p>\n     <p>3.获得国家承认的高职（专科）毕业学历后满2年及以上人员（毕业后到录取当年入学前，下同）或国家承认学历的本科结业生，且符合招生单位提出的具体学业要求的，按本科毕业同等学力身份报考。</p>\n     <p>4.已获硕士、博士研究生学历或学位的人员。</p>\n     <p>第十六条 报考下列专业学位的人员，按有关规定执行。</p>\n     <p>（一）报考法律（法学）专业学位的，须符合第十五条中的各项要求，且报名前所学专业为法学专业（获得法学第二学士学位的人员可报考）。</p>\n     <p>报考法律（非法学）专业学位的，须符合第十五条中的各项要求，且报考前所学专业为非法学专业。</p>\n     <p>（二）报考工商管理、公共管理、旅游管理专业学位，以及工程管理专业学位中的工程管理（代码为125601）和项目管理（代码为125602）、教育专业学位中的教育管理、体育专业学位中的竞赛组织的，须符合下列条件：</p>\n     <p>1.符合第十五条中第（一）、（二）、（三）项要求。</p>\n     <p>2.本科毕业后有3年以上工作经验；或获得国家承认的高职（专科）毕业学历或本科结业后，符合招生单位提出的相关学业要求，达到本科毕业同等学力并有5年以上工作经验；或获得硕士、博士研究生学历或学位后有2年以上工作经验。</p>\n     <p>工商管理硕士专业学位研究生相关考试招生政策同时按照《教育部关于进一步规范工商管理硕士专业学位研究生教育的意见》（教研〔2016〕2号）有关规定执行。</p>\n     <p>2027年招生起，工程管理专业学位中的工业工程与管理（代码为125603）、物流工程与管理（代码为125604）也须符合上述两项报考条件。</p>\n     <p>第十七条 报名参加单独考试的人员，须符合下列条件：</p>\n     <p>（一）符合第十五条中第（一）、（二）、（三）项要求。</p>\n     <p>（二）符合下列条件之一：</p>\n     <p>1.本科毕业后连续工作４年以上，或获硕士、博士研究生学历（或学位）后工作2年以上；在工作单位表现优秀的业务骨干，经考生所在单位同意和两名具有相关领域高级专业技术职称的专家推荐，回原单位定向就业的在职人员；所从事工作与报考专业密切相关。</p>\n     <p>2.符合有关试点高校面向残障考生开展单独考试相关报名条件的人员。</p>\n     <p>第十八条 除经教育部批准或同意的有关专项计划外，招生单位不得按单位、行业、地域等限定生源范围，也不得设置其他歧视性报考条件。</p>\n     <p>第十九条 报名包括网上报名和网上确认两个阶段。</p>\n     <p>网上报名时间为2025年10月16日至10月27日（网上预报名时间为2025年10月10日至10月13日，相关工作安排由各省级教育招生考试机构确定并公布），每日9:00—22:00。考生应在规定时间登录“中国研究生招生信息网”（网址：https://yz.chsi.com.cn）参加报名，按要求如实填写并提供真实材料。</p>\n     <p>网上确认时间由各省级教育招生考试机构根据教育部有关工作安排和本地区报考组织情况自行确定和公布，具体确认工作由相关报考点组织实施。</p>\n     <p>所有考生均须参加网上报名和网上确认，积极配合签署《考生诚信考试承诺书》并遵守相关约定，认真核对并确认本人报名信息，根据核验工作要求提交补充材料，逾期不得补办。在读研究生报考须在报名前征得所在培养单位同意。考生因网报信息填写错误、填报虚假信息而造成不能考试（含初试、复试）或录取的，后果由考生本人承担。</p>\n     <p>报名网络技术服务工作由教育部学生服务与素质发展中心负责。</p>\n     <p>第二十条 省级招委会应统筹考虑考生规模、考务组织、服务保障等因素，安排充足的考试服务资源，合理设置并公布报考点，妥善安排考生报考和咨询。应届本科毕业生原则上应选择就读学校所在地省级教育招生考试机构指定的报考点，其中成人高校应届本科毕业生也可选择教学点所在地省级教育招生考试机构指定的报考点；凡招生单位要求使用画板类、非常规考试用纸的，或初试科目中有考试时长超过三小时的，招生单位应在本考点为所有报考该学科专业的考生组织考试。单独考试考生应选择招生单位所在地省级教育招生考试机构指定的报考点；其他考生应选择工作所在地或户籍所在地省级教育招生考试机构指定的报考点（相关具体要求由所在地省级教育招生考试机构因地制宜、合理确定）。鼓励有条件的省份为更多考生就地报考提供服务。考生户籍所在地应做好考生报名兜底服务保障。</p>\n     <p>第二十一条 各省级招生考试机构和招生单位应遵循《中华人民共和国无障碍环境建设法》《中华人民共和国残疾人教育条例》和全国硕士研究生招生考试组织规则，参照《教育部 中国残联关于印发〈残疾人参加普通高等学校招生全国统一考试管理规定〉的通知》（教学〔2017〕4号）有关要求，积极为残疾人参加考试提供必要支持条件和合理便利。残疾考生如需组考单位在考试期间提供合理考试便利服务，应于报名阶段与报考点所在地省级招生考试机构和招生单位沟通申请，以便提前做好安排。</p>\n     <p>第二十二条 符合下列条件之一后3年内报名参加全国硕士研究生招生考试（不含单独考试）的考生，可申请享受初试总成绩加10分，同等条件下优先录取。符合多项加分项目的考生，分值不得累加。</p>\n     <p>（一）参加“大学生志愿服务西部计划”“三支一扶计划”“农村义务教育阶段学校教师特设岗位计划”“国际中文教育志愿者”项目之一，服务期满且考核合格。</p>\n     <p>（二）退役大学生士兵〔即高校学生应征入伍退出现役者，其中，高校学生指全日制普通本专科（含高职）、研究生、第二学士学位的应（往）届毕业生、在校生和入学新生，以及成人高校招收的普通本专科（含高职）应（往）届毕业生、在校生和入学新生，下同〕达到全国硕士研究生招生考试报考条件。</p>\n     <p>除上述加分项目外，各地各招生单位不得擅自扩大加分范围、另设标准。</p>\n     <p>第二十三条 报考地处二区（具体范围见第四十八条）招生单位且毕业后在国务院公布的民族区域自治地方定向就业的少数民族普通高校应届本科毕业生；或者报名时工作单位和户籍在国务院公布的民族区域自治地方，且定向就业单位为原单位的少数民族在职人员考生，可按规定享受少数民族照顾政策。申请享受少数民族照顾政策的考生，不再享受初试加分政策。</p>\n     <p>第二十四条 报考有关专项计划的考生，须符合相应报考条件并在网上报名时填报。报考专项计划的考生，不再享受初试加分、少数民族照顾政策。</p>\n     <p>（一）“退役大学生士兵计划”。高校学生应征入伍退出现役且符合全国硕士研究生招生考试报考条件，可以申请报考。</p>\n     <p>（二）其余专项计划，执行相应文件规定。</p>\n     <p>第二十五条 对服役期间获得三等战功、二等功以上奖励或者二级以上表彰，符合全国硕士研究生招生考试报考条件的退役人员，可申请免初试攻读硕士研究生。</p>\n     <p>符合免初试资格的考生，应在教育部规定的全国统考报名时间内登录“全国推荐免试攻读研究生（免初试、转段）信息公开暨管理服务系统”（网址：https://yz.chsi.com.cn/tm）报名，逾期不得补报。招生单位对审核通过的考生组织复试，复试合格者即可予以拟录取。</p>\n     <p>第二十六条 招生单位和报考点应根据相关规定，组织专人对考生报考信息和网上确认材料进行全面、认真审核，确定考生的考试资格。考生填报的报名信息与报考条件不符的，不得准予考试、录取，随时发现、随时处理。报考点和招生单位发现有考生伪造、变造证件时，应立即向公安机关报案。</p>\n     <p>符合享受初试加分、少数民族照顾政策、免初试或报考专项计划有关条件的考生，须在网上报名时按要求填报申请信息。有关部门、报考点对相关考生资格进行初审，招生单位在复试前进行复审，确定考生的相应资格。其中，申请享受少数民族照顾政策的资格由报考点进行初审，其余资格由有关部门按职责分工进行初审。未按规定申报或审核（含复审）未通过的，不享受相应的加分、照顾、免初试政策，或不得参加有关专项计划初、复试。</p>\n     <p>申请报考“退役大学生士兵计划”的考生，须在复试前向招生单位提供《入伍批准书》和《退出现役证》（限士兵）进行复核。审核或复核未通过的，不得按照“退役大学生士兵计划”参加复试，仅可在调剂阶段按规定申请调剂到普通计划。报考普通计划的考生，若报名时申请退役大学生士兵初试加分并审核通过，调剂阶段可按规定申请调剂“退役大学生士兵计划”；若报名时未申请退役大学生士兵初试加分的，不可参加“退役大学生士兵计划”调剂。</p>\n     <p>第二十七条 具有推荐免试资格的考生，须在教育部规定的时间内登录“全国推荐免试攻读研究生（免初试、转段）信息公开暨管理服务系统”报名。已被招生单位录取的推免生，不得再报名参加当年全国统一考试、单独考试。截止规定日期未被招生单位录取的推免生，其推免资格自动失效。</p>\n     <p style=\"text-align: center;\"><strong>第四章 命题</strong></p>\n     <p>第二十八条 硕士研究生招生考试是选拔性考试。各有关单位应根据硕士研究生招生考试工作定位和相应考试大纲（考试内容范围说明），参考本科教学大纲，开展初试科目命题工作，考查考生是否具备硕士研究生入学的基本能力和专业素质。</p>\n     <p>第二十九条 全国统一命题科目的命题工作由教育部教育考试院统一组织。</p>\n     <p>第三十条 招生单位自命题科目的命题工作由招生单位自行组织。</p>\n     <p>招生单位要加强对自命题工作的组织领导，统筹推进自命题管理各项工作，坚决杜绝简单下放、层层转交。对标国家教育考试有关规定，建立健全本单位自命题工作规范，加强对命题相关人员以及命题、审题、制卷，试题和答案保密保管、运送交接等各工作环节的规范管理和监督，确保试题、答案、试卷绝对安全。加大对自命题题库建设投入和研究力度。大力推进按一级学科命题或跨一级学科命题，医学学术学位自命题科目应按一级学科命题。鼓励招生单位优先选用全国统一命题科目试卷，或招生单位间联合命题。不得委托非硕士研究生招生单位或个人命制自命题科目试题，委托其他招生单位命制的，要签订保密协议。对于新增学位授予单位和新增学位授权点，鼓励选用其他招生单位相同相近学科或本单位其他已开展招生的相近学科专业试题。</p>\n     <p>招生单位要按学院或考试科目组成多个自命题科目命题小组。各命题小组至少应当由两名政治素质过硬、责任心强、教学经验丰富、学术水平较高并且近期承担教学工作的人员组成，其中一人为组长。命题人员原则上应当具有副教授以上职称或相当职称，命题小组组长应当具有教授或相当职称并具有硕士研究生招生考试命题经验，每位命题人员只能参加一门科目的命题工作。加强命题工作研究和培训，优化完善试题题型和考查形式，把握适宜的信度、效度、难度、区分度，不得出现政治性的错误，避免出现学术界尚有争议的问题，切实提高自命题质量。命题人员在命题前要签订保密协议，遵纪守法，信守承诺，保守秘密，过失泄密和故意泄密行为均须承担刑事责任。有关学院主要负责同志、命题小组组长是相关自命题科目的第一责任人，要对试题内容严格审查把关，确保命题不出差错。命题小组人员名单须报招生单位研究生招生管理部门严格审核。</p>\n     <p>第三十一条 单独考试初试科目设置应与相应学科专业全国统一考试初试科目设置相同。单独考试的各考试科目可选用全国统一命题科目，也可由招生单位自命题或委托其他招生单位命题。</p>\n     <p style=\"text-align: center;\"><strong>第五章 初试</strong></p>\n     <p>第三十二条 初试一般设置四个单元考试科目，即思想政治理论、外国语、业务课（一）和业务课（二），满分分别为100分、100分、150分、150分。</p>\n     <p>第三十三条 教育学、历史学、医学等3个门类学术学位，及体育、应用心理、博物馆、临床医学、口腔医学、公共卫生、护理、药学、中药、中医、医学技术、针灸等12个专业学位，初试设置三个单元考试科目，即思想政治理论、外国语、专业基础综合，满分分别为100分、100分、300分。</p>\n     <p>工商管理、公共管理、会计、旅游管理、图书情报、工程管理和审计等7个专业学位，初试设置两个单元考试科目，即管理类综合能力、外国语，满分分别为200分、100分。思想政治理论由招生单位在复试中考核。</p>\n     <p>第三十四条 全国统一命题科目有，思想政治理论、英语（一）、英语（二）、俄语、日语、数学（一）、数学（二）、数学（三）、教育学专业基础、心理学专业基础、历史学专业基础、临床医学综合能力（中医）、临床医学综合能力（西医）、数学（农）、化学（农）、植物生理学与生物化学、动物生理学与生物化学、计算机学科专业基础、管理类综合能力、法律硕士专业基础（非法学）、法律硕士综合（非法学）、法律硕士专业基础（法学）、法律硕士综合（法学）、经济类综合能力、教育综合。</p>\n     <p>鼓励招生单位积极选择使用上述全国统一命题科目。</p>\n     <p>第三十五条 招生单位须按教育部有关规定确定考试科目并使用相关试题。</p>\n     <p>第三十六条 初试方式均为笔试。初试时间为2025年12月20日至21日。其中，12月20日上午8:30—11:30，思想政治理论或管理类综合能力；12月20日下午14:00—17:00，外国语；12月21日上午8:30—11:30，业务课（一）或专业基础综合；12月21日14:00开始，业务课（二）。考试时间以北京时间为准。</p>\n     <p>不在规定日期举行的考试，一律不予承认。具体考试时间、考试科目及有关要求等由报考点和招生单位公布。</p>\n     <p>第三十七条 初试的组织工作和考务工作由教育部教育考试院及各级教育招生考试机构按照相关文件规定执行。</p>\n     <p>第三十八条 因试卷错寄、漏寄、邮递故障等非考生本人原因而无法正常考试的考生可参加补考。</p>\n     <p>招生单位将初步审查同意补考的工作方案（含补考考生姓名、报考单位、补考科目、补考原因及补考时间、地点等信息），报所在省级教育招生考试机构审核批准，并在其指导监督下组织补考。补考一般安排在考试结束后半个月内进行。</p>\n     <p>各补考科目均由招生单位命题。补考试题的形式和难易程度应与原试题相一致。</p>\n     <p style=\"text-align: center;\"><strong>第六章 评卷</strong></p>\n     <p>第三十九条 全国统一命题科目的评卷工作实行省级招委会统一领导、省级教育招生考试机构统一组织、评卷点具体实施的管理体制。省级教育招生考试机构要在教育部教育考试院指导下按要求制订评卷细则、程序、工作要求和纪律等。招生单位有责任和义务承担属地全国统一命题科目评卷工作。</p>\n     <p>第四十条 省级教育招生考试机构要加强评卷点建设。各评卷点要成立由省级教育招生考试机构负责人和承办单位负责人共同组成的领导小组，加强对评卷工作的领导和管理；建立健全评卷工作系列规章制度，特别是评卷工作责任制度、责任追究制度和评卷工作质量监督保证制度；完善评卷教师聘任机制，保证评卷工作平稳有序。</p>\n     <p>第四十一条 省级教育招生考试机构成立由相关招生单位各学科权威专家组成的全国统一命题科目评卷工作专家组，根据教育部教育考试院提供的评分参考，负责本地区全国统一命题科目评卷工作细则的拟定、试卷的试评、评卷教师的培训、评卷工作的业务指导与组织实施、试卷评阅过程中争议问题的仲裁等工作。</p>\n     <p>第四十二条 省级教育招生考试机构根据有关规定，聘请有关教师承担各学科评卷工作。招生单位有责任和义务按省级教育招生考试机构的要求选派所需评卷教师，无正当理由不得推辞拒绝。评卷教师所在学校要按规定将教师参加评卷工作相关情况纳入教师履职考评体系。</p>\n     <p>第四十三条 招生单位自命题科目的评卷工作由本单位负责，原则上采用网上评卷方式。招生单位参照全国统一命题科目评卷管理机制、办法和有关要求开展自命题科目评卷，制订评分细则，统一评分标准，推进多人分题评卷、双人双评等改革，加强评卷工作规范管理，保证评卷质量。联合命题的评卷工作原则上要确定一个招生单位作为牵头单位，负责统筹组织和管理评卷工作。招生单位应组织开展自命题科目评卷自查，确保不发生误评、漏评、统分错误等情况，自查结束后将加盖单位公章的自查报告（相关负责人员须签字确认）及自命题科目成绩报送省级教育招生考试机构。</p>\n     <p>省级教育招生考试机构应开展全国统一命题科目评卷自查，并监督检查本行政区域内招生单位自命题科目评卷工作。自查检查完成后，将全国统一命题科目成绩和自命题科目成绩合成，在规定时间上报教育部，并将全国统一命题科目成绩返回招生单位。</p>\n     <p>第四十四条 招生单位应当在规定时间内向考生公布成绩。考生若对评卷结果有异议，可以依程序申请成绩复查，具体的复查办法按照教育部相关考务文件执行。</p>\n     <p>第四十五条 全国统一命题科目答卷由省级教育招生考试机构保存，自命题科目答卷由招生单位保存。所有纸介质答卷均须进行电子扫描保存，其中，纸介质至少保留1年，电子扫描版至少保留5年。</p>\n     <p style=\"text-align: center;\"><strong>第七章 复试</strong></p>\n     <p>第四十六条 复试的主要形式有笔试、面试、实践（实验）能力考核等，其中面试是必要环节。招生单位应对复试考核总成绩设立合格标准，也可在此基础上，根据部分学科专业特点对复试中的单项考核成绩设立合格标准。复试不合格者不予录取。</p>\n     <p>招生单位根据办学特色，针对不同的复试方式、学科专业特点，精心设计复试内容，确保复试考核科学有效。同时，可结合考生大学学业成绩单、毕业论文（应届本科毕业生可提供毕业论文开题报告）、科研成果等补充材料，加强对考生既往学业基础、专业能力素质、科研创新潜质等方面的全面考查和综合评价。</p>\n     <p>第四十七条 招生单位要按照教育部有关规定制订本单位复试录取办法，审核各院（系、所等）实施细则，明确复试时间、地点、内容、方式、考生进入复试的初试成绩要求（以下简称考生初试成绩要求）、成绩使用办法、工作程序、组织管理、咨询渠道等，提前在本单位网站向社会公布并严格执行。未提前公布的复试录取办法一律无效。</p>\n     <p>招生单位复试试题管理工作参照初试自命题有关工作要求执行，原则上应命制多套试题。</p>\n     <p>招生单位应制订复试工作人员的遴选标准。严格依据标准选聘人品公道正派、工作能力突出的人员参与复试工作；考前对所有工作人员进行政策、业务、纪律等方面的培训和考核，强化保密意识、责任意识和法治意识，考核不合格者不得上岗。招生单位应制订复试行为规范，明确工作纪律、工作程序、评判规则、评判标准，规范工作人员的复试工作行为和用语。</p>\n     <p>第四十八条 教育部按照一区、二区制定并公布参加全国硕士研究生招生考试考生进入复试的初试成绩基本要求（以下简称国家分数线）。一区包括北京、天津、河北、山西、辽宁、吉林、黑龙江、上海、江苏、浙江、安徽、福建、江西、山东、河南、湖北、湖南、广东、重庆、四川、陕西等21省（市）；二区包括内蒙古、广西、海南、贵州、云南、西藏、甘肃、青海、宁夏、新疆等10省（区）。原则上按学科门类分别划线，“少数民族高层次骨干人才计划”、少数民族照顾政策、工商管理等管理类专业学位、以及有关照顾专业（指工学、教育学照顾专业，具体范围由教育部根据国家战略需要、社会发展需求、考生报考情况等因素适时调整，下同）单独划线。</p>\n     <p>第四十九条 招生单位应确定并公布报考本单位的考生初试成绩要求（分学科门类或学科专业的总成绩、单科成绩要求，含有关专项计划，下同）等。</p>\n     <p>（一）自主确定并公布报考本单位临床医学、口腔医学、中医和针灸（以下简称临床医学类）专业学位考生初试成绩要求。教育部划定的临床医学类专业学位国家分数线供招生单位参考。</p>\n     <p>（二）自主确定“退役大学生士兵计划”考生初试成绩要求（一般不高于本单位相应学科专业普通计划考生初试成绩要求）、该计划接受考生调剂的初试成绩要求。同等条件下服役时间长的考生优先录取。</p>\n     <p>（三）自主确定参加单独考试（含强军计划、援藏计划）的考生初试成绩要求。</p>\n     <p>（四）除上述（一）、（二）、（三）等3种情形外，招生单位须在国家分数线基础上，结合生源、招生计划、复试比例等情况，自主确定本单位考生初试成绩要求及其他学术要求，但不得提出歧视性或其他有违公平的要求。</p>\n     <p>其中，经教育部批准的有关招生单位可直接自主划定考生初试成绩要求，报经所在地省级教育招生考试机构备案后方可公布，未经备案的不得公布执行。有关招生单位划线工作要坚持质量为先、宁缺毋滥的原则，初试成绩要求应符合学校办学定位和人才选拔要求，不得单纯为完成招生计划而降低要求。所有考试科目均为全国统一命题科目的学科专业，招生单位自主划定的考生初试成绩要求不得低于国家分数线。招生单位自主划定的考生初试总成绩要求低于国家分数线的学科专业，下一年度不得扩大该学科专业招生规模（不含“退役大学生士兵计划”）。</p>\n     <p>第五十条 复试采取差额形式，差额比例由招生单位自主确定并提前公布，进入复试的考生人数一般不少于各学科专业已公布招生计划的120%。合格生源比例不足的，按实际合格生源数组织复试。</p>\n     <p>第五十一条 招生单位应在复试期间严格采取人证识别、相关信息库数据比对等措施，加强对考生的身份审核及报考专项计划、申请享受初试加分或少数民族照顾政策等资格的复审。对不符合规定条件者，不予复试。</p>\n     <p>第五十二条 招生单位一般应按学科专业成立复试面试小组，面试小组一般不少于5人，鼓励聘请符合遴选标准的外单位（高校、科研院所、企业等）专家参与面试。小组成员须现场独立评分，原始评分记录和考生作答情况在本单元面试工作结束后立即交招生单位研究生招生管理部门集中统一保管，任何人不得改动。</p>\n     <p>招生单位要加强复试过程管理和监督。采取随机选定考生次序、随机确定复试工作组成人员、随机抽取复试试题等措施，复试全程录音录像，选派专门人员到复试现场巡视，确保公平公正。</p>\n     <p>所有纸介质评分记录和考生作答情况均须进行电子扫描保存，其中，纸介质至少保留1年，电子扫描版至少保留5年。复试录音录像电子材料至少保留5年。</p>\n     <p>招生单位应提醒考生自觉遵守招生单位考场规则及考生所签署的《诚信复试承诺书》等内容，在招生单位复试工作结束前不得对外透露或传播复试试题内容等有关情况。</p>\n     <p>第五十三条 招生单位对以同等学力身份报考并参加复试的考生，在复试中须加试至少两门与报考专业相关的本科主干课程。加试方式为笔试，加试科目不得与初试科目相同，加试不合格者不予录取。</p>\n     <p>跨学科专业复试的考生（不仅限以同等学力身份报考的）是否需要在复试中加试与报考专业相关的本科主干课程，由招生单位自主确定。</p>\n     <p>第五十四条 招生单位须在工商管理、公共管理、会计、旅游管理、图书情报、工程管理和审计等7个专业学位复试中组织思想政治理论考试，成绩计入复试总成绩。</p>\n     <p>第五十五条 外国语听力及口语测试均在复试中进行，由招生单位自行组织，成绩计入复试总成绩。</p>\n     <p>第五十六条 招生单位可设立破格复试机制。对初试公共科目（思想政治理论、外国语等考试科目）成绩略低于全国初试单科成绩基本要求，但业务课科目成绩特别优异并在报考的相关学科专业领域实践或科研创新方面具有突出表现的考生，可允许其破格参加第一志愿报考单位第一志愿专业复试。</p>\n     <p>破格复试办法（含破格标准等）、程序须经招生单位招委会研究审定后，报省级教育招生考试机构备案，纳入本单位复试录取办法一并提前对外公布。符合破格复试基本条件的考生按程序提交申请；有关招生单位应组织相关学科领域权威专家（不少于5人），对考生申请材料进行审核，必要时可组织答辩，对是否符合破格复试资格提出专家意见，报招生单位招委会审定。参加破格复试的考生名单须单独公示。破格复试应优先考虑基础学科、艰苦专业等国家战略急需但生源相对不足的学科专业。</p>\n     <p>对一志愿合格生源不足的专业，招生单位要积极做好调剂工作，不得单纯为完成招生计划而降低标准进行破格复试。合格生源（含调剂生源）充足的招生专业一般不再进行破格复试。破格复试未被录取考生不得破格参加调剂。</p>\n     <p>第五十七条 如有必要，经所在地省级教育招生考试机构同意，招生单位可以对考生再次复试。</p>\n     <p style=\"text-align: center;\"><strong>第八章 调剂</strong></p>\n     <p>第五十八条 招生单位在第一志愿合格生源不足时，可组织开展调剂工作。招生单位接受所有考生（含报考“退役大学生士兵计划”与普通计划之间调剂的考生等）调剂申请均须通过教育部“全国硕士生招生复试调剂服务系统”（网址：https://yz.chsi.com.cn/yztj）进行，严禁通过其他渠道接受考生调剂申请。</p>\n     <p>第五十九条 开展调剂的招生单位应当按教育部有关政策规定以及本单位学科建设和发展需要，坚持“公平、公正、公开”的原则，科学、规范制订调剂工作办法，并提前在“全国硕士生招生复试调剂服务系统”和本单位网站公布。</p>\n     <p>招生单位调剂工作办法应明确接受考生调剂的时间、基本要求（含考生第一志愿专业范围、初试科目、初试成绩要求等，其中初试成绩含加分）、工作程序、复试录取办法（含考生进入复试的遴选规则）、咨询渠道等信息，报本单位招委会审定，其中涉及考生第一志愿专业范围等学术要求的，须先经本单位学位评定委员会或学术委员会审核同意，确保科学性。调剂考生初试成绩须符合第一志愿报考专业在调入地区的国家分数线，并符合调入专业的报考条件。原则上，调剂考生第一志愿专业与调入专业相同相近，或初试科目与调入专业初试科目相同相近。</p>\n     <p>招生单位要规范制订调剂考生进入复试的遴选规则，不得将考生第一志愿报考单位、毕业院校、提交调剂志愿的时间先后顺序等非学业水平标准作为遴选依据。对申请同一招生单位同一专业、初试科目完全相同的调剂考生，招生单位应当按考生初试成绩择优遴选进入复试的考生。</p>\n     <p>省级教育行政部门、教育招生考试机构要加强对本行政区域内招生单位调剂办法、调剂录取名单的审核，及对调剂工作的监督。</p>\n     <p>第六十条 第一志愿报考下列专业（或专项计划），应遵循相关调剂要求。</p>\n     <p>（一）考生在照顾专业与非照顾专业之间调剂，其初试成绩均须符合调入地区第一志愿报考专业所在学科门类的非照顾专业国家分数线。</p>\n     <p>考生在工学照顾专业之间，教育学照顾专业之间调剂，按本类照顾专业国家分数线执行。</p>\n     <p>（二）报考工商管理、公共管理、会计、旅游管理、图书情报、工程管理、审计等7个专业学位的考生，在满足调入专业报考条件、且初试成绩同时符合调出专业和调入专业在调入地区的国家分数线的基础上，可申请相互调剂，但不得调入其他专业；报考其他专业的考生不得调入该7个专业学位。</p>\n     <p>（三）报考“退役大学生士兵计划”的考生，申请调剂到普通计划，其初试成绩须达到调入地区相关专业所在学科门类的国家分数线。符合条件的，可按规定享受退役大学生士兵初试加分政策。</p>\n     <p>报考普通计划的考生，若符合“退役大学生士兵计划”报考条件，可申请调剂到该专项计划，其初试成绩须符合相关招生单位确定的接受“退役大学生士兵计划”考生调剂的初试成绩要求。对于“退役大学生士兵计划”和普通计划之间的调剂，招生单位须严格按照调剂程序和要求组织，不得直接改变考生志愿、调整计划类型进行复试录取。</p>\n     <p>（四）招生单位自主确定并公布本单位接受报考其他单位临床医学类专业学位调剂申请的成绩要求。教育部划定临床医学类专业学位初试成绩基本要求作为报考临床医学类专业学位的考生调剂到其他学科专业的基本成绩要求。</p>\n     <p>报考临床医学类专业学位的考生可按相关政策调剂到其他学科专业，报考其他学科专业（含医学学术学位）的考生不可调剂到临床医学类专业学位。</p>\n     <p>（五）报考法律（非法学）专业学位以外的考生不得调剂到法律（非法学）专业学位。</p>\n     <p>（六）报考“少数民族高层次骨干人才计划”的考生不得调剂到该专项计划以外；未报考的不得调剂到该专项计划。</p>\n     <p>（七）参加单独考试（含强军计划、援藏计划）的考生不得调剂。</p>\n     <p>第六十一条 招生单位应根据本单位复试录取情况，通过本单位官方网站和“全国硕士生招生复试调剂服务系统”及时、准确发布招生计划余额信息，为调剂考生做好政策宣传解读、咨询答复等服务保障工作。严禁招生单位任何工作人员和学生未经单位授权擅自发布调剂信息。</p>\n     <p>招生单位通过“全国硕士生招生复试调剂服务系统”自主设定调剂系统持续时间、考生调剂志愿锁定时间等，并在时间安排上为考生提供合理便利。其中，每次开放调剂系统持续时间不得低于12小时，考生调剂志愿锁定时间不得超过36小时。锁定时间到达后，如招生单位未明确受理意见，系统自动解除锁定，考生可继续填报其他志愿。</p>\n     <p>招生单位发布需考生确认拟录取或复试通知时，需充分考虑考生学习、工作、休息时间等因素作出合理安排，给考生预留充裕的确认时间。对于没有按时确认的考生，招生单位应通过电话、短信、邮件等方式逐一联系确认，不得简单以“逾期不接受视为自行放弃”对待。</p>\n     <p style=\"text-align: center;\"><strong>第九章 思想政治素质和品德考核</strong></p>\n     <p>第六十二条 思想政治素质和品德考核是保证入学新生质量的重要工作环节。招生单位必须严格遵循实事求是的原则认真做好考核工作，对于思想政治素质和品德考核不合格者不予录取。</p>\n     <p>第六十三条 思想政治素质和品德考核主要考核考生本人的现实表现，包括考生的政治态度、思想表现、道德品质、遵纪守法、诚实守信等方面。</p>\n     <p>招生单位要强化对考生诚信的要求，充分利用《国家教育考试考生诚信档案》记录，对考生在报考时填写的考试作弊受处罚情况进行认真核查，将考生诚信状况作为思想品德考核的重要内容和录取的重要依据。凡有违反国家教育考试规定、情节严重受到停考处罚，在处罚结束后继续报名参加研究生招生考试的，由招生单位决定是否予以录取。</p>\n     <p>第六十四条 招生单位可在复试中加强对考生思想政治素质和品德考核，也可组织思想政治工作、招生工作等部门工作人员与考生面谈，直接了解考生思想政治情况，还可采取“函调”或“派人外调”等方式对考生的思想政治素质和品德进行考核。</p>\n     <p>拟录取名单确定后，招生单位应向考生所在单位函调人事档案（或档案审查意见）和本人现实表现等材料，全面考查其思想政治和品德情况。函调的考生现实表现材料，须由考生本人档案或工作所在单位的人事、政工部门加盖印章。</p>\n     <p style=\"text-align: center;\"><strong>第十章 录取</strong></p>\n     <p>第六十五条 招生单位要在本单位招委会的统一领导下，按照教育部有关招生政策规定及所在地省级招委会的管理和实施办法，根据本单位招生计划、复试录取办法以及考生考试综合成绩、思想政治素质和品德考核情况、身心健康状况等择优确定拟录取名单。其中，考试综合成绩由初试成绩和复试成绩按权重相加，初试成绩占综合成绩的权重一般不低于50%，具体由招生单位自定；对于调剂考生的综合成绩构成，招生单位可在此基础上优化调整。</p>\n     <p>招生单位要在录取工作中依法保护残疾考生的合法权益。</p>\n     <p>招生单位录取工作一般应在录取当年4月底前完成。</p>\n     <p>第六十六条 招生单位要严格按照教育部下达的招生计划（含各专项计划）及相关要求开展招生录取工作，录取人数不得超过本单位招生计划。同一招生单位内，学术学位招生计划可调整到专业学位使用，专业学位招生计划不得调整到学术学位专业使用。全日制招生计划与非全日制招生计划不得相互调整使用。</p>\n     <p>招生单位承担的各类专项计划均包含在本单位的招生总规模以内，专项计划专项使用，不得挪用。破格复试录取人数原则上不超过本单位全日制硕士研究生招生计划的3%。单独考试录取人数不得超过教育部下达的单独考试招生限额。</p>\n     <p>第六十七条 对于拟录取为定向就业的考生，招生单位须严格审核其定向就业合同，从严把握，并提前告知其相关就业政策等。一经录取后，不得变更录取信息中的就业方式。</p>\n     <p>定向就业的考生应当在被录取前与招生单位、用人单位签订定向就业合同。参加单独考试（除报考面向残障考生单独考试）的考生，只能被录取为回原单位定向就业。</p>\n     <p>考生因报考硕士研究生与所在单位产生的问题由考生自行处理。若因此造成考生不能复试或无法录取，招生单位不承担责任。</p>\n     <p>第六十八条 招生单位在确定拟录取名单前，要全面开展录取检查，对报考资格、录取条件、录取程序等不符合规定者不予录取。不得将未通过或未完成学历（学籍）审核的考生列入拟录取名单公示或上报。</p>\n     <p>招生单位为录取考生打印《录取登记表》，盖章后存入考生的人事档案。</p>\n     <p>第六十九条 省级教育行政部门、教育招生考试机构应当按国家规定对招生单位的录取工作进行监督检查。</p>\n     <p>第七十条 应届本科毕业生及自学考试和网络教育届时可毕业本科生考生，在录取当年入学前（具体时限由招生单位规定，下同）须取得国家承认的国（境）内高校本科毕业证书或教育部留学服务中心出具的《国（境）外学历学位认证书》。招生单位要加强对相关证书的核验。录取当年入学前未取得相关证书的，其录取资格无效。</p>\n     <p>第七十一条 被录取的新生（录取资格无效的除外），可以申请保留入学资格，保留入学资格的条件、期限等由招生单位规定。经招生单位同意保留入学资格的新生纳入招生单位录取当年的招生计划管理。</p>\n     <p>第七十二条 考生体检工作由招生单位在考生拟录取后组织进行。招生单位根据《中华人民共和国残疾人教育条例》和《教育部办公厅 卫生部办公厅关于普通高等学校招生学生入学身体检查取消乙肝项目检测有关问题的通知》（教学厅〔2010〕2号）等文件规定，参照《教育部 卫生部 中国残疾人联合会关于印发〈普通高等学校招生体检工作指导意见〉的通知》（教学〔2003〕3号）要求，结合招生专业实际情况，提出本单位体检要求。</p>\n     <p style=\"text-align: center;\"><strong>第十一章 信息公开公示</strong></p>\n     <p>第七十三条 省级教育行政部门、教育招生考试机构和招生单位应当按教育部有关政策规定和“谁公开、谁把关”“谁公开、谁解释”的原则，积极推进本地区、本单位研究生招生信息公开。</p>\n     <p>第七十四条 省级教育行政部门、教育招生考试机构应在本单位网站公布本地区硕士研究生招生的相关办法、考试组织的相关安排和要求等。加强对本行政区域内招生单位招生信息公开工作的指导和监督，审核招生单位上报公开的信息。</p>\n     <p>第七十五条 招生单位应在本单位招生网站公开年度硕士研究生招生信息，所有公开的信息均须符合研究生招生政策规定。</p>\n     <p>报名前，应公布本单位硕士研究生招生章程。招生章程中应明确本单位各学科专业（含单独考试）的报考条件、拟安排招生计划，初试考试科目、复试方式及有关考核要求（含破格复试、加试办法）、录取程序和标准，学习方式、学制、学费标准、奖助办法、毕业就业、住宿情况以及培养所在校区等内容。原则上招生单位非全日制硕士研究生招收在职定向就业人员。复试前，还应根据本办法第七章、第八章有关要求公布本单位复试录取办法、调剂工作办法及经审定的各院（系、所等）实施细则，公布进入复试的考生名单（包括考生姓名、考生编号、初试各科成绩等信息）。有关招生章程、办法在公开前应报当地省级教育行政部门、教育招生考试机构备案。</p>\n     <p>第七十六条 招生单位应在本单位招生网站公示拟录取考生名单（包括考生姓名、考生编号、初试成绩、复试成绩、总成绩等信息），公示时间不少于7日，公示期间名单不得修改；名单如有变动，须对变动部分作出说明，并对变动内容另行公示7日。未经招生单位公示的考生，一律不得录取，不予学籍注册。</p>\n     <p>对破格复试、报考专项计划、享受初试加分或照顾政策的考生相关情况，在公布考生名单时应当进行说明。相关信息及材料需存档备查，并明确责任人。</p>\n     <p>公示结束后，招生单位将拟录取名单报省级教育行政部门、教育招生考试机构进行政策审核。省级教育行政部门、教育招生考试机构及时向招生单位反馈审核意见。招生单位应按要求将审核通过的录取名单上传至教育部“全国硕士研究生招生信息公开平台”（网址：https://yz.chsi.com.cn/zsgs）进行公开。最终录取名单及新生学籍注册均以招生单位上报平台的信息为准。</p>\n     <p>第七十七条 省级教育行政部门、教育招生考试机构及招生单位应公开考生咨询及申诉渠道（包括联系部门、电子信箱、电话号码和通讯地址等）。建立完善接诉即办机制，对相关申诉和举报及时调查处理。及时公开重大违规事件调查处理结果。</p>\n     <p style=\"text-align: center;\"><strong>第十二章 违规处理</strong></p>\n     <p>第七十八条 建立健全研究生考试招生回避制度。各地各招生单位参与考试招生相关工作的人员，如本人报名参加本次研究生招生考试的，应主动向本单位申请全程回避；如有直系亲属或利益相关者报名的，应主动向本单位申请在影响保密、公平的必要环节和特定工作时期回避；有非直系亲属等报名的应主动报备，由本单位或本地省级招生考试机构研究决定是否需要回避及如何回避。招生单位中层及以上领导干部，其本人或直系亲属、其他利益相关者报名参加本单位研究生考试招生的，应主动向本单位报备并全程回避；如有非直系亲属等报名本单位的，应主动报备，由本单位研究决定是否需要回避及如何回避。招生单位工作人员原则上不得报考本单位单独考试。对未按规定报备或回避的相关工作人员，应依规依纪严肃处理。</p>\n     <p>各省级招委会、招生单位招委会要根据上述要求，制订本单位研究生考试招生回避制度实施细则，并严格执行。</p>\n     <p>第七十九条 全国硕士研究生招生考试是法律规定的国家考试。招生单位和省级教育招生考试机构要教育引导考生遵章守纪、诚信考试。对在研究生招生考试中违反考试管理规定和考场纪律，影响考试公平、公正的考生、考试工作人员及其他相关人员，一律按《中华人民共和国刑法》《中华人民共和国教育法》《最高人民法院 最高人民检察院关于办理组织考试作弊等刑事案件适用法律若干问题的解释》及《国家教育考试违规处理办法》（教育部令第33号）严肃处理。对在校生，由其所在学校按有关规定给予处分，直至开除学籍；对在职考生，应通知考生所在单位，由考生所在单位视情节给予党纪或政纪处分；对考试工作人员，由教育招生考试机构或其所在单位视情节给予相应的行政处分；构成违法的,依法追究法律责任，其中构成犯罪的，依法追究刑事责任。</p>\n     <p>相关单位应当依法将考生在硕士研究生招生考试中的作弊事实记入《国家教育考试考生诚信档案》，并将考生的有关情况通报其所在学校或单位。</p>\n     <p>第八十条 对在招生工作中有违反国家有关法律法规和招生管理规定行为的招生单位、招生考试机构、主管教育行政部门及其招生工作人员，一律按相关法律法规严肃处理，并追究直接责任人员的责任，造成严重后果和恶劣影响的，还将按规定对有关责任人实行问责。</p>\n     <p>严禁招生工作人员接受考生及家长赠送的礼金和有价证券，以及可能影响考试招生公平公正的宴请等消费娱乐活动。</p>\n     <p>第八十一条 各级教育行政部门、教育招生考试机构和研究生招生单位要认真落实《教育部关于进一步加强考研辅导活动管理的通知》（教学〔2008〕1号）等要求，加强考研辅导活动监管和依法整治。</p>\n     <p>对社会培训机构违规开展辅导培训或发布虚假招生宣传（广告）骗取钱财的，当地教育行政部门或其他有关部门应依据《中华人民共和国民办教育促进法》《中华人民共和国广告法》等责令其限期改正，并予以警告；有违法所得的，没收非法所得；情节严重的责令停止招生，吊销办学许可证和营业执照；构成犯罪的依法追究法律责任。</p>\n     <p>严禁招生单位内部任何部门和工作人员举办或参与举办考研辅导活动。严禁招生单位自命题科目相关命题人员参与任何与考研内容有关的咨询、考研复习资料编写、出版等活动，相关人员须向招生单位作出书面承诺。严禁招生单位向社会培训机构提供举办考研辅导活动的场所和设施，严禁社会培训机构进入校园以张贴简章、广告等各种方式进行考研辅导培训宣传和组织活动。在校生不得举办或参与助考作弊、虚假宣传等涉考违规违法活动。违反规定的要坚决予以清理取缔并追究有关部门和相关人员责任。</p>\n     <p>第八十二条 招生单位要严格执行国家收费政策，禁止在研究生招生过程中乱收费，违反规定的要追究有关部门和相关人员责任。</p>\n     <p>第八十三条 考生认为所报考招生单位的招生录取行为有违反本规定或其他相关规定的，可向报考招生单位提出异议、申诉或举报。招生单位应当进行调查、处理，属于对政策执行存在异议的，应当及时书面或口头答复申诉人；属于对违规违纪违法行为举报的，应当依规依纪依法处置。</p>\n     <p>考生对招生单位作出的书面答复不服的，可向招生单位所在地省级教育行政部门或省级教育招生考试机构申请复查。对复查结论不服的，可按相关规定向省级教育行政部门或省级教育招生考试机构的上一级机关提出复核。</p>\n     <p style=\"text-align: center;\"><strong>第十三章 附则</strong></p>\n     <p>第八十四条 现役军人报考硕士研究生及军队系统的招生单位招收硕士研究生的办法由军队相关部门参照本规定另行制定。</p>\n     <p>第八十五条 单独考试招生方案须经招生单位主管部门和所在地省级教育行政部门、招生考试机构审核后报教育部高校学生司备案。</p>\n     <p>第八十六条 推荐免试工作相关管理办法由教育部另文规定。</p>\n     <p>第八十七条 有关研究生招生计划管理、生均拨款、学费标准、奖助政策、新生管理等未尽事宜，按照有关规定执行。</p>\n     <p>第八十八条 其他招生政策和程序与本规定不符的以本规定为准。</p>\n     <p>第八十九条 本规定自印发之日起施行。</p>\n    </div>\n    <div id=\"dzz\"></div>\n   </div>\n   <div class=\"content-r\">\n    <div class=\"img-box\">\n     <chsi-ad value=\"687793826\"></chsi-ad>\n    </div>\n    <div class=\"aside-box aside-con-hot\">\n     <div class=\"aside-title\">\n      近期热点\n     </div>\n     <div class=\"aside-con\">\n      <ul class=\"r_box_txt\">\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/tydxs.shtml\" style=\"color: #ff0000\" target=\"_blank\">退役大学生士兵报考硕士研究生有关招生政策解读</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202602/20260228/2293449091.html\" target=\"_blank\">2026年研考国家线发布</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/kyfs.shtml\" target=\"_blank\">2026年研考分数查询及复试分数线汇总</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/jybzc/202509/20250924/2293432108.html\" target=\"_blank\">2026年研招管理规定</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/kydt/202509/20250924/2293432116.html\" target=\"_blank\">2026研考日程表</a></li>\n       <li><a href=\"https://yz.chsi.com.cn/kyzx/zt/lnfsx2025.shtml\" target=\"_blank\">近五年研考分数线及趋势图</a></li>\n      </ul>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      招生信息\n     </div>\n     <div class=\"aside-con\">\n      <chsi-ad value=\"695740799\"></chsi-ad>\n     </div>\n    </div>\n    <div class=\"aside-box\">\n     <div class=\"aside-title\">\n      考研工具箱\n     </div>\n     <div class=\"aside-con\">\n      <div class=\"aside-con-title\">\n       查询\n      </div>\n      <div class=\"aside-con-item block\">\n       <a href=\"https://yz.chsi.com.cn/sch/\" target=\"_blank\">院校库</a> <a href=\"https://yz.chsi.com.cn/zyk/\" target=\"_blank\">专业库</a> <a href=\"https://yz.chsi.com.cn/zsml/\" target=\"_blank\">硕士目录</a> <a href=\"https://