INSERT INTO `yl_news` VALUES (9, '多地开启成绩复核通道，高校复试工作全面启动', '<ul>\n<li>\n<div><strong>成绩复核集中受理</strong>：四川、江苏、烟台等多地高校于<strong>3 月 1 日 - 2 日</strong>集中受理考研初试成绩复核申请，逾期不再受理。考生需按招生单位公布的申请方式和流程提交复核材料，复核范围仅限答卷漏评、成绩累加错误等，不涉及评分标准宽严问题。</div>\n<div>&nbsp;</div>\n</li>\n<li>\n<div><strong>清华等高校发布成绩查询通知</strong>：清华大学今日正式开通 2026 年考研初试成绩网上查询通道，考生可通过研招网或学校研究生院官网查询，同时公布成绩复核申请时间为<strong>3 月 1 日 - 3 月 3 日</strong>。</div>\n<div>&nbsp;</div>\n</li>\n<li>\n<div><strong>复试准备进入关键期</strong>：国家线已于<strong>2 月 28 日</strong>公布，各招生单位陆续发布复试分数线和复试安排中国研究生招生信息网。今年新规明确<strong>初试成绩占综合成绩权重不得低于 50%</strong>，各院校须提前公示比例，录取过程不能随意更改。</div>\n<div>&nbsp;</div>\n</li>\n<li>\n<div><strong>调剂系统时间确定</strong>：研招网调剂意向采集系统将于<strong>3 月 27 日</strong>开通，调剂服务系统<strong>4 月 8 日</strong>正式开放，考生可提前准备调剂材料，密切关注目标院校调剂信息中国研究生招生信息网。</div>\n<div>&nbsp;</div>\n</li>\n</ul>\n<div>&nbsp;</div>\n<div><strong>温馨提示</strong>：成绩复核结果一般在申请结束后 5-7 个工作日公布，考生可通过原查询渠道查询复核结果，同时建议提前准备复试，熟悉目标院校复试科目和流程。</div>', '报考', 'http://localhost:8080/files/ff4da1d610c94481b6a07f4f997b9062.png', 9, 1, '2026-03-01 21:20:00', '2026-03-01 21:20:00', 0, 0, 9);
